function ensureA11yElementId(element, prefix = "a11y") {
  if (!element) {
    return "";
  }
  const existingId = String(element.id || "").trim();
  if (existingId) {
    return existingId;
  }
  a11yIdSequence += 1;
  const nextId = `${prefix}-${a11yIdSequence}`;
  element.id = nextId;
  return nextId;
}

function isElementHiddenByTree(element) {
  if (!element || !(element instanceof HTMLElement)) {
    return true;
  }
  if (element.classList.contains("hidden")) {
    return true;
  }
  if (element.hidden) {
    return true;
  }
  if (element.getAttribute("aria-hidden") === "true") {
    return true;
  }
  if (element.closest(".hidden")) {
    return true;
  }
  return false;
}

function getAccessibleModalElements() {
  return Array.from(document.querySelectorAll(A11Y_MODAL_SELECTOR));
}

function getOpenModalElements() {
  return getAccessibleModalElements().filter((modal) => !isElementHiddenByTree(modal));
}

function getTopOpenModalElement() {
  const openModals = getOpenModalElements();
  return openModals.length ? openModals[openModals.length - 1] : null;
}

function getFocusableElementsWithin(container) {
  if (!container) {
    return [];
  }
  return Array.from(container.querySelectorAll(A11Y_FOCUSABLE_SELECTOR)).filter((element) => {
    if (!(element instanceof HTMLElement)) {
      return false;
    }
    if (isElementHiddenByTree(element)) {
      return false;
    }
    return !element.hasAttribute("disabled");
  });
}

function findModalDialogLabelElement(modalElement) {
  if (!modalElement) {
    return null;
  }
  return (
    modalElement.querySelector(".modal-dialog-head h1, .modal-dialog-head h2, .modal-dialog-head h3, h1, h2, h3") ||
    null
  );
}

function initializeModalA11ySemantics() {
  getAccessibleModalElements().forEach((modalElement) => {
    if (!(modalElement instanceof HTMLElement)) {
      return;
    }
    if (!modalElement.hasAttribute("role")) {
      modalElement.setAttribute("role", "dialog");
    }
    if (!modalElement.hasAttribute("aria-modal")) {
      modalElement.setAttribute("aria-modal", "true");
    }
    const modalId = ensureA11yElementId(modalElement, "modal");
    modalElement.dataset.a11yModalId = modalId;
    const heading = findModalDialogLabelElement(modalElement);
    if (heading) {
      const headingId = ensureA11yElementId(heading, `${modalId}-title`);
      modalElement.setAttribute("aria-labelledby", headingId);
      modalElement.removeAttribute("aria-label");
    } else if (!modalElement.getAttribute("aria-label")) {
      modalElement.setAttribute("aria-label", "Dialog");
    }
  });
}

function syncModalA11yState() {
  initializeModalA11ySemantics();
  const openModalIds = new Set();
  const openModals = getOpenModalElements();
  openModals.forEach((modalElement) => {
    const modalId = modalElement.dataset.a11yModalId || ensureA11yElementId(modalElement, "modal");
    modalElement.dataset.a11yModalId = modalId;
    modalElement.setAttribute("aria-hidden", "false");
    openModalIds.add(modalId);
    if (!a11yOpenModalIds.has(modalId)) {
      const activeElement = document.activeElement;
      if (
        activeElement instanceof HTMLElement &&
        !modalElement.contains(activeElement) &&
        !isElementHiddenByTree(activeElement)
      ) {
        a11yLastFocusedByModalId.set(modalId, activeElement);
      }
    }
  });

  getAccessibleModalElements().forEach((modalElement) => {
    const modalId = modalElement.dataset.a11yModalId || ensureA11yElementId(modalElement, "modal");
    if (!openModalIds.has(modalId)) {
      modalElement.setAttribute("aria-hidden", "true");
    }
  });

  const closedModalIds = Array.from(a11yOpenModalIds).filter((modalId) => !openModalIds.has(modalId));
  closedModalIds.forEach((modalId) => {
    const focusTarget = a11yLastFocusedByModalId.get(modalId);
    if (
      focusTarget instanceof HTMLElement &&
      !isElementHiddenByTree(focusTarget) &&
      typeof focusTarget.focus === "function"
    ) {
      window.setTimeout(() => {
        try {
          focusTarget.focus({ preventScroll: true });
        } catch (error) {
          // no-op
        }
      }, 0);
    }
    a11yLastFocusedByModalId.delete(modalId);
  });

  const topModal = getTopOpenModalElement();
  if (topModal && !topModal.contains(document.activeElement)) {
    const focusables = getFocusableElementsWithin(topModal);
    const fallbackTarget = focusables[0] || topModal;
    if (!focusables.length) {
      topModal.setAttribute("tabindex", "-1");
    }
    if (fallbackTarget instanceof HTMLElement && typeof fallbackTarget.focus === "function") {
      window.setTimeout(() => {
        try {
          fallbackTarget.focus({ preventScroll: true });
        } catch (error) {
          // no-op
        }
      }, 0);
    }
  }

  a11yOpenModalIds = openModalIds;
}

function setTabButtonA11yState(button, isActive) {
  if (!(button instanceof HTMLElement)) {
    return;
  }
  button.setAttribute("role", "tab");
  button.setAttribute("aria-selected", isActive ? "true" : "false");
  button.setAttribute("tabindex", isActive ? "0" : "-1");
  button.removeAttribute("aria-pressed");
}

function setTabPanelA11yState(panel, isActive) {
  if (!(panel instanceof HTMLElement)) {
    return;
  }
  panel.setAttribute("role", "tabpanel");
  panel.setAttribute("aria-hidden", isActive ? "false" : "true");
}

function setupTabGroupA11y(buttons, resolveValue, resolvePanel, prefix = "tab") {
  const entries = Array.from(buttons || []).filter((entry) => entry instanceof HTMLElement);
  if (!entries.length) {
    return;
  }
  const tablist = entries[0].closest("[role='tablist']") || entries[0].parentElement;
  if (tablist && !tablist.hasAttribute("role")) {
    tablist.setAttribute("role", "tablist");
  }
  entries.forEach((button, index) => {
    const tabValue = String(resolveValue(button) || "").trim();
    if (!tabValue) {
      return;
    }
    const panel = resolvePanel(tabValue);
    const buttonId = ensureA11yElementId(button, `${prefix}-tab-${tabValue || index + 1}`);
    if (panel) {
      const panelId = ensureA11yElementId(panel, `${prefix}-panel-${tabValue || index + 1}`);
      button.setAttribute("aria-controls", panelId);
      panel.setAttribute("aria-labelledby", buttonId);
    }
    const active =
      button.classList.contains("is-active") ||
      button.classList.contains("active") ||
      button.getAttribute("aria-selected") === "true";
    setTabButtonA11yState(button, active);
    if (panel) {
      setTabPanelA11yState(panel, !panel.classList.contains("hidden"));
    }
  });
}

