function handleA11yModalFocusTrap(event) {
  if (event.key !== "Tab" || event.defaultPrevented) {
    return;
  }
  const topModal = getTopOpenModalElement();
  if (!topModal) {
    return;
  }
  const focusables = getFocusableElementsWithin(topModal);
  if (!focusables.length) {
    event.preventDefault();
    if (typeof topModal.focus === "function") {
      topModal.focus({ preventScroll: true });
    }
    return;
  }
  const first = focusables[0];
  const last = focusables[focusables.length - 1];
  const activeElement = document.activeElement;
  if (event.shiftKey) {
    if (activeElement === first || !topModal.contains(activeElement)) {
      event.preventDefault();
      last.focus({ preventScroll: true });
    }
    return;
  }
  if (activeElement === last || !topModal.contains(activeElement)) {
    event.preventDefault();
    first.focus({ preventScroll: true });
  }
}

function handleA11yTablistNavigation(event) {
  const target = event.target;
  if (!(target instanceof HTMLElement)) {
    return;
  }
  const tabButton = target.closest("[role='tab']");
  if (!tabButton) {
    return;
  }
  const tablist = tabButton.closest("[role='tablist']");
  if (!tablist) {
    return;
  }
  const tabs = Array.from(tablist.querySelectorAll("[role='tab']")).filter(
    (entry) => entry instanceof HTMLElement && !entry.hasAttribute("disabled")
  );
  if (!tabs.length) {
    return;
  }
  const currentIndex = tabs.indexOf(tabButton);
  if (currentIndex < 0) {
    return;
  }
  const normalizedKey = String(event.key || "");
  if (!["ArrowLeft", "ArrowRight", "Home", "End", "Enter", " "].includes(normalizedKey)) {
    return;
  }
  event.preventDefault();
  if (normalizedKey === "Enter" || normalizedKey === " ") {
    tabButton.click();
    return;
  }
  let nextIndex = currentIndex;
  if (normalizedKey === "ArrowLeft") {
    nextIndex = currentIndex === 0 ? tabs.length - 1 : currentIndex - 1;
  } else if (normalizedKey === "ArrowRight") {
    nextIndex = currentIndex === tabs.length - 1 ? 0 : currentIndex + 1;
  } else if (normalizedKey === "Home") {
    nextIndex = 0;
  } else if (normalizedKey === "End") {
    nextIndex = tabs.length - 1;
  }
  const nextTab = tabs[nextIndex];
  if (!(nextTab instanceof HTMLElement)) {
    return;
  }
  nextTab.focus({ preventScroll: true });
  nextTab.click();
}

function initializeAccessibilityInfrastructure() {
  initializeModalA11ySemantics();
  initializeTabsA11ySemantics();
  syncModalA11yState();
}

function normalizeUserRole(role) {
  const normalizedRole = String(role || "").trim().toLowerCase();
  if (normalizedRole === ROLE_ADMIN) {
    return normalizedRole;
  }
  if (normalizedRole === ROLE_SUPERADMIN || normalizedRole === ROLE_SUPAADMIN_LEGACY) {
    return ROLE_SUPERADMIN;
  }
  if (
    normalizedRole === ROLE_VERTRIEBSMITARBEITER ||
    normalizedRole === "vertrieb" ||
    normalizedRole === "vertreibmitarbeiter"
  ) {
    return ROLE_VERTRIEBSMITARBEITER;
  }
  return ROLE_MITARBEITER;
}

function isPrivilegedRole(role) {
  return PRIVILEGED_ROLES.has(normalizeUserRole(role));
}

function isSuperAdmin(user = getCurrentUser()) {
  return normalizeUserRole(user?.role) === ROLE_SUPERADMIN;
}

function isSalesRepresentative(user = getCurrentUser()) {
  return normalizeUserRole(user?.role) === ROLE_VERTRIEBSMITARBEITER;
}

function normalizeMarketingRole(role) {
  return String(role || "")
    .trim()
    .toLowerCase();
}

function hasMarketingRoleValue(role) {
  const normalizedRole = normalizeMarketingRole(role);
  return MARKETING_ACCESS_ROLES.has(normalizedRole);
}

function isMarketingSectionId(sectionId) {
  return false;
}

function canAccessMarketingModule(user = getCurrentUser()) {
  return false;
}

function canApproveMarketingWorkflow(user = getCurrentUser()) {
  return false;
}

function getMarketingRoleLabel(role) {
  const normalizedRole = normalizeMarketingRole(role);
  if (normalizedRole === "marketing_manager") {
    return "Marketing Manager";
  }
  if (normalizedRole === "marketing_editor") {
    return "Marketing Editor";
  }
  if (normalizedRole === "marketing_designer") {
    return "Marketing Designer";
  }
  if (normalizedRole === "marketing") {
    return "Marketing";
  }
  return "";
}

