function setAppLoadingState(isLoading) {
  document.body.classList.toggle("app-loading", Boolean(isLoading));
}

function isProviderFormDirtyRelevantTarget(target) {
  if (!(target instanceof HTMLElement)) {
    return false;
  }
  const tagName = String(target.tagName || "").toLowerCase();
  if (!["input", "select", "textarea"].includes(tagName)) {
    return false;
  }
  if (target.id === "provider-topic-search") {
    return false;
  }
  if (target.closest("#provider-notes-tab-panel")) {
    return false;
  }
  if (target.matches('input[name="provider-bigplayer-mode"]')) {
    return false;
  }
  if (
    target.id === "provider-bigplayer-category-select" ||
    target.id === "provider-bigplayer-subcategory-category-select" ||
    target.id === "provider-bigplayer-subcategory-select" ||
    target.id === "provider-topic-template"
  ) {
    return false;
  }
  return true;
}

function markProviderFormDirty(target = null) {
  if (target && !isProviderFormDirtyRelevantTarget(target)) {
    return;
  }
  if (providersViewMode !== "form") {
    return;
  }
  providerFormDirty = true;
  providerDraftPendingResume = true;
}

function inferFeedbackTone(message, fallbackTone = "info") {
  const normalized = String(message || "").trim().toLowerCase();
  if (!normalized) {
    return fallbackTone;
  }
  if (
    normalized.includes("konnte nicht") ||
    normalized.includes("fehlgeschlagen") ||
    normalized.includes("fehler") ||
    normalized.includes("ungultig") ||
    normalized.includes("ungültig") ||
    normalized.includes("blockiert") ||
    normalized.includes("nicht erlaubt") ||
    normalized.includes("nicht moglich") ||
    normalized.includes("nicht möglich") ||
    normalized.includes("sql fehlt")
  ) {
    return "error";
  }
  if (
    normalized.includes("gespeichert") ||
    normalized.includes("aktualisiert") ||
    normalized.includes("geloscht") ||
    normalized.includes("gelöscht") ||
    normalized.includes("entfernt") ||
    normalized.includes("freigeschaltet") ||
    normalized.includes("erstellt")
  ) {
    return "success";
  }
  if (normalized.startsWith("bitte ")) {
    return "warning";
  }
  return fallbackTone;
}

function renderActionFeedbackStatus(message, tone = "info", persistMs = 2600) {
  if (!els.actionFeedbackStatus) {
    return;
  }
  const text = String(message || "").trim();
  if (!text) {
    els.actionFeedbackStatus.textContent = "";
    els.actionFeedbackStatus.classList.add("hidden");
    return;
  }

  const sequence = actionFeedbackSequence + 1;
  actionFeedbackSequence = sequence;
  if (actionFeedbackStatusTimeoutId) {
    window.clearTimeout(actionFeedbackStatusTimeoutId);
    actionFeedbackStatusTimeoutId = 0;
  }

  els.actionFeedbackStatus.textContent = text;
  els.actionFeedbackStatus.classList.remove("hidden", "is-success", "is-error", "is-warning", "is-info");
  els.actionFeedbackStatus.classList.add(
    tone === "error" ? "is-error" : tone === "success" ? "is-success" : tone === "warning" ? "is-warning" : "is-info"
  );

  if (persistMs > 0) {
    actionFeedbackStatusTimeoutId = window.setTimeout(() => {
      if (sequence !== actionFeedbackSequence || !els.actionFeedbackStatus) {
        return;
      }
      els.actionFeedbackStatus.classList.add("hidden");
      els.actionFeedbackStatus.textContent = "";
    }, persistMs);
  }
}

function renderActionToast(message, tone = "info", durationMs = 3600) {
  if (!els.actionToastStack) {
    return;
  }
  const text = String(message || "").trim();
  if (!text) {
    return;
  }

  const toast = document.createElement("div");
  toast.className = `action-toast is-${tone}`;
  toast.textContent = text;
  toast.dataset.toastId = String(++actionToastSequence);
  els.actionToastStack.prepend(toast);

  const lifetimeMs = Number.isFinite(durationMs) ? Math.max(1100, durationMs) : 3600;
  window.setTimeout(() => {
    toast.remove();
  }, lifetimeMs);
}

function showActionFeedback(message, options = {}) {
  const text = String(message || "").trim();
  if (!text) {
    return;
  }
  const tone = options?.tone || inferFeedbackTone(text, "info");
  const statusPersistMs = Number.isFinite(options?.statusPersistMs) ? options.statusPersistMs : 2600;
  const withToast = options?.toast === true;
  const toastDurationMs = Number.isFinite(options?.toastDurationMs) ? options.toastDurationMs : 3600;
  renderActionFeedbackStatus(text, tone, statusPersistMs);
  if (withToast) {
    renderActionToast(text, tone, toastDurationMs);
  }
}

function showSuccessFeedback(message, options = {}) {
  showActionFeedback(message, { ...options, tone: "success" });
}

function showInfoFeedback(message, options = {}) {
  showActionFeedback(message, { ...options, tone: "info" });
}

function showWarningFeedback(message, options = {}) {
  showActionFeedback(message, { ...options, tone: "warning" });
}

function showErrorFeedback(message, options = {}) {
  showActionFeedback(message, { ...options, tone: "error" });
}

function announceAutoSaveFeedback() {
  const now = Date.now();
  if (now - lastAutoSaveFeedbackAt < 1400) {
    return;
  }
  lastAutoSaveFeedbackAt = now;
  showSuccessFeedback("Änderungen gespeichert.", { toast: false, statusPersistMs: 1700 });
}

function setActionButtonBusy(button, busy, busyLabel = "Speichert...") {
  if (!(button instanceof HTMLElement)) {
    return;
  }
  if (busy) {
    button.dataset.busyOriginalLabel = button.textContent || "";
    button.textContent = busyLabel;
    button.classList.add("is-busy");
    button.setAttribute("disabled", "disabled");
    return;
  }
  const originalLabel = String(button.dataset.busyOriginalLabel || "").trim();
  if (originalLabel) {
    button.textContent = originalLabel;
  }
  delete button.dataset.busyOriginalLabel;
  button.classList.remove("is-busy");
  button.removeAttribute("disabled");
}

function installAlertBridge() {
  if (typeof window === "undefined" || typeof window.alert !== "function") {
    return;
  }
  if (window.__vertriebsmanagerAlertBridgeInstalled) {
    return;
  }
  nativeWindowAlert = window.alert.bind(window);
  window.alert = (message) => {
    const text = String(message || "").trim();
    if (!text) {
      return;
    }
    showActionFeedback(text, {
      tone: inferFeedbackTone(text, "warning"),
      toast: true,
      statusPersistMs: 5400,
      toastDurationMs: 5400,
    });
  };
  window.__vertriebsmanagerAlertBridgeInstalled = true;
}

function normalizeAuthMode(mode) {
  return mode === "signup" ? "signup" : "signin";
}

function setAuthFieldRequired(field, required) {
  if (!field) {
    return;
  }
  field.required = Boolean(required);
}

function setAuthMode(mode, { preserveMessage = false } = {}) {
  authMode = normalizeAuthMode(mode);
  const signInMode = authMode === "signin";

  if (els.authModeSignInBtn) {
    els.authModeSignInBtn.classList.toggle("active", signInMode);
  }
  if (els.authModeSignUpBtn) {
    els.authModeSignUpBtn.classList.toggle("active", !signInMode);
  }
  if (els.authSignInFields) {
    els.authSignInFields.classList.toggle("hidden", !signInMode);
  }
  if (els.authSignUpFields) {
    els.authSignUpFields.classList.toggle("hidden", signInMode);
  }
  if (els.authSubmitBtn) {
    els.authSubmitBtn.textContent = signInMode ? "Anmelden" : "Registrieren";
  }

  if (signInMode) {
    if (els.authSignInEmail && !els.authSignInEmail.value && els.authSignUpEmail?.value) {
      els.authSignInEmail.value = els.authSignUpEmail.value;
    }
  } else if (els.authSignUpEmail && !els.authSignUpEmail.value && els.authSignInEmail?.value) {
    els.authSignUpEmail.value = els.authSignInEmail.value;
  }

  setAuthFieldRequired(els.authSignInEmail, signInMode);
  setAuthFieldRequired(els.authSignInPassword, signInMode);
  setAuthFieldRequired(els.authSignUpFullName, !signInMode);
  setAuthFieldRequired(els.authSignUpEmail, !signInMode);
  setAuthFieldRequired(els.authSignUpPassword, !signInMode);

  if (!preserveMessage && els.authMessage) {
    els.authMessage.textContent = "";
  }
}

async function initialize() {
  setAppLoadingState(true);
  setAuthMode("signin", { preserveMessage: true });
  clearLegacyAuthErrorParams();
  const authReady = await initializeAuth();
  bindEvents();
  if (!authReady) {
    showAuthGate("Bitte melde dich an.");
    return;
  }
  await bootstrapAfterAuth();
  hideAuthGate();
}

async function bootstrapAfterAuth() {
  providerRegistryRepairChecked = false;
  conversationThreadsLoadingRemote = false;
  conversationThreadsLoadedRemote = false;
  conversationThreadsRemoteUnavailable = false;
  conversationThreadsRemoteWarningShown = false;
  conversationThreadsBackfillAttempted = false;
  incomingInvoicesLoadedRemote = false;
  incomingInvoicesLoadingRemote = false;
  incomingInvoicesRemoteUnavailable = false;
  incomingInvoicesRemoteWarningShown = false;
  incomingInvoices = [];
  incomingInvoiceFiles = [];
  incomingInvoiceEvents = [];
  incomingOffers = [];
  incomingOfferFiles = [];
  contractManagerEntries = [];
  await hydrateState();
  const offerFallback = getIncomingOffersLocalFallback();
  applyIncomingOffersCache(offerFallback.offers, offerFallback.files, { persistBackup: false });
  applyContractManagerCache(getContractManagerLocalFallback(), { persistBackup: false });
  await syncUsersFromSupabase();
  await hydrateIncomingInvoicesFromSupabase({ force: true });
  ensureSessionUser();
  ensureManagementSelection();
  await repairOrphanProviderRegistryEntries();
  initGooglePlaces();
  setUsersView("list");
  setProvidersView("list");
  startRemoteStateSync();
  renderAll();
  if (isSalesRepresentative()) {
    setActiveSection("sales-dashboard-section");
  }
  setAppLoadingState(false);
}

