    const removeIndex = Number(removeBtn.dataset.userResponsibilityRemove);
    if (!Number.isInteger(removeIndex) || removeIndex < 0 || removeIndex >= userResponsibilityDraft.length) {
      return;
    }
    userResponsibilityDraft = userResponsibilityDraft.filter((_, index) => index !== removeIndex);
