  // Backdrop clicks do not close popups; close via explicit controls only.

  document.addEventListener("keydown", (event) => {
    if (event.defaultPrevented) {
      return;
    }
    if ((event.ctrlKey || event.metaKey) && normalizeText(event.key) === "k") {
      event.preventDefault();
      openCommandPalette();
      return;
    }
    if (event.key === "Escape" && isCommandPaletteOpen()) {
      closeCommandPalette();
      return;
    }
    if (event.key === "Escape" && isCompanyNoteReadModalOpen()) {
      closeCompanyNoteReadModal();
      return;
    }
    if (event.key === "Escape" && departmentModalOpen) {
      closeDepartmentModal();
      return;
    }
    if (event.key === "Escape" && departmentMembersModalOpen) {
      closeDepartmentMembersModal();
      return;
    }
    if (event.key === "Escape" && isOrgChartEditModalOpen()) {
      closeOrgChartEditModal();
      return;
    }
    if (event.key === "Escape" && isOrgChartInfoModalOpen()) {
      closeOrgChartInfoModal();
      return;
    }
    if (event.key === "Escape" && conversationOrganizationCreateOpen) {
      conversationOrganizationCreateOpen = false;
      syncConversationOrganizationCreateFormVisibility();
      return;
    }
    if (event.key === "Escape" && isConversationEditModalOpen()) {
      closeConversationEditModal();
      return;
    }
    if (event.key === "Escape" && isSalesPhoneModalOpen()) {
      closeSalesPhoneModal();
      return;
    }
    if (event.key === "Escape" && isTourModalOpen()) {
      closeTourModals();
      return;
    }
    if (event.key === "Escape" && isEmployeeDetailsModalOpen()) {
      clearSelectedEmployeeDetails();
      return;
    }
    if (event.key === "Escape" && isProviderOpenNotesModalOpen()) {
      closeProviderOpenNotesModal();
      return;
    }
    if (event.key === "Escape" && els.topicMovePanel && !els.topicMovePanel.classList.contains("hidden")) {
      els.topicMoveNo?.click();
    }
  });

  els.mapParamsForm?.addEventListener("submit", (event) => {
    event.preventDefault();
    if (!isRoleAdmin()) {
      return;
    }
    setActionButtonBusy(els.mapParamsSaveBtn, true, "Speichert...");
    try {

      const formData = new FormData(event.currentTarget);
      state.settings = normalizeSettings({
        ...state.settings,
        mapParameters: {
          categoryRadiusKm: formData.get("radiusCategory"),
          subcategoryRadiusKm: formData.get("radiusSubcategory"),
          topicRadiusKm: formData.get("radiusTopic"),
          stateTopThreshold: formData.get("stateTopThreshold"),
          stateFlopThreshold: formData.get("stateFlopThreshold"),
        },
      });

      saveState({ showFeedback: false });
      renderMapParameterForm();
      renderActiveDashboardAdminPanel();
      showSuccessFeedback("Parameter gespeichert.");
    } finally {
      setActionButtonBusy(els.mapParamsSaveBtn, false);
    }
  });

  els.paramTargetCountry?.addEventListener("change", () => {
    parameterTargetCountry = String(els.paramTargetCountry.value || "").trim();
    renderProviderTargetParameterForm();
  });

  els.providerTargetForm?.addEventListener("submit", (event) => {
    event.preventDefault();
    if (!isRoleAdmin()) {
      return;
    }
    setActionButtonBusy(els.providerTargetSaveBtn, true, "Speichert...");
    try {

      const formData = new FormData(event.currentTarget);
      const country = String(formData.get("targetCountry") || "").trim();
      if (!country) {
        window.alert("Bitte ein Land auswählen.");
        return;
      }
      parameterTargetCountry = country;

      const rawTarget = String(formData.get("targetValue") || "").trim();
      const targetValue = sanitizeProviderTargetValue(rawTarget);
      const shouldClear = rawTarget === "" || targetValue <= 0;

      const targetsMap = getProviderTargetsByCountry();
      const countryKey = normalizeText(country);
      if (!countryKey) {
        window.alert("Ungültiges Land.");
        return;
      }
      if (shouldClear) {
        delete targetsMap[countryKey];
      } else {
        targetsMap[countryKey] = {
          country,
          target: targetValue,
        };
      }

      state.settings = normalizeSettings({
        ...state.settings,
        providerTargetsByCountry: targetsMap,
      });
      saveState({ showFeedback: false });
      renderMapParameterForm();
      renderActiveDashboardAdminPanel();
      showSuccessFeedback(
        shouldClear
          ? `Zielwert für ${country} entfernt.`
          : `Zielwert für ${country} gespeichert (${targetValue} Live-Anbieter).`
      );
    } finally {
      setActionButtonBusy(els.providerTargetSaveBtn, false);
    }
  });

  els.providersTableBody.addEventListener("click", (event) => {
    const openNotesButton = event.target.closest("button[data-provider-open-notes]");
    if (openNotesButton) {
      const providerId = String(openNotesButton.dataset.providerOpenNotes || "").trim();
      if (!providerId) {
        return;
      }
      void openProviderOpenNotesModal(providerId);
      return;
    }

    const editButton = event.target.closest("button[data-edit-provider]");
    if (editButton) {
      const providerId = editButton.dataset.editProvider;
      const provider = state.providers.find((entry) => entry.id === providerId);
      if (!provider) {
        return;
      }
      const currentUser = getCurrentUser();
      if (!currentUser) {
        return;
      }
      if (!isAdmin() && !providerVisibleForCurrentUser(provider, currentUser)) {
        return;
      }

      editingProviderId = provider.id;
      fillProviderForm(provider);
      els.providerSaveBtn.textContent = "Aktualisieren";
      setProvidersView("form");
      return;
    }

    const viewButton = event.target.closest("button[data-view-provider]");
    if (viewButton) {
      const providerId = viewButton.dataset.viewProvider;
      const provider = state.providers.find((entry) => entry.id === providerId);
      if (!provider) {
        return;
      }
      editingProviderId = provider.id;
      fillProviderForm(provider);
      els.providerSaveBtn.textContent = "Aktualisieren";
      setProviderDetailTab("master");
      setProvidersView("form");
      return;
    }

    const deleteButton = event.target.closest("button[data-delete-provider]");
    if (deleteButton) {
      const providerId = deleteButton.dataset.deleteProvider;
      const provider = state.providers.find((entry) => entry.id === providerId);
      if (!provider) {
        return;
      }
      if (!canCurrentUserDeleteProvider(provider)) {
        window.alert("Löschen nur als Superadmin oder als Ersteller des Anbieters.");
        return;
      }
      void handleDeleteProvider(providerId);
    }
  });

