  els.tourMobileCompleteBtn?.addEventListener("click", () => {
    const selectedTour = getSelectedTourForCurrentUser();
    const activeStopContext = getTourCarActiveStopContext(selectedTour);
    if (!selectedTour || !activeStopContext?.stop?.id || !canCurrentUserEditTour(selectedTour)) {
      return;
    }
    const wasDone = Boolean(String(activeStopContext.stop.doneAt || "").trim());
    if (!wasDone) {
      const nextOpenIndex = findNextOpenTourCarStopIndex(selectedTour, activeStopContext.index + 1);
      if (nextOpenIndex >= 0) {
        tourCarActiveStopIndex = nextOpenIndex;
      } else {
        tourCarActiveStopIndex = Math.min(activeStopContext.index + 1, activeStopContext.total - 1);
      }
    }
    handleTourToggleStopDone(selectedTour.id, activeStopContext.stop.id);
  });
