  const handleSalesDashboardActionClick = (event) => {
    const trigger = event.target.closest("[data-sales-dashboard-action]");
    if (!trigger) {
      return;
    }
    const action = String(trigger.dataset.salesDashboardAction || "").trim();
    if (!action) {
      return;
    }
    if (action === "open-tour") {
      const tourId = String(trigger.dataset.tourId || "").trim();
      if (!tourId) {
        return;
      }
      selectedTourId = tourId;
      setActiveSection("tour-planner-section");
      return;
    }
    if (action === "mark-done") {
      const tourId = String(trigger.dataset.tourId || "").trim();
      const stopId = String(trigger.dataset.stopId || "").trim();
      if (!tourId || !stopId) {
        return;
      }
      selectedTourId = tourId;
      handleTourToggleStopDone(tourId, stopId);
      renderSalesDashboardSection();
      return;
    }
    if (action === "open-phone") {
      const callId = String(trigger.dataset.callId || "").trim();
      if (!callId) {
        return;
      }
      salesPhoneSelectedCallId = callId;
      setSalesPhoneSubpage("detail", { render: false });
      setActiveSection("sales-phone-section");
    }
  };
  els.salesDashboardNextBody?.addEventListener("click", handleSalesDashboardActionClick);
  els.salesDashboardTourList?.addEventListener("click", handleSalesDashboardActionClick);
