function markDeleteActionButton(button) {
  if (!button) {
    return;
  }
  button.classList.add("danger");
  if (button.classList.contains("btn")) {
    button.classList.add("btn-danger");
  }
  if (button.classList.contains("table-btn")) {
    button.classList.add("danger");
  }
}

function iconifyDetailActionButton(button, role) {
  if (!button || !role) {
    return;
  }
  const currentLabel = String(button.dataset.iconLabel || button.textContent || "").trim();
  const fallbackLabel = role === "delete" ? "Löschen" : "Speichern";
  const label = currentLabel || fallbackLabel;
  button.dataset.iconLabel = label;
  button.dataset.iconRole = role;
  button.setAttribute("title", label);
  button.setAttribute("aria-label", label);
  button.classList.add("btn-icon-compact");
  if (role === "delete") {
    markDeleteActionButton(button);
    button.textContent = "✕";
    return;
  }
  button.classList.remove("btn-success");
  if (!button.classList.contains("btn-danger")) {
    button.classList.add("btn-primary");
  }
  button.textContent = "✓";
}

function applyActionButtonIcons() {
  const keepTextDeleteIds = new Set(["delete-confirm-yes"]);
  const detailSaveIconIds = new Set([
    "user-save-btn",
    "conversation-meta-save-btn",
    "company-save-btn",
    "provider-save-btn",
    "tour-detail-save-btn",
    "sales-phone-detail-save-btn",
  ]);
  const detailDeleteIconIds = new Set([
    "conversation-delete-btn",
    "tour-delete-btn",
    "sales-phone-delete-btn",
  ]);
  document.querySelectorAll("button").forEach((button) => {
    if (button.dataset.noIconify === "true") {
      return;
    }
    const buttonId = String(button.id || "").trim();
    if (detailSaveIconIds.has(buttonId)) {
      iconifyDetailActionButton(button, "save");
      return;
    }
    if (detailDeleteIconIds.has(buttonId)) {
      iconifyDetailActionButton(button, "delete");
      return;
    }
    if (button.closest("#conversation-notes-section")) {
      return;
    }
    const text = String(button.textContent || button.dataset.iconLabel || "").trim();
    if (!text) {
      return;
    }
    const normalizedText = normalizeText(text);
    const isDeleteLabel = normalizedText.includes("losch");
    const isEditLabel = normalizedText.includes("bearbeit");
    const hasDeleteDataAttr = button
      .getAttributeNames()
      .some((name) => name.startsWith("data-") && (name.includes("delete") || name.includes("remove")));

    if (isDeleteLabel || hasDeleteDataAttr) {
      markDeleteActionButton(button);
    }

    if (isDeleteLabel && !keepTextDeleteIds.has(buttonId)) {
      if (!button.getAttribute("title")) {
        button.setAttribute("title", text);
      }
      if (!button.getAttribute("aria-label")) {
        button.setAttribute("aria-label", text);
      }
      button.textContent = "✕";
      return;
    }

    if (isEditLabel) {
      if (!button.getAttribute("title")) {
        button.setAttribute("title", text);
      }
      if (!button.getAttribute("aria-label")) {
        button.setAttribute("aria-label", text);
      }
      button.textContent = "✎";
    }
  });
}

function renderUserSwitch() {
  const activeUser = getCurrentUser();
  if (!activeUser) {
    els.currentUserLabel.textContent = "Nicht angemeldet";
    return;
  }

  els.currentUserLabel.textContent = String(activeUser.name || "Benutzer").trim();
}

function isAllowedSalesNavigationTarget(targetId) {
  return ["providers-section", "sales-dashboard-section", "tour-planner-section", "sales-leads-section", "sales-phone-section"].includes(
    String(targetId || "").trim()
  );
}

function isAllowedSalesNavigationButton(button) {
  if (!button) {
    return false;
  }
  const targetId = String(button.dataset.target || "").trim();
  const inSalesSubmenu = Boolean(button.closest("#sales-nav-submenu"));
  if (inSalesSubmenu && targetId === "sales-dashboard-section") {
    return false;
  }
  const navToggle = String(button.dataset.navToggle || "").trim();
  if (navToggle === "sales-submenu") {
    return true;
  }
  return isAllowedSalesNavigationTarget(targetId);
}

function resolveAccessibleSectionForRole(targetId, roleLike) {
  let sectionId = String(targetId || "").trim();
  if (sectionId === "org-chart-section") {
    sectionId = "departments-section";
  }
  const targetPanelExists = Array.from(els.panels || []).some((panel) => panel.id === sectionId);
  if (!targetPanelExists) {
    sectionId = "dashboard-section";
  }
  const normalizedRole = normalizeUserRole(roleLike);
  const roleAdmin = isPrivilegedRole(normalizedRole);
  const roleSuperAdmin = normalizedRole === ROLE_SUPERADMIN;
  const roleSales = normalizedRole === ROLE_VERTRIEBSMITARBEITER;

  if ((sectionId === "parameters-section" || sectionId === "management-section") && !roleAdmin) {
    sectionId = "dashboard-section";
  }
  if (sectionId === "companies-section" && !roleAdmin) {
    sectionId = "dashboard-section";
  }
  if (sectionId === "incoming-invoices-section" && !roleAdmin) {
    sectionId = "dashboard-section";
  }
  if (sectionId === "incoming-offers-section" && !roleAdmin) {
    sectionId = "dashboard-section";
  }
  if (sectionId === "contract-manager-section" && !roleSuperAdmin) {
    sectionId = "dashboard-section";
  }
  if (sectionId === "users-section" && !roleAdmin) {
    sectionId = "dashboard-section";
  }
  if (sectionId === "departments-section" && !roleAdmin) {
    sectionId = "dashboard-section";
  }
  if (sectionId === "employee-admin-section" && !roleSuperAdmin) {
    sectionId = "dashboard-section";
  }
  if (sectionId === "conversation-notes-section" && !roleAdmin) {
    sectionId = "dashboard-section";
  }
  if (roleSales && !isAllowedSalesNavigationTarget(sectionId)) {
    sectionId = "sales-dashboard-section";
  }
  return sectionId;
}

function renderRoleState() {
  const activeUser = getCurrentUser();
  if (!activeUser) {
    if (els.mainDashboardNavBtn) {
      els.mainDashboardNavBtn.dataset.target = "dashboard-section";
    }
    els.roleBadge.textContent = "Nicht angemeldet";
    els.adminOnlyNav.forEach((button) => {
      button.classList.add("hidden");
    });
    els.superadminOnlyNav?.forEach((button) => {
      button.classList.add("hidden");
    });
    els.roleAdminOnlyNav?.forEach((button) => {
      button.classList.add("hidden");
    });
    document.querySelectorAll(".admin-only-view").forEach((element) => {
      element.classList.add("hidden");
    });
    document.querySelectorAll(".superadmin-only-view").forEach((element) => {
      element.classList.add("hidden");
    });
    document.querySelectorAll(".role-admin-only-view").forEach((element) => {
      element.classList.add("hidden");
    });
    els.navButtons?.forEach((button) => {
      button.classList.remove("role-sales-hidden");
    });
    if (els.commandPaletteOpenBtn) {
      els.commandPaletteOpenBtn.classList.add("hidden");
    }
    closeCommandPalette();
    return;
  }

  const roleAdmin = isRoleAdmin(activeUser);
  const roleSuperAdmin = isSuperAdmin(activeUser);
  const salesRepresentative = isSalesRepresentative(activeUser);
  const canUseAdminUi = canUseAdminFeatures(activeUser);
  if (els.mainDashboardNavBtn) {
    els.mainDashboardNavBtn.dataset.target = salesRepresentative ? "sales-dashboard-section" : "dashboard-section";
  }
  if (els.commandPaletteOpenBtn) {
    els.commandPaletteOpenBtn.classList.remove("hidden");
  }
  els.roleBadge.textContent = `Rolle: ${getRoleLabel(activeUser.role)}`;

  els.adminOnlyNav.forEach((button) => {
    button.classList.toggle("hidden", !roleAdmin);
  });
  els.roleAdminOnlyNav?.forEach((button) => {
    button.classList.toggle("hidden", !roleAdmin);
  });
  els.superadminOnlyNav?.forEach((button) => {
    button.classList.toggle("hidden", !roleSuperAdmin);
  });
  document.querySelectorAll(".admin-only-view").forEach((element) => {
    element.classList.toggle("hidden", !canUseAdminUi);
  });
  document.querySelectorAll(".superadmin-only-view").forEach((element) => {
    element.classList.toggle("hidden", !roleSuperAdmin);
  });
  document.querySelectorAll(".role-admin-only-view").forEach((element) => {
    element.classList.toggle("hidden", !roleAdmin);
  });

  els.navButtons?.forEach((button) => {
    const allowedForSalesRole = isAllowedSalesNavigationButton(button);
    button.classList.toggle("role-sales-hidden", salesRepresentative && !allowedForSalesRole);
  });

  if (els.userCreateBtn) {
    els.userCreateBtn.classList.toggle("hidden", !canUseAdminUi || usersViewMode === "form");
  }
  if (els.providerCreateBtn) {
    els.providerCreateBtn.classList.toggle("hidden", providersViewMode === "form");
  }

  document.querySelectorAll(".admin-lock").forEach((container) => {
    const controls = container.querySelectorAll("input, select, textarea, button");
    controls.forEach((control) => {
      if (control.dataset.adminLockExempt === "true") {
        return;
      }
      control.disabled = !canUseAdminUi;
    });
  });

  if (!roleAdmin) {
    const currentPanel = document.querySelector(".panel.active");
    if (
      currentPanel?.id === "users-section" ||
      currentPanel?.id === "departments-section" ||
      currentPanel?.id === "management-section" ||
      currentPanel?.id === "parameters-section" ||
      currentPanel?.id === "companies-section" ||
      currentPanel?.id === "incoming-invoices-section" ||
      currentPanel?.id === "incoming-offers-section"
    ) {
      setActiveSection("dashboard-section");
    }
  }
  if (!roleSuperAdmin) {
    const currentPanel = document.querySelector(".panel.active");
    if (currentPanel?.id === "employee-admin-section" || currentPanel?.id === "contract-manager-section") {
      setActiveSection("dashboard-section");
    }
  }
  if (!roleAdmin) {
    const currentPanel = document.querySelector(".panel.active");
    if (currentPanel?.id === "conversation-notes-section") {
      setActiveSection("dashboard-section");
    }
  }
  if (salesRepresentative) {
    const currentPanelId = String(document.querySelector(".panel.active")?.id || "").trim();
    if (!isAllowedSalesNavigationTarget(currentPanelId)) {
      setActiveSection("sales-dashboard-section");
    }
  }
}

