function getDefaultMarketingUiState() {
  return {
    campaigns: {
      search: "",
      status: "all",
      view: "board",
      page: 1,
      formOpen: false,
    },
    content: {
      search: "",
      status: "all",
      view: "board",
      page: 1,
      formOpen: false,
    },
    tasks: {
      search: "",
      status: "all",
      campaignId: "all",
      view: "board",
      page: 1,
      formOpen: false,
    },
    assets: {
      search: "",
      view: "grid",
      page: 1,
      formOpen: false,
    },
    activity: {
      search: "",
      type: "all",
      page: 1,
      formOpen: false,
    },
  };
}

function normalizeMarketingUiState(rawState) {
  const fallback = getDefaultMarketingUiState();
  const value = rawState && typeof rawState === "object" ? rawState : {};
  const normalizeSection = (sectionKey, withStatus = true) => {
    const section = value?.[sectionKey] && typeof value[sectionKey] === "object" ? value[sectionKey] : {};
    return {
      search: String(section.search || "").trim().slice(0, 120),
      status: withStatus ? String(section.status || "all").trim().toLowerCase() : undefined,
      page: Math.max(1, Number(section.page || 1) || 1),
      formOpen: Boolean(section.formOpen),
    };
  };
  const campaigns = normalizeSection("campaigns", true);
  const content = normalizeSection("content", true);
  const tasks = normalizeSection("tasks", true);
  const assets = normalizeSection("assets", false);
  const activity = normalizeSection("activity", false);
  const normalizedCampaignView = ["board", "table"].includes(String(value?.campaigns?.view || "").trim().toLowerCase())
    ? String(value?.campaigns?.view || "").trim().toLowerCase()
    : "board";
  const normalizedContentView = ["board", "table"].includes(String(value?.content?.view || "").trim().toLowerCase())
    ? String(value?.content?.view || "").trim().toLowerCase()
    : "board";
  const normalizedTaskView = ["board", "table", "timeline"].includes(String(value?.tasks?.view || "").trim().toLowerCase())
    ? String(value?.tasks?.view || "").trim().toLowerCase()
    : "board";
  const normalizedAssetView = ["grid", "table"].includes(String(value?.assets?.view || "").trim().toLowerCase())
    ? String(value?.assets?.view || "").trim().toLowerCase()
    : "grid";
  const normalizedActivityType = MARKETING_ACTIVITY_ENTITY_TYPES.has(
    String(value?.activity?.type || "").trim().toLowerCase()
  )
    ? String(value?.activity?.type || "").trim().toLowerCase()
    : "all";
  return {
    campaigns: { ...fallback.campaigns, ...campaigns, view: normalizedCampaignView },
    content: { ...fallback.content, ...content, view: normalizedContentView },
    tasks: {
      ...fallback.tasks,
      ...tasks,
      campaignId: String(value?.tasks?.campaignId || fallback.tasks.campaignId || "all").trim() || "all",
      view: normalizedTaskView,
    },
    assets: { ...fallback.assets, ...assets, view: normalizedAssetView },
    activity: { ...fallback.activity, ...activity, type: normalizedActivityType },
  };
}

function loadMarketingUiState() {
  try {
    const raw = localStorage.getItem(MARKETING_UI_STORAGE_KEY);
    if (!raw) {
      return getDefaultMarketingUiState();
    }
    return normalizeMarketingUiState(JSON.parse(raw));
  } catch (error) {
    return getDefaultMarketingUiState();
  }
}

function saveMarketingUiState() {
  try {
    localStorage.setItem(MARKETING_UI_STORAGE_KEY, JSON.stringify(marketingUiState));
  } catch (error) {
    // ignore localStorage edge cases (private mode/quota)
  }
}

function updateMarketingUiSection(sectionKey, patch) {
  const base = normalizeMarketingUiState(marketingUiState);
  const section = { ...(base?.[sectionKey] || {}), ...(patch || {}) };
  marketingUiState = {
    ...base,
    [sectionKey]: section,
  };
  saveMarketingUiState();
}

function resetMarketingEditState() {
  marketingEditState = {
    campaignId: "",
    contentId: "",
    taskId: "",
    assetId: "",
  };
}

function setMarketingFormOpen(sectionKey, isOpen) {
  updateMarketingUiSection(sectionKey, {
    formOpen: Boolean(isOpen),
  });
  syncMarketingFormVisibility();
}

function syncMarketingFormVisibility() {
  if (els.marketingCampaignFormWrap) {
    els.marketingCampaignFormWrap.classList.toggle("hidden", !marketingUiState.campaigns.formOpen);
  }
  if (els.marketingContentFormWrap) {
    els.marketingContentFormWrap.classList.toggle("hidden", !marketingUiState.content.formOpen);
  }
  if (els.marketingTaskFormWrap) {
    els.marketingTaskFormWrap.classList.toggle("hidden", !marketingUiState.tasks.formOpen);
  }
  if (els.marketingAssetFormWrap) {
    els.marketingAssetFormWrap.classList.toggle("hidden", !marketingUiState.assets.formOpen);
  }
  if (els.marketingCampaignToggleFormBtn) {
    els.marketingCampaignToggleFormBtn.textContent = marketingUiState.campaigns.formOpen
      ? "Formular schließen"
      : "Neue Kampagne";
  }
  if (els.marketingContentToggleFormBtn) {
    els.marketingContentToggleFormBtn.textContent = marketingUiState.content.formOpen
      ? "Formular schließen"
      : "Neuer Inhalt";
  }
  if (els.marketingTaskToggleFormBtn) {
    els.marketingTaskToggleFormBtn.textContent = marketingUiState.tasks.formOpen
      ? "Formular schließen"
      : "Neue Aufgabe";
  }
  if (els.marketingAssetToggleFormBtn) {
    els.marketingAssetToggleFormBtn.textContent = marketingUiState.assets.formOpen
      ? "Formular schließen"
      : "Neues Asset";
  }
}

function ensureMarketingPageInBounds(sectionKey, totalRows) {
  const section = marketingUiState?.[sectionKey];
  if (!section) {
    return;
  }
  const totalPages = Math.max(1, Math.ceil(Math.max(0, totalRows) / MARKETING_PAGE_SIZE));
  if (section.page > totalPages) {
    updateMarketingUiSection(sectionKey, { page: totalPages });
  }
}

function paginateRows(rows, sectionKey) {
  const list = Array.isArray(rows) ? rows : [];
  ensureMarketingPageInBounds(sectionKey, list.length);
  const currentPage = Math.max(1, Number(marketingUiState?.[sectionKey]?.page || 1));
  const start = (currentPage - 1) * MARKETING_PAGE_SIZE;
  const end = start + MARKETING_PAGE_SIZE;
  return {
    pageRows: list.slice(start, end),
    currentPage,
    totalPages: Math.max(1, Math.ceil(Math.max(0, list.length) / MARKETING_PAGE_SIZE)),
    totalRows: list.length,
  };
}

function renderMarketingPagination(targetElement, sectionKey, meta) {
  if (!targetElement) {
    return;
  }
  const totalPages = Math.max(1, Number(meta?.totalPages || 1));
  const currentPage = Math.min(totalPages, Math.max(1, Number(meta?.currentPage || 1)));
  const totalRows = Math.max(0, Number(meta?.totalRows || 0));

  targetElement.innerHTML = `
    <div class="table-pagination">
      <div class="table-pagination-meta">${escapeHtml(String(totalRows))} Einträge</div>
      <div class="table-pagination-actions">
        <button type="button" class="mini-btn" data-marketing-page-nav="${escapeHtml(sectionKey)}" data-direction="prev" ${
          currentPage <= 1 ? "disabled" : ""
        }>Zurück</button>
        <span>Seite ${escapeHtml(String(currentPage))} / ${escapeHtml(String(totalPages))}</span>
        <button type="button" class="mini-btn" data-marketing-page-nav="${escapeHtml(sectionKey)}" data-direction="next" ${
          currentPage >= totalPages ? "disabled" : ""
        }>Weiter</button>
      </div>
    </div>
  `;
}

function getMarketingActivityLogTable() {
  return window.APP_CONFIG?.SUPABASE_MARKETING_ACTIVITY_LOG_TABLE || "marketing_activity_log";
}

async function logMarketingActivity(actionType, entityType, entityId, payload = {}) {
  const client = getSupabaseClient();
  if (!client || !getAuthUid()) {
    return;
  }
  const actorName = String(getCurrentUser()?.name || authProfile?.full_name || authProfile?.email || "").trim();
  const actorRole = String(marketingAccess?.role || getCurrentUser()?.role || authProfile?.role || "").trim().toLowerCase();
  const safePayload = payload && typeof payload === "object" && !Array.isArray(payload) ? payload : {};
  const enrichedPayload = {
    ...safePayload,
    actor_name: actorName || undefined,
    actor_role: actorRole || undefined,
    event_time: new Date().toISOString(),
  };
  try {
    const { error } = await client.from(getMarketingActivityLogTable()).insert({
      action_type: String(actionType || "").trim().slice(0, 80),
      entity_type: String(entityType || "").trim().slice(0, 80),
      entity_id: String(entityId || "").trim() || null,
      actor_user_id: getAuthUid(),
      payload: enrichedPayload,
    });
    if (error && !isSupabaseMissingRelationError(error, getMarketingActivityLogTable())) {
      console.warn("Marketing Activity Log fehlgeschlagen.", error);
    }
  } catch (error) {
    console.warn("Marketing Activity Log Ausnahme.", error);
  }
}

