function getFilteredMarketingTasks() {
  return marketingData.tasks
    .slice()
    .sort((left, right) => String(left.dueDate || "9999-12-31").localeCompare(String(right.dueDate || "9999-12-31")))
    .filter((entry) => {
      const searchTerm = normalizeText(marketingUiState.tasks.search || "");
      const statusFilter = String(marketingUiState.tasks.status || "all");
      const campaignFilter = String(marketingUiState.tasks.campaignId || "all");
      if (statusFilter !== "all" && entry.status !== statusFilter) {
        return false;
      }
      if (campaignFilter !== "all" && String(entry.campaignId || "") !== campaignFilter) {
        return false;
      }
      if (!searchTerm) {
        return true;
      }
      return normalizeText(
        `${entry.title} ${getMarketingCampaignName(entry.campaignId)} ${formatMarketingPriorityLabel(entry.priority)}`
      ).includes(searchTerm);
    });
}

