async function updateMarketingCampaignFields(campaignId, patch = {}, options = {}) {
  const normalizedId = String(campaignId || "").trim();
  if (!normalizedId || !patch || typeof patch !== "object") {
    return false;
  }
  const client = getSupabaseClient();
  if (!client) {
    showMarketingError("Supabase Verbindung fehlt.");
    return false;
  }

  const payload = {};
  if (Object.prototype.hasOwnProperty.call(patch, "status")) {
    payload.status = String(patch.status || "").trim().toLowerCase() || "draft";
  }
  if (!Object.keys(payload).length) {
    return false;
  }

  const { error } = await client.from(getMarketingCampaignsTable()).update(payload).eq("id", normalizedId);
  if (error) {
    showMarketingError(`Kampagne konnte nicht aktualisiert werden: ${getSupabaseErrorSummary(error)}`);
    return false;
  }
  await logMarketingActivity("campaign_updated_inline", "campaign", normalizedId, payload);
  await hydrateMarketingData({ force: true });
  renderMarketingModule();
  if (options?.successMessage) {
    showMarketingSuccess(options.successMessage);
  }
  return true;
}

