async function ensureMarketingApproval(entityType, entityId) {
  const client = getSupabaseClient();
  if (!client || !getAuthUid()) {
    return null;
  }
  const normalizedType = String(entityType || "").trim().toLowerCase();
  const normalizedEntityId = String(entityId || "").trim();
  if (!normalizedType || !normalizedEntityId) {
    return null;
  }
  const existing = getLatestApprovalByEntity(normalizedType, normalizedEntityId);
  if (existing && existing.status === "in_review") {
    return existing;
  }

  const { data, error } = await client
    .from(getMarketingApprovalsTable())
    .insert({
      entity_type: normalizedType,
      entity_id: normalizedEntityId,
      requested_by: getAuthUid(),
      reviewer_user_id: null,
      status: "in_review",
      comment: "",
    })
    .select("id")
    .single();
  if (error) {
    showMarketingError(`Review konnte nicht erstellt werden: ${getSupabaseErrorSummary(error)}`);
    return null;
  }
  await logMarketingActivity("approval_created", normalizedType, normalizedEntityId, {
    approvalId: data?.id || "",
  });
  await hydrateMarketingData({ force: true });
  renderMarketingModule();
  return data || null;
}

async function handleMarketingApprovalAction(action, approvalId) {
  const client = getSupabaseClient();
  if (!client || !approvalId) {
    return;
  }
  const normalizedAction = String(action || "").trim().toLowerCase();
  const targetStatus = normalizedAction === "approve" ? "approved" : normalizedAction === "reject" ? "rejected" : "";
  if (!targetStatus) {
    return;
  }
  if (!canApproveMarketingWorkflow()) {
    showMarketingWarning("Nur Marketing Manager oder Superadmin dürfen Freigaben entscheiden.");
    return;
  }
  const { error } = await client
    .from(getMarketingApprovalsTable())
    .update({
      status: targetStatus,
      reviewer_user_id: getAuthUid() || null,
      updated_at: new Date().toISOString(),
    })
    .eq("id", approvalId);
  if (error) {
    showMarketingError(`Freigabe-Status konnte nicht aktualisiert werden: ${getSupabaseErrorSummary(error)}`);
    return;
  }
  await logMarketingActivity("approval_status_changed", "approval", approvalId, {
    status: targetStatus,
  });
  await hydrateMarketingData({ force: true });
  renderMarketingModule();
  showMarketingSuccess(targetStatus === "approved" ? "Freigabe erteilt." : "Freigabe abgelehnt.");
}

async function handleMarketingCampaignAction(action, campaignId) {
  const client = getSupabaseClient();
  if (!client || !campaignId) {
    return;
  }
  const campaign = marketingData.campaigns.find((entry) => entry.id === campaignId);
  if (!campaign) {
    return;
  }
  if (action === "edit") {
    fillMarketingCampaignForm(campaign);
    return;
  }
  if (action === "review") {
    await ensureMarketingApproval("campaign", campaignId);
    return;
  }
  if (action === "delete") {
    const confirmed = await confirmDeleteAction(`Kampagne "${campaign.name}" wirklich löschen?`);
    if (!confirmed) {
      return;
    }
    const { error } = await client.from(getMarketingCampaignsTable()).delete().eq("id", campaignId);
    if (error) {
      showMarketingError(`Kampagne konnte nicht gelöscht werden: ${getSupabaseErrorSummary(error)}`);
      return;
    }
    await logMarketingActivity("campaign_deleted", "campaign", campaignId, { name: campaign.name });
    await hydrateMarketingData({ force: true });
    renderMarketingModule();
    showMarketingSuccess("Kampagne gelöscht.");
  }
}

