async function openMarketingAssetInNewTab(assetEntry) {
  const client = getSupabaseClient();
  if (!client || !assetEntry?.storageBucket || !assetEntry?.storagePath) {
    return;
  }
  try {
    const { data, error } = await client.storage
      .from(assetEntry.storageBucket)
      .createSignedUrl(assetEntry.storagePath, 120);
    if (error || !data?.signedUrl) {
      showMarketingError("Asset-Link konnte nicht erzeugt werden.");
      return;
    }
    window.open(data.signedUrl, "_blank", "noopener,noreferrer");
  } catch (error) {
    showMarketingError("Asset konnte nicht geöffnet werden.");
  }
}

