async function handleMarketingCampaignCreate(event) {
  if (!canAccessMarketingModule()) {
    return;
  }
  const client = getSupabaseClient();
  if (!client || !getAuthUid()) {
    showMarketingError("Supabase Verbindung fehlt.");
    return;
  }

  const formData = new FormData(event.currentTarget);
  const campaignName = String(formData.get("name") || "").trim();
  const goal = String(formData.get("goal") || "").trim();
  const budgetRaw = String(formData.get("budget") || "").trim();
  const startDate = String(formData.get("startDate") || "").trim();
  const endDate = String(formData.get("endDate") || "").trim();
  const status = String(formData.get("status") || "draft").trim().toLowerCase();
  const channel = String(formData.get("channel") || "social").trim().toLowerCase();
  const budget = parseOptionalNumber(budgetRaw);

  if (!campaignName || !startDate || !endDate || budget === null || budget < 0) {
    showMarketingWarning("Bitte Kampagnenname, Zeitraum und Budget korrekt ausfüllen.");
    return;
  }
  if (!MARKETING_STATUS_FLOW.includes(status)) {
    showMarketingWarning("Ungültiger Kampagnenstatus.");
    return;
  }
  if (!MARKETING_CHANNELS.has(channel)) {
    showMarketingWarning("Ungültiger Kampagnenkanal.");
    return;
  }

  const isEditing = Boolean(marketingEditState.campaignId);
  setActionButtonBusy(els.marketingCampaignSaveBtn, true, isEditing ? "Aktualisiert..." : "Speichert...");
  try {
    const campaignPayload = {
      name: campaignName,
      goal,
      budget,
      start_date: startDate,
      end_date: endDate,
      status,
      owner_user_id: getAuthUid(),
    };
    let insertedCampaign = null;
    let campaignError = null;
    if (isEditing) {
      const updateResult = await client
        .from(getMarketingCampaignsTable())
        .update(campaignPayload)
        .eq("id", marketingEditState.campaignId)
        .select("id")
        .single();
      insertedCampaign = updateResult.data;
      campaignError = updateResult.error;
    } else {
      const insertResult = await client
        .from(getMarketingCampaignsTable())
        .insert(campaignPayload)
        .select("id")
        .single();
      insertedCampaign = insertResult.data;
      campaignError = insertResult.error;
    }
    if (campaignError) {
      if (isSupabaseMissingRelationError(campaignError, getMarketingCampaignsTable())) {
        showMarketingError(getMarketingMissingTableMessage(getMarketingCampaignsTable()));
      } else {
        showMarketingError(`Kampagne konnte nicht gespeichert werden: ${getSupabaseErrorSummary(campaignError)}`);
      }
      return;
    }

    if (insertedCampaign?.id) {
      const { error: channelError } = await client.from(getMarketingCampaignChannelsTable()).upsert(
        {
          campaign_id: insertedCampaign.id,
          channel,
          planned_budget: budget,
        },
        { onConflict: "campaign_id,channel" }
      );
      if (channelError && !isSupabaseMissingRelationError(channelError, getMarketingCampaignChannelsTable())) {
        showMarketingError(`Kampagnenkanal konnte nicht gespeichert werden: ${getSupabaseErrorSummary(channelError)}`);
      }
    }

    await logMarketingActivity(isEditing ? "campaign_updated" : "campaign_created", "campaign", insertedCampaign?.id || "", {
      name: campaignName,
      status,
    });
    clearMarketingCampaignForm();
    await hydrateMarketingData({ force: true });
    renderMarketingModule();
    showMarketingSuccess(isEditing ? "Kampagne aktualisiert." : "Kampagne erstellt.");
  } finally {
    setActionButtonBusy(els.marketingCampaignSaveBtn, false);
  }
}

async function handleMarketingContentCreate(event) {
  if (!canAccessMarketingModule()) {
    return;
  }
  const client = getSupabaseClient();
  if (!client || !getAuthUid()) {
    showMarketingError("Supabase Verbindung fehlt.");
    return;
  }

  const formData = new FormData(event.currentTarget);
  const campaignId = String(formData.get("campaignId") || "").trim();
  const contentType = String(formData.get("contentType") || "").trim().toLowerCase();
  const channel = String(formData.get("channel") || "social").trim().toLowerCase();
  const title = String(formData.get("title") || "").trim();
  const status = String(formData.get("status") || "draft").trim().toLowerCase();
  const dueDate = String(formData.get("dueDate") || "").trim();

  if (!campaignId || !title) {
    showMarketingWarning("Bitte Kampagne und Titel auswählen.");
    return;
  }
  if (!MARKETING_CONTENT_TYPES.has(contentType)) {
    showMarketingWarning("Ungültiger Content-Typ.");
    return;
  }
  if (!MARKETING_CHANNELS.has(channel)) {
    showMarketingWarning("Ungültiger Kanal.");
    return;
  }
  if (!MARKETING_STATUS_FLOW.includes(status)) {
    showMarketingWarning("Ungültiger Status.");
    return;
  }

  const isEditing = Boolean(marketingEditState.contentId);
  setActionButtonBusy(els.marketingContentSaveBtn, true, isEditing ? "Aktualisiert..." : "Speichert...");
  try {
    const payload = {
      campaign_id: campaignId,
      content_type: contentType,
      channel,
      title,
      status,
      body: {},
      due_at: dueDate || null,
      created_by: getAuthUid(),
    };
    const { data, error } = isEditing
      ? await client
          .from(getMarketingContentItemsTable())
          .update(payload)
          .eq("id", marketingEditState.contentId)
          .select("id")
          .single()
      : await client
          .from(getMarketingContentItemsTable())
          .insert({
            ...payload,
            version: 1,
          })
          .select("id")
          .single();
    if (error) {
      if (isSupabaseMissingRelationError(error, getMarketingContentItemsTable())) {
        showMarketingError(getMarketingMissingTableMessage(getMarketingContentItemsTable()));
      } else {
        showMarketingError(`Inhalt konnte nicht gespeichert werden: ${getSupabaseErrorSummary(error)}`);
      }
      return;
    }

    await logMarketingActivity(isEditing ? "content_updated" : "content_created", "content_item", data?.id || "", {
      title,
      status,
    });
    clearMarketingContentForm();
    await hydrateMarketingData({ force: true });
    renderMarketingModule();
    showMarketingSuccess(isEditing ? "Inhalt aktualisiert." : "Inhalt erstellt.");
  } finally {
    setActionButtonBusy(els.marketingContentSaveBtn, false);
  }
}

