function normalizeDepartmentsPageTab(value) {
  const normalizedValue = String(value || "").trim().toLowerCase();
  if (["departments", "orgchart"].includes(normalizedValue)) {
    return normalizedValue;
  }
  return "departments";
}

function setDepartmentsPageTab(nextTab, options = {}) {
  departmentsPageTab = normalizeDepartmentsPageTab(nextTab);
  const activeTab = departmentsPageTab;
  els.departmentsTabButtons?.forEach((button) => {
    const target = normalizeDepartmentsPageTab(button.dataset.departmentsTabTarget || "");
    const isActive = target === activeTab;
    button.classList.toggle("is-active", isActive);
    setTabButtonA11yState(button, isActive);
  });
  els.departmentsTabPanels?.forEach((panel) => {
    const target = normalizeDepartmentsPageTab(panel.dataset.departmentsTabPanel || "");
    const isActive = target === activeTab;
    panel.classList.toggle("hidden", !isActive);
    setTabPanelA11yState(panel, isActive);
  });
  if (options?.render !== false) {
    if (activeTab === "orgchart") {
      renderOrgChartSection();
      return;
    }
    renderDepartmentsSection();
  }
}

function renderDepartmentsSection() {
  if (!els.departmentsTableBody) {
    return;
  }
  setDepartmentsPageTab(departmentsPageTab, { render: false });
  if (els.departmentsSearchInput && els.departmentsSearchInput.value !== departmentsSearchTerm) {
    els.departmentsSearchInput.value = departmentsSearchTerm;
  }
  const canManage = isRoleAdmin();
  if (!canManage) {
    closeDepartmentModal();
    closeDepartmentMembersModal();
    departmentsSelectedId = "";
    els.departmentsTableBody.innerHTML = "";
    if (els.departmentsEmpty) {
      els.departmentsEmpty.classList.remove("hidden");
      els.departmentsEmpty.textContent = "Nur Admin und Superadmin können Abteilungen verwalten.";
    }
    return;
  }

  const departments = getDepartments();
  const usageMap = getDepartmentUsageCountMap(departments);
  const normalizedSearchTerm = normalizeText(departmentsSearchTerm);
  const filteredDepartments = departments.filter((entry) => {
    if (!normalizedSearchTerm) {
      return true;
    }
    return normalizeText(`${entry.name} ${entry.description}`).includes(normalizedSearchTerm);
  });

  if (!departments.length) {
    closeDepartmentMembersModal();
    departmentsSelectedId = "";
    els.departmentsTableBody.innerHTML = '<tr><td colspan="5" class="empty">Noch keine Abteilungen angelegt.</td></tr>';
  } else if (!filteredDepartments.length) {
    closeDepartmentMembersModal();
    departmentsSelectedId = "";
    els.departmentsTableBody.innerHTML = '<tr><td colspan="5" class="empty">Keine Abteilungen für die Suche gefunden.</td></tr>';
  } else {
    const selectedDepartmentStillVisible = filteredDepartments.some((entry) => entry.id === departmentsSelectedId);
    if (!selectedDepartmentStillVisible) {
      departmentsSelectedId = filteredDepartments[0].id;
    }
    els.departmentsTableBody.innerHTML = filteredDepartments
      .map((entry) => {
        const usageCount = Number(usageMap.get(entry.id) || 0);
        const isSelected = entry.id === departmentsSelectedId;
        return `
          <tr class="${isSelected ? "is-selected" : ""}" data-department-select="${escapeHtml(entry.id)}">
            <td><strong>${escapeHtml(entry.name)}</strong></td>
            <td>${escapeHtml(entry.description || "–")}</td>
            <td>${escapeHtml(String(usageCount))}</td>
            <td>${escapeHtml(formatDateTime(entry.updatedAt))}</td>
            <td>
              <div class="table-action-group">
                <button
                  type="button"
                  class="mini-btn"
                  title="Abteilung bearbeiten"
                  aria-label="Abteilung bearbeiten"
                  data-stop-row-select="1"
                  data-department-edit="${escapeHtml(entry.id)}"
                >✎</button>
                <button
                  type="button"
                  class="mini-btn danger"
                  title="Abteilung löschen"
                  aria-label="Abteilung löschen"
                  data-stop-row-select="1"
                  data-department-delete="${escapeHtml(entry.id)}"
                >✕</button>
              </div>
            </td>
          </tr>
        `;
      })
      .join("");
  }

  if (els.departmentsEmpty) {
    els.departmentsEmpty.classList.add("hidden");
    els.departmentsEmpty.textContent = "";
  }
}

async function handleDepartmentFormSave(event) {
  const submitter = event.submitter instanceof HTMLElement ? event.submitter : null;
  setActionButtonBusy(submitter, true, "Speichert...");
  try {
    const formData = new FormData(event.currentTarget);
    const name = String(formData.get("name") || "").trim();
    if (!name) {
      showWarningFeedback("Bitte einen Abteilungsnamen eingeben.");
      return;
    }
    const description = String(formData.get("description") || "").trim();
    const now = new Date().toISOString();
    const departments = getDepartments();
    const normalizedName = normalizeText(name);
    const duplicate = departments.find(
      (entry) => normalizeText(entry.name) === normalizedName && entry.id !== departmentModalEditingId
    );
    if (duplicate) {
      showWarningFeedback("Eine Abteilung mit diesem Namen existiert bereits.");
      return;
    }

    const isEditMode = Boolean(departmentModalEditingId);
    let nextDepartments;
    if (isEditMode) {
      nextDepartments = departments.map((entry) =>
        entry.id === departmentModalEditingId
          ? {
              ...entry,
              name,
              description,
              updatedAt: now,
            }
          : entry
      );
    } else {
      nextDepartments = departments.concat({
        id: createId("dep"),
        name,
        description,
        createdAt: now,
        updatedAt: now,
      });
    }

    state.settings = normalizeSettings({
      ...state.settings,
      departments: nextDepartments,
    });
    saveState({ showFeedback: false });
    closeDepartmentModal();
    closeDepartmentMembersModal();
    renderDepartmentsSection();
    renderOrgChartSection();
    renderEmployeeAdminSection();
    showSuccessFeedback(isEditMode ? "Abteilung aktualisiert." : "Abteilung angelegt.");
  } finally {
    setActionButtonBusy(submitter, false);
  }
}

async function handleDepartmentDelete(departmentId) {
  const normalizedDepartmentId = String(departmentId || "").trim();
  if (!normalizedDepartmentId) {
    return;
  }
  const departments = getDepartments();
  const department = departments.find((entry) => entry.id === normalizedDepartmentId);
  if (!department) {
    return;
  }
  const usageMap = getDepartmentUsageCountMap(departments);
  const usageCount = Number(usageMap.get(department.id) || 0);
  const usageHint = usageCount > 0 ? `\n\n${usageCount} Mitarbeiter sind aktuell zugeordnet.` : "";
  const confirmed = await confirmDeleteAction(`Abteilung "${department.name}" wirklich löschen?${usageHint}`);
  if (!confirmed) {
    return;
  }
  const nextDepartments = departments.filter((entry) => entry.id !== department.id);
  const profilesMap = normalizeEmployeeProfilesByUserId(state.settings?.employeeProfilesByUserId || {}, departments);
  Object.keys(profilesMap).forEach((userId) => {
    if (String(profilesMap[userId]?.department || "").trim() === department.id) {
      profilesMap[userId] = {
        ...profilesMap[userId],
        department: "",
      };
    }
  });
  state.settings = normalizeSettings({
    ...state.settings,
    departments: nextDepartments,
    employeeProfilesByUserId: profilesMap,
  });
  saveState({ showFeedback: false });
  if (departmentMembersModalDepartmentId === department.id) {
    closeDepartmentMembersModal();
  }
  renderDepartmentsSection();
  renderOrgChartSection();
  renderEmployeeAdminSection();
  showSuccessFeedback("Abteilung gelöscht.");
}

