    status: sanitizeConversationTaskStatus(task?.status),
    created_at: String(task?.createdAt || "").trim() || new Date().toISOString(),
    created_by_user_id: normalizeUserId(task?.createdByUserId || "") || null,
    created_by_name: String(task?.createdByName || "").trim(),
