    updated_at: String(task?.updatedAt || "").trim() || new Date().toISOString(),
    updated_by_user_id: normalizeUserId(task?.updatedByUserId || "") || null,
    updated_by_name: String(task?.updatedByName || "").trim(),
    updated_by_role: normalizeUserRole(task?.updatedByRole || ""),
