function executeConversationFormatCommand(command) {
  if (!els.conversationNoteEditor) {
    return;
  }
  focusConversationNoteEditor();
  if (command === "unorderedList") {
    document.execCommand("insertUnorderedList", false);
    return;
  }
  if (["bold", "italic", "underline"].includes(command)) {
    document.execCommand(command, false);
  }
}

function serializeConversationEditorNodesToMarkdown(nodeList) {
  const chunks = [];
  Array.from(nodeList || []).forEach((node) => {
    if (!node) {
      return;
    }
    if (node.nodeType === Node.TEXT_NODE) {
      chunks.push(String(node.textContent || "").replace(/\u00a0/g, " "));
      return;
    }
    if (node.nodeType !== Node.ELEMENT_NODE) {
      return;
    }
    const tagName = String(node.tagName || "").toLowerCase();
    if (tagName === "br") {
      chunks.push("\n");
      return;
    }
    if (tagName === "strong" || tagName === "b") {
      const content = serializeConversationEditorNodesToMarkdown(node.childNodes).trim();
      chunks.push(content ? `**${content}**` : "");
      return;
    }
    if (tagName === "em" || tagName === "i") {
      const content = serializeConversationEditorNodesToMarkdown(node.childNodes).trim();
      chunks.push(content ? `*${content}*` : "");
      return;
    }
    if (tagName === "u") {
      const content = serializeConversationEditorNodesToMarkdown(node.childNodes).trim();
      chunks.push(content ? `++${content}++` : "");
      return;
    }
    if (tagName === "ul") {
      const items = Array.from(node.children || [])
        .filter((entry) => String(entry.tagName || "").toLowerCase() === "li")
        .map((entry) => {
          const itemText = serializeConversationEditorNodesToMarkdown(entry.childNodes).trim();
          return itemText ? `- ${itemText}` : "";
        })
        .filter(Boolean);
      if (items.length) {
        chunks.push(`${items.join("\n")}\n`);
      }
      return;
    }
    if (tagName === "li") {
      const itemText = serializeConversationEditorNodesToMarkdown(node.childNodes).trim();
      if (itemText) {
        chunks.push(`- ${itemText}`);
      }
      return;
    }
    if (tagName === "div" || tagName === "p") {
      const paragraph = serializeConversationEditorNodesToMarkdown(node.childNodes).trim();
      if (paragraph) {
        chunks.push(`${paragraph}\n`);
      }
      return;
    }
    chunks.push(serializeConversationEditorNodesToMarkdown(node.childNodes));
  });
  return chunks.join("");
}

function getConversationNoteEditorMarkdown() {
  if (!els.conversationNoteEditor) {
    return "";
  }
  const markdown = serializeConversationEditorNodesToMarkdown(els.conversationNoteEditor.childNodes);
  return String(markdown || "")
    .replace(/\n{3,}/g, "\n\n")
    .trim();
}

function convertConversationMarkdownToPlainText(markdown) {
  const text = String(markdown || "")
    .replace(/\*\*(.+?)\*\*/g, "$1")
    .replace(/\*(.+?)\*/g, "$1")
    .replace(/\+\+(.+?)\+\+/g, "$1")
    .replace(/^\s*-\s+/gm, "")
    .replace(/\n+/g, " ")
    .trim();
  return text;
}

function renderConversationMarkdown(markdown) {
  const escaped = escapeHtml(String(markdown || "").trim());
  if (!escaped) {
    return "";
  }
  const lines = escaped.split("\n");
  const htmlParts = [];
  let listBuffer = [];

  const applyInlineFormatting = (line) =>
    line
      .replace(/\+\+(.+?)\+\+/g, "<u>$1</u>")
      .replace(/\*\*(.+?)\*\*/g, "<strong>$1</strong>")
      .replace(/\*(.+?)\*/g, "<em>$1</em>");

  const flushList = () => {
    if (!listBuffer.length) {
      return;
    }
    htmlParts.push(`<ul>${listBuffer.map((entry) => `<li>${applyInlineFormatting(entry)}</li>`).join("")}</ul>`);
    listBuffer = [];
  };

  lines.forEach((rawLine) => {
    const line = String(rawLine || "");
    const listMatch = line.match(/^\s*-\s+(.*)$/);
    if (listMatch) {
      listBuffer.push(listMatch[1] || "");
      return;
    }
    flushList();
    if (!line.trim()) {
      htmlParts.push("<br/>");
      return;
    }
    htmlParts.push(`<p>${applyInlineFormatting(line)}</p>`);
  });
  flushList();
  return htmlParts.join("");
}

function buildConversationTaskAssigneeOptions(selectedUserId = "") {
  const normalizedSelectedUserId = normalizeUserId(selectedUserId || "");
  const users = getEmployeeAdminManagedUsers();
  const baseOptions = ['<option value="">Nicht zugewiesen</option>'].concat(
    users.map(
      (entry) =>
        `<option value="${escapeHtml(entry.userId)}">${escapeHtml(entry.name)} · ${escapeHtml(getRoleLabel(entry.role))}</option>`
    )
  );
  if (!normalizedSelectedUserId) {
    return baseOptions.join("");
  }
  const exists = users.some((entry) => entry.userId === normalizedSelectedUserId);
  if (exists) {
    return baseOptions.join("");
  }
  const fallbackName = getUserDisplayNameByUserId(normalizedSelectedUserId) || normalizedSelectedUserId;
  return baseOptions
    .concat(`<option value="${escapeHtml(normalizedSelectedUserId)}">${escapeHtml(fallbackName)}</option>`)
    .join("");
}

function getConversationTaskAssigneeSelectionFromComposer() {
  const assigneeType = sanitizeConversationTaskAssigneeType(els.conversationNoteTaskAssigneeType?.value || "organization");
  if (assigneeType === "organization") {
    return resolveConversationTaskAssigneeSelection({
      assigneeType,
      assigneeOrganizationId: String(els.conversationNoteTaskOrganization?.value || "").trim(),
    });
  }
  return resolveConversationTaskAssigneeSelection({
    assigneeType: "employee",
    assigneeUserId: normalizeUserId(els.conversationNoteTaskAssignee?.value || ""),
  });
}

function syncConversationLinkedTaskAssigneeMode(taskGridElement, forcedType = "") {
  if (!taskGridElement) {
    return "employee";
  }
  const assigneeType = sanitizeConversationTaskAssigneeType(
    forcedType || taskGridElement.querySelector("select[data-conversation-task-assignee-type]")?.value || "employee"
  );
  const organizationField = taskGridElement.querySelector("[data-conversation-task-organization-field]");
  const organizationSelect = taskGridElement.querySelector("select[data-conversation-task-organization]");
  const employeeField = taskGridElement.querySelector("[data-conversation-task-employee-field]");
  const employeeSelect = taskGridElement.querySelector("select[data-conversation-task-assignee]");
  const organizationMode = assigneeType === "organization";
  if (organizationField) {
    organizationField.classList.toggle("hidden", !organizationMode);
  }
  if (employeeField) {
    employeeField.classList.toggle("hidden", organizationMode);
  }
  if (organizationSelect) {
    organizationSelect.disabled = !organizationMode;
  }
  if (employeeSelect) {
    employeeSelect.disabled = organizationMode;
  }
  return assigneeType;
}

function getConversationTaskAssigneeSelectionForTaskId(taskId) {
  const normalizedTaskId = String(taskId || "").trim();
  if (!normalizedTaskId || !els.conversationNoteFeed) {
    return resolveConversationTaskAssigneeSelection({});
  }
  const assigneeTypeSelect = els.conversationNoteFeed.querySelector(
    `select[data-conversation-task-assignee-type="${normalizedTaskId}"]`
  );
  const assigneeOrganizationSelect = els.conversationNoteFeed.querySelector(
    `select[data-conversation-task-organization="${normalizedTaskId}"]`
  );
  const assigneeEmployeeSelect = els.conversationNoteFeed.querySelector(
    `select[data-conversation-task-assignee="${normalizedTaskId}"]`
  );
  return resolveConversationTaskAssigneeSelection({
    assigneeType: assigneeTypeSelect?.value || "employee",
    assigneeOrganizationId: assigneeOrganizationSelect?.value || "",
    assigneeUserId: assigneeEmployeeSelect?.value || "",
  });
}

function renderConversationTaskSummary(thread) {
  if (!els.conversationTaskSummary) {
    return;
  }
  const tasks = Array.isArray(thread?.tasks) ? thread.tasks : [];
  const counts = {
    offen: 0,
    in_arbeit: 0,
    warten: 0,
    erledigt: 0,
    overdue: 0,
  };
  tasks.forEach((task) => {
    const status = sanitizeConversationTaskStatus(task.status);
    counts[status] += 1;
    if (isConversationTaskOverdue(task)) {
      counts.overdue += 1;
    }
  });
  els.conversationTaskSummary.innerHTML = `
    <div class="conversation-task-chip">Offen: <strong>${escapeHtml(String(counts.offen))}</strong></div>
    <div class="conversation-task-chip">In Arbeit: <strong>${escapeHtml(String(counts.in_arbeit))}</strong></div>
    <div class="conversation-task-chip">Warten: <strong>${escapeHtml(String(counts.warten))}</strong></div>
    <div class="conversation-task-chip">Erledigt: <strong>${escapeHtml(String(counts.erledigt))}</strong></div>
    <div class="conversation-task-chip conversation-task-chip-overdue">Überfällig: <strong>${escapeHtml(
      String(counts.overdue)
    )}</strong></div>
  `;
}

function renderConversationNoteFeed(thread) {
  if (!els.conversationNoteFeed) {
    return;
  }
  const notes = Array.isArray(thread?.notes) ? thread.notes.slice() : [];
  const tasks = Array.isArray(thread?.tasks) ? thread.tasks : [];
  const taskMap = new Map(tasks.map((entry) => [String(entry.id || "").trim(), entry]));
  if (!notes.length) {
    els.conversationNoteFeed.innerHTML = '<p class="empty">Noch keine Notizen vorhanden.</p>';
    return;
  }
  notes.sort((left, right) => String(right.createdAt || "").localeCompare(String(left.createdAt || "")));

  els.conversationNoteFeed.innerHTML = notes
    .map((note) => {
      const linkedTask = note.linkedTaskId ? taskMap.get(note.linkedTaskId) || null : null;
      const createdStamp = formatAuditStamp(note.createdAt, note.createdByRole, note.createdByName || "Unbekannt");
      const updatedStamp = formatAuditStamp(note.updatedAt, note.updatedByRole, note.updatedByName || "Unbekannt");
      const noteText = String(note.text || "").trim();
      const noteBodyHtml = noteText
        ? `<div class="conversation-note-text">${renderConversationMarkdown(noteText)}</div>`
        : '<p class="conversation-note-text conversation-note-text-muted">Verknüpfte Aufgabenaktion</p>';
      const taskCardHtml = linkedTask
        ? `
          <div class="conversation-linked-task ${isConversationTaskOverdue(linkedTask) ? "is-overdue" : ""}">
            <div class="conversation-linked-task-head">
              <strong>${escapeHtml(linkedTask.title)}</strong>
              <span class="conversation-task-priority priority-${escapeHtml(linkedTask.priority)}">${escapeHtml(
                getConversationTaskPriorityLabel(linkedTask.priority)
              )}</span>
            </div>
            <div class="conversation-linked-task-grid">
              <label>
                Titel
                <input
                  type="text"
                  value="${escapeHtml(linkedTask.title || "")}"
                  data-conversation-task-title="${escapeHtml(linkedTask.id)}"
                />
              </label>
              <label>
                Status
                <select data-conversation-task-status="${escapeHtml(linkedTask.id)}">
                  ${Array.from(CONVERSATION_TASK_STATUSES)
                    .map(
                      (status) =>
                        `<option value="${escapeHtml(status)}" ${
                          status === sanitizeConversationTaskStatus(linkedTask.status) ? "selected" : ""
                        }>${escapeHtml(getConversationTaskStatusLabel(status))}</option>`
                    )
                    .join("")}
                </select>
              </label>
              <label>
                Zuweisungsart
                <select data-conversation-task-assignee-type="${escapeHtml(linkedTask.id)}">
                  ${Array.from(CONVERSATION_TASK_ASSIGNEE_TYPES)
                    .map(
                      (type) =>
                        `<option value="${escapeHtml(type)}" ${
                          type === sanitizeConversationTaskAssigneeType(linkedTask.assigneeType) ? "selected" : ""
                        }>${escapeHtml(getConversationTaskAssigneeTypeLabel(type))}</option>`
                    )
                    .join("")}
                </select>
              </label>
              <label data-conversation-task-organization-field="true">
                Organisation
                <select data-conversation-task-organization="${escapeHtml(linkedTask.id)}">
                  ${buildConversationTaskOrganizationOptions(linkedTask.assigneeOrganizationId)}
                </select>
              </label>
              <label data-conversation-task-employee-field="true">
                Mitarbeiter
                <select data-conversation-task-assignee="${escapeHtml(linkedTask.id)}">
                  ${buildConversationTaskEmployeeOptions(linkedTask.assigneeUserId)}
                </select>
              </label>
              <label>
                Fällig
                <input
                  type="date"
                  value="${escapeHtml(linkedTask.dueDate || "")}"
                  data-conversation-task-due="${escapeHtml(linkedTask.id)}"
                />
              </label>
              <button
                type="button"
                class="mini-btn danger"
                title="Aufgabe löschen"
                aria-label="Aufgabe löschen"
                data-no-iconify="true"
                data-conversation-task-delete="${escapeHtml(linkedTask.id)}"
              >✕</button>
            </div>
            <small>
              Erstellt: ${escapeHtml(
                formatAuditStamp(linkedTask.createdAt, linkedTask.createdByRole, linkedTask.createdByName || "Unbekannt")
              )} · Aktualisiert: ${escapeHtml(
                formatAuditStamp(linkedTask.updatedAt, linkedTask.updatedByRole, linkedTask.updatedByName || "Unbekannt")
              )}
            </small>
          </div>
        `
        : "";
      return `
        <article class="conversation-note-item">
          <div class="conversation-note-meta">
            <div>
              <span>${escapeHtml(createdStamp)}</span>
              ${createdStamp !== updatedStamp ? `<small>Bearbeitet: ${escapeHtml(updatedStamp)}</small>` : ""}
            </div>
            <div class="conversation-note-actions">
              <button
                type="button"
                class="mini-btn"
                title="Notiz bearbeiten"
                aria-label="Notiz bearbeiten"
                data-no-iconify="true"
                data-conversation-note-edit="${escapeHtml(note.id)}"
              >✎</button>
              <button
                type="button"
                class="mini-btn danger"
                title="Notiz löschen"
                aria-label="Notiz löschen"
                data-no-iconify="true"
                data-conversation-note-delete="${escapeHtml(note.id)}"
              >✕</button>
            </div>
          </div>
          ${noteBodyHtml}
          ${taskCardHtml}
        </article>
      `;
    })
    .join("");

  Array.from(els.conversationNoteFeed.querySelectorAll("select[data-conversation-task-assignee-type]")).forEach((typeSelect) => {
    const taskId = String(typeSelect.getAttribute("data-conversation-task-assignee-type") || "").trim();
    if (!taskId) {
      return;
    }
    const task = taskMap.get(taskId);
    if (!task) {
      return;
    }
    const assigneeType = sanitizeConversationTaskAssigneeType(task.assigneeType || "employee");
    typeSelect.value = assigneeType;
    const grid = typeSelect.closest(".conversation-linked-task-grid");
    if (grid) {
      syncConversationLinkedTaskAssigneeMode(grid, assigneeType);
    }
    const organizationSelect = els.conversationNoteFeed.querySelector(
      `select[data-conversation-task-organization="${taskId}"]`
    );
    const employeeSelect = els.conversationNoteFeed.querySelector(
      `select[data-conversation-task-assignee="${taskId}"]`
    );
    if (organizationSelect) {
      organizationSelect.value = String(task.assigneeOrganizationId || "");
    }
    if (employeeSelect) {
      employeeSelect.value = String(task.assigneeUserId || "");
    }
  });
}

function renderConversationOverviewInfo(thread) {
  if (!els.conversationOverviewInfo) {
    return;
  }
  if (!thread) {
    els.conversationOverviewInfo.innerHTML = '<p class="empty">Kein Gespräch ausgewählt.</p>';
    return;
  }
  const isInternal = sanitizeConversationContactType(thread.contactType) === "intern";
  const organizationName = getConversationOrganizationById(thread.organizationId)?.name || thread.organization || "Keine Organisation";
  const participants = getConversationInternalParticipantNames(thread.internalParticipantUserIds || []).join(", ") || "–";
  const contactTypeLabel = isInternal ? "Intern" : "Extern";
  const channelLabel = getConversationChannelLabel(thread.channel);
  const conversationDateLabel = thread.conversationDate ? formatEmployeeAdminDate(thread.conversationDate) : "–";
  const createdLabel = formatAuditStamp(thread.createdAt, thread.createdByRole, thread.createdByName || "Unbekannt");
  const updatedLabel = formatAuditStamp(thread.updatedAt, thread.updatedByRole, thread.updatedByName || "Unbekannt");

  els.conversationOverviewInfo.innerHTML = `
    <div class="conversation-overview-grid">
      <p><strong>Titel:</strong> ${escapeHtml(thread.title || "Gespräch")}</p>
      <p><strong>Kontakt:</strong> ${escapeHtml(thread.contactName || "Unbekannt")}</p>
      <p><strong>Kontaktart:</strong> ${escapeHtml(contactTypeLabel)}</p>
      <p><strong>Organisation:</strong> ${escapeHtml(organizationName)}</p>
      <p><strong>Kanal:</strong> ${escapeHtml(channelLabel)}</p>
      <p><strong>Datum:</strong> ${escapeHtml(conversationDateLabel)}</p>
      <p><strong>Teilnehmer:</strong> ${escapeHtml(participants)}</p>
      <p><strong>Angelegt:</strong> ${escapeHtml(createdLabel)}</p>
      <p><strong>Aktualisiert:</strong> ${escapeHtml(updatedLabel)}</p>
    </div>
  `;
}

function buildConversationThreadSearchIndex(thread) {
  const organizationName = getConversationOrganizationById(thread?.organizationId)?.name || thread?.organization || "";
  const internalParticipantNames = getConversationInternalParticipantNames(thread?.internalParticipantUserIds || []).join(" ");
  const noteText = Array.isArray(thread?.notes)
    ? thread.notes
        .map((entry) => String(entry?.text || "").trim())
        .filter(Boolean)
        .join(" ")
    : "";
  const taskText = Array.isArray(thread?.tasks)
    ? thread.tasks
        .map((entry) => `${entry?.title || ""} ${entry?.assigneeName || ""}`)
        .join(" ")
    : "";
  return normalizeText(
    [
      thread?.title || "",
      thread?.contactName || "",
      organizationName,
      internalParticipantNames,
      thread?.channel || "",
      noteText,
      taskText,
    ].join(" ")
  );
}

function conversationThreadMatchesFilters(thread) {
  const normalizedSearch = normalizeText(conversationNotesSearchTerm || "");
  if (normalizedSearch) {
    const haystack = buildConversationThreadSearchIndex(thread);
    if (!haystack.includes(normalizedSearch)) {
      return false;
    }
  }
  if (conversationNotesTypeFilter !== "all") {
    if (sanitizeConversationContactType(thread?.contactType) !== conversationNotesTypeFilter) {
      return false;
    }
  }
  if (conversationNotesTaskFilter !== "all") {
    const tasks = Array.isArray(thread?.tasks) ? thread.tasks : [];
    if (conversationNotesTaskFilter === "overdue") {
      return tasks.some((task) => isConversationTaskOverdue(task));
    }
    return tasks.some((task) => sanitizeConversationTaskStatus(task.status) === conversationNotesTaskFilter);
  }
  return true;
}

function normalizeConversationDetailTab(value) {
  const normalized = String(value || "").trim().toLowerCase();
  if (["overview", "create"].includes(normalized)) {
    return normalized;
  }
  return "overview";
}

function normalizeCompaniesTab(value) {
  const normalized = String(value || "").trim().toLowerCase();
  if (["overview", "detail"].includes(normalized)) {
    return normalized;
  }
  return "overview";
}

function normalizeCompaniesDetailWorkspaceTab(value) {
  const normalized = String(value || "").trim().toLowerCase();
  if (["overview", "finance", "contracts", "conversations"].includes(normalized)) {
    return normalized;
  }
  return "overview";
}

function setCompaniesTab(nextTab, options = {}) {
  companiesTab = normalizeCompaniesTab(nextTab);
  const activeTab = companiesTab;
  els.companiesTabButtons?.forEach((button) => {
    const target = normalizeCompaniesTab(button.dataset.companiesTabTarget || "");
    const active = target === activeTab;
    button.classList.toggle("is-active", active);
    setTabButtonA11yState(button, active);
  });
  if (els.companiesTabOverview) {
    const isActive = activeTab === "overview";
    els.companiesTabOverview.classList.toggle("hidden", !isActive);
    setTabPanelA11yState(els.companiesTabOverview, isActive);
  }
  if (els.companiesTabDetail) {
    const isActive = activeTab === "detail";
    els.companiesTabDetail.classList.toggle("hidden", !isActive);
    setTabPanelA11yState(els.companiesTabDetail, isActive);
  }
  if (options?.render !== false) {
    renderCompaniesSection();
  }
}

function setConversationDetailTab(nextTab, options = {}) {
  conversationDetailTab = normalizeConversationDetailTab(nextTab);
  const activeTab = conversationDetailTab;
  els.conversationDetailTabButtons?.forEach((button) => {
    const target = normalizeConversationDetailTab(button.dataset.conversationDetailTabTarget || "");
    const active = target === activeTab;
    button.classList.toggle("is-active", active);
    setTabButtonA11yState(button, active);
  });
  if (els.conversationDetailTabOverview) {
    const isActive = activeTab === "overview";
    els.conversationDetailTabOverview.classList.toggle("hidden", !isActive);
    setTabPanelA11yState(els.conversationDetailTabOverview, isActive);
  }
  if (els.conversationDetailTabCreate) {
    const isActive = activeTab === "create";
    els.conversationDetailTabCreate.classList.toggle("hidden", !isActive);
    setTabPanelA11yState(els.conversationDetailTabCreate, isActive);
  }
  if (options?.render !== false) {
    renderConversationNotesSection();
  }
}

function isConversationEditModalOpen() {
  return !!els.conversationEditModal && !els.conversationEditModal.classList.contains("hidden");
}

function closeConversationEditModal() {
  conversationEditModalOpen = false;
  if (els.conversationEditModal) {
    els.conversationEditModal.classList.add("hidden");
  }
  resetConversationNoteComposer();
  syncBodyModalOpenState();
}

function openConversationEditModal() {
  const selectedThread = getConversationThreadById(conversationSelectedThreadId);
  if (!selectedThread) {
    showInfoFeedback("Bitte zuerst ein Gespräch auswählen.");
    return;
  }
  conversationEditModalOpen = true;
  if (els.conversationEditModal) {
    els.conversationEditModal.classList.remove("hidden");
  }
  syncBodyModalOpenState();
}

function startConversationNoteEditing(noteId) {
  const selectedThread = getConversationThreadById(conversationSelectedThreadId);
  const normalizedNoteId = String(noteId || "").trim();
  if (!selectedThread || !normalizedNoteId) {
    showInfoFeedback("Notiz konnte nicht geöffnet werden.");
    return false;
  }
  const note = Array.isArray(selectedThread.notes)
    ? selectedThread.notes.find((entry) => String(entry?.id || "").trim() === normalizedNoteId) || null
    : null;
  if (!note) {
    showWarningFeedback("Notiz wurde nicht gefunden.");
    return false;
  }

  setConversationNoteComposerMode("edit", { noteId: normalizedNoteId });
  if (els.conversationNoteEditor) {
    const noteText = String(note.text || "").trim();
    els.conversationNoteEditor.innerHTML = noteText ? renderConversationMarkdown(noteText) : "";
  }

  const linkedTaskId = String(note.linkedTaskId || "").trim();
  const linkedTask = linkedTaskId && Array.isArray(selectedThread.tasks)
    ? selectedThread.tasks.find((entry) => String(entry?.id || "").trim() === linkedTaskId) || null
    : null;
  if (linkedTask) {
    if (els.conversationNoteTaskToggle) {
      els.conversationNoteTaskToggle.checked = true;
    }
    if (els.conversationNoteTaskTitle) {
      els.conversationNoteTaskTitle.value = String(linkedTask.title || "").trim();
    }
    if (els.conversationNoteTaskAssigneeType) {
      els.conversationNoteTaskAssigneeType.value = sanitizeConversationTaskAssigneeType(linkedTask.assigneeType || "organization");
    }
    if (els.conversationNoteTaskOrganization) {
      els.conversationNoteTaskOrganization.innerHTML = buildConversationTaskOrganizationOptions(linkedTask.assigneeOrganizationId || "");
      els.conversationNoteTaskOrganization.value = String(linkedTask.assigneeOrganizationId || "");
    }
    if (els.conversationNoteTaskAssignee) {
      els.conversationNoteTaskAssignee.innerHTML = buildConversationTaskEmployeeOptions(linkedTask.assigneeUserId || "");
      els.conversationNoteTaskAssignee.value = String(linkedTask.assigneeUserId || "");
    }
    if (els.conversationNoteTaskDue) {
      els.conversationNoteTaskDue.value = sanitizeConversationDate(linkedTask.dueDate || "");
    }
    if (els.conversationNoteTaskPriority) {
      els.conversationNoteTaskPriority.value = sanitizeConversationTaskPriority(linkedTask.priority || "mittel");
    }
  } else {
    if (els.conversationNoteTaskToggle) {
      els.conversationNoteTaskToggle.checked = false;
    }
    if (els.conversationNoteTaskTitle) {
      els.conversationNoteTaskTitle.value = "";
    }
    if (els.conversationNoteTaskAssigneeType) {
      els.conversationNoteTaskAssigneeType.value = "organization";
    }
    if (els.conversationNoteTaskOrganization) {
      els.conversationNoteTaskOrganization.innerHTML = buildConversationTaskOrganizationOptions("");
      els.conversationNoteTaskOrganization.value = "";
    }
    if (els.conversationNoteTaskAssignee) {
      els.conversationNoteTaskAssignee.innerHTML = buildConversationTaskEmployeeOptions("");
      els.conversationNoteTaskAssignee.value = "";
    }
    if (els.conversationNoteTaskDue) {
      els.conversationNoteTaskDue.value = "";
    }
    if (els.conversationNoteTaskPriority) {
      els.conversationNoteTaskPriority.value = "mittel";
    }
  }
  syncConversationTaskFieldsVisibility();
  return true;
}

function renderConversationNotesSection() {
  if (
    !els.conversationNotesList ||
    !els.conversationNotesDetailBody ||
    !els.conversationNotesEmpty
  ) {
    return;
  }
  if (els.conversationNotesSearchInput && els.conversationNotesSearchInput.value !== conversationNotesSearchTerm) {
    els.conversationNotesSearchInput.value = conversationNotesSearchTerm;
  }
  if (els.conversationNotesTypeFilter) {
    els.conversationNotesTypeFilter.value = conversationNotesTypeFilter;
  }
  if (els.conversationNotesTaskFilter) {
    els.conversationNotesTaskFilter.value = conversationNotesTaskFilter;
  }

  if (!isRoleAdmin()) {
    els.conversationNotesList.innerHTML = "";
    els.conversationNotesDetailBody.classList.add("hidden");
    els.conversationNotesEmpty.classList.remove("hidden");
    els.conversationNotesEmpty.textContent = "Nur Admin/Superadmin kann diese Seite verwenden.";
    closeConversationEditModal();
    return;
  }

  els.conversationNotesDetailBody.classList.remove("hidden");
  setConversationDetailTab(conversationDetailTab, { render: false });

  if (shouldHydrateConversationRemoteNow() && !conversationThreadsLoadedRemote && !conversationThreadsLoadingRemote) {
    void hydrateConversationThreadsFromSupabase();
  }

  const allThreads = getConversationThreads();
  ensureConversationSelection();
  const filteredThreads = allThreads.filter((thread) => conversationThreadMatchesFilters(thread));

  if (filteredThreads.length && !filteredThreads.some((entry) => entry.id === conversationSelectedThreadId)) {
    conversationSelectedThreadId = filteredThreads[0].id;
  }
  if (!filteredThreads.length) {
    els.conversationNotesList.innerHTML = conversationThreadsLoadingRemote
      ? '<p class="empty">Gespräche werden geladen...</p>'
      : '<p class="empty">Keine Gespräche für die aktuelle Filterung gefunden.</p>';
    els.conversationNotesEmpty.textContent = conversationThreadsLoadingRemote
      ? "Gespräche werden geladen..."
      : "Keine Gespräche für die aktuelle Filterung gefunden.";
    els.conversationNotesEmpty.classList.remove("hidden");
    renderConversationTaskSummary(null);
    renderConversationOverviewInfo(null);
    if (els.conversationNoteFeed) {
      els.conversationNoteFeed.innerHTML = "";
    }
    closeConversationEditModal();
    return;
  } else {
    els.conversationNotesList.innerHTML = filteredThreads
      .map((thread) => {
        const threadId = String(thread.id || "").trim();
        const isActive = threadId === conversationSelectedThreadId;
        const tasks = Array.isArray(thread.tasks) ? thread.tasks : [];
        const openTasks = tasks.filter((task) => sanitizeConversationTaskStatus(task.status) !== "erledigt").length;
        const overdueTasks = tasks.filter((task) => isConversationTaskOverdue(task)).length;
        const isInternal = sanitizeConversationContactType(thread.contactType) === "intern";
        const organizationName = getConversationOrganizationById(thread.organizationId)?.name || thread.organization || "";
        const internalParticipantsLabel = getConversationInternalParticipantNames(thread.internalParticipantUserIds || []).join(", ");
        const secondLineLabel = isInternal
          ? internalParticipantsLabel || "Interne Mitarbeiter"
          : organizationName || "Ohne Organisation";
        return `
          <article class="conversation-thread-item ${isActive ? "active" : ""}" data-conversation-select="${escapeHtml(threadId)}">
            <button
              type="button"
              class="conversation-thread-select-btn"
              data-conversation-select="${escapeHtml(threadId)}"
            >
              <strong>${escapeHtml(thread.title || "Gespräch")}</strong>
              <span>${escapeHtml(thread.contactName || "Unbekannt")} · ${escapeHtml(
            isInternal ? "Intern" : "Extern"
          )}</span>
              <small>${escapeHtml(secondLineLabel)} · ${escapeHtml(
            formatEmployeeAdminDate(thread.conversationDate)
          )}</small>
              <small>Offene Aufgaben: ${escapeHtml(String(openTasks))} · Überfällig: ${escapeHtml(String(overdueTasks))}</small>
            </button>
            <div class="conversation-thread-actions">
              <button
                type="button"
                class="mini-btn"
                title="Gespräch bearbeiten"
                aria-label="Gespräch bearbeiten"
                data-no-iconify="true"
                data-conversation-edit="${escapeHtml(threadId)}"
              >✎</button>
              <button
                type="button"
                class="mini-btn danger"
                title="Löschen"
                aria-label="Löschen"
                data-no-iconify="true"
                data-conversation-delete="${escapeHtml(threadId)}"
              >✕</button>
            </div>
          </article>
        `;
      })
      .join("");
  }

  const selectedThread = getConversationThreadById(conversationSelectedThreadId);
  if (!selectedThread) {
    els.conversationNotesEmpty.classList.remove("hidden");
    els.conversationNotesEmpty.textContent = allThreads.length
      ? "Bitte links ein Gespräch auswählen."
      : "Noch keine Gespräche vorhanden. Über \"Neues Gespräch\" starten.";
    renderConversationTaskSummary(null);
    renderConversationOverviewInfo(null);
    if (els.conversationNoteFeed) {
      els.conversationNoteFeed.innerHTML = "";
    }
    closeConversationEditModal();
    return;
  }

  els.conversationNotesEmpty.classList.add("hidden");
  if (conversationDetailTab === "create") {
    renderConversationTaskSummary(null);
    if (els.conversationNoteFeed) {
      els.conversationNoteFeed.innerHTML = '<p class="empty">Für Übersicht zu Tab "Übersicht" wechseln.</p>';
    }
  }

  if (els.conversationMetaForm) {
    const fields = els.conversationMetaForm.elements;
    fields.title.value = selectedThread.title || "";
    fields.contactName.value = selectedThread.contactName || "";
    fields.contactType.value = selectedThread.contactType || "extern";
    fields.channel.value = selectedThread.channel || "meeting";
    fields.conversationDate.value = selectedThread.conversationDate || "";
    renderConversationOrganizationOptions(selectedThread.organizationId || "");
    syncConversationContactModeFields({
      thread: selectedThread,
      selectedOrganizationId: selectedThread.organizationId || "",
      selectedInternalParticipantUserIds: selectedThread.internalParticipantUserIds || [],
    });
  }

  const currentAssigneeType = sanitizeConversationTaskAssigneeType(
    els.conversationNoteTaskAssigneeType?.value || "organization"
  );
  const currentOrganizationSelection = String(els.conversationNoteTaskOrganization?.value || "").trim();
  const currentEmployeeSelection = String(els.conversationNoteTaskAssignee?.value || "").trim();
  if (els.conversationNoteTaskAssigneeType) {
    els.conversationNoteTaskAssigneeType.value = currentAssigneeType;
  }
  if (els.conversationNoteTaskOrganization) {
    els.conversationNoteTaskOrganization.innerHTML = buildConversationTaskOrganizationOptions(currentOrganizationSelection);
    if (currentOrganizationSelection) {
      els.conversationNoteTaskOrganization.value = currentOrganizationSelection;
    }
  }
  if (els.conversationNoteTaskAssignee) {
    els.conversationNoteTaskAssignee.innerHTML = buildConversationTaskEmployeeOptions(currentEmployeeSelection);
    if (currentEmployeeSelection) {
      els.conversationNoteTaskAssignee.value = currentEmployeeSelection;
    }
  }
  syncConversationTaskComposerAssigneeMode(currentAssigneeType);
  syncConversationTaskFieldsVisibility();
  if (conversationDetailTab === "overview") {
    renderConversationOverviewInfo(selectedThread);
    renderConversationTaskSummary(selectedThread);
    renderConversationNoteFeed(selectedThread);
  }
}

function updateConversationThreadWithAudit(threadId, updateFn) {
  const normalizedThreadId = String(threadId || "").trim();
  if (!normalizedThreadId || typeof updateFn !== "function") {
    return false;
  }
  const threads = getConversationThreads();
  const index = threads.findIndex((entry) => entry.id === normalizedThreadId);
  if (index < 0) {
    return false;
  }
  const draft = JSON.parse(JSON.stringify(threads[index]));
  const updatedDraft = updateFn(draft);
  if (!updatedDraft || typeof updatedDraft !== "object") {
    return false;
  }
  const normalizedEntry = normalizeConversationThreadRecord(updatedDraft, index);
  if (!normalizedEntry) {
    return false;
  }
  threads[index] = normalizedEntry;
  setConversationThreads(threads);
  return true;
}

function appendConversationSystemNote(threadDraft, text, actor, atIso, linkedTaskId = "") {
  if (!threadDraft || typeof threadDraft !== "object") {
    return;
  }
  const noteText = String(text || "").trim();
  if (!noteText) {
    return;
  }
  const note = {
    id: createId("cnote"),
    text: noteText,
    linkedTaskId: String(linkedTaskId || "").trim(),
    createdAt: atIso,
    createdByUserId: actor.userId,
    createdByName: actor.name,
    createdByRole: actor.role,
    updatedAt: atIso,
    updatedByUserId: actor.userId,
    updatedByName: actor.name,
    updatedByRole: actor.role,
  };
  if (!Array.isArray(threadDraft.notes)) {
    threadDraft.notes = [];
  }
  threadDraft.notes.push(note);
}

async function handleCreateConversationThread(options = {}) {
  const actor = getCurrentActorInfo();
  const nowIso = new Date().toISOString();
  const threads = getConversationThreads();
  const selectedOrganizationId = String(options?.organizationId || "").trim();
  const selectedOrganization =
    selectedOrganizationId ? getConversationOrganizationById(selectedOrganizationId) : null;
  const organizationId = selectedOrganization?.id || "";
  const organizationName = String(options?.organizationName || selectedOrganization?.name || "").trim();
  const contactName = String(options?.contactName || "").trim() || actor.name || "Kontakt";
  const thread = normalizeConversationThreadRecord(
    {
      id: createId("conv"),
      title: "Neues Gespräch",
      contactName,
      contactType: "extern",
      organizationId,
      organization: organizationName,
      channel: "meeting",
      conversationDate: getTodayDateInputValue(),
      internalParticipantUserIds: [],
      createdAt: nowIso,
      createdByUserId: actor.userId,
      createdByName: actor.name,
      createdByRole: actor.role,
      updatedAt: nowIso,
      updatedByUserId: actor.userId,
      updatedByName: actor.name,
      updatedByRole: actor.role,
      notes: [],
      tasks: [],
    },
    threads.length
  );
  if (!thread) {
    return;
  }
  threads.unshift(thread);
  setConversationThreads(threads);
  conversationSelectedThreadId = thread.id;
  conversationDetailTab = "overview";
  resetConversationNoteComposer();
  saveState({ showFeedback: false });
  await syncConversationThreadRemoteOrWarn(thread.id, { deleteMissing: true });
  renderConversationNotesSection();
  openConversationEditModal();
  showSuccessFeedback("Gespräch angelegt.");
}

async function handleDeleteConversationThread() {
  const selectedThread = getConversationThreadById(conversationSelectedThreadId);
  if (!selectedThread) {
    return;
  }
  const confirmed = await confirmDeleteAction(`Gespräch "${selectedThread.title}" wirklich löschen?`);
  if (!confirmed) {
    return;
  }
  const threads = getConversationThreads().filter((entry) => entry.id !== selectedThread.id);
  setConversationThreads(threads);
  conversationSelectedThreadId = threads[0]?.id || "";
  closeConversationEditModal();
  resetConversationNoteComposer();
  saveState({ showFeedback: false });
  const remoteDeleteResult = await deleteConversationThreadFromSupabase(selectedThread.id);
  if (!remoteDeleteResult.ok && remoteDeleteResult.error && shouldUseConversationLocalFallback(remoteDeleteResult.error)) {
    conversationThreadsRemoteUnavailable = true;
    const technicalDetail = getSupabaseErrorSummary(remoteDeleteResult.error);
    showActionFeedback(
      isConversationTableMissingError(remoteDeleteResult.error)
        ? `Gespräch lokal gelöscht. SQL für Gesprächsnotizen fehlt noch.${technicalDetail ? ` (${technicalDetail})` : ""}`
        : `Gespräch lokal gelöscht. Supabase-Löschen aktuell blockiert.${technicalDetail ? ` (${technicalDetail})` : ""}`,
      { tone: "warning", toast: false, statusPersistMs: 6200 }
    );
  }
  renderConversationNotesSection();
  showSuccessFeedback("Gespräch gelöscht.");
}

async function handleConversationMetaSave(event) {
  const selectedThreadId = String(conversationSelectedThreadId || "").trim();
  if (!selectedThreadId) {
    return;
  }
  const submitter = event.submitter instanceof HTMLElement ? event.submitter : null;
  setActionButtonBusy(submitter, true, "Speichert...");
  try {
    const formData = new FormData(event.currentTarget);
    const title = String(formData.get("title") || "").trim();
    const contactType = sanitizeConversationContactType(formData.get("contactType"));
    const externalContactName = String(formData.get("contactName") || "").trim();
    const internalParticipantUserIds = getSelectedConversationInternalParticipantUserIds();
    const internalParticipantNames = getConversationInternalParticipantNames(internalParticipantUserIds);
    const contactName = contactType === "intern" ? internalParticipantNames.join(", ") : externalContactName;
    if (!title) {
      showWarningFeedback("Titel ist erforderlich.");
      return;
    }
    if (contactType === "intern" && !internalParticipantUserIds.length) {
      showWarningFeedback("Bitte mindestens einen internen Mitarbeiter auswählen.");
      return;
    }
    if (contactType === "extern" && !contactName) {
      showWarningFeedback("Kontaktname ist erforderlich.");
      return;
    }
    const selectedOrganizationId = contactType === "extern"
      ? String(formData.get("organizationId") || "").trim()
      : "";
    const selectedOrganization = selectedOrganizationId ? getConversationOrganizationById(selectedOrganizationId) : null;
    const actor = getCurrentActorInfo();
    const nowIso = new Date().toISOString();
    const updated = updateConversationThreadWithAudit(selectedThreadId, (draft) => ({
      ...draft,
      title,
      contactName,
      contactType,
      organizationId: contactType === "extern" ? selectedOrganizationId : "",
      organization: contactType === "extern" ? String(selectedOrganization?.name || "").trim() : "",
      channel: sanitizeConversationChannel(formData.get("channel")),
      conversationDate: sanitizeConversationDate(formData.get("conversationDate")),
      internalParticipantUserIds: contactType === "intern" ? internalParticipantUserIds : [],
      updatedAt: nowIso,
      updatedByUserId: actor.userId,
      updatedByName: actor.name,
      updatedByRole: actor.role,
    }));
    if (!updated) {
      showErrorFeedback("Gespräch konnte nicht gespeichert werden.");
      return;
    }
    saveState({ showFeedback: false });
    await syncConversationThreadRemoteOrWarn(selectedThreadId, { deleteMissing: true });
    renderConversationNotesSection();
    showSuccessFeedback("Gespräch gespeichert.");
  } finally {
    setActionButtonBusy(submitter, false);
  }
}

async function handleAddConversationNote() {
  const selectedThreadId = String(conversationSelectedThreadId || "").trim();
  if (!selectedThreadId) {
    return;
  }
  const noteText = getConversationNoteEditorMarkdown();
  const taskModeEnabled = Boolean(els.conversationNoteTaskToggle?.checked);
  const editingMode = conversationNoteComposerMode === "edit" && !!String(conversationNoteEditingNoteId || "").trim();
  const actor = getCurrentActorInfo();
  const nowIso = new Date().toISOString();
  const taskTitleRaw = String(els.conversationNoteTaskTitle?.value || "").trim();
  const assigneeSelection = getConversationTaskAssigneeSelectionFromComposer();
  const dueDate = sanitizeConversationDate(els.conversationNoteTaskDue?.value || "");
  const priority = sanitizeConversationTaskPriority(els.conversationNoteTaskPriority?.value || "mittel");
  const formContactType = sanitizeConversationContactType(els.conversationMetaForm?.elements?.contactType?.value || "extern");
  const formTitle = String(els.conversationMetaForm?.elements?.title?.value || "").trim();
  const formExternalContactName = String(els.conversationMetaForm?.elements?.contactName?.value || "").trim();
  const formChannel = sanitizeConversationChannel(els.conversationMetaForm?.elements?.channel?.value || "");
  const formConversationDate = sanitizeConversationDate(els.conversationMetaForm?.elements?.conversationDate?.value || "");
  const formInternalParticipantUserIds =
    formContactType === "intern" ? getSelectedConversationInternalParticipantUserIds() : [];
  const formInternalParticipantNames = getConversationInternalParticipantNames(formInternalParticipantUserIds);
  const formOrganizationId =
    formContactType === "extern" ? String(els.conversationMetaForm?.elements?.organizationId?.value || "").trim() : "";
  const formOrganization = formOrganizationId ? getConversationOrganizationById(formOrganizationId) : null;
  const taskOrganizationId =
    taskModeEnabled && assigneeSelection.assigneeType === "organization"
      ? String(assigneeSelection.assigneeOrganizationId || "").trim()
      : "";
  const taskOrganization = taskOrganizationId ? getConversationOrganizationById(taskOrganizationId) : null;

  if (!editingMode && !noteText && !taskModeEnabled) {
    showWarningFeedback("Bitte eine Notiz eingeben oder Aufgabe aktivieren.");
    return;
  }

  const updated = updateConversationThreadWithAudit(selectedThreadId, (draft) => {
    const next = { ...draft };
    if (formTitle) {
      next.title = formTitle;
    }
    next.contactType = formContactType;
    if (formContactType === "intern") {
      next.internalParticipantUserIds = formInternalParticipantUserIds;
      if (formInternalParticipantNames.length) {
        next.contactName = formInternalParticipantNames.join(", ");
      }
    } else {
      next.internalParticipantUserIds = [];
      if (formExternalContactName) {
        next.contactName = formExternalContactName;
      }
    }
    if (formChannel) {
      next.channel = formChannel;
    }
    if (formConversationDate) {
      next.conversationDate = formConversationDate;
    }
    const existingOrganizationId = String(next.organizationId || "").trim();
    const effectiveOrganizationId = String(formOrganizationId || taskOrganizationId || existingOrganizationId).trim();
    if (effectiveOrganizationId) {
      const effectiveOrganization = formOrganization
        || taskOrganization
        || getConversationOrganizationById(effectiveOrganizationId);
      next.organizationId = effectiveOrganizationId;
      next.organization = String(effectiveOrganization?.name || next.organization || "").trim();
    }
    if (!Array.isArray(next.notes)) {
      next.notes = [];
    }
    if (!Array.isArray(next.tasks)) {
      next.tasks = [];
    }

    if (editingMode) {
      const editingNoteId = String(conversationNoteEditingNoteId || "").trim();
      const noteIndex = next.notes.findIndex((entry) => String(entry?.id || "").trim() === editingNoteId);
      if (noteIndex < 0) {
        return null;
      }
      const currentNote = normalizeConversationNoteRecord(next.notes[noteIndex], noteIndex);
      if (!currentNote) {
        return null;
      }
      let linkedTaskId = String(currentNote.linkedTaskId || "").trim();
      if (taskModeEnabled) {
        const taskTitle = taskTitleRaw || convertConversationMarkdownToPlainText(noteText) || "Aufgabe";
        if (!taskTitle) {
          return null;
        }
        if (linkedTaskId) {
          const taskIndex = next.tasks.findIndex((entry) => String(entry?.id || "").trim() === linkedTaskId);
          if (taskIndex >= 0) {
            const currentTask = normalizeConversationTaskRecord(next.tasks[taskIndex], taskIndex);
            if (currentTask) {
              next.tasks[taskIndex] = {
                ...currentTask,
                title: taskTitle,
                assigneeType: assigneeSelection.assigneeType,
                assigneeUserId: assigneeSelection.assigneeUserId,
                assigneeOrganizationId: assigneeSelection.assigneeOrganizationId,
                assigneeName: assigneeSelection.assigneeName,
                dueDate,
                priority,
                updatedAt: nowIso,
                updatedByUserId: actor.userId,
                updatedByName: actor.name,
                updatedByRole: actor.role,
              };
            }
          }
        } else {
          const task = normalizeConversationTaskRecord(
            {
              id: createId("ctask"),
              title: taskTitle,
              assigneeType: assigneeSelection.assigneeType,
              assigneeUserId: assigneeSelection.assigneeUserId,
              assigneeOrganizationId: assigneeSelection.assigneeOrganizationId,
              assigneeName: assigneeSelection.assigneeName,
              dueDate,
              priority,
              status: "offen",
              createdAt: nowIso,
              createdByUserId: actor.userId,
              createdByName: actor.name,
              createdByRole: actor.role,
              updatedAt: nowIso,
              updatedByUserId: actor.userId,
              updatedByName: actor.name,
              updatedByRole: actor.role,
            },
            next.tasks.length
          );
          if (task) {
            next.tasks.push(task);
            linkedTaskId = task.id;
          }
        }
      }

      const nextNoteText = noteText || (linkedTaskId ? currentNote.text : "");
      if (!nextNoteText && !linkedTaskId) {
        return null;
      }
      next.notes[noteIndex] = {
        ...currentNote,
        text: nextNoteText,
        linkedTaskId,
        updatedAt: nowIso,
        updatedByUserId: actor.userId,
        updatedByName: actor.name,
        updatedByRole: actor.role,
      };
    } else {
      let linkedTaskId = "";
      if (taskModeEnabled) {
        const taskTitle = taskTitleRaw || convertConversationMarkdownToPlainText(noteText) || "Neue Aufgabe";
        const task = normalizeConversationTaskRecord(
          {
            id: createId("ctask"),
            title: taskTitle,
            assigneeType: assigneeSelection.assigneeType,
            assigneeUserId: assigneeSelection.assigneeUserId,
            assigneeOrganizationId: assigneeSelection.assigneeOrganizationId,
            assigneeName: assigneeSelection.assigneeName,
            dueDate,
            priority,
            status: "offen",
            createdAt: nowIso,
            createdByUserId: actor.userId,
            createdByName: actor.name,
            createdByRole: actor.role,
            updatedAt: nowIso,
            updatedByUserId: actor.userId,
            updatedByName: actor.name,
            updatedByRole: actor.role,
          },
          next.tasks.length
        );
        if (task) {
          next.tasks.push(task);
          linkedTaskId = task.id;
        }
      }

      const note = normalizeConversationNoteRecord(
        {
          id: createId("cnote"),
          text: noteText || (linkedTaskId ? `Aufgabe erstellt: ${taskTitleRaw || "Neue Aufgabe"}` : ""),
          linkedTaskId,
          createdAt: nowIso,
          createdByUserId: actor.userId,
          createdByName: actor.name,
          createdByRole: actor.role,
          updatedAt: nowIso,
          updatedByUserId: actor.userId,
          updatedByName: actor.name,
          updatedByRole: actor.role,
        },
        next.notes.length
      );
      if (note) {
        next.notes.push(note);
      }
    }

    next.updatedAt = nowIso;
    next.updatedByUserId = actor.userId;
    next.updatedByName = actor.name;
    next.updatedByRole = actor.role;
    return next;
  });

  if (!updated) {
    showErrorFeedback("Notiz konnte nicht gespeichert werden.");
    return;
  }
  saveState({ showFeedback: false });
  await syncConversationThreadRemoteOrWarn(selectedThreadId, { deleteMissing: true });
  resetConversationNoteComposer();
  renderConversationNotesSection();
  if (editingMode) {
    showSuccessFeedback("Notiz aktualisiert.");
  } else {
    showSuccessFeedback(taskModeEnabled ? "Notiz und Aufgabe gespeichert." : "Notiz gespeichert.");
  }
}

async function handleConversationTaskTitleUpdate(taskId, nextTitleRaw) {
  const selectedThreadId = String(conversationSelectedThreadId || "").trim();
  const normalizedTaskId = String(taskId || "").trim();
  if (!selectedThreadId || !normalizedTaskId) {
    return;
  }
  const nextTitle = String(nextTitleRaw || "").trim();
  if (!nextTitle) {
    showWarningFeedback("Aufgabentitel darf nicht leer sein.");
    renderConversationNotesSection();
    return;
  }
  const actor = getCurrentActorInfo();
  const nowIso = new Date().toISOString();
  const updated = updateConversationThreadWithAudit(selectedThreadId, (draft) => {
    const next = { ...draft };
    const tasks = Array.isArray(next.tasks) ? next.tasks.slice() : [];
    const taskIndex = tasks.findIndex((entry) => String(entry.id || "").trim() === normalizedTaskId);
    if (taskIndex < 0) {
      return null;
    }
    const currentTask = normalizeConversationTaskRecord(tasks[taskIndex], taskIndex);
    if (!currentTask || String(currentTask.title || "").trim() === nextTitle) {
      return null;
    }
    const previousTitle = currentTask.title;
    tasks[taskIndex] = {
      ...currentTask,
      title: nextTitle,
      updatedAt: nowIso,
      updatedByUserId: actor.userId,
      updatedByName: actor.name,
      updatedByRole: actor.role,
    };
    next.tasks = tasks;
    appendConversationSystemNote(next, `Aufgabentitel geändert: ${previousTitle} → ${nextTitle}`, actor, nowIso, normalizedTaskId);
    next.updatedAt = nowIso;
    next.updatedByUserId = actor.userId;
    next.updatedByName = actor.name;
    next.updatedByRole = actor.role;
    return next;
  });
  if (!updated) {
    renderConversationNotesSection();
    return;
  }
  saveState({ showFeedback: false });
  await syncConversationThreadRemoteOrWarn(selectedThreadId, { deleteMissing: true });
  renderConversationNotesSection();
  showSuccessFeedback("Aufgabentitel aktualisiert.");
}

