async function handleConversationTaskDelete(taskId) {
  const selectedThreadId = String(conversationSelectedThreadId || "").trim();
  const normalizedTaskId = String(taskId || "").trim();
  if (!selectedThreadId || !normalizedTaskId) {
    return;
  }
  const thread = getConversationThreadById(selectedThreadId);
  const task = Array.isArray(thread?.tasks)
    ? thread.tasks.find((entry) => String(entry.id || "").trim() === normalizedTaskId) || null
    : null;
  if (!task) {
    return;
  }
  const confirmed = await confirmDeleteAction(`Aufgabe "${task.title}" wirklich löschen?`);
  if (!confirmed) {
    return;
  }
  const actor = getCurrentActorInfo();
  const nowIso = new Date().toISOString();
  const updated = updateConversationThreadWithAudit(selectedThreadId, (draft) => {
    const next = { ...draft };
    const tasks = Array.isArray(next.tasks) ? next.tasks.slice() : [];
    next.tasks = tasks.filter((entry) => String(entry.id || "").trim() !== normalizedTaskId);
    if (!Array.isArray(next.notes)) {
      next.notes = [];
    }
    next.notes = next.notes.map((entry) =>
      String(entry?.linkedTaskId || "").trim() === normalizedTaskId ? { ...entry, linkedTaskId: "" } : entry
    );
    appendConversationSystemNote(next, `Aufgabe gelöscht: ${task.title}`, actor, nowIso);
    next.updatedAt = nowIso;
    next.updatedByUserId = actor.userId;
    next.updatedByName = actor.name;
    next.updatedByRole = actor.role;
    return next;
  });
  if (!updated) {
    return;
  }
  saveState({ showFeedback: false });
  await syncConversationThreadRemoteOrWarn(selectedThreadId, { deleteMissing: true });
  renderConversationNotesSection();
  showSuccessFeedback("Aufgabe gelöscht.");
}

async function handleConversationNoteEdit(noteId) {
  if (!isConversationEditModalOpen()) {
    openConversationEditModal();
  }
  const loaded = startConversationNoteEditing(noteId);
  if (!loaded) {
    return;
  }
  window.setTimeout(() => {
    try {
      els.conversationNoteEditor?.focus({ preventScroll: true });
    } catch (error) {
      // no-op
    }
  }, 0);
}

async function handleConversationNoteDelete(noteId) {
  const selectedThreadId = String(conversationSelectedThreadId || "").trim();
  const normalizedNoteId = String(noteId || "").trim();
  if (!selectedThreadId || !normalizedNoteId) {
    return;
  }
  const thread = getConversationThreadById(selectedThreadId);
  const note = Array.isArray(thread?.notes)
    ? thread.notes.find((entry) => String(entry.id || "").trim() === normalizedNoteId) || null
    : null;
  if (!note) {
    return;
  }
  const previewText = convertConversationMarkdownToPlainText(note.text || "") || "Diese Notiz";
  const confirmed = await confirmDeleteAction(`Notiz "${previewText.slice(0, 80)}" wirklich löschen?`);
  if (!confirmed) {
    return;
  }
  const actor = getCurrentActorInfo();
  const nowIso = new Date().toISOString();
  const updated = updateConversationThreadWithAudit(selectedThreadId, (draft) => {
    const next = { ...draft };
    const notes = Array.isArray(next.notes) ? next.notes.slice() : [];
    next.notes = notes.filter((entry) => String(entry?.id || "").trim() !== normalizedNoteId);
    next.updatedAt = nowIso;
    next.updatedByUserId = actor.userId;
    next.updatedByName = actor.name;
    next.updatedByRole = actor.role;
    return next;
  });
  if (!updated) {
    return;
  }
  saveState({ showFeedback: false });
  await syncConversationThreadRemoteOrWarn(selectedThreadId, { deleteMissing: true });
  if (conversationNoteComposerMode === "edit" && String(conversationNoteEditingNoteId || "").trim() === normalizedNoteId) {
    resetConversationNoteComposer();
  }
  renderConversationNotesSection();
  showSuccessFeedback("Notiz gelöscht.");
}

function buildProviderSearchIndexText(provider, topicLookup) {
  const topicDetails = (provider.topicIds || [])
    .map((topicId) => topicLookup.get(topicId))
    .filter(Boolean);
  const topicNames = topicDetails.map((topic) => String(topic.name || "").trim());
  const subcategoryNames = topicDetails.map((topic) => String(topic.subcategoryName || "").trim());
  const categoryNames = topicDetails.map((topic) => String(topic.categoryName || "").trim());
  const locationEntries = getProviderEffectiveLocations(provider);
  const locationParts = locationEntries.flatMap((location) => [
    String(location?.address || "").trim(),
    String(location?.postalCode || "").trim(),
    String(location?.city || "").trim(),
    String(location?.state || "").trim(),
    String(location?.country || "").trim(),
  ]);
  const coverageParts = isBigPlayerProvider(provider)
    ? [
        String(provider.coverageCountry || "").trim(),
        ...getProviderCoverageStates(provider).map((stateLabel) => String(stateLabel || "").trim()),
      ]
    : [];
  if (isProviderOnlineOnly(provider)) {
    coverageParts.push("online");
  }

  return normalizeText(
    [
      String(provider.name || "").trim(),
      String(provider.status || "").trim(),
      String(getProviderCoverageSummary(provider) || "").trim(),
      ...locationParts,
      ...coverageParts,
      ...categoryNames,
      ...subcategoryNames,
      ...topicNames,
    ].join(" ")
  );
}

function providerMatchesListSearch(provider, normalizedSearchTerm, topicLookup) {
  if (!normalizedSearchTerm) {
    return true;
  }
  const haystack = buildProviderSearchIndexText(provider, topicLookup);
  if (!haystack) {
    return false;
  }

  const searchTerms = String(normalizedSearchTerm)
    .split(/\s+/)
    .map((term) => String(term || "").trim())
    .filter(Boolean);
  if (!searchTerms.length) {
    return true;
  }

  return searchTerms.every((term) => haystack.includes(term));
}

function getProviderCreatorDisplayName(provider) {
  return pickFirstNonEmpty(
    provider?.createdByName,
    getUserDisplayNameByUserId(provider?.createdByUserId),
    provider?.updatedByName,
    getUserDisplayNameByUserId(provider?.updatedByUserId),
    provider?.liveByName,
    getUserDisplayNameByUserId(provider?.liveByUserId),
    "Unbekannt"
  );
}

function getProviderCreatorFilterKey(provider) {
  const userId = normalizeUserId(
    provider?.createdByUserId || provider?.updatedByUserId || provider?.liveByUserId || ""
  );
  if (userId) {
    return `uid:${userId}`;
  }
  const displayName = getProviderCreatorDisplayName(provider);
  if (displayName) {
    return `name:${normalizeText(displayName)}`;
  }
  return "unknown";
}

function buildProviderCreatorFilterOptions(providers) {
  const map = new Map();
  (Array.isArray(providers) ? providers : []).forEach((provider) => {
    const key = getProviderCreatorFilterKey(provider);
    if (!key) {
      return;
    }
    if (!map.has(key)) {
      const creatorName = getProviderCreatorDisplayName(provider);
      map.set(key, {
        key,
        label: creatorName,
      });
    }
  });
  return Array.from(map.values()).sort((left, right) =>
    String(left.label || "").localeCompare(String(right.label || ""), "de")
  );
}

function renderProviderCreatorFilters(providers) {
  if (!els.providerListOwnerFilter) {
    return;
  }

  const options = buildProviderCreatorFilterOptions(providers);
  const selectedOwnerFilter = String(providerListOwnerFilter || "all").trim() || "all";
  const ownerExists = options.some((entry) => entry.key === selectedOwnerFilter);
  if (selectedOwnerFilter !== "all" && !ownerExists) {
    providerListOwnerFilter = "all";
  }

  els.providerListOwnerFilter.innerHTML = [
    '<option value="all">Alle Personen</option>',
    ...options.map((entry) => `<option value="${escapeHtml(entry.key)}">${escapeHtml(entry.label)}</option>`),
  ].join("");
  els.providerListOwnerFilter.value = providerListOwnerFilter;
}

function providerMatchesCreatorPersonFilter(provider, personFilter = providerListOwnerFilter) {
  const normalizedPersonFilter = String(personFilter || "all").trim() || "all";
  if (normalizedPersonFilter === "all") {
    return true;
  }
  return getProviderCreatorFilterKey(provider) === normalizedPersonFilter;
}

function buildProviderTopicHoverText(topicEntries) {
  const categories = Array.from(
    new Set(topicEntries.map((topic) => String(topic.categoryName || "").trim()).filter(Boolean))
  ).sort((a, b) => a.localeCompare(b, "de"));
  const subcategories = Array.from(
    new Set(topicEntries.map((topic) => String(topic.subcategoryName || "").trim()).filter(Boolean))
  ).sort((a, b) => a.localeCompare(b, "de"));
  const topics = topicEntries
    .map((topic) => String(topic.name || "").trim())
    .filter(Boolean)
    .sort((a, b) => a.localeCompare(b, "de"));

  if (!topics.length) {
    return "";
  }

  return [
    `Kategorien: ${categories.join(", ") || "-"}`,
    `Themenbereiche: ${subcategories.join(", ") || "-"}`,
    `Themen: ${topics.join(", ")}`,
  ].join("\n");
}

function buildColorHash(value) {
  const text = String(value || "").trim();
  if (!text) {
    return 0;
  }
  let hash = 0;
  for (let index = 0; index < text.length; index += 1) {
    hash = (hash * 31 + text.charCodeAt(index)) >>> 0;
  }
  return hash;
}

function getTourPlannerColorByKey(keyLike) {
  const hash = buildColorHash(keyLike);
  const hue = hash % 360;
  return `hsl(${hue}, 72%, 42%)`;
}

function getTourPlannerShortLabel(nameLike, userIdLike = "") {
  const fullName = String(nameLike || "").trim();
  if (fullName) {
    const words = fullName.split(/\s+/).filter(Boolean);
    const initials = words
      .slice(0, 2)
      .map((word) => String(word || "").charAt(0))
      .join("")
      .toUpperCase();
    if (initials) {
      return initials;
    }
    return fullName.slice(0, 2).toUpperCase();
  }
  const fallbackId = String(userIdLike || "").trim();
  if (!fallbackId) {
    return "User";
  }
  return fallbackId.slice(0, 2).toUpperCase();
}

function buildProviderTourPlannerMap(tours = getVisibleToursForCurrentUser()) {
  const rows = Array.isArray(tours) ? tours : [];
  const mapByProviderId = new Map();

  rows.forEach((tour) => {
    const plannerUserId = normalizeUserId(tour?.assigneeUserId || tour?.createdByUserId || "");
    const plannerName = getTourAssigneeNameByUserId(
      plannerUserId,
      String(tour?.assigneeName || tour?.createdByName || "Mitarbeiter").trim()
    );
    const plannerKey = plannerUserId || normalizeText(plannerName) || String(tour?.id || "").trim();
    if (!plannerKey) {
      return;
    }
    const plannerColor = getTourPlannerColorByKey(plannerKey);
    const plannerShortLabel = getTourPlannerShortLabel(plannerName, plannerUserId);
    (Array.isArray(tour?.stops) ? tour.stops : []).forEach((stop) => {
      const providerId = String(stop?.providerId || "").trim();
      if (!providerId) {
        return;
      }
      if (!mapByProviderId.has(providerId)) {
        mapByProviderId.set(providerId, new Map());
      }
      const plannerMap = mapByProviderId.get(providerId);
      const existing = plannerMap.get(plannerKey);
      if (existing) {
        existing.tourCount += 1;
        return;
      }
      plannerMap.set(plannerKey, {
        key: plannerKey,
        userId: plannerUserId,
        name: plannerName,
        shortLabel: plannerShortLabel,
        color: plannerColor,
        tourCount: 1,
      });
    });
  });

  const result = new Map();
  mapByProviderId.forEach((plannerMap, providerId) => {
    const planners = Array.from(plannerMap.values()).sort((left, right) => {
      const byName = String(left?.name || "").localeCompare(String(right?.name || ""), "de", {
        sensitivity: "base",
        ignorePunctuation: true,
      });
      if (byName !== 0) {
        return byName;
      }
      return String(left?.key || "").localeCompare(String(right?.key || ""), "de");
    });
    result.set(providerId, planners);
  });
  return result;
}

function buildProviderTourAssignmentMap(tours = state.tours) {
  const rows = Array.isArray(tours) ? tours : [];
  const mapByProviderId = new Map();

  rows.forEach((tour) => {
    const tourId = String(tour?.id || "").trim();
    if (!tourId) {
      return;
    }
    const tourName = String(tour?.name || "").trim() || "Tour";
    const assigneeUserId = normalizeUserId(tour?.assigneeUserId || tour?.createdByUserId || "");
    const assigneeName = getTourAssigneeNameByUserId(
      assigneeUserId,
      String(tour?.assigneeName || tour?.createdByName || "Mitarbeiter").trim()
    );
    const plannedDateLabel = formatTourDateLabel(tour?.plannedDate);
    const assignment = {
      tourId,
      tourName,
      assigneeUserId,
      assigneeName,
      plannedDate: String(tour?.plannedDate || "").trim(),
      plannedDateLabel,
    };
    const seenProviderIds = new Set();
    (Array.isArray(tour?.stops) ? tour.stops : []).forEach((stop) => {
      const providerId = String(stop?.providerId || "").trim();
      if (!providerId || seenProviderIds.has(providerId)) {
        return;
      }
      seenProviderIds.add(providerId);
      if (!mapByProviderId.has(providerId)) {
        mapByProviderId.set(providerId, new Map());
      }
      mapByProviderId.get(providerId).set(tourId, assignment);
    });
  });

  const result = new Map();
  mapByProviderId.forEach((assignmentMap, providerId) => {
    const assignments = Array.from(assignmentMap.values()).sort((left, right) => {
      const byDate = String(left?.plannedDate || "").localeCompare(String(right?.plannedDate || ""), "de", {
        sensitivity: "base",
        ignorePunctuation: true,
      });
      if (byDate !== 0) {
        return byDate;
      }
      return String(left?.tourName || "").localeCompare(String(right?.tourName || ""), "de", {
        sensitivity: "base",
        ignorePunctuation: true,
      });
    });
    result.set(providerId, assignments);
  });

  return result;
}

function renderProvidersTable() {
  const visibleProviders = getVisibleProvidersForCurrentUser();
  const providerTourAssignmentMap = buildProviderTourAssignmentMap();
  const providerSalesPhonePlanMap = buildSalesPhoneOpenPlanMap();
  queueProviderNotesPrefetchForList(visibleProviders);
  renderProviderCreatorFilters(visibleProviders);
  const normalizedSearchTerm = normalizeText(providerListSearchTerm);
  const allTopics = getAllTopics();
  const topicLookup = new Map(allTopics.map((topic) => [topic.id, topic]));
  const filteredProviders = visibleProviders.filter((provider) =>
    providerMatchesListSearch(provider, normalizedSearchTerm, topicLookup) &&
    providerMatchesCreatorPersonFilter(provider)
  );
  const hasProviderFiltersActive =
    Boolean(String(providerListSearchTerm || "").trim()) ||
    String(providerListOwnerFilter || "all").trim() !== "all";
  if (els.providerHeadingLabel) {
    els.providerHeadingLabel.textContent = hasProviderFiltersActive
      ? `Anbieter (${filteredProviders.length}/${visibleProviders.length})`
      : `Anbieter (${visibleProviders.length})`;
  }
  const sortedProviders = filteredProviders
    .slice()
    .sort((left, right) => {
      const leftName = String(left?.name || "").trim();
      const rightName = String(right?.name || "").trim();
      const byName = leftName.localeCompare(rightName, "de", {
        sensitivity: "base",
        ignorePunctuation: true,
        numeric: true,
      });
      if (byName !== 0) {
        return byName;
      }
      return String(left?.id || "").localeCompare(String(right?.id || ""), "de");
    });

  if (els.providerListSearchInput && els.providerListSearchInput.value !== providerListSearchTerm) {
    els.providerListSearchInput.value = providerListSearchTerm;
  }

  if (!visibleProviders.length) {
    const restrictedByTerritory = hasCurrentUserTerritoryAssignment();
    const emptyMessage =
      restrictedByTerritory
        ? "Keine Anbieter in deinen zugewiesenen Gebieten."
        : "Noch keine Anbieter vorhanden.";
    els.providersTableBody.innerHTML =
      `<tr><td colspan="6" class="empty">${escapeHtml(emptyMessage)}</td></tr>`;
    return;
  }
  if (!filteredProviders.length) {
    const emptyMessage = hasProviderFiltersActive
      ? "Keine Anbieter für die gewählten Filter gefunden."
      : "Keine Anbieter gefunden.";
    els.providersTableBody.innerHTML =
      `<tr><td colspan="6" class="empty">${escapeHtml(emptyMessage)}</td></tr>`;
    return;
  }

  els.providersTableBody.innerHTML = sortedProviders
    .map((provider) => {
      const topicEntries = (provider.topicIds || [])
        .map((topicId) => topicLookup.get(topicId))
        .filter(Boolean);
      const topicHoverText = buildProviderTopicHoverText(topicEntries);
      const hasTopicDetails = Boolean(topicHoverText);
      const locationLabel = getProviderCoverageSummary(provider);
      const live = normalizeText(provider.status || "") === "live";
      const adminOnly = isProviderAdminOnly(provider);
      const onlineOnly = isProviderOnlineOnly(provider);
      const statusLabel = String(provider.status || "offen").trim() || "offen";
      const canDelete = canCurrentUserDeleteProvider(provider);
      const openNoteCount = getProviderOpenNotesCountForCurrentUser(provider);
      const providerId = String(provider.id || "").trim();
      const tourAssignments = providerTourAssignmentMap.get(providerId) || [];
      const hasTourPlanning = tourAssignments.length > 0;
      const primaryTourAssignment = tourAssignments[0] || null;
      const primaryTourAssigneeUserId = normalizeUserId(primaryTourAssignment?.assigneeUserId || "");
      const primaryTourAssigneeName = String(primaryTourAssignment?.assigneeName || "").trim();
      const salesPhonePlanEntries = providerSalesPhonePlanMap.get(providerId) || [];
      const hasSalesPhonePlanning = salesPhonePlanEntries.length > 0;
      const primarySalesPhonePlan = salesPhonePlanEntries[0] || null;
      const primarySalesPhoneAssigneeUserId = normalizeUserId(primarySalesPhonePlan?.assigneeUserId || "");
      const primarySalesPhoneAssignee = String(
        primarySalesPhonePlan?.assigneeName ||
          getUserDisplayNameByUserId(primarySalesPhonePlan?.assigneeUserId) ||
          "Mitarbeiter"
      ).trim();
      const primarySalesPhoneDateLabel = primarySalesPhonePlan?.plannedDate
        ? formatTourDateLabel(primarySalesPhonePlan.plannedDate)
        : "ohne Datum";
      const additionalSalesPhonePlans = Math.max(0, salesPhonePlanEntries.length - 1);
      const salesPhonePlanLabel = hasSalesPhonePlanning
        ? `${primarySalesPhoneAssignee} · ${primarySalesPhoneDateLabel}${
            additionalSalesPhonePlans > 0 ? ` (+${additionalSalesPhonePlans})` : ""
          }`
        : "";
      const markerUserId = hasTourPlanning ? primaryTourAssigneeUserId : primarySalesPhoneAssigneeUserId;
      const markerName = hasTourPlanning
        ? primaryTourAssigneeName
        : hasSalesPhonePlanning
          ? primarySalesPhoneAssignee
          : "";
      const markerColor = markerUserId || markerName ? getEmployeeMarkerColorByUserId(markerUserId, markerName) : "";
      const tourPlanningHoverText = tourAssignments
        .map((assignment) => {
          const datePart = assignment.plannedDateLabel ? ` · Datum: ${assignment.plannedDateLabel}` : "";
          return `Tour: ${assignment.tourName} · Mitarbeiter: ${assignment.assigneeName}${datePart}`;
        })
        .join("\n");
      const rowClassName = [hasTourPlanning ? "provider-row-in-tour" : "", hasSalesPhonePlanning ? "provider-row-in-sales-phone" : ""]
        .filter(Boolean)
        .join(" ");
      const rowStyleAttribute = markerColor ? ` style="--provider-employee-color:${escapeHtml(markerColor)}"` : "";

      return `
        <tr class="${rowClassName}"${rowStyleAttribute}>
          <td class="provider-tour-check-cell">
            ${
              hasTourPlanning
                ? `<span class="provider-tour-check has-tooltip" tabindex="0" aria-label="In Tour geplant">
                     <span class="provider-tour-check-icon">✓</span>
                     <span class="provider-tour-check-tooltip" role="tooltip">${escapeHtml(tourPlanningHoverText)}</span>
                   </span>`
                : '<span class="provider-tour-check-empty" aria-hidden="true">·</span>'
            }
          </td>
          <td>
            <div class="provider-name-cell">
              <span>${escapeHtml(provider.name)}</span>
              ${adminOnly ? '<span class="provider-admin-badge">Nur Admin</span>' : ""}
              ${onlineOnly ? '<span class="provider-online-badge">Online</span>' : ""}
              ${
                hasTourPlanning
                  ? `<small class="provider-sales-phone-plan">${renderEmployeeColorTag(
                      primaryTourAssigneeUserId,
                      primaryTourAssigneeName,
                      { prefix: "Tour" }
                    )}</small>`
                  : ""
              }
              ${
                hasSalesPhonePlanning
                  ? `<small class="provider-sales-phone-plan">${renderEmployeeColorTag(
                      primarySalesPhoneAssigneeUserId,
                      salesPhonePlanLabel,
                      { prefix: "Telefon" }
                    )}</small>`
                  : ""
              }
              ${
                openNoteCount
                  ? `<button
                      type="button"
                      class="provider-open-notes-btn"
                      title="Offene Notizen anzeigen"
                      aria-label="Offene Notizen anzeigen"
                      data-provider-open-notes="${escapeHtml(provider.id)}"
                    >
                      <span class="provider-open-notes-icon">📝</span>
                      <span class="provider-open-notes-count">${escapeHtml(String(openNoteCount))}</span>
                    </button>`
                  : ""
              }
            </div>
          </td>
          <td>
            <span class="provider-status-pill ${live ? "live" : ""}">
              <span class="provider-status-light ${live ? "live" : ""}"></span>
              ${escapeHtml(statusLabel)}
            </span>
          </td>
	          <td>${escapeHtml(locationLabel)}</td>
	          <td>
	            <span class="provider-topics-hover ${hasTopicDetails ? "has-tooltip" : ""}" ${hasTopicDetails ? 'tabindex="0"' : ""}>
	              <span class="provider-topics-count">${escapeHtml(String(topicEntries.length))}</span>
	              ${
                  hasTopicDetails
                    ? `<span class="provider-topics-hint">Details</span>
                       <span class="provider-topics-tooltip" role="tooltip">${escapeHtml(topicHoverText)}</span>`
                    : ""
                }
	            </span>
	          </td>
	          <td>
	            <div class="table-icon-actions">
                <label class="live-toggle-switch">
                  <input
                    type="checkbox"
                    data-live-toggle-provider="${escapeHtml(provider.id)}"
                    ${live ? "checked" : ""}
                  />
                  <span class="live-toggle-track"><span class="live-toggle-thumb"></span></span>
                  <span class="live-toggle-text">Live</span>
                </label>
                <button
                  type="button"
                  class="mini-btn"
                  title="Anbieter bearbeiten"
                  aria-label="Anbieter bearbeiten"
                  data-edit-provider="${escapeHtml(provider.id)}"
                >✎</button>
                <button
                  type="button"
                  class="mini-btn danger"
                  title="${
                    canDelete
                      ? "Anbieter löschen"
                      : "Löschen nur für Superadmin oder Ersteller"
                  }"
                  aria-label="Anbieter löschen"
                  data-delete-provider="${escapeHtml(provider.id)}"
                  ${canDelete ? "" : "disabled"}
                >✕</button>
              </div>
	          </td>
        </tr>
      `;
    })
    .join("");
}

function normalizeTourDateInput(value, fallback = "") {
  const parsedDate = parseDateInputStart(value);
  if (parsedDate) {
    return toDateInputValue(parsedDate);
  }
  const fallbackDate = parseDateInputStart(fallback);
  if (fallbackDate) {
    return toDateInputValue(fallbackDate);
  }
  return getTodayDateInputValue();
}

function getCurrentSalesUserId() {
  return normalizeUserId(getCurrentUserId());
}

function getTourAssigneeOptions() {
  const currentUser = getCurrentUser();
  if (!currentUser) {
    return [];
  }

  const optionsById = new Map();
  const pushOption = (userId, name, role) => {
    const normalizedUserId = normalizeUserId(userId);
    if (!normalizedUserId || optionsById.has(normalizedUserId)) {
      return;
    }
    const label = String(name || "").trim() || "Mitarbeiter";
    optionsById.set(normalizedUserId, {
      userId: normalizedUserId,
      name: label,
      role: normalizeUserRole(role),
    });
  };

  if (isRoleAdmin(currentUser)) {
    state.users
      .filter((entry) => entry.source === "profile" && isUserStatusActive(entry.status))
      .forEach((entry) => {
        pushOption(entry.sourceId, entry.name || entry.email, entry.role);
      });
  }

  pushOption(
    authProfile?.user_id || currentUser?.sourceId || currentUser?.id || "",
    currentUser?.name || currentUser?.email || "Mitarbeiter",
    currentUser?.role
  );

  return Array.from(optionsById.values()).sort((left, right) =>
    String(left.name || "").localeCompare(String(right.name || ""), "de")
  );
}

function getTourAssigneeNameByUserId(userId, fallback = "") {
  const normalizedUserId = normalizeUserId(userId);
  if (!normalizedUserId) {
    return String(fallback || "").trim() || "Unbekannt";
  }
  const fromState = getUserDisplayNameByUserId(normalizedUserId);
  if (fromState) {
    return fromState;
  }
  return String(fallback || "").trim() || "Unbekannt";
}

function canCurrentUserAccessTour(tour, currentUser = getCurrentUser()) {
  if (!tour || !currentUser) {
    return false;
  }
  if (isSuperAdmin(currentUser)) {
    return true;
  }
  const currentUserId = getCurrentSalesUserId();
  if (!currentUserId) {
    return false;
  }
  const assigneeUserId = normalizeUserId(tour.assigneeUserId || "");
  if (assigneeUserId) {
    return assigneeUserId === currentUserId;
  }
  const creatorUserId = normalizeUserId(tour.createdByUserId || "");
  return creatorUserId === currentUserId;
}

function canCurrentUserEditTour(tour, currentUser = getCurrentUser()) {
  return canCurrentUserAccessTour(tour, currentUser);
}

function getTourPlannerUserId(tour) {
  return normalizeUserId(tour?.assigneeUserId || tour?.createdByUserId || "");
}

function getTourPlannerName(tour, fallback = "Mitarbeiter") {
  const plannerUserId = getTourPlannerUserId(tour);
  const fallbackName = String(tour?.assigneeName || tour?.createdByName || fallback).trim() || fallback;
  return getTourAssigneeNameByUserId(plannerUserId, fallbackName);
}

function findProviderPlanningConflict(providerId, targetTourLike) {
  const normalizedProviderId = String(providerId || "").trim();
  if (!normalizedProviderId) {
    return null;
  }
  const targetTour =
    typeof targetTourLike === "string"
      ? getTourById(targetTourLike)
      : targetTourLike && typeof targetTourLike === "object"
        ? targetTourLike
        : null;
  if (!targetTour) {
    return null;
  }
  const targetTourId = String(targetTour.id || "").trim();
  if (!targetTourId) {
    return null;
  }

  const targetPlannerUserId = getTourPlannerUserId(targetTour);
  const tours = Array.isArray(state.tours) ? state.tours : [];
  for (const tour of tours) {
    const otherTourId = String(tour?.id || "").trim();
    if (!otherTourId || otherTourId === targetTourId) {
      continue;
    }
    const hasProviderInTour = (Array.isArray(tour?.stops) ? tour.stops : []).some(
      (stop) => String(stop?.providerId || "").trim() === normalizedProviderId
    );
    if (!hasProviderInTour) {
      continue;
    }
    const otherPlannerUserId = getTourPlannerUserId(tour);
    if (targetPlannerUserId && otherPlannerUserId && targetPlannerUserId === otherPlannerUserId) {
      continue;
    }
    return {
      tourId: otherTourId,
      tourName: String(tour?.name || "Tour").trim(),
      plannedDateLabel: formatTourDateLabel(tour?.plannedDate),
      assigneeUserId: otherPlannerUserId,
      assigneeName: getTourPlannerName(tour),
    };
  }

  return null;
}

function sortToursForPlanning(tours) {
  return (Array.isArray(tours) ? tours : []).slice().sort((left, right) => {
    const leftDate = parseDateInputStart(left?.plannedDate || "");
    const rightDate = parseDateInputStart(right?.plannedDate || "");
    const leftTime = leftDate ? leftDate.getTime() : Number.MAX_SAFE_INTEGER;
    const rightTime = rightDate ? rightDate.getTime() : Number.MAX_SAFE_INTEGER;
    if (leftTime !== rightTime) {
      return leftTime - rightTime;
    }
    const leftUpdated = String(left?.updatedAt || left?.createdAt || "");
    const rightUpdated = String(right?.updatedAt || right?.createdAt || "");
    if (leftUpdated !== rightUpdated) {
      return rightUpdated.localeCompare(leftUpdated, "de");
    }
    return String(left?.name || "").localeCompare(String(right?.name || ""), "de");
  });
}

function getVisibleToursForCurrentUser() {
  const currentUser = getCurrentUser();
  if (!currentUser) {
    return [];
  }
  return sortToursForPlanning(
    (state.tours || []).filter((tour) => canCurrentUserAccessTour(tour, currentUser))
  );
}

function ensureSelectedTour(visibleTours = getVisibleToursForCurrentUser()) {
  if (!visibleTours.length) {
    selectedTourId = "";
    return;
  }
  const hasSelectedTour = visibleTours.some((tour) => tour.id === selectedTourId);
  if (!hasSelectedTour) {
    selectedTourId = visibleTours[0].id;
  }
}

function getTourById(tourId) {
  const normalizedTourId = String(tourId || "").trim();
  if (!normalizedTourId) {
    return null;
  }
  return (state.tours || []).find((tour) => tour.id === normalizedTourId) || null;
}

function getSelectedTourForCurrentUser() {
  if (!selectedTourId) {
    return null;
  }
  const selectedTour = getTourById(selectedTourId);
  if (!selectedTour || !canCurrentUserAccessTour(selectedTour)) {
    return null;
  }
  return selectedTour;
}

function normalizeTourStopRecord(stop, fallbackProviderId = "") {
  if (!stop || typeof stop !== "object") {
    return null;
  }
  const providerId = String(stop.providerId || stop.provider_id || fallbackProviderId || "").trim();
  if (!providerId) {
    return null;
  }
  return {
    id: String(stop.id || "").trim() || createId("tstop"),
    providerId,
    addedAt: String(stop.addedAt || stop.added_at || stop.createdAt || "").trim(),
    addedByUserId: normalizeUserId(stop.addedByUserId || stop.added_by_user_id || ""),
    addedByName: String(stop.addedByName || stop.added_by_name || "").trim(),
    doneAt: String(stop.doneAt || stop.done_at || "").trim(),
    doneByUserId: normalizeUserId(stop.doneByUserId || stop.done_by_user_id || ""),
    doneByName: String(stop.doneByName || stop.done_by_name || "").trim(),
  };
}

function normalizeTourActivityRecord(entry) {
  if (!entry || typeof entry !== "object") {
    return null;
  }
  const action = String(entry.action || "").trim().toLowerCase() || "updated";
  const details = String(entry.details || "").trim();
  if (!action && !details) {
    return null;
  }
  return {
    id: String(entry.id || "").trim() || createId("tact"),
    at: String(entry.at || entry.createdAt || "").trim(),
    actorUserId: normalizeUserId(entry.actorUserId || entry.actor_user_id || ""),
    actorName: String(entry.actorName || entry.actor_name || "").trim(),
    action,
    details: details || "Aktualisierung",
  };
}

function normalizeTourRecord(tour) {
  if (!tour || typeof tour !== "object") {
    return null;
  }

  const createdAt = String(tour.createdAt || "").trim();
  const normalizedTour = {
    id: String(tour.id || "").trim() || createId("tour"),
    name: String(tour.name || "").trim() || "Neue Tour",
    plannedDate: normalizeTourDateInput(tour.plannedDate, getTodayDateInputValue()),
    assigneeUserId: normalizeUserId(tour.assigneeUserId || tour.assignee_user_id || tour.createdByUserId || ""),
    assigneeName: String(tour.assigneeName || tour.assignee_name || "").trim(),
    createdAt,
    createdByUserId: normalizeUserId(tour.createdByUserId || tour.created_by_user_id || ""),
    createdByName: String(tour.createdByName || tour.created_by_name || "").trim(),
    updatedAt: String(tour.updatedAt || "").trim() || createdAt,
    updatedByUserId: normalizeUserId(tour.updatedByUserId || tour.updated_by_user_id || ""),
    updatedByName: String(tour.updatedByName || tour.updated_by_name || "").trim(),
    stops: [],
    activity: [],
  };

  const seenProviderIds = new Set();
  const normalizedStops = Array.isArray(tour.stops)
    ? tour.stops
        .map((stop) => normalizeTourStopRecord(stop))
        .filter(Boolean)
        .filter((stop) => {
          const providerKey = String(stop.providerId || "").trim();
          if (!providerKey || seenProviderIds.has(providerKey)) {
            return false;
          }
          seenProviderIds.add(providerKey);
          return true;
        })
    : [];
  normalizedTour.stops = normalizedStops;

  const normalizedActivity = Array.isArray(tour.activity)
    ? tour.activity.map((entry) => normalizeTourActivityRecord(entry)).filter(Boolean)
    : [];
  normalizedTour.activity = normalizedActivity.slice(-MAX_TOUR_ACTIVITY_ENTRIES);

  if (!normalizedTour.assigneeName) {
    normalizedTour.assigneeName = getTourAssigneeNameByUserId(
      normalizedTour.assigneeUserId,
      normalizedTour.createdByName
    );
  }

  return normalizedTour;
}

function appendTourActivity(tour, action, details, actor = getCurrentActorInfo(), timestampIso = "") {
  if (!tour || typeof tour !== "object") {
    return;
  }
  const normalizedAction = String(action || "").trim().toLowerCase() || "updated";
  const normalizedDetails = String(details || "").trim() || "Aktualisierung";
  const actorUserId = normalizeUserId(actor?.userId || "");
  const actorName = String(actor?.name || "").trim() || getTourAssigneeNameByUserId(actorUserId, "Unbekannt");
  const at = String(timestampIso || "").trim() || new Date().toISOString();
  const currentActivity = Array.isArray(tour.activity) ? tour.activity.slice() : [];
  currentActivity.push({
    id: createId("tact"),
    at,
    actorUserId,
    actorName,
    action: normalizedAction,
    details: normalizedDetails,
  });
  tour.activity = currentActivity.slice(-MAX_TOUR_ACTIVITY_ENTRIES);
}

function upsertTourAssigneeSelectOptions(selectElement, selectedUserId, options = {}) {
  if (!selectElement) {
    return "";
  }
  const allowEmpty = !!options.allowEmpty;
  const assigneeOptions = getTourAssigneeOptions();
  const fallbackUserId = assigneeOptions[0]?.userId || "";
  const normalizedSelectedUserId = normalizeUserId(selectedUserId || fallbackUserId);
  const selectedExists = assigneeOptions.some((entry) => entry.userId === normalizedSelectedUserId);
  const nextSelectedUserId = selectedExists ? normalizedSelectedUserId : fallbackUserId;

  const optionMarkup = [];
  if (allowEmpty) {
    optionMarkup.push('<option value="">Bitte wählen</option>');
  }
  assigneeOptions.forEach((entry) => {
    optionMarkup.push(
      `<option value="${escapeHtml(entry.userId)}">${escapeHtml(entry.name)} · ${escapeHtml(getRoleLabel(entry.role))}</option>`
    );
  });
  selectElement.innerHTML = optionMarkup.join("");
  selectElement.value = nextSelectedUserId;
  selectElement.disabled = !isRoleAdmin() || assigneeOptions.length <= 1;
  return nextSelectedUserId;
}

function formatTourDateLabel(value) {
  const parsedDate = parseDateInputStart(value);
  if (!parsedDate) {
    return "ohne Datum";
  }
  return new Intl.DateTimeFormat("de-AT", { dateStyle: "medium" }).format(parsedDate);
}

function getTourStatusCssClass(status) {
  const bucket = getProviderStatusBucket(status);
  if (bucket === "live") {
    return "is-live";
  }
  if (bucket === "captured") {
    return "is-captured";
  }
  if (bucket === "inProgress") {
    return "is-progress";
  }
  return "is-open";
}

function buildTourStopInfoListMarkup(items, emptyLabel) {
  const rows = Array.isArray(items) ? items.filter(Boolean) : [];
  if (!rows.length) {
    return `<p class="tour-stop-info-empty">${escapeHtml(emptyLabel)}</p>`;
  }
  return `<ul class="tour-stop-info-list">${rows
    .map((label) => `<li>${escapeHtml(String(label || "").trim())}</li>`)
    .join("")}</ul>`;
}

function normalizeTourModalKey(modalKey) {
  const normalizedKey = String(modalKey || "").trim().toLowerCase();
  if (["create", "detail", "providers", "stopinfo"].includes(normalizedKey)) {
    return normalizedKey;
  }
  return "";
}

function getTourModalElement(modalKey) {
  const key = normalizeTourModalKey(modalKey);
  if (key === "create") {
    return els.tourCreateModal || null;
  }
  if (key === "detail") {
    return els.tourDetailModal || null;
  }
  if (key === "providers") {
    return els.tourProviderModal || null;
  }
  if (key === "stopinfo") {
    return els.tourStopInfoModal || null;
  }
  return null;
}

function isTourModalOpen() {
  return ["create", "detail", "providers", "stopinfo"].some((key) => {
    const modal = getTourModalElement(key);
    return !!modal && !modal.classList.contains("hidden");
  });
}

function closeTourModals() {
  ["create", "detail", "providers", "stopinfo"].forEach((key) => {
    const modal = getTourModalElement(key);
    if (modal) {
      modal.classList.add("hidden");
    }
  });
  activeTourModal = "";
  draggingTourStopId = "";
  els.tourStopList?.querySelectorAll(".is-dragging, .is-drop-target").forEach((entry) => {
    entry.classList.remove("is-dragging", "is-drop-target");
  });
  syncBodyModalOpenState();
}

function openTourModal(modalKey) {
  const key = normalizeTourModalKey(modalKey);
  if (!key) {
    return;
  }
  const modal = getTourModalElement(key);
  if (!modal) {
    return;
  }

  const selectedTour = getSelectedTourForCurrentUser();
  const requiresSelectedTour = key !== "create";
  const requiresEditAccess = ["detail", "providers"].includes(key);
  if (requiresSelectedTour && !selectedTour) {
    showInfoFeedback("Tour wählen.");
    return;
  }
  if (requiresEditAccess && selectedTour && !canCurrentUserEditTour(selectedTour)) {
    showInfoFeedback("Für diese Tour hast du nur Leserechte.");
    return;
  }

  closeTourModals();
  modal.classList.remove("hidden");
  activeTourModal = key;
  syncBodyModalOpenState();

  if (key === "create") {
    if (els.tourDateInput && !els.tourDateInput.value) {
      els.tourDateInput.value = getTodayDateInputValue();
    }
    upsertTourAssigneeSelectOptions(
      els.tourAssigneeSelect,
      els.tourAssigneeSelect?.value || getCurrentSalesUserId()
    );
    if (els.tourNameInput) {
      window.setTimeout(() => {
        els.tourNameInput.focus({ preventScroll: true });
      }, 0);
    }
    return;
  }
  if (key === "detail") {
    if (els.tourSelectedNameInput) {
      window.setTimeout(() => {
        els.tourSelectedNameInput.focus({ preventScroll: true });
        els.tourSelectedNameInput.select();
      }, 0);
    }
    return;
  }
  if (key === "providers") {
    if (els.tourProviderSearchInput) {
      window.setTimeout(() => {
        els.tourProviderSearchInput.focus({ preventScroll: true });
      }, 0);
    }
  }
}

function isTourPlannerViewVisible() {
  const tourSection = document.getElementById("tour-planner-section");
  if (!tourSection) {
    return false;
  }
  return tourSection.classList.contains("active");
}

function setTourRouteMapStatus(message, tone = "info") {
  if (!els.tourRouteMapStatus) {
    return;
  }
  if (message == null) {
    els.tourRouteMapStatus.textContent = "";
    els.tourRouteMapStatus.classList.add("hidden");
    els.tourRouteMapStatus.classList.remove(
      "is-info",
      "is-success",
      "is-warning",
      "is-error"
    );
    return;
  }
  els.tourRouteMapStatus.classList.remove("hidden");
  const normalizedTone = ["info", "success", "warning", "error"].includes(String(tone || "").trim())
    ? String(tone || "").trim()
    : "info";
  const text = String(message || "").trim() || "Route lädt...";
  els.tourRouteMapStatus.textContent = text;
  els.tourRouteMapStatus.classList.remove(
    "is-info",
    "is-success",
    "is-warning",
    "is-error"
  );
  els.tourRouteMapStatus.classList.add(`is-${normalizedTone}`);
}

function clearTourRouteMapStats() {
  if (!els.tourRouteMapStats) {
    return;
  }
  els.tourRouteMapStats.innerHTML = "";
}

function formatTourRouteDistanceLabel(distanceMeters) {
  const numericDistanceMeters = Number(distanceMeters);
  if (!Number.isFinite(numericDistanceMeters) || numericDistanceMeters < 0) {
    return "–";
  }
  return `${(numericDistanceMeters / 1000).toLocaleString("de-AT", {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  })} km`;
}

function buildTourRouteMetricsSignature(tour, points = [], skippedCount = 0) {
  const tourId = String(tour?.id || "").trim();
  const plannedStopsCount = Math.max(0, Number(Array.isArray(tour?.stops) ? tour.stops.length : 0));
  const pointKey = (Array.isArray(points) ? points : [])
    .map((point, index) => {
      const stopId = String(point?.stopId || "").trim() || `idx-${index}`;
      const locationKey = formatTourRoutePointForMaps(point);
      return `${index}:${stopId}:${locationKey}`;
    })
    .join("|");
  return `${tourId}::${plannedStopsCount}::${Math.max(0, Number(skippedCount || 0))}::${pointKey}`;
}

function cacheTourRouteMetrics(signature, metrics) {
  const normalizedSignature = String(signature || "").trim();
  if (!normalizedSignature || !metrics || typeof metrics !== "object") {
    return;
  }
  if (tourRouteMetricsCacheBySignature.size > 150) {
    tourRouteMetricsCacheBySignature.clear();
  }
  tourRouteMetricsCacheBySignature.set(normalizedSignature, metrics);
}

function getCachedTourRouteMetrics(signature) {
  const normalizedSignature = String(signature || "").trim();
  if (!normalizedSignature) {
    return null;
  }
  return tourRouteMetricsCacheBySignature.get(normalizedSignature) || null;
}

function buildTourRouteDirectionsRequest(points = []) {
  const rows = Array.isArray(points) ? points : [];
  if (rows.length < 2) {
    return null;
  }
  return {
    origin: rows[0].requestLocation,
    destination: rows[rows.length - 1].requestLocation,
    waypoints: rows.slice(1, -1).map((point) => ({
      location: point.requestLocation,
      stopover: true,
    })),
    optimizeWaypoints: false,
    travelMode: window.google.maps.TravelMode.DRIVING,
    unitSystem: window.google.maps.UnitSystem.METRIC,
    provideRouteAlternatives: false,
    region: "AT",
  };
}

function setTourProviderPlanningStatus(message, tone = "info") {
  if (!els.tourProviderPlanningStatus) {
    return;
  }
  if (message == null) {
    els.tourProviderPlanningStatus.textContent = "";
    els.tourProviderPlanningStatus.classList.add("hidden");
    els.tourProviderPlanningStatus.classList.remove("is-info", "is-warning", "is-error");
    return;
  }
  const normalizedTone = ["info", "warning", "error"].includes(String(tone || "").trim())
    ? String(tone || "").trim()
    : "info";
  els.tourProviderPlanningStatus.textContent = String(message || "").trim();
  els.tourProviderPlanningStatus.classList.remove("hidden");
  els.tourProviderPlanningStatus.classList.remove("is-info", "is-warning", "is-error");
  els.tourProviderPlanningStatus.classList.add(`is-${normalizedTone}`);
}

function renderTourProviderPlanningMetricsChips(data = {}) {
  if (!els.tourProviderPlanningMetrics) {
    return;
  }
  const stopsCount = Math.max(0, Number(data.stopsCount || 0));
  const legsCount = Math.max(0, Number(data.legsCount || 0));
  const skippedCount = Math.max(0, Number(data.skippedCount || 0));
  const distanceLabel = formatTourRouteDistanceLabel(data.distanceMeters);
  const durationSeconds = Number(data.durationSeconds);
  const durationLabel = Number.isFinite(durationSeconds) && durationSeconds >= 0
    ? formatTourRouteDuration(durationSeconds)
    : "–";
  const sourceLabel = String(data.sourceLabel || "Prüfung nötig").trim();
  const sourceWarning = data.sourceWarning !== false;
  els.tourProviderPlanningMetrics.innerHTML = `
    <span class="tour-route-stat-chip">Stops: <strong>${escapeHtml(String(stopsCount))}</strong></span>
    <span class="tour-route-stat-chip">Abschnitte: <strong>${escapeHtml(String(legsCount))}</strong></span>
    <span class="tour-route-stat-chip">Distanz: <strong>${escapeHtml(distanceLabel)}</strong></span>
    <span class="tour-route-stat-chip">Fahrzeit: <strong>${escapeHtml(durationLabel)}</strong></span>
    <span class="tour-route-stat-chip ${sourceWarning ? "is-warning" : ""}">Quelle: <strong>${escapeHtml(
      sourceLabel
    )}</strong></span>
    ${
      skippedCount > 0
        ? `<span class="tour-route-stat-chip is-warning">Ohne Route: <strong>${escapeHtml(
            String(skippedCount)
          )}</strong></span>`
        : ""
    }
  `;
}

function renderTourProviderPlanningMetrics(selectedTour) {
  if (!els.tourProviderPlanningMetrics) {
    return;
  }
  if (!selectedTour) {
    els.tourProviderPlanningMetrics.innerHTML = "";
    setTourProviderPlanningStatus(null);
    return;
  }

  const plannedStopsCount = Math.max(0, Number(Array.isArray(selectedTour.stops) ? selectedTour.stops.length : 0));
  const { points, skippedCount } = getTourRoutePoints(selectedTour);
  const fallbackLegsCount = Math.max(0, plannedStopsCount - 1);
  if (points.length < 2) {
    renderTourProviderPlanningMetricsChips({
      stopsCount: plannedStopsCount,
      legsCount: fallbackLegsCount,
      distanceMeters: null,
      durationSeconds: null,
      skippedCount,
      sourceLabel: "Nicht berechenbar",
      sourceWarning: true,
    });
    setTourProviderPlanningStatus("Mind. 2 Stopps für Distanz/Fahrzeit.", "warning");
    return;
  }

  const signature = buildTourRouteMetricsSignature(selectedTour, points, skippedCount);
  const cachedMetrics = getCachedTourRouteMetrics(signature);
  if (cachedMetrics) {
    renderTourProviderPlanningMetricsChips({
      ...cachedMetrics,
      sourceLabel: cachedMetrics.verified ? "Google Route" : "Prüfung nötig",
      sourceWarning: !cachedMetrics.verified,
    });
    setTourProviderPlanningStatus(
      cachedMetrics.verified ? null : "Routenwerte prüfen.",
      cachedMetrics.verified ? "info" : "warning"
    );
    tourProviderPlanningLastSignature = signature;
    tourProviderPlanningLastResult = {
      metrics: cachedMetrics,
      statusMessage: cachedMetrics.verified ? "" : "Routenwerte prüfen.",
      statusTone: cachedMetrics.verified ? "info" : "warning",
    };
    return;
  }

  if (signature === tourProviderPlanningLastSignature && tourProviderPlanningLastResult) {
    renderTourProviderPlanningMetricsChips({
      ...tourProviderPlanningLastResult.metrics,
      sourceLabel: tourProviderPlanningLastResult.metrics?.verified ? "Google Route" : "Prüfung nötig",
      sourceWarning: !tourProviderPlanningLastResult.metrics?.verified,
    });
    setTourProviderPlanningStatus(
      tourProviderPlanningLastResult.statusMessage || null,
      tourProviderPlanningLastResult.statusTone || "info"
    );
    return;
  }

  renderTourProviderPlanningMetricsChips({
    stopsCount: plannedStopsCount,
    legsCount: fallbackLegsCount,
    distanceMeters: null,
    durationSeconds: null,
    skippedCount,
    sourceLabel: "Wird berechnet...",
    sourceWarning: true,
  });
  if (!googleMapsReady || !window.google?.maps) {
    setTourProviderPlanningStatus(
      googlePlacesLoadError || "Karte lädt. Distanz/Fahrzeit folgen.",
      "warning"
    );
    return;
  }

  if (signature === tourProviderPlanningInFlightSignature) {
    setTourProviderPlanningStatus("Route wird berechnet...", "info");
    return;
  }

  if (!tourProviderPlanningDirectionsService) {
    tourProviderPlanningDirectionsService = new window.google.maps.DirectionsService();
  }
  const directionsRequest = buildTourRouteDirectionsRequest(points);
  if (!directionsRequest) {
    setTourProviderPlanningStatus("Route nicht möglich.", "warning");
    return;
  }

  const requestId = ++tourProviderPlanningRequestId;
  tourProviderPlanningInFlightSignature = signature;
  setTourProviderPlanningStatus("Route wird berechnet...", "info");
  tourProviderPlanningDirectionsService.route(directionsRequest, (result, status) => {
    if (requestId !== tourProviderPlanningRequestId) {
      return;
    }
    tourProviderPlanningInFlightSignature = "";
    if (status !== "OK" || !result?.routes?.length) {
      const errorMessage = getTourDirectionsStatusMessage(status);
      const errorMetrics = {
        stopsCount: plannedStopsCount,
        legsCount: fallbackLegsCount,
        distanceMeters: null,
        durationSeconds: null,
        skippedCount,
        verified: false,
      };
      renderTourProviderPlanningMetricsChips({
        ...errorMetrics,
        sourceLabel: "Prüfung nötig",
        sourceWarning: true,
      });
      setTourProviderPlanningStatus(errorMessage, "error");
      tourProviderPlanningLastSignature = signature;
      tourProviderPlanningLastResult = {
        metrics: errorMetrics,
        statusMessage: errorMessage,
        statusTone: "error",
      };
      return;
    }

    const routeMetrics = buildTourRouteMetricsFromGoogleRoute(
      result.routes[0],
      points,
      skippedCount,
      plannedStopsCount
    );
    cacheTourRouteMetrics(signature, routeMetrics);
    renderTourProviderPlanningMetricsChips({
      ...routeMetrics,
      sourceLabel: routeMetrics.verified ? "Google Route" : "Prüfung nötig",
      sourceWarning: !routeMetrics.verified,
    });
    const warningMessage = routeMetrics.verified
      ? ""
      : "Routenwerte prüfen.";
    setTourProviderPlanningStatus(warningMessage || null, routeMetrics.verified ? "info" : "warning");
    tourProviderPlanningLastSignature = signature;
    tourProviderPlanningLastResult = {
      metrics: routeMetrics,
      statusMessage: warningMessage,
      statusTone: routeMetrics.verified ? "info" : "warning",
    };
  });
}

function clearTourRouteMapLegend() {
  if (!els.tourRouteMapLegend) {
    return;
  }
  els.tourRouteMapLegend.innerHTML = "";
}

function renderTourRouteMapLegend(points = []) {
  if (!els.tourRouteMapLegend) {
    return;
  }
  const rows = Array.isArray(points) ? points : [];
  if (!rows.length) {
    clearTourRouteMapLegend();
    return;
  }
  els.tourRouteMapLegend.innerHTML = rows
    .map((point, index) => {
      const label = `${index + 1}. ${String(point?.providerName || "Anbieter").trim()}`;
      const locationLabel = String(point?.locationLabel || "").trim();
      return `
        <article class="tour-route-legend-item">
          <span class="tour-route-legend-number">${escapeHtml(String(index + 1))}</span>
          <div class="tour-route-legend-text">
            <strong>${escapeHtml(label)}</strong>
            <small>${escapeHtml(locationLabel || "Standort unbekannt")}</small>
          </div>
        </article>
      `;
    })
    .join("");
}

function renderTourRouteMapStats(metrics) {
  if (!els.tourRouteMapStats) {
    return;
  }
  if (!metrics || typeof metrics !== "object") {
    clearTourRouteMapStats();
    return;
  }
  const distanceKm = Number(metrics.distanceMeters || 0) / 1000;
  const stopsCount = Number(metrics.routedStopsCount || metrics.stopsCount || 0);
  const legsCount = Number(metrics.legsCount || 0);
  const skippedCount = Number(metrics.skippedCount || 0);
  const verified = !!metrics.verified;
  els.tourRouteMapStats.innerHTML = `
    <span class="tour-route-stat-chip">Stops: <strong>${escapeHtml(String(stopsCount))}</strong></span>
    <span class="tour-route-stat-chip">Abschnitte: <strong>${escapeHtml(String(legsCount))}</strong></span>
    <span class="tour-route-stat-chip">Distanz: <strong>${escapeHtml(
      `${distanceKm.toLocaleString("de-AT", {
        minimumFractionDigits: 2,
        maximumFractionDigits: 2,
      })} km`
    )}</strong></span>
    <span class="tour-route-stat-chip">Fahrzeit: <strong>${escapeHtml(
      formatTourRouteDuration(metrics.durationSeconds || 0)
    )}</strong></span>
    <span class="tour-route-stat-chip ${verified ? "" : "is-warning"}">Quelle: <strong>${escapeHtml(
      verified ? "Google Route" : "Prüfung nötig"
    )}</strong></span>
    ${
      skippedCount > 0
        ? `<span class="tour-route-stat-chip is-warning">Ohne Route: <strong>${escapeHtml(
            String(skippedCount)
          )}</strong></span>`
        : ""
    }
  `;
}

function buildTourRouteMetricsFromGoogleRoute(route, points, skippedCount = 0, plannedStopsCount = 0) {
  const legs = Array.isArray(route?.legs) ? route.legs : [];
  const expectedLegsCount = Math.max(0, (Array.isArray(points) ? points.length : 0) - 1);
  const distanceMeters = legs.reduce((sum, leg) => sum + Number(leg?.distance?.value || 0), 0);
  const durationSeconds = legs.reduce((sum, leg) => sum + Number(leg?.duration?.value || 0), 0);
  const hasInvalidLegValues = legs.some(
    (leg) => !Number.isFinite(Number(leg?.distance?.value)) || !Number.isFinite(Number(leg?.duration?.value))
  );
  const routedStopsCount = legs.length > 0 ? legs.length + 1 : 0;
  const normalizedPlannedStopsCount = Math.max(0, Number(plannedStopsCount || 0));
  const verified =
    expectedLegsCount > 0 &&
    legs.length === expectedLegsCount &&
    !hasInvalidLegValues &&
    Number.isFinite(distanceMeters) &&
    Number.isFinite(durationSeconds) &&
    routedStopsCount > 1 &&
    Number(skippedCount || 0) === 0 &&
    normalizedPlannedStopsCount >= routedStopsCount;

  return {
    routedStopsCount,
    legsCount: legs.length,
    distanceMeters: Number.isFinite(distanceMeters) ? distanceMeters : 0,
    durationSeconds: Number.isFinite(durationSeconds) ? durationSeconds : 0,
    skippedCount: Math.max(0, Number(skippedCount || 0)),
    expectedLegsCount,
    plannedStopsCount: normalizedPlannedStopsCount,
    verified,
  };
}

function formatTourRouteDuration(totalSeconds) {
  const numericSeconds = Number(totalSeconds || 0);
  if (!Number.isFinite(numericSeconds) || numericSeconds <= 0) {
    return "0 Min";
  }
  const minutesTotal = Math.round(numericSeconds / 60);
  const hours = Math.floor(minutesTotal / 60);
  const minutes = minutesTotal % 60;
  if (!hours) {
    return `${minutes} Min`;
  }
  if (!minutes) {
    return `${hours} h`;
  }
  return `${hours} h ${minutes} Min`;
}

function resolveTourProviderPrimaryLocation(provider) {
  const effectiveLocations = getProviderEffectiveLocations(provider);
  if (effectiveLocations.length) {
    return normalizeProviderLocation(effectiveLocations[0]);
  }
  const fallbackLocations = getProviderLocations(provider);
  if (fallbackLocations.length) {
    return normalizeProviderLocation(fallbackLocations[0]);
  }
  return normalizeProviderLocation(provider);
}

function buildTourRouteLocationLabel(location) {
  const normalizedLocation = normalizeProviderLocation(location);
  const lineParts = [
    normalizedLocation.address,
    [normalizedLocation.postalCode, normalizedLocation.city].filter(Boolean).join(" "),
    normalizedLocation.state,
    normalizedLocation.country,
  ]
    .map((part) => String(part || "").trim())
    .filter(Boolean);
  return lineParts.join(", ");
}

function buildTourRoutePointFromProvider(provider, stop = null) {
  if (!provider || typeof provider !== "object") {
    return null;
  }
  const location = resolveTourProviderPrimaryLocation(provider);
  const latitude = parseOptionalNumber(location.latitude);
  const longitude = parseOptionalNumber(location.longitude);
  const providerName = String(provider.name || "").trim() || "Anbieter";
  const locationLabel = buildTourRouteLocationLabel(location);

  let requestLocation = null;
  if (typeof latitude === "number" && typeof longitude === "number") {
    requestLocation = { lat: latitude, lng: longitude };
  } else if (locationLabel) {
    requestLocation = locationLabel;
  }
  if (!requestLocation) {
    return null;
  }

  return {
    stopId: String(stop?.id || "").trim(),
    providerId: String(provider.id || "").trim(),
    providerName,
    locationLabel,
    requestLocation,
  };
}

function getTourRoutePoints(tour) {
  const providerById = new Map((state.providers || []).map((provider) => [String(provider.id || "").trim(), provider]));
  const points = [];
  let missingProviders = 0;
  let missingLocations = 0;

  (tour?.stops || []).forEach((stop) => {
    const providerId = String(stop?.providerId || "").trim();
    if (!providerId) {
      missingProviders += 1;
      return;
    }
    const provider = providerById.get(providerId);
    if (!provider) {
      missingProviders += 1;
      return;
    }
    const point = buildTourRoutePointFromProvider(provider, stop);
    if (!point) {
      missingLocations += 1;
      return;
    }
    points.push(point);
  });

  return {
    points,
    missingProviders,
    missingLocations,
    skippedCount: missingProviders + missingLocations,
  };
}

function formatTourRoutePointForMaps(point) {
  if (!point || typeof point !== "object") {
    return "";
  }
  const requestLocation = point.requestLocation;
  if (requestLocation && typeof requestLocation === "object") {
    const latitude = Number(requestLocation.lat);
    const longitude = Number(requestLocation.lng);
    if (Number.isFinite(latitude) && Number.isFinite(longitude)) {
      return `${latitude},${longitude}`;
    }
  }
  return String(point.locationLabel || point.providerName || "").trim();
}

function buildGoogleMapsTourUrl(points = []) {
  const locations = (Array.isArray(points) ? points : [])
    .map((point) => formatTourRoutePointForMaps(point))
    .filter(Boolean);
  if (!locations.length) {
    return "";
  }
  if (locations.length === 1) {
    const params = new URLSearchParams({
      api: "1",
      query: locations[0],
    });
    return `https://www.google.com/maps/search/?${params.toString()}`;
  }
  const params = new URLSearchParams({
    api: "1",
    origin: locations[0],
    destination: locations[locations.length - 1],
    travelmode: "driving",
  });
  const waypoints = locations.slice(1, -1).slice(0, 23);
  if (waypoints.length) {
    params.set("waypoints", waypoints.join("|"));
  }
  return `https://www.google.com/maps/dir/?${params.toString()}`;
}

function buildTelHref(phoneValue) {
  const rawValue = String(phoneValue || "").trim();
  if (!rawValue) {
    return "";
  }
  const normalizedValue = rawValue.replace(/[^0-9+]/g, "");
  const compactValue = normalizedValue.startsWith("+")
    ? `+${normalizedValue.slice(1).replace(/\+/g, "")}`
    : normalizedValue.replace(/\+/g, "");
  if (!compactValue || !/\d/.test(compactValue)) {
    return "";
  }
  return `tel:${compactValue}`;
}

function getPreferredTourCarStopIndex(selectedTour) {
  const stops = Array.isArray(selectedTour?.stops) ? selectedTour.stops : [];
  if (!stops.length) {
    return 0;
  }
  const nextOpenIndex = stops.findIndex((stop) => !String(stop?.doneAt || "").trim());
  return nextOpenIndex >= 0 ? nextOpenIndex : 0;
}

function syncTourCarStopIndex(selectedTour) {
  const tourId = String(selectedTour?.id || "").trim();
  const stops = Array.isArray(selectedTour?.stops) ? selectedTour.stops : [];
  if (!tourId || !stops.length) {
    tourCarActiveTourId = tourId;
    tourCarActiveStopIndex = 0;
    return;
  }
  if (tourCarActiveTourId !== tourId) {
    tourCarActiveTourId = tourId;
    tourCarActiveStopIndex = getPreferredTourCarStopIndex(selectedTour);
    return;
  }
  if (tourCarActiveStopIndex < 0 || tourCarActiveStopIndex >= stops.length) {
    tourCarActiveStopIndex = getPreferredTourCarStopIndex(selectedTour);
  }
}

function getTourCarActiveStopContext(selectedTour) {
  const stops = Array.isArray(selectedTour?.stops) ? selectedTour.stops : [];
  if (!selectedTour || !stops.length) {
    return null;
  }
  syncTourCarStopIndex(selectedTour);
  const index = Math.max(0, Math.min(stops.length - 1, Number(tourCarActiveStopIndex || 0)));
  const stop = stops[index];
  if (!stop) {
    return null;
  }
  return {
    stop,
    index,
    total: stops.length,
  };
}

function findNextOpenTourCarStopIndex(selectedTour, startIndex = 0) {
  const stops = Array.isArray(selectedTour?.stops) ? selectedTour.stops : [];
  if (!stops.length) {
    return -1;
  }
  const safeStartIndex = Math.max(0, Number(startIndex || 0));
  for (let index = safeStartIndex; index < stops.length; index += 1) {
    if (!String(stops[index]?.doneAt || "").trim()) {
      return index;
    }
  }
  return -1;
}

function stepTourCarStop(direction = 1) {
  const selectedTour = getSelectedTourForCurrentUser();
  const activeStopContext = getTourCarActiveStopContext(selectedTour);
  if (!selectedTour || !activeStopContext) {
    return;
  }
  const delta = Number(direction) < 0 ? -1 : 1;
  const nextIndex = Math.max(0, Math.min(activeStopContext.total - 1, activeStopContext.index + delta));
  if (nextIndex === activeStopContext.index) {
    return;
  }
  tourCarActiveStopIndex = nextIndex;
  renderToursSection();
}

function renderTourMobileQuickView(selectedTour) {
  if (
    !els.tourMobileQuick ||
    !els.tourMobileTitle ||
    !els.tourMobileMeta ||
    !els.tourMobileNextStop ||
    !els.tourMobileOpenMapsBtn
  ) {
    return;
  }
  if (!selectedTour) {
    els.tourMobileQuick.classList.add("hidden");
    return;
  }

  const stopCount = Array.isArray(selectedTour.stops) ? selectedTour.stops.length : 0;
  const assigneeName = getTourAssigneeNameByUserId(selectedTour.assigneeUserId, selectedTour.assigneeName);
  els.tourMobileTitle.textContent = String(selectedTour.name || "Tour").trim();
  const providerById = new Map((state.providers || []).map((provider) => [String(provider.id || "").trim(), provider]));
  const activeStopContext = getTourCarActiveStopContext(selectedTour);
  if (activeStopContext) {
    const provider = providerById.get(String(activeStopContext.stop.providerId || "").trim());
    const providerName = String(provider?.name || activeStopContext.stop.providerId || "Anbieter").trim();
    const locationLabel = provider ? buildTourRouteLocationLabel(resolveTourProviderPrimaryLocation(provider)) : "";
    const isDone = Boolean(String(activeStopContext.stop.doneAt || "").trim());
    const statusLabel = isDone ? "Erledigt" : "Offen";
    els.tourMobileMeta.textContent = `Stopp ${activeStopContext.index + 1}/${activeStopContext.total} · ${statusLabel} · ${assigneeName}`;
    els.tourMobileNextStop.textContent = locationLabel ? `${providerName} · ${locationLabel}` : providerName;

    const routePoint = provider ? buildTourRoutePointFromProvider(provider, activeStopContext.stop) : null;
    const mapsUrl = routePoint ? buildGoogleMapsTourUrl([routePoint]) : "";
    if (mapsUrl) {
      els.tourMobileOpenMapsBtn.href = mapsUrl;
      els.tourMobileOpenMapsBtn.classList.remove("is-disabled");
      els.tourMobileOpenMapsBtn.removeAttribute("aria-disabled");
    } else {
      els.tourMobileOpenMapsBtn.href = "#";
      els.tourMobileOpenMapsBtn.classList.add("is-disabled");
      els.tourMobileOpenMapsBtn.setAttribute("aria-disabled", "true");
    }

    if (els.tourMobileCallBtn) {
      const telHref = buildTelHref(provider?.phone || "");
      if (telHref) {
        els.tourMobileCallBtn.href = telHref;
        els.tourMobileCallBtn.classList.remove("is-disabled");
        els.tourMobileCallBtn.removeAttribute("aria-disabled");
      } else {
        els.tourMobileCallBtn.href = "#";
        els.tourMobileCallBtn.classList.add("is-disabled");
        els.tourMobileCallBtn.setAttribute("aria-disabled", "true");
      }
    }

    if (els.tourMobileCompleteBtn) {
      els.tourMobileCompleteBtn.textContent = isDone ? "Stopp öffnen" : "Stopp erledigt";
      els.tourMobileCompleteBtn.classList.toggle("is-done", isDone);
      els.tourMobileCompleteBtn.disabled = !canCurrentUserEditTour(selectedTour);
    }

    if (els.tourMobilePrevBtn) {
      els.tourMobilePrevBtn.disabled = activeStopContext.index <= 0;
    }
    if (els.tourMobileNextBtn) {
      els.tourMobileNextBtn.disabled = activeStopContext.index >= activeStopContext.total - 1;
    }
  } else {
    els.tourMobileMeta.textContent = `${formatTourDateLabel(selectedTour.plannedDate)} · ${assigneeName} · ${stopCount} ${
      stopCount === 1 ? "Stop" : "Stops"
    }`;
    els.tourMobileNextStop.textContent = "Noch keine Stopps.";
    els.tourMobileOpenMapsBtn.href = "#";
    els.tourMobileOpenMapsBtn.classList.add("is-disabled");
    els.tourMobileOpenMapsBtn.setAttribute("aria-disabled", "true");
    if (els.tourMobileCallBtn) {
      els.tourMobileCallBtn.href = "#";
      els.tourMobileCallBtn.classList.add("is-disabled");
      els.tourMobileCallBtn.setAttribute("aria-disabled", "true");
    }
    if (els.tourMobileCompleteBtn) {
      els.tourMobileCompleteBtn.textContent = "Stopp erledigt";
      els.tourMobileCompleteBtn.classList.remove("is-done");
      els.tourMobileCompleteBtn.disabled = true;
    }
    if (els.tourMobilePrevBtn) {
      els.tourMobilePrevBtn.disabled = true;
    }
    if (els.tourMobileNextBtn) {
      els.tourMobileNextBtn.disabled = true;
    }
  }

  els.tourMobileQuick.classList.remove("hidden");
}

function normalizeTourMobileViewMode(mode) {
  const normalizedMode = String(mode || "").trim().toLowerCase();
  if (normalizedMode === "map" || normalizedMode === "stops") {
    return normalizedMode;
  }
  return "stops";
}

function isTourMobileViewport() {
  return window.matchMedia("(max-width: 980px)").matches;
}

function renderTourMobileViewSwitch(selectedTour) {
  if (
    !els.tourRouteLayout ||
    !els.tourMobileViewSwitch ||
    !els.tourMobileViewMapBtn ||
    !els.tourMobileViewStopsBtn
  ) {
    return {
      mobileActive: false,
      viewMode: normalizeTourMobileViewMode(tourMobileViewMode),
    };
  }
  const stopCount = Array.isArray(selectedTour?.stops) ? selectedTour.stops.length : 0;
  if (els.tourMobileViewStopsCount) {
    els.tourMobileViewStopsCount.textContent = String(stopCount);
  }

  const mobileActive = !!selectedTour && isTourMobileViewport();
  els.tourMobileViewSwitch.classList.toggle("hidden", !mobileActive);
  els.tourRouteLayout.classList.remove("is-mobile-map", "is-mobile-stops", "is-mobile-car");
  els.tourPlannerSection?.classList.remove("is-mobile-car-focus");
  if (!mobileActive) {
    return {
      mobileActive: false,
      viewMode: normalizeTourMobileViewMode(tourMobileViewMode),
    };
  }

  const viewMode = normalizeTourMobileViewMode(tourMobileViewMode);
  const carMode = viewMode === "map";
  els.tourRouteLayout.classList.add(carMode ? "is-mobile-car" : "is-mobile-stops");
  els.tourPlannerSection?.classList.toggle("is-mobile-car-focus", carMode);
  els.tourMobileViewMapBtn.classList.toggle("is-active", viewMode === "map");
  els.tourMobileViewStopsBtn.classList.toggle("is-active", viewMode === "stops");
  els.tourMobileViewMapBtn.setAttribute("aria-pressed", viewMode === "map" ? "true" : "false");
  els.tourMobileViewStopsBtn.setAttribute("aria-pressed", viewMode === "stops" ? "true" : "false");

  return {
    mobileActive: true,
    viewMode,
  };
}

function setTourMobileViewMode(mode) {
  tourMobileViewMode = normalizeTourMobileViewMode(mode);
  const selectedTour = getSelectedTourForCurrentUser();
  const mobileViewState = renderTourMobileViewSwitch(selectedTour);
  if (!selectedTour) {
    return;
  }
  if (mobileViewState.mobileActive) {
    renderToursSection();
    return;
  }
  renderTourRouteMap(selectedTour, { forceRecenter: true });
}

function clearTourRouteMapMarkers() {
  tourRouteMapMarkers.forEach((marker) => marker.setMap(null));
  tourRouteMapInfoWindows.forEach((infoWindow) => infoWindow.close());
  tourRouteMapMarkers = [];
  tourRouteMapInfoWindows = [];
}

function resetTourRouteRenderer() {
  if (!window.google?.maps || !tourRouteMap) {
    return;
  }
  clearTourRouteMapMarkers();
  if (tourRouteDirectionsRenderer) {
    tourRouteDirectionsRenderer.setMap(null);
  }
  tourRouteDirectionsRenderer = new window.google.maps.DirectionsRenderer({
    map: tourRouteMap,
    suppressMarkers: true,
    preserveViewport: false,
    polylineOptions: {
      strokeColor: "#1f5da8",
      strokeOpacity: 0.86,
      strokeWeight: 5,
    },
  });
}

function ensureTourRouteMapReady() {
  if (!isTourPlannerViewVisible()) {
    return false;
  }
  if (!els.tourRouteMapCanvas) {
    return false;
  }
  if (!els.tourRouteMapCanvas.getClientRects().length) {
    return false;
  }
  if (!googleMapsReady || !window.google?.maps) {
    return false;
  }

  if (!tourRouteMap) {
    tourRouteMap = new window.google.maps.Map(els.tourRouteMapCanvas, {
      center: { lat: 48.2082, lng: 16.3738 },
      zoom: 7,
      mapTypeControl: false,
      streetViewControl: false,
      fullscreenControl: true,
    });
  }
  if (!tourRouteDirectionsService) {
    tourRouteDirectionsService = new window.google.maps.DirectionsService();
  }
  if (!tourRouteDirectionsRenderer) {
    resetTourRouteRenderer();
  }
  return true;
}

function getTourDirectionsStatusMessage(status) {
  const normalizedStatus = String(status || "").trim().toUpperCase();
  if (normalizedStatus === "NOT_FOUND") {
    return "Ein Stopp wurde nicht gefunden.";
  }
  if (normalizedStatus === "ZERO_RESULTS") {
    return "Keine Route gefunden.";
  }
  if (normalizedStatus === "MAX_WAYPOINTS_EXCEEDED") {
    return "Zu viele Stopps für eine Route.";
  }
  if (normalizedStatus === "OVER_QUERY_LIMIT") {
    return "Karten-Limit erreicht. Kurz warten.";
  }
  if (normalizedStatus === "REQUEST_DENIED") {
    return "Kartenanfrage abgelehnt.";
  }
  return `Route fehlgeschlagen (${normalizedStatus || "UNKNOWN"}).`;
}

function getTourRouteMarkerPositionFromLegs(points, legs, index) {
  if (Array.isArray(legs) && legs.length) {
    if (index === 0) {
      return legs[0]?.start_location || null;
    }
    return legs[index - 1]?.end_location || null;
  }
  const point = points[index];
  if (point && typeof point.requestLocation === "object") {
    return point.requestLocation;
  }
  return null;
}

function renderTourRouteNumberedMarkers(points, legs) {
  if (!tourRouteMap || !window.google?.maps) {
    return;
  }
  clearTourRouteMapMarkers();
  const rows = Array.isArray(points) ? points : [];
  if (!rows.length) {
    return;
  }

  rows.forEach((point, index) => {
    const position = getTourRouteMarkerPositionFromLegs(rows, legs, index);
    if (!position) {
      return;
    }

    const markerNumber = String(index + 1);
    const isStart = index === 0;
    const isEnd = index === rows.length - 1;
    const fillColor = isStart ? "#1c7f47" : isEnd ? "#b4232f" : "#1f5da8";
    const providerName = String(point.providerName || "Anbieter").trim();
    const locationLabel = String(point.locationLabel || "").trim();
    const title = `${markerNumber}. ${providerName}`;
    const marker = new window.google.maps.Marker({
      map: tourRouteMap,
      position,
      title,
      label: {
        text: markerNumber,
        color: "#ffffff",
        fontSize: "11px",
        fontWeight: "700",
      },
      icon: {
        path: window.google.maps.SymbolPath.CIRCLE,
        scale: 12,
        fillColor,
        fillOpacity: 0.98,
        strokeColor: "#ffffff",
        strokeWeight: 2,
      },
      zIndex: 100 + index,
    });
    const infoWindow = new window.google.maps.InfoWindow({
      content: `
        <div style="font-family: Sora, sans-serif; max-width: min(300px, calc(100vw - 120px)); overflow-wrap: anywhere;">
          <strong>${escapeHtml(title)}</strong><br/>
          <span>${escapeHtml(locationLabel || "Standort unbekannt")}</span>
        </div>
      `,
    });
    marker.addListener("click", () => {
      infoWindow.open({ anchor: marker, map: tourRouteMap });
    });
    tourRouteMapMarkers.push(marker);
    tourRouteMapInfoWindows.push(infoWindow);
  });
}

function renderTourRouteMap(selectedTour, options = {}) {
  if (!els.tourRouteMapCanvas || !els.tourRouteMapStatus) {
    return;
  }
  if (!isTourPlannerViewVisible()) {
    return;
  }

  const forceRecenter = !!options.forceRecenter;
  if (!selectedTour) {
    clearTourRouteMapStats();
    clearTourRouteMapLegend();
    clearTourRouteMapMarkers();
    setTourRouteMapStatus("Tour wählen.", "warning");
    return;
  }

  if (!googleMapsReady || !window.google?.maps) {
    clearTourRouteMapStats();
    clearTourRouteMapLegend();
    clearTourRouteMapMarkers();
    setTourRouteMapStatus(
      googlePlacesLoadError || "Karte lädt...",
      "warning"
    );
    return;
  }

  if (!ensureTourRouteMapReady()) {
    clearTourRouteMapStats();
    clearTourRouteMapLegend();
    clearTourRouteMapMarkers();
    setTourRouteMapStatus("Karte nicht verfügbar.", "error");
    return;
  }

  const { points, skippedCount } = getTourRoutePoints(selectedTour);
  renderTourRouteMapLegend(points);
  if (forceRecenter && tourRouteMap) {
    window.google.maps.event.trigger(tourRouteMap, "resize");
  }
  if (points.length < 2) {
    clearTourRouteMapStats();
    clearTourRouteMapMarkers();
    if (points.length === 1) {
      const onlyPoint = points[0];
      if (tourRouteMap && typeof onlyPoint.requestLocation === "object") {
        tourRouteMap.setCenter(onlyPoint.requestLocation);
        tourRouteMap.setZoom(11);
      }
      setTourRouteMapStatus(
        "Mind. 2 Stopps für Route.",
        "warning"
      );
    } else {
      setTourRouteMapStatus(
        "Kein gültiger Standort.",
        "warning"
      );
    }
    resetTourRouteRenderer();
    return;
  }

  const routeSignature = buildTourRouteMetricsSignature(selectedTour, points, skippedCount);
  const directionsRequest = buildTourRouteDirectionsRequest(points);
  if (!directionsRequest) {
    clearTourRouteMapStats();
    clearTourRouteMapMarkers();
    setTourRouteMapStatus("Route nicht möglich.", "warning");
    resetTourRouteRenderer();
    return;
  }

  const requestId = ++tourRouteRenderRequestId;
  setTourRouteMapStatus("Route wird berechnet...", "info");

  tourRouteDirectionsService.route(
    directionsRequest,
    (result, status) => {
      if (requestId !== tourRouteRenderRequestId) {
        return;
      }
      if (status !== "OK" || !result?.routes?.length) {
        clearTourRouteMapStats();
        clearTourRouteMapMarkers();
        setTourRouteMapStatus(getTourDirectionsStatusMessage(status), "error");
        resetTourRouteRenderer();
        return;
      }

      tourRouteDirectionsRenderer.setDirections(result);
      const legs = result.routes[0]?.legs || [];
      renderTourRouteNumberedMarkers(points, legs);
      const routeMetrics = buildTourRouteMetricsFromGoogleRoute(
        result.routes[0],
        points,
        skippedCount,
        Array.isArray(selectedTour?.stops) ? selectedTour.stops.length : 0
      );
      cacheTourRouteMetrics(routeSignature, routeMetrics);
      renderTourRouteMapStats(routeMetrics);
      if (!routeMetrics.verified) {
        setTourRouteMapStatus(
          "Routenwerte prüfen.",
          "warning"
        );
        return;
      }
      setTourRouteMapStatus(null);
    }
  );
}

function renderToursSection(options = {}) {
  if (!els.tourSelectInput || !els.tourProviderPicker || !els.tourStopList) {
    return;
  }
  const forceRecenter = !!options.forceRecenter;

  if (els.tourDateInput && !els.tourDateInput.value) {
    els.tourDateInput.value = getTodayDateInputValue();
  }
  upsertTourAssigneeSelectOptions(els.tourAssigneeSelect, els.tourAssigneeSelect?.value || getCurrentSalesUserId());

  const visibleTours = getVisibleToursForCurrentUser();
  ensureSelectedTour(visibleTours);
  const selectedTour = getSelectedTourForCurrentUser();
  const selectedTourCanEdit = selectedTour ? canCurrentUserEditTour(selectedTour) : false;

  if (activeTourModal && !["create", "detail", "providers"].includes(activeTourModal)) {
    closeTourModals();
  }
  if (activeTourModal && activeTourModal !== "create" && !selectedTour) {
    closeTourModals();
  }
  if (activeTourModal && ["detail", "providers"].includes(activeTourModal) && !selectedTourCanEdit) {
    closeTourModals();
  }

  renderTourSelect(visibleTours, selectedTour);
  renderTourMobileTourList(visibleTours, selectedTour);
  renderTourSelectedSummary(selectedTour);
  renderTourDetailPanel(selectedTour);
  renderTourKpiStrip(selectedTour);
  renderTourMobileQuickView(selectedTour);
  renderTourProviderPicker(selectedTour);
  renderTourStopList(selectedTour);
  const mobileViewState = renderTourMobileViewSwitch(selectedTour);
  const shouldRenderRouteMap = !mobileViewState.mobileActive;
  if (shouldRenderRouteMap) {
    renderTourRouteMap(selectedTour, { forceRecenter });
  } else {
    setTourRouteMapStatus(null);
  }
}

function getTimestampMs(value) {
  const timestamp = new Date(String(value || "").trim()).getTime();
  return Number.isFinite(timestamp) ? timestamp : 0;
}

function getDateStart(dateLike) {
  const baseDate = dateLike instanceof Date ? new Date(dateLike.getTime()) : new Date();
  baseDate.setHours(0, 0, 0, 0);
  return baseDate;
}

function getSalesDashboardWeekdayLabel(date) {
  return new Intl.DateTimeFormat("de-AT", { weekday: "short" }).format(date).replace(".", "");
}

function buildSalesDashboardModel() {
  const visibleTours = getVisibleToursForCurrentUser();
  const salesPhoneCalls = getSalesPhoneCalls();
  const providerById = new Map((state.providers || []).map((provider) => [String(provider?.id || "").trim(), provider]));
  const todayStart = getDateStart(new Date());
  const todayStartTs = todayStart.getTime();
  const statusPriority = {
    offen: 0,
    "in Bearbeitung": 1,
    erfasst: 2,
    live: 3,
  };

  const tours = visibleTours
    .map((tour) => {
      const plannedDate = parseDateInputStart(tour?.plannedDate || "");
      const plannedDateTs = plannedDate ? plannedDate.getTime() : Number.MAX_SAFE_INTEGER;
      const canEdit = canCurrentUserEditTour(tour);
      const stops = (Array.isArray(tour?.stops) ? tour.stops : []).map((stop, stopIndex) => {
        const providerId = String(stop?.providerId || "").trim();
        const provider = providerById.get(providerId) || null;
        const providerStatus = normalizeProviderStatusValue(provider?.status || "offen");
        const addedAt = String(stop?.addedAt || tour?.updatedAt || tour?.createdAt || "").trim();
        const doneAt = String(stop?.doneAt || "").trim();
        const addedAtTs = getTimestampMs(addedAt);
        const doneAtTs = getTimestampMs(doneAt);
        const isDone = Boolean(doneAt);
        const locationLabel = [provider?.city, provider?.state, provider?.country]
          .map((entry) => String(entry || "").trim())
          .filter(Boolean)
          .join(", ");
        return {
          id: String(stop?.id || "").trim() || `${tour?.id || "tour"}::${providerId || stopIndex}`,
          providerId,
          providerName: String(provider?.name || `Anbieter ${stopIndex + 1}`).trim(),
          providerStatus,
          providerStatusLabel: getSalesLeadStatusLabel(providerStatus),
          addedAt,
          addedAtTs,
          doneAt,
          doneAtTs,
          isDone,
          stopIndex,
          hasProvider: !!provider,
          hasContact: Boolean(String(provider?.phone || "").trim() || String(provider?.email || "").trim()),
          locationLabel: locationLabel || "ohne Ort",
          canMarkDone: canEdit && !isDone,
        };
      });
      const doneStops = stops.filter((stop) => stop.isDone).length;
      const totalStops = stops.length;
      const openStops = Math.max(0, totalStops - doneStops);
      const overdue = Boolean(plannedDate && plannedDateTs < todayStartTs && openStops > 0);
      return {
        id: String(tour?.id || "").trim(),
        name: String(tour?.name || "Tour").trim(),
        plannedDate: String(tour?.plannedDate || "").trim(),
        plannedDateTs,
        plannedDateLabel: formatTourDateLabel(tour?.plannedDate),
        stops,
        totalStops,
        doneStops,
        openStops,
        completionRate: totalStops ? Math.round((doneStops / totalStops) * 100) : 0,
        overdue,
      };
    })
    .sort((left, right) => {
      if (left.plannedDateTs !== right.plannedDateTs) {
        return left.plannedDateTs - right.plannedDateTs;
      }
      return String(left.name || "").localeCompare(String(right.name || ""), "de", { sensitivity: "base" });
    });

  const totals = {
    tours: tours.length,
    stops: 0,
    done: 0,
    open: 0,
    overdueTours: 0,
    completionRate: 0,
  };
  const statusCounts = {
    offen: 0,
    inBearbeitung: 0,
    erfasst: 0,
    live: 0,
    missing: 0,
  };
  const unresolvedStops = [];
  const riskRows = [];
  const riskKeys = new Set();
  const pushRisk = (risk) => {
    const key = String(risk?.key || "").trim();
    if (!key || riskKeys.has(key)) {
      return;
    }
    riskKeys.add(key);
    riskRows.push(risk);
  };

  tours.forEach((tour) => {
    totals.stops += tour.totalStops;
    totals.done += tour.doneStops;
    totals.open += tour.openStops;
    if (tour.overdue) {
      totals.overdueTours += 1;
      pushRisk({
        key: `tour-overdue:${tour.id}`,
        tone: "high",
        weight: 300 + tour.openStops,
        label: `${tour.name}: ${tour.openStops} offen`,
        meta: `Überfällig seit ${tour.plannedDateLabel}`,
      });
    }
    tour.stops.forEach((stop) => {
      if (!stop.hasProvider) {
        statusCounts.missing += 1;
      }
      if (stop.providerStatus === "in Bearbeitung") {
        statusCounts.inBearbeitung += 1;
      } else if (stop.providerStatus === "erfasst") {
        statusCounts.erfasst += 1;
      } else if (stop.providerStatus === "live") {
        statusCounts.live += 1;
      } else {
        statusCounts.offen += 1;
      }
      if (stop.isDone) {
        return;
      }
      unresolvedStops.push({
        ...stop,
        tourId: tour.id,
        tourName: tour.name,
        tourPlannedDate: tour.plannedDate,
        tourPlannedDateTs: tour.plannedDateTs,
        tourPlannedDateLabel: tour.plannedDateLabel,
        tourOverdue: tour.overdue,
        statusPriority: Object.prototype.hasOwnProperty.call(statusPriority, stop.providerStatus)
          ? statusPriority[stop.providerStatus]
          : 10,
      });

      if (!stop.hasContact) {
        pushRisk({
          key: `stop-contact:${tour.id}:${stop.id}`,
          tone: "medium",
          weight: 180,
          label: `${stop.providerName}: kein Telefon/E-Mail`,
          meta: `${tour.name} · ${tour.plannedDateLabel}`,
        });
      }
      const openAgeDays = stop.addedAtTs ? Math.floor((todayStartTs - stop.addedAtTs) / 86400000) : 0;
      if (openAgeDays >= 3 && stop.providerStatus !== "live") {
        pushRisk({
          key: `stop-stale:${tour.id}:${stop.id}`,
          tone: "high",
          weight: 200 + openAgeDays,
          label: `${stop.providerName}: ${openAgeDays} Tage offen`,
          meta: `${tour.name} · Status ${stop.providerStatusLabel}`,
        });
      }
    });
  });
  totals.completionRate = totals.stops ? Math.round((totals.done / totals.stops) * 100) : 0;

  unresolvedStops.sort((left, right) => {
    if (left.tourOverdue !== right.tourOverdue) {
      return left.tourOverdue ? -1 : 1;
    }
    if (left.tourPlannedDateTs !== right.tourPlannedDateTs) {
      return left.tourPlannedDateTs - right.tourPlannedDateTs;
    }
    if (left.statusPriority !== right.statusPriority) {
      return left.statusPriority - right.statusPriority;
    }
    if (left.addedAtTs && right.addedAtTs && left.addedAtTs !== right.addedAtTs) {
      return left.addedAtTs - right.addedAtTs;
    }
    return left.stopIndex - right.stopIndex;
  });

  const weekRows = [];
  for (let dayOffset = 6; dayOffset >= 0; dayOffset -= 1) {
    const dayDate = new Date(todayStart.getTime());
    dayDate.setDate(todayStart.getDate() - dayOffset);
    weekRows.push({
      key: toDateInputValue(dayDate),
      label: getSalesDashboardWeekdayLabel(dayDate),
      count: 0,
    });
  }
  const weekCountByDate = new Map(weekRows.map((row) => [row.key, row]));
  tours.forEach((tour) => {
    tour.stops.forEach((stop) => {
      if (!stop.doneAtTs) {
        return;
      }
      const dateKey = toDateInputValue(new Date(stop.doneAtTs));
      const target = weekCountByDate.get(dateKey);
      if (!target) {
        return;
      }
      target.count += 1;
    });
  });
  const weekDone = weekRows.reduce((sum, row) => sum + row.count, 0);
  const weekMax = Math.max(...weekRows.map((row) => row.count), 0);
  const weekStart = getStartOfWeek(todayStart);
  const weekStartLabel = new Intl.DateTimeFormat("de-AT", { day: "2-digit", month: "2-digit" }).format(weekStart);

  const severityRank = {
    high: 0,
    medium: 1,
    low: 2,
  };
  const orderedRiskRows = riskRows
    .slice()
    .sort((left, right) => {
      const leftRank = Object.prototype.hasOwnProperty.call(severityRank, left.tone)
        ? severityRank[left.tone]
        : 99;
      const rightRank = Object.prototype.hasOwnProperty.call(severityRank, right.tone)
        ? severityRank[right.tone]
        : 99;
      if (leftRank !== rightRank) {
        return leftRank - rightRank;
      }
      if ((right.weight || 0) !== (left.weight || 0)) {
        return (right.weight || 0) - (left.weight || 0);
      }
      return String(left.label || "").localeCompare(String(right.label || ""), "de", { sensitivity: "base" });
    })
    .slice(0, 7);

  const phoneRows = salesPhoneCalls
    .filter((entry) => !isSalesPhoneStatusFinal(entry?.status))
    .map((entry) => {
      const provider = getSalesPhoneProviderById(entry?.providerId);
      const providerName = String(provider?.name || entry?.providerName || "Anbieter").trim();
      const plannedDateLabel = entry?.plannedDate ? formatTourDateLabel(entry.plannedDate) : "ohne Datum";
      const assigneeName = String(entry?.assigneeName || getUserDisplayNameByUserId(entry?.assigneeUserId) || "Unbekannt").trim();
      const status = sanitizeSalesPhoneStatus(entry?.status);
      const reminderState = getSalesPhoneReminderState(entry?.reminderAt);
      const openTasks = (Array.isArray(entry?.tasks) ? entry.tasks : []).filter(
        (task) => sanitizeSalesPhoneTaskStatus(task?.status) !== "erledigt"
      ).length;
      const plannedDateSort = sanitizeEmployeeAdminDate(entry?.plannedDate || "");
      return {
        id: String(entry?.id || "").trim(),
        providerName,
        plannedDateLabel,
        assigneeName,
        status,
        statusLabel: getSalesPhoneStatusLabel(status),
        reminderState,
        reminderLabel: entry?.reminderAt ? formatDateTime(entry.reminderAt) : "kein Reminder",
        openTasks,
        plannedDateSort,
        updatedAt: String(entry?.updatedAt || "").trim(),
      };
    })
    .filter((entry) => !!entry.id)
    .sort((left, right) => {
      if (left.plannedDateSort !== right.plannedDateSort) {
        if (!left.plannedDateSort) {
          return 1;
        }
        if (!right.plannedDateSort) {
          return -1;
        }
        return left.plannedDateSort.localeCompare(right.plannedDateSort);
      }
      return String(right.updatedAt || "").localeCompare(String(left.updatedAt || ""));
    });

  const phoneEmployeeMap = new Map();
  state.users
    .filter((entry) => entry.source === "profile" && isUserStatusActive(entry.status))
    .forEach((entry) => {
      const assigneeUserId = normalizeUserId(entry.sourceId || "");
      if (!assigneeUserId) {
        return;
      }
      phoneEmployeeMap.set(assigneeUserId, {
        assigneeUserId,
        name: String(entry.name || entry.email || "Unbekannt").trim(),
        role: normalizeUserRole(entry.role),
        planned: 0,
        inProgress: 0,
        done: 0,
        total: 0,
      });
    });

  const plannedPhoneStatuses = new Set(["neu", "nicht_erreicht", "mailbox"]);
  const inProgressPhoneStatuses = new Set(["rueckruf", "erreicht", "interessiert", "angebot_gesendet", "termin_vereinbart"]);
  salesPhoneCalls.forEach((entry) => {
    const status = sanitizeSalesPhoneStatus(entry?.status);
    const assigneeUserId = normalizeUserId(entry?.assigneeUserId || "");
    const mapKey = assigneeUserId || "__unassigned__";
    const existing = phoneEmployeeMap.get(mapKey);
    const row = existing || {
      assigneeUserId: mapKey,
      name: assigneeUserId
        ? String(entry?.assigneeName || getUserDisplayNameByUserId(assigneeUserId) || "Unbekannt").trim()
        : "Nicht zugewiesen",
      role: assigneeUserId
        ? normalizeUserRole(
            state.users.find(
              (userEntry) => userEntry.source === "profile" && normalizeUserId(userEntry.sourceId || "") === assigneeUserId
            )?.role || ""
          )
        : "",
      planned: 0,
      inProgress: 0,
      done: 0,
      total: 0,
    };
    row.total += 1;
    if (plannedPhoneStatuses.has(status)) {
      row.planned += 1;
    } else if (inProgressPhoneStatuses.has(status)) {
      row.inProgress += 1;
    } else if (isSalesPhoneStatusFinal(status)) {
      row.done += 1;
    } else {
      row.inProgress += 1;
    }
    phoneEmployeeMap.set(mapKey, row);
  });
  const phoneEmployeeRows = Array.from(phoneEmployeeMap.values()).sort((left, right) => {
    if (right.total !== left.total) {
      return right.total - left.total;
    }
    return String(left.name || "").localeCompare(String(right.name || ""), "de", { sensitivity: "base" });
  });

  return {
    tours,
    phoneRows,
    phoneEmployeeRows,
    totals,
    statusCounts,
    nextStop: unresolvedStops[0] || null,
    riskRows: orderedRiskRows,
    weekRows,
    weekDone,
    weekMax,
    weekStartLabel,
  };
}

function renderSalesDashboardKpis(model) {
  if (!els.salesDashboardKpis) {
    return;
  }
  const totals = model?.totals || {};
  const kpis = [
    { label: "Touren", value: totals.tours || 0, hint: "aktiv" },
    { label: "Stopps", value: totals.stops || 0, hint: "gesamt" },
    { label: "Offen", value: totals.open || 0, hint: "zu erledigen" },
    { label: "Erledigt", value: totals.done || 0, hint: "abgeschlossen" },
    { label: "Quote", value: `${totals.completionRate || 0}%`, hint: "Erledigungsrate" },
    { label: "Überfällig", value: totals.overdueTours || 0, hint: "Touren" },
  ];
  els.salesDashboardKpis.innerHTML = kpis
    .map(
      (entry) => `
        <article class="sales-dashboard-kpi">
          <span class="sales-dashboard-kpi-label">${escapeHtml(entry.label)}</span>
          <strong class="sales-dashboard-kpi-value">${escapeHtml(String(entry.value))}</strong>
          <small class="sales-dashboard-kpi-hint">${escapeHtml(entry.hint)}</small>
        </article>
      `
    )
    .join("");
}

function renderSalesDashboardNextAction(model) {
  if (!els.salesDashboardNextBody || !els.salesDashboardNextMeta) {
    return;
  }
  const nextStop = model?.nextStop || null;
  if (!nextStop) {
    els.salesDashboardNextMeta.textContent = "Keine offene Aktion";
    els.salesDashboardNextBody.innerHTML = '<p class="empty">Alle geplanten Stopps sind erledigt.</p>';
    return;
  }
  const openDays = nextStop.addedAtTs
    ? Math.max(0, Math.floor((getDateStart(new Date()).getTime() - nextStop.addedAtTs) / 86400000))
    : 0;
  const openLabel = openDays > 0 ? `${openDays} Tage offen` : "Heute hinzugefügt";
  const overdueMarkup = nextStop.tourOverdue ? '<span class="sales-dashboard-next-chip is-danger">Überfällig</span>' : "";
  const statusClass = getTourStatusCssClass(nextStop.providerStatus);
  const locationLabel = nextStop.locationLabel || "ohne Ort";

  els.salesDashboardNextMeta.textContent = `${nextStop.tourName} · ${nextStop.tourPlannedDateLabel}`;
  els.salesDashboardNextBody.innerHTML = `
    <article class="sales-dashboard-next-item">
      <strong>${escapeHtml(nextStop.providerName)}</strong>
      <p>${escapeHtml(locationLabel)}</p>
      <div class="sales-dashboard-next-chips">
        <span class="tour-status-pill ${statusClass}">${escapeHtml(nextStop.providerStatusLabel)}</span>
        <span class="sales-dashboard-next-chip">${escapeHtml(openLabel)}</span>
        ${overdueMarkup}
      </div>
      <div class="sales-dashboard-next-actions">
        <button
          type="button"
          class="btn btn-primary"
          data-sales-dashboard-action="open-tour"
          data-tour-id="${escapeHtml(nextStop.tourId)}"
        >Tour öffnen</button>
        <button
          type="button"
          class="btn btn-success"
          data-sales-dashboard-action="mark-done"
          data-tour-id="${escapeHtml(nextStop.tourId)}"
          data-stop-id="${escapeHtml(nextStop.id)}"
          ${nextStop.canMarkDone ? "" : "disabled"}
        >Erledigt</button>
      </div>
    </article>
  `;
}

function renderSalesDashboardTourList(model) {
  if (!els.salesDashboardTourList || !els.salesDashboardTourMeta) {
    return;
  }
  const tours = Array.isArray(model?.tours) ? model.tours : [];
  const totalOpen = Number(model?.totals?.open || 0);
  els.salesDashboardTourMeta.textContent = `${tours.length} Touren · ${totalOpen} offene Stopps`;

  if (!tours.length) {
    els.salesDashboardTourList.innerHTML = '<p class="empty">Noch keine Touren geplant.</p>';
    return;
  }
  els.salesDashboardTourList.innerHTML = tours
    .map((tour) => {
      const progressWidth = Math.max(0, Math.min(100, Number(tour.completionRate || 0)));
      return `
        <article class="sales-dashboard-tour-item ${tour.overdue ? "is-overdue" : ""}">
          <div class="sales-dashboard-tour-item-head">
            <strong>${escapeHtml(tour.name || "Tour")}</strong>
            <span>${escapeHtml(tour.plannedDateLabel)}</span>
          </div>
          <div class="sales-dashboard-tour-progress">
            <div class="sales-dashboard-progress-track" aria-hidden="true">
              <span style="width:${escapeHtml(String(progressWidth))}%"></span>
            </div>
            <small>${escapeHtml(String(tour.doneStops))}/${escapeHtml(String(tour.totalStops))} erledigt</small>
          </div>
          <div class="sales-dashboard-tour-item-foot">
            <span class="sales-dashboard-tour-flag ${tour.overdue ? "is-danger" : "is-ok"}">
              ${escapeHtml(tour.overdue ? "Überfällig" : "Plan")}
            </span>
            <button
              type="button"
              class="mini-btn"
              data-sales-dashboard-action="open-tour"
              data-tour-id="${escapeHtml(tour.id)}"
            >Öffnen</button>
          </div>
        </article>
      `;
    })
    .join("");
}

function renderSalesDashboardPhoneList(model) {
  if (!els.salesDashboardPhoneList || !els.salesDashboardPhoneMeta) {
    return;
  }
  const phoneRows = Array.isArray(model?.phoneRows) ? model.phoneRows : [];
  const followUpCount = phoneRows.filter((entry) => entry.status === "rueckruf").length;
  els.salesDashboardPhoneMeta.textContent = `${phoneRows.length} geplant · ${followUpCount} Rückruf`;
  if (!phoneRows.length) {
    els.salesDashboardPhoneList.innerHTML = '<p class="empty">Keine offenen Telefonakquise-Einträge.</p>';
    return;
  }
  els.salesDashboardPhoneList.innerHTML = phoneRows
    .slice(0, 7)
    .map((entry) => {
      const reminderClass = entry.reminderState ? `sales-dashboard-phone-reminder ${entry.reminderState}` : "sales-dashboard-phone-reminder";
      return `
        <article class="sales-dashboard-phone-item">
          <div class="sales-dashboard-phone-item-head">
            <strong>${escapeHtml(entry.providerName)}</strong>
            <span>${escapeHtml(entry.plannedDateLabel)}</span>
          </div>
          <div class="sales-dashboard-phone-item-meta">
            <span class="sales-phone-status ${getSalesPhoneStatusCssClass(entry.status)}">${escapeHtml(entry.statusLabel)}</span>
            <small>${escapeHtml(entry.assigneeName)} · Aufgaben: ${escapeHtml(String(entry.openTasks))}</small>
          </div>
          <div class="sales-dashboard-phone-item-foot">
            <small class="${escapeHtml(reminderClass)}">${escapeHtml(entry.reminderLabel)}</small>
            <button
              type="button"
              class="mini-btn sales-phone-open-btn"
              data-sales-dashboard-action="open-phone"
              data-call-id="${escapeHtml(entry.id)}"
            >Öffnen</button>
          </div>
        </article>
      `;
    })
    .join("");
}

function renderSalesDashboardPhoneTeamOverview(model) {
  if (!els.salesDashboardPhoneTeamBody || !els.salesDashboardPhoneTeamMeta) {
    return;
  }
  const rows = Array.isArray(model?.phoneEmployeeRows) ? model.phoneEmployeeRows : [];
  const totalPlanned = rows.reduce((sum, row) => sum + Number(row?.planned || 0), 0);
  const totalInProgress = rows.reduce((sum, row) => sum + Number(row?.inProgress || 0), 0);
  const totalDone = rows.reduce((sum, row) => sum + Number(row?.done || 0), 0);
  els.salesDashboardPhoneTeamMeta.textContent = `${rows.length} Mitarbeiter · Geplant ${totalPlanned} · In Arbeit ${totalInProgress} · Erledigt ${totalDone}`;
  if (!rows.length) {
    els.salesDashboardPhoneTeamBody.innerHTML = '<tr><td colspan="6" class="empty">Keine Telefonakquise-Daten vorhanden.</td></tr>';
    return;
  }
  els.salesDashboardPhoneTeamBody.innerHTML = rows
    .map((row) => {
      const roleLabel = row.assigneeUserId === "__unassigned__" ? "—" : getRoleLabel(row.role);
      return `
        <tr>
          <td>${escapeHtml(row.name || "Unbekannt")}</td>
          <td>${escapeHtml(roleLabel)}</td>
          <td>${escapeHtml(String(row.planned || 0))}</td>
          <td>${escapeHtml(String(row.inProgress || 0))}</td>
          <td>${escapeHtml(String(row.done || 0))}</td>
          <td><strong>${escapeHtml(String(row.total || 0))}</strong></td>
        </tr>
      `;
    })
    .join("");
}

function renderSalesDashboardStatusGrid(model) {
  if (!els.salesDashboardStatusGrid) {
    return;
  }
  const statusCounts = model?.statusCounts || {};
  const total = Number(model?.totals?.stops || 0);
  const statusRows = [
    { key: "offen", label: "Offen", count: Number(statusCounts.offen || 0), cssClass: "is-open" },
    {
      key: "inBearbeitung",
      label: "In Bearbeitung",
      count: Number(statusCounts.inBearbeitung || 0),
      cssClass: "is-progress",
    },
    { key: "erfasst", label: "Erfasst", count: Number(statusCounts.erfasst || 0), cssClass: "is-captured" },
    { key: "live", label: "Live", count: Number(statusCounts.live || 0), cssClass: "is-live" },
  ];
  els.salesDashboardStatusGrid.innerHTML = statusRows
    .map((row) => {
      const share = total ? Math.round((row.count / total) * 100) : 0;
      return `
        <article class="sales-dashboard-status-card ${row.cssClass}">
          <span>${escapeHtml(row.label)}</span>
          <strong>${escapeHtml(String(row.count))}</strong>
          <small>${escapeHtml(String(share))}%</small>
        </article>
      `;
    })
    .join("");
}

function renderSalesDashboardRiskList(model) {
  if (!els.salesDashboardRiskList || !els.salesDashboardRiskMeta) {
    return;
  }
  const riskRows = Array.isArray(model?.riskRows) ? model.riskRows : [];
  els.salesDashboardRiskMeta.textContent = `${riskRows.length} Hinweise`;
  if (!riskRows.length) {
    els.salesDashboardRiskList.innerHTML = '<li class="empty">Keine offenen Risiken.</li>';
    return;
  }
  els.salesDashboardRiskList.innerHTML = riskRows
    .map(
      (risk) => `
        <li class="sales-dashboard-risk-item ${risk?.tone === "high" ? "is-high" : "is-medium"}">
          <strong>${escapeHtml(String(risk?.label || "Hinweis"))}</strong>
          <span>${escapeHtml(String(risk?.meta || ""))}</span>
        </li>
      `
    )
    .join("");
}

function renderSalesDashboardWeekBars(model) {
  if (!els.salesDashboardWeekBars || !els.salesDashboardWeekMeta) {
    return;
  }
  const weekRows = Array.isArray(model?.weekRows) ? model.weekRows : [];
  const maxCount = Number(model?.weekMax || 0);
  const weekDone = Number(model?.weekDone || 0);
  const weekStartLabel = String(model?.weekStartLabel || "").trim();
  els.salesDashboardWeekMeta.textContent = `${weekDone} erledigt seit ${weekStartLabel || "Wochenstart"}`;
  if (!weekRows.length) {
    els.salesDashboardWeekBars.innerHTML = '<p class="empty">Keine Wochenwerte vorhanden.</p>';
    return;
  }
  els.salesDashboardWeekBars.innerHTML = weekRows
    .map((row) => {
      const count = Number(row?.count || 0);
      const width = maxCount > 0 && count > 0 ? Math.max(12, Math.round((count / maxCount) * 100)) : 0;
      return `
        <div class="sales-dashboard-week-row">
          <span>${escapeHtml(String(row?.label || ""))}</span>
          <div class="sales-dashboard-week-track">
            <span class="sales-dashboard-week-fill" style="width:${escapeHtml(String(width))}%"></span>
          </div>
          <strong>${escapeHtml(String(count))}</strong>
        </div>
      `;
    })
    .join("");
}

function renderSalesDashboardSection() {
  if (
    !els.salesDashboardKpis ||
    !els.salesDashboardNextMeta ||
    !els.salesDashboardNextBody ||
    !els.salesDashboardTourMeta ||
    !els.salesDashboardTourList ||
    !els.salesDashboardPhoneMeta ||
    !els.salesDashboardPhoneList ||
    !els.salesDashboardStatusGrid ||
    !els.salesDashboardRiskMeta ||
    !els.salesDashboardRiskList ||
    !els.salesDashboardWeekMeta ||
    !els.salesDashboardWeekBars ||
    !els.salesDashboardPhoneTeamMeta ||
    !els.salesDashboardPhoneTeamBody
  ) {
    return;
  }
  setSalesDashboardTab(salesDashboardTab, { render: false });
  const model = buildSalesDashboardModel();
  renderSalesDashboardKpis(model);
  renderSalesDashboardNextAction(model);
  renderSalesDashboardTourList(model);
  renderSalesDashboardPhoneList(model);
  renderSalesDashboardPhoneTeamOverview(model);
  renderSalesDashboardStatusGrid(model);
  renderSalesDashboardRiskList(model);
  renderSalesDashboardWeekBars(model);
}

function normalizeSalesLeadsDateInputValue(value) {
  const normalizedValue = String(value || "").trim();
  return parseDateInputStart(normalizedValue) ? normalizedValue : "";
}

function normalizeSalesLeadsEmployeeFilterValue(value) {
  const normalizedValue = String(value || "").trim();
  if (!normalizedValue || normalizeText(normalizedValue) === "all") {
    return "all";
  }
  return normalizedValue;
}

function normalizeSalesLeadsStatusFilterValue(value) {
  const rawValue = String(value || "").trim();
  if (!rawValue || normalizeText(rawValue) === "all") {
    return "all";
  }
  const normalizedValue = normalizeProviderStatusValue(rawValue);
  if (["offen", "in Bearbeitung", "erfasst", "live"].includes(normalizedValue)) {
    return normalizedValue;
  }
  return "all";
}

function getSalesLeadStatusLabel(status) {
  const normalizedValue = normalizeProviderStatusValue(status);
  if (normalizedValue === "in Bearbeitung") {
    return "In Bearbeitung";
  }
  if (normalizedValue === "erfasst") {
    return "Erfasst";
  }
  if (normalizedValue === "live") {
    return "Live";
  }
  return "Offen";
}

function normalizeSalesDashboardTab(value) {
  const normalized = String(value || "").trim().toLowerCase();
  if (["tour", "phone"].includes(normalized)) {
    return normalized;
  }
  return "tour";
}

function setSalesDashboardTab(nextTab, options = {}) {
  salesDashboardTab = normalizeSalesDashboardTab(nextTab);
  const activeTab = salesDashboardTab;

  els.salesDashboardTabButtons?.forEach((button) => {
    const target = normalizeSalesDashboardTab(button.dataset.salesDashboardTabTarget || "");
    const active = target === activeTab;
    button.classList.toggle("is-active", active);
    setTabButtonA11yState(button, active);
  });

  if (els.salesDashboardTabTourPanel) {
    const isActive = activeTab === "tour";
    els.salesDashboardTabTourPanel.classList.toggle("hidden", !isActive);
    setTabPanelA11yState(els.salesDashboardTabTourPanel, isActive);
  }
  if (els.salesDashboardTabPhonePanel) {
    const isActive = activeTab === "phone";
    els.salesDashboardTabPhonePanel.classList.toggle("hidden", !isActive);
    setTabPanelA11yState(els.salesDashboardTabPhonePanel, isActive);
  }

  if (options?.render !== false) {
    renderSalesDashboardSection();
  }
}

function buildSalesLeadRows() {
  const visibleTours = getVisibleToursForCurrentUser();
  const providerById = new Map(
    getVisibleProvidersForCurrentUser("all").map((provider) => [String(provider?.id || "").trim(), provider])
  );

  const rows = [];
  visibleTours.forEach((tour) => {
    const tourId = String(tour?.id || "").trim();
    const tourName = String(tour?.name || "Tour").trim();
    const tourDateLabel = formatTourDateLabel(tour?.plannedDate || "");
    const defaultAssigneeName = getTourAssigneeNameByUserId(tour?.assigneeUserId, tour?.assigneeName || "Unbekannt");
    const stops = Array.isArray(tour?.stops) ? tour.stops : [];
    stops.forEach((stop, index) => {
      const providerId = String(stop?.providerId || "").trim();
      if (!providerId) {
        return;
      }
      const provider = providerById.get(providerId);
      const providerName = String(provider?.name || `Anbieter ${index + 1}`).trim();
      const statusValue = normalizeProviderStatusValue(provider?.status || "offen");
      const statusLabel = getSalesLeadStatusLabel(statusValue);
      const addedAt = String(stop?.addedAt || tour?.createdAt || "").trim();
      const doneAt = String(stop?.doneAt || "").trim();
      const activityAt = doneAt || addedAt || String(tour?.updatedAt || tour?.createdAt || "").trim();
      const activityAtTs = Number.isFinite(new Date(activityAt).getTime()) ? new Date(activityAt).getTime() : 0;
      const addedByUserId = normalizeUserId(stop?.addedByUserId || "");
      const doneByUserId = normalizeUserId(stop?.doneByUserId || "");
      const employeeUserId = doneByUserId || addedByUserId || normalizeUserId(tour?.assigneeUserId || "");
      const employeeName =
        String(stop?.doneByName || "").trim() ||
        String(stop?.addedByName || "").trim() ||
        getTourAssigneeNameByUserId(employeeUserId, defaultAssigneeName || "Unbekannt");
      const employeeFilterKey = employeeUserId
        ? `uid:${employeeUserId}`
        : `name:${normalizeText(employeeName || "unbekannt")}`;

      rows.push({
        id: String(stop?.id || "").trim() || `${tourId}::${providerId}`,
        providerName,
        providerStatus: statusValue,
        providerStatusLabel: statusLabel,
        tourName,
        tourDateLabel,
        employeeUserId,
        employeeName: employeeName || "Unbekannt",
        employeeFilterKey,
        addedAt,
        doneAt,
        activityAt,
        activityAtTs,
        searchHaystack: normalizeText(
          [
            providerName,
            statusLabel,
            tourName,
            tourDateLabel,
            employeeName,
            provider?.city,
            provider?.state,
            provider?.country,
          ]
            .filter(Boolean)
            .join(" ")
        ),
      });
    });
  });

  return rows.sort((left, right) => {
    if (right.activityAtTs !== left.activityAtTs) {
      return right.activityAtTs - left.activityAtTs;
    }
    return left.providerName.localeCompare(right.providerName, "de", { sensitivity: "base" });
  });
}

function matchesSalesLeadDateRange(row, fromDate, toDate) {
  if (!fromDate && !toDate) {
    return true;
  }
  const referenceDate = new Date(String(row?.activityAt || "").trim());
  if (Number.isNaN(referenceDate.getTime())) {
    return false;
  }
  if (fromDate && referenceDate < fromDate) {
    return false;
  }
  if (toDate) {
    const toEnd = new Date(toDate.getTime());
    toEnd.setDate(toEnd.getDate() + 1);
    if (referenceDate >= toEnd) {
      return false;
    }
  }
  return true;
}

function renderSalesLeadsEmployeeFilterOptions(rows) {
  if (!els.salesLeadsEmployeeFilter) {
    return;
  }
  const optionsMap = new Map();
  (Array.isArray(rows) ? rows : []).forEach((row) => {
    const key = String(row?.employeeFilterKey || "").trim();
    const label = String(row?.employeeName || "").trim();
    if (!key || !label || optionsMap.has(key)) {
      return;
    }
    optionsMap.set(key, label);
  });
  const options = Array.from(optionsMap.entries()).sort((left, right) =>
    left[1].localeCompare(right[1], "de", { sensitivity: "base" })
  );
  const normalizedFilterValue = normalizeSalesLeadsEmployeeFilterValue(salesLeadsEmployeeFilter);
  if (normalizedFilterValue !== "all" && !optionsMap.has(normalizedFilterValue)) {
    salesLeadsEmployeeFilter = "all";
  } else {
    salesLeadsEmployeeFilter = normalizedFilterValue;
  }
  els.salesLeadsEmployeeFilter.innerHTML = [
    '<option value="all">Alle Mitarbeiter</option>',
    ...options.map(([value, label]) => `<option value="${escapeHtml(value)}">${escapeHtml(label)}</option>`),
  ].join("");
  els.salesLeadsEmployeeFilter.value = salesLeadsEmployeeFilter;
}

function renderSalesLeadsKpis(rows) {
  if (!els.salesLeadsKpis) {
    return;
  }
  const totals = {
    total: 0,
    offen: 0,
    progress: 0,
    erfasst: 0,
    live: 0,
  };
  (Array.isArray(rows) ? rows : []).forEach((row) => {
    totals.total += 1;
    const normalizedStatus = normalizeProviderStatusValue(row?.providerStatus || "offen");
    if (normalizedStatus === "in Bearbeitung") {
      totals.progress += 1;
      return;
    }
    if (normalizedStatus === "erfasst") {
      totals.erfasst += 1;
      return;
    }
    if (normalizedStatus === "live") {
      totals.live += 1;
      return;
    }
    totals.offen += 1;
  });

  els.salesLeadsKpis.innerHTML = `
    <article class="sales-leads-kpi">
      <span>Gesamt</span>
      <strong>${escapeHtml(String(totals.total))}</strong>
    </article>
    <article class="sales-leads-kpi">
      <span>Offen</span>
      <strong>${escapeHtml(String(totals.offen))}</strong>
    </article>
    <article class="sales-leads-kpi">
      <span>In Bearbeitung</span>
      <strong>${escapeHtml(String(totals.progress))}</strong>
    </article>
    <article class="sales-leads-kpi">
      <span>Erfasst</span>
      <strong>${escapeHtml(String(totals.erfasst))}</strong>
    </article>
    <article class="sales-leads-kpi">
      <span>Live</span>
      <strong>${escapeHtml(String(totals.live))}</strong>
    </article>
  `;
}

function renderSalesLeadsSection() {
  if (!els.salesLeadsTableBody) {
    return;
  }
  const rows = buildSalesLeadRows();

  if (els.salesLeadsSearchInput && els.salesLeadsSearchInput.value !== salesLeadsSearchTerm) {
    els.salesLeadsSearchInput.value = salesLeadsSearchTerm;
  }
  if (els.salesLeadsDateFrom && els.salesLeadsDateFrom.value !== salesLeadsDateFrom) {
    els.salesLeadsDateFrom.value = salesLeadsDateFrom;
  }
  if (els.salesLeadsDateTo && els.salesLeadsDateTo.value !== salesLeadsDateTo) {
    els.salesLeadsDateTo.value = salesLeadsDateTo;
  }
  if (els.salesLeadsStatusFilter) {
    salesLeadsStatusFilter = normalizeSalesLeadsStatusFilterValue(salesLeadsStatusFilter);
    if (els.salesLeadsStatusFilter.value !== salesLeadsStatusFilter) {
      els.salesLeadsStatusFilter.value = salesLeadsStatusFilter;
    }
  }

  renderSalesLeadsEmployeeFilterOptions(rows);

  const searchNeedle = normalizeText(salesLeadsSearchTerm);
  const fromDate = parseDateInputStart(salesLeadsDateFrom);
  const toDate = parseDateInputStart(salesLeadsDateTo);
  const preStatusRows = rows.filter((row) => {
    if (salesLeadsEmployeeFilter !== "all" && row.employeeFilterKey !== salesLeadsEmployeeFilter) {
      return false;
    }
    if (searchNeedle && !String(row.searchHaystack || "").includes(searchNeedle)) {
      return false;
    }
    if (!matchesSalesLeadDateRange(row, fromDate, toDate)) {
      return false;
    }
    return true;
  });

  renderSalesLeadsKpis(preStatusRows);

  const tableRows =
    salesLeadsStatusFilter === "all"
      ? preStatusRows
      : preStatusRows.filter((row) => row.providerStatus === salesLeadsStatusFilter);

  if (!tableRows.length) {
    els.salesLeadsTableBody.innerHTML = '<tr><td colspan="6" class="empty">Keine Leads im gewählten Filter.</td></tr>';
  } else {
    els.salesLeadsTableBody.innerHTML = tableRows
      .map((row) => `
        <tr>
          <td>${escapeHtml(row.providerName)}</td>
          <td>
            <span class="tour-status-pill ${getTourStatusCssClass(row.providerStatus)}">${escapeHtml(
              row.providerStatusLabel
            )}</span>
          </td>
          <td>${escapeHtml(`${row.tourName} · ${row.tourDateLabel}`)}</td>
          <td>${renderEmployeeColorTag(row.employeeUserId, row.employeeName)}</td>
          <td>${escapeHtml(row.addedAt ? formatDateTime(row.addedAt) : "–")}</td>
          <td>${escapeHtml(row.doneAt ? formatDateTime(row.doneAt) : "–")}</td>
        </tr>
      `)
      .join("");
  }

  if (els.salesLeadsTableMeta) {
    const statusPart =
      salesLeadsStatusFilter === "all" ? "alle Status" : `Status: ${getSalesLeadStatusLabel(salesLeadsStatusFilter)}`;
    els.salesLeadsTableMeta.textContent = `${tableRows.length} Einträge · ${statusPart}`;
  }
}

function normalizeSalesPhoneSubpage(value) {
  const normalized = String(value || "").trim().toLowerCase();
  if (["overview", "planning", "detail"].includes(normalized)) {
    return normalized;
  }
  return "overview";
}

function setSalesPhoneSubpage(nextSubpage, options = {}) {
  salesPhoneSubpage = normalizeSalesPhoneSubpage(nextSubpage);
  const subpage = salesPhoneSubpage;
  els.salesPhoneSubpageButtons?.forEach((button) => {
    const target = normalizeSalesPhoneSubpage(button.dataset.salesPhoneSubpageTarget || "");
    const active = target === subpage;
    button.classList.toggle("is-active", active);
    setTabButtonA11yState(button, active);
  });
  if (els.salesPhoneSubpageOverview) {
    const isActive = subpage === "overview";
    els.salesPhoneSubpageOverview.classList.toggle("hidden", !isActive);
    setTabPanelA11yState(els.salesPhoneSubpageOverview, isActive);
  }
  if (els.salesPhoneSubpagePlanning) {
    const isActive = subpage === "planning";
    els.salesPhoneSubpagePlanning.classList.toggle("hidden", !isActive);
    setTabPanelA11yState(els.salesPhoneSubpagePlanning, isActive);
  }
  if (els.salesPhoneSubpageDetail) {
    const isActive = subpage === "detail";
    els.salesPhoneSubpageDetail.classList.toggle("hidden", !isActive);
    setTabPanelA11yState(els.salesPhoneSubpageDetail, isActive);
  }
  if (options?.render !== false) {
    renderSalesPhoneSection();
  }
}

function normalizeSalesPhoneModalKey(value) {
  const normalized = String(value || "").trim().toLowerCase();
  if (["status", "note", "task"].includes(normalized)) {
    return normalized;
  }
  return "";
}

function getSalesPhoneModalElement(modalKey) {
  const key = normalizeSalesPhoneModalKey(modalKey);
  if (key === "status") {
    return els.salesPhoneStatusModal || null;
  }
  if (key === "note") {
    return els.salesPhoneNoteModal || null;
  }
  if (key === "task") {
    return els.salesPhoneTaskModal || null;
  }
  return null;
}

function isSalesPhoneModalOpen() {
  return ["status", "note", "task"].some((key) => {
    const modal = getSalesPhoneModalElement(key);
    return !!modal && !modal.classList.contains("hidden");
  });
}

function closeSalesPhoneModal(modalKey = "") {
  const normalizedModalKey = normalizeSalesPhoneModalKey(modalKey);
  const keys = normalizedModalKey ? [normalizedModalKey] : ["status", "note", "task"];
  keys.forEach((key) => {
    const modal = getSalesPhoneModalElement(key);
    if (modal) {
      modal.classList.add("hidden");
    }
  });
  syncBodyModalOpenState();
}

function openSalesPhoneModal(modalKey) {
  const key = normalizeSalesPhoneModalKey(modalKey);
  if (!key) {
    return;
  }
  const selectedCall = getSalesPhoneCallById(salesPhoneSelectedCallId);
  if (!selectedCall) {
    showInfoFeedback("Bitte zuerst einen Eintrag über 'Öffnen' auswählen.");
    return;
  }
  setSalesPhoneSubpage("detail", { render: false });
  closeSalesPhoneModal();
  const modal = getSalesPhoneModalElement(key);
  if (!modal) {
    return;
  }
  modal.classList.remove("hidden");
  syncBodyModalOpenState();
}

function sanitizeSalesPhoneStatus(value) {
  const normalized = normalizeText(value || "");
  return SALES_PHONE_STATUSES.has(normalized) ? normalized : "neu";
}

function sanitizeSalesPhonePlanSlot(value) {
  const normalized = normalizeText(value || "");
  return SALES_PHONE_PLAN_SLOTS.has(normalized) ? normalized : "vormittag";
}

function sanitizeSalesPhoneTaskStatus(value) {
  const normalized = normalizeText(value || "");
  return SALES_PHONE_TASK_STATUSES.has(normalized) ? normalized : "offen";
}

function normalizeSalesPhoneDateInputValue(value) {
  return sanitizeEmployeeAdminDate(value);
}

function normalizeSalesPhoneAssigneeFilterValue(value) {
  const normalized = String(value || "").trim();
  if (!normalized || normalizeText(normalized) === "all") {
    return "all";
  }
  return normalizeUserId(normalized);
}

function normalizeSalesPhoneStatusFilterValue(value) {
  const normalized = String(value || "").trim();
  if (!normalized || normalizeText(normalized) === "all") {
    return "all";
  }
  return sanitizeSalesPhoneStatus(normalized);
}

function normalizeSalesPhoneReminderAt(value) {
  const rawValue = String(value || "").trim();
  if (!rawValue) {
    return "";
  }
  const parsed = new Date(rawValue);
  if (Number.isNaN(parsed.getTime())) {
    return "";
  }
  return parsed.toISOString();
}

function toDateTimeLocalInputValue(value) {
  const rawValue = String(value || "").trim();
  if (!rawValue) {
    return "";
  }
  const parsed = new Date(rawValue);
  if (Number.isNaN(parsed.getTime())) {
    return "";
  }
  const year = parsed.getFullYear();
  const month = String(parsed.getMonth() + 1).padStart(2, "0");
  const day = String(parsed.getDate()).padStart(2, "0");
  const hours = String(parsed.getHours()).padStart(2, "0");
  const minutes = String(parsed.getMinutes()).padStart(2, "0");
  return `${year}-${month}-${day}T${hours}:${minutes}`;
}

function getSalesPhoneStatusLabel(status) {
  const normalized = sanitizeSalesPhoneStatus(status);
  if (normalized === "nicht_erreicht") {
    return "Nicht erreicht";
  }
  if (normalized === "mailbox") {
    return "Mailbox";
  }
  if (normalized === "rueckruf") {
    return "Rueckruf noetig";
  }
  if (normalized === "erreicht") {
    return "Erreicht";
  }
  if (normalized === "kein_interesse") {
    return "Kein Interesse";
  }
  if (normalized === "interessiert") {
    return "Interessiert";
  }
  if (normalized === "angebot_gesendet") {
    return "Angebot gesendet";
  }
  if (normalized === "termin_vereinbart") {
    return "Termin vereinbart";
  }
  if (normalized === "abschluss") {
    return "Abschluss";
  }
  return "Neu";
}

function getSalesPhonePlanSlotLabel(slot) {
  const normalized = sanitizeSalesPhonePlanSlot(slot);
  if (normalized === "mittag") {
    return "Mittag";
  }
  if (normalized === "nachmittag") {
    return "Nachmittag";
  }
  if (normalized === "abend") {
    return "Abend";
  }
  return "Vormittag";
}

function normalizeSalesPhoneNoteRecord(note, index = 0) {
  if (!note || typeof note !== "object") {
    return null;
  }
  const text = String(note.text || note.note_text || "").trim();
  if (!text) {
    return null;
  }
  const id = String(note.id || `snote_${index}`).trim();
  if (!id) {
    return null;
  }
  const createdAtRaw = String(note.createdAt || note.created_at || "").trim();
  const createdAt = Number.isNaN(new Date(createdAtRaw).getTime()) ? new Date().toISOString() : createdAtRaw;
  return {
    id,
    text,
    createdAt,
    createdByUserId: normalizeUserId(note.createdByUserId || note.created_by_user_id || ""),
    createdByName: String(note.createdByName || note.created_by_name || "").trim(),
    createdByRole: normalizeUserRole(note.createdByRole || note.created_by_role || ""),
  };
}

function normalizeSalesPhoneTaskRecord(task, index = 0) {
  if (!task || typeof task !== "object") {
    return null;
  }
  const title = String(task.title || task.task_title || "").trim();
  if (!title) {
    return null;
  }
  const id = String(task.id || `stask_${index}`).trim();
  if (!id) {
    return null;
  }
  const createdAtRaw = String(task.createdAt || task.created_at || "").trim();
  const createdAt = Number.isNaN(new Date(createdAtRaw).getTime()) ? new Date().toISOString() : createdAtRaw;
  const updatedAtRaw = String(task.updatedAt || task.updated_at || createdAt).trim();
  const updatedAt = Number.isNaN(new Date(updatedAtRaw).getTime()) ? createdAt : updatedAtRaw;
  const assigneeUserId = normalizeUserId(task.assigneeUserId || task.assignee_user_id || "");
  return {
    id,
    title,
    assigneeUserId,
    assigneeName: String(task.assigneeName || task.assignee_name || getUserDisplayNameByUserId(assigneeUserId) || "").trim(),
    dueDate: sanitizeEmployeeAdminDate(task.dueDate || task.due_date),
    status: sanitizeSalesPhoneTaskStatus(task.status || task.task_status),
    createdAt,
    createdByUserId: normalizeUserId(task.createdByUserId || task.created_by_user_id || ""),
    createdByName: String(task.createdByName || task.created_by_name || "").trim(),
    createdByRole: normalizeUserRole(task.createdByRole || task.created_by_role || ""),
    updatedAt,
    updatedByUserId: normalizeUserId(task.updatedByUserId || task.updated_by_user_id || ""),
    updatedByName: String(task.updatedByName || task.updated_by_name || "").trim(),
    updatedByRole: normalizeUserRole(task.updatedByRole || task.updated_by_role || ""),
  };
}

function normalizeSalesPhoneCallRecord(entry, index = 0) {
  if (!entry || typeof entry !== "object") {
    return null;
  }
  const id = String(entry.id || `scall_${index}`).trim();
  if (!id) {
    return null;
  }
  const providerId = String(entry.providerId || entry.provider_id || "").trim();
  const providerName = String(entry.providerName || entry.provider_name || "").trim();
  if (!providerId && !providerName) {
    return null;
  }
  const createdAtRaw = String(entry.createdAt || entry.created_at || "").trim();
  const createdAt = Number.isNaN(new Date(createdAtRaw).getTime()) ? new Date().toISOString() : createdAtRaw;
  const updatedAtRaw = String(entry.updatedAt || entry.updated_at || createdAt).trim();
  const updatedAt = Number.isNaN(new Date(updatedAtRaw).getTime()) ? createdAt : updatedAtRaw;
  const notesRaw = Array.isArray(entry.notes) ? entry.notes : [];
  const notes = notesRaw.map((note, noteIndex) => normalizeSalesPhoneNoteRecord(note, noteIndex)).filter(Boolean);
  const tasksRaw = Array.isArray(entry.tasks) ? entry.tasks : [];
  const tasks = tasksRaw.map((task, taskIndex) => normalizeSalesPhoneTaskRecord(task, taskIndex)).filter(Boolean);
  const assigneeUserId = normalizeUserId(entry.assigneeUserId || entry.assignee_user_id || "");
  const reminderAt = normalizeSalesPhoneReminderAt(entry.reminderAt || entry.reminder_at || "");
  const lastContactAt = normalizeSalesPhoneReminderAt(entry.lastContactAt || entry.last_contact_at || "");
  return {
    id,
    providerId,
    providerName: providerName || `Anbieter ${index + 1}`,
    providerPhone: String(entry.providerPhone || entry.provider_phone || "").trim(),
    assigneeUserId,
    assigneeName: String(entry.assigneeName || entry.assignee_name || getUserDisplayNameByUserId(assigneeUserId) || "").trim(),
    plannedDate: sanitizeEmployeeAdminDate(entry.plannedDate || entry.planned_date),
    planSlot: sanitizeSalesPhonePlanSlot(entry.planSlot || entry.plan_slot),
    status: sanitizeSalesPhoneStatus(entry.status),
    reminderAt,
    lastContactAt,
    createdAt,
    createdByUserId: normalizeUserId(entry.createdByUserId || entry.created_by_user_id || ""),
    createdByName: String(entry.createdByName || entry.created_by_name || "").trim(),
    createdByRole: normalizeUserRole(entry.createdByRole || entry.created_by_role || ""),
    updatedAt,
    updatedByUserId: normalizeUserId(entry.updatedByUserId || entry.updated_by_user_id || ""),
    updatedByName: String(entry.updatedByName || entry.updated_by_name || "").trim(),
    updatedByRole: normalizeUserRole(entry.updatedByRole || entry.updated_by_role || ""),
    notes,
    tasks,
  };
}

function normalizeSalesPhoneCalls(rawList) {
  if (!Array.isArray(rawList)) {
    return [];
  }
  const seenIds = new Set();
  const normalized = [];
  rawList.forEach((entry, index) => {
    const normalizedEntry = normalizeSalesPhoneCallRecord(entry, index);
    if (!normalizedEntry) {
      return;
    }
    if (seenIds.has(normalizedEntry.id)) {
      return;
    }
    seenIds.add(normalizedEntry.id);
    normalized.push(normalizedEntry);
  });
  return normalized.sort((left, right) => String(right.updatedAt || "").localeCompare(String(left.updatedAt || "")));
}

function getSalesPhoneCalls() {
  return normalizeSalesPhoneCalls(state.settings?.salesPhoneCalls || []);
}

function setSalesPhoneCalls(calls) {
  state.settings = normalizeSettings({
    ...state.settings,
    salesPhoneCalls: normalizeSalesPhoneCalls(calls || []),
  });
}

function getSalesPhoneAssignableUsers() {
  const rows = getEmployeeAdminManagedUsers().filter((entry) => !!entry.userId);
  const actor = getCurrentActorInfo();
  if (actor.userId && !rows.some((entry) => entry.userId === actor.userId)) {
    rows.push({
      userId: actor.userId,
      name: actor.name || actor.userId,
      email: "",
      role: actor.role,
      status: "active",
      statusLabel: "Aktiv",
    });
  }
  return rows.sort((left, right) => left.name.localeCompare(right.name, "de", { sensitivity: "base" }));
}

function getSalesPhoneProviderById(providerId) {
  const normalizedProviderId = String(providerId || "").trim();
  if (!normalizedProviderId) {
    return null;
  }
  return getVisibleProvidersForCurrentUser("all").find((provider) => String(provider?.id || "").trim() === normalizedProviderId) || null;
}

function getSalesPhoneCallById(callId) {
  const normalizedCallId = String(callId || "").trim();
  if (!normalizedCallId) {
    return null;
  }
  return getSalesPhoneCalls().find((entry) => entry.id === normalizedCallId) || null;
}

function getSalesPhoneStatusCssClass(status) {
  const normalized = sanitizeSalesPhoneStatus(status);
  if (["interessiert", "angebot_gesendet", "termin_vereinbart", "abschluss"].includes(normalized)) {
    return "is-hot";
  }
  if (["nicht_erreicht", "mailbox", "rueckruf", "kein_interesse"].includes(normalized)) {
    return "is-risk";
  }
  return "is-neutral";
}

function isSalesPhoneStatusFinal(status) {
  const normalized = sanitizeSalesPhoneStatus(status);
  return normalized === "kein_interesse" || normalized === "abschluss";
}

function buildSalesPhoneOpenPlanMap(calls = getSalesPhoneCalls()) {
  const rows = Array.isArray(calls) ? calls : [];
  const map = new Map();
  rows.forEach((entry) => {
    const providerId = String(entry?.providerId || "").trim();
    if (!providerId || isSalesPhoneStatusFinal(entry?.status)) {
      return;
    }
    if (!map.has(providerId)) {
      map.set(providerId, []);
    }
    map.get(providerId).push(entry);
  });
  map.forEach((entries, providerId) => {
    const sortedEntries = entries.slice().sort((left, right) => {
      const leftDate = sanitizeEmployeeAdminDate(left?.plannedDate || "");
      const rightDate = sanitizeEmployeeAdminDate(right?.plannedDate || "");
      if (leftDate !== rightDate) {
        if (!leftDate) {
          return 1;
        }
        if (!rightDate) {
          return -1;
        }
        return leftDate.localeCompare(rightDate);
      }
      return String(right?.updatedAt || "").localeCompare(String(left?.updatedAt || ""));
    });
    map.set(providerId, sortedEntries);
  });
  return map;
}

function getSalesPhoneReminderState(reminderAt) {
  const parsed = new Date(String(reminderAt || "").trim());
  if (Number.isNaN(parsed.getTime())) {
    return "";
  }
  const deltaMs = parsed.getTime() - Date.now();
  if (deltaMs < 0) {
    return "is-overdue";
  }
  if (deltaMs <= 86400000) {
    return "is-soon";
  }
  return "";
}

function upsertSalesPhoneProviderOptions(selectedProviderId = "") {
  if (!els.salesPhoneProviderSelect) {
    return "";
  }
  const activePlanMap = buildSalesPhoneOpenPlanMap();
  const providers = getVisibleProvidersForCurrentUser("all")
    .slice()
    .sort((left, right) => String(left?.name || "").localeCompare(String(right?.name || ""), "de", { sensitivity: "base" }));
  if (!providers.length) {
    els.salesPhoneProviderSelect.innerHTML = '<option value="">Keine Anbieter verfügbar</option>';
    els.salesPhoneProviderSelect.disabled = true;
    els.salesPhoneProviderSelect.value = "";
    return "";
  }
  const availableProviders = providers.filter((provider) => {
    const providerId = String(provider?.id || "").trim();
    return providerId && !activePlanMap.has(providerId);
  });
  if (!availableProviders.length) {
    els.salesPhoneProviderSelect.innerHTML = '<option value="">Alle Anbieter sind bereits geplant</option>';
    els.salesPhoneProviderSelect.disabled = true;
    els.salesPhoneProviderSelect.value = "";
    return "";
  }
  els.salesPhoneProviderSelect.innerHTML = providers
    .map((provider) => {
      const providerId = String(provider?.id || "").trim();
      const planEntries = activePlanMap.get(providerId) || [];
      const hasActivePlan = planEntries.length > 0;
      const primaryPlan = planEntries[0] || null;
      const plannedByLabel = String(
        primaryPlan?.assigneeName || getUserDisplayNameByUserId(primaryPlan?.assigneeUserId) || "Mitarbeiter"
      ).trim();
      const plannedDateLabel = primaryPlan?.plannedDate ? formatTourDateLabel(primaryPlan.plannedDate) : "ohne Datum";
      const locationLabel = [provider.city, provider.country].filter(Boolean).join(", ");
      const optionLabelBase = locationLabel ? `${provider.name} · ${locationLabel}` : provider.name;
      const optionLabel = hasActivePlan
        ? `${optionLabelBase} · bereits geplant (${plannedByLabel} · ${plannedDateLabel})`
        : optionLabelBase;
      return `<option value="${escapeHtml(provider.id)}" ${hasActivePlan ? "disabled" : ""}>${escapeHtml(optionLabel)}</option>`;
    })
    .join("");
  els.salesPhoneProviderSelect.disabled = false;
  const candidateId = String(selectedProviderId || "").trim();
  const hasCandidate = candidateId && availableProviders.some((provider) => provider.id === candidateId);
  const nextProviderId = hasCandidate ? candidateId : String(availableProviders[0]?.id || "").trim();
  els.salesPhoneProviderSelect.value = nextProviderId;
  return nextProviderId;
}

function upsertSalesPhoneAssigneeOptions(selectedAssigneeUserId = "") {
  const assignees = getSalesPhoneAssignableUsers();
  const candidateId = normalizeUserId(selectedAssigneeUserId || getCurrentActorInfo().userId || "");
  const hasCandidate = candidateId && assignees.some((entry) => entry.userId === candidateId);
  const nextAssigneeId = hasCandidate ? candidateId : String(assignees[0]?.userId || "");

  const options = assignees.map((entry) => `<option value="${escapeHtml(entry.userId)}">${escapeHtml(entry.name)}</option>`);
  if (els.salesPhoneAssigneeSelect) {
    els.salesPhoneAssigneeSelect.innerHTML = options.join("");
    els.salesPhoneAssigneeSelect.value = nextAssigneeId;
  }
  if (els.salesPhoneTaskAssignee) {
    els.salesPhoneTaskAssignee.innerHTML = options.join("");
    els.salesPhoneTaskAssignee.value = nextAssigneeId;
  }
  if (els.salesPhoneFilterAssignee) {
    const filterOptions = ['<option value="all">Alle Mitarbeiter</option>'].concat(options);
    els.salesPhoneFilterAssignee.innerHTML = filterOptions.join("");
    const normalizedFilter = normalizeSalesPhoneAssigneeFilterValue(salesPhoneAssigneeFilter);
    salesPhoneAssigneeFilter =
      normalizedFilter !== "all" && !assignees.some((entry) => entry.userId === normalizedFilter)
        ? "all"
        : normalizedFilter;
    els.salesPhoneFilterAssignee.value = salesPhoneAssigneeFilter;
  }
  return nextAssigneeId;
}

function matchesSalesPhoneDateRange(entry, fromDate, toDate) {
  if (!fromDate && !toDate) {
    return true;
  }
  const rawDate = sanitizeEmployeeAdminDate(entry?.plannedDate);
  if (!rawDate) {
    return false;
  }
  const plannedDate = parseDateInputStart(rawDate);
  if (!plannedDate) {
    return false;
  }
  if (fromDate && plannedDate < fromDate) {
    return false;
  }
  if (toDate) {
    const toEnd = new Date(toDate.getTime());
    toEnd.setDate(toEnd.getDate() + 1);
    if (plannedDate >= toEnd) {
      return false;
    }
  }
  return true;
}

function renderSalesPhoneKpis(rows) {
  if (!els.salesPhoneKpis) {
    return;
  }
  const totals = {
    total: 0,
    dueToday: 0,
    followUp: 0,
    interested: 0,
    overdueReminder: 0,
    openTasks: 0,
  };
  const today = getTodayDateInputValue();
  (Array.isArray(rows) ? rows : []).forEach((entry) => {
    totals.total += 1;
    if (sanitizeEmployeeAdminDate(entry?.plannedDate) === today) {
      totals.dueToday += 1;
    }
    const status = sanitizeSalesPhoneStatus(entry?.status);
    if (["nicht_erreicht", "mailbox", "rueckruf"].includes(status)) {
      totals.followUp += 1;
    }
    if (["interessiert", "angebot_gesendet", "termin_vereinbart"].includes(status)) {
      totals.interested += 1;
    }
    if (getSalesPhoneReminderState(entry?.reminderAt) === "is-overdue") {
      totals.overdueReminder += 1;
    }
    const openTaskCount = (Array.isArray(entry?.tasks) ? entry.tasks : []).filter(
      (task) => sanitizeSalesPhoneTaskStatus(task.status) !== "erledigt"
    ).length;
    totals.openTasks += openTaskCount;
  });
  els.salesPhoneKpis.innerHTML = `
    <article class="sales-phone-kpi"><span>Anrufpläne</span><strong>${escapeHtml(String(totals.total))}</strong></article>
    <article class="sales-phone-kpi"><span>Heute</span><strong>${escapeHtml(String(totals.dueToday))}</strong></article>
    <article class="sales-phone-kpi"><span>Follow-up</span><strong>${escapeHtml(String(totals.followUp))}</strong></article>
    <article class="sales-phone-kpi"><span>Interessiert</span><strong>${escapeHtml(String(totals.interested))}</strong></article>
    <article class="sales-phone-kpi"><span>Reminder überfällig</span><strong>${escapeHtml(String(totals.overdueReminder))}</strong></article>
    <article class="sales-phone-kpi"><span>Offene Aufgaben</span><strong>${escapeHtml(String(totals.openTasks))}</strong></article>
  `;
}

function renderSalesPhoneDetail(call) {
  if (
    !els.salesPhoneDetailCard ||
    !els.salesPhoneDetailTitle ||
    !els.salesPhoneDetailMeta ||
    !els.salesPhoneDetailPhone ||
    !els.salesPhoneDetailStatus ||
    !els.salesPhoneDetailReminder ||
    !els.salesPhoneNoteList ||
    !els.salesPhoneTaskList
  ) {
    return;
  }
  if (!call) {
    els.salesPhoneDetailCard.classList.add("hidden");
    els.salesPhoneNoteList.innerHTML = "";
    els.salesPhoneTaskList.innerHTML = "";
    return;
  }
  els.salesPhoneDetailCard.classList.remove("hidden");
  const provider = getSalesPhoneProviderById(call.providerId);
  const providerName = String(provider?.name || call.providerName || "Anbieter").trim();
  const plannedDateLabel = call.plannedDate ? formatTourDateLabel(call.plannedDate) : "ohne Datum";
  const assigneeLabel = String(call.assigneeName || getUserDisplayNameByUserId(call.assigneeUserId) || "Unbekannt").trim();
  const lastContactLabel = call.lastContactAt ? formatDateTime(call.lastContactAt) : "Noch kein Kontakt dokumentiert";
  const phoneValue = String(provider?.phone || call.providerPhone || "").trim();
  const telHref = buildTelHref(phoneValue);
  const phoneMarkup = telHref ? `<a href="${escapeHtml(telHref)}">${escapeHtml(phoneValue)}</a>` : "Telefon nicht hinterlegt";

  els.salesPhoneDetailTitle.textContent = providerName;
  els.salesPhoneDetailMeta.textContent = `${plannedDateLabel} · ${getSalesPhonePlanSlotLabel(call.planSlot)} · ${assigneeLabel} · ${lastContactLabel}`;
  els.salesPhoneDetailPhone.innerHTML = phoneMarkup;
  els.salesPhoneDetailStatus.value = sanitizeSalesPhoneStatus(call.status);
  els.salesPhoneDetailReminder.value = toDateTimeLocalInputValue(call.reminderAt);

  const notes = (Array.isArray(call.notes) ? call.notes : []).slice().sort((left, right) => {
    return String(right?.createdAt || "").localeCompare(String(left?.createdAt || ""));
  });
  if (!notes.length) {
    els.salesPhoneNoteList.innerHTML = '<p class="empty">Noch keine Notizen.</p>';
  } else {
    els.salesPhoneNoteList.innerHTML = notes
      .map((note) => {
        const createdBy = String(note.createdByName || "Unbekannt").trim();
        const roleLabel = getRoleLabel(note.createdByRole);
        return `
          <article class="sales-phone-note-item">
            <p>${escapeHtml(String(note.text || "")).replace(/\n/g, "<br/>")}</p>
            <small class="sales-phone-note-meta">${escapeHtml(formatDateTime(note.createdAt))} · ${escapeHtml(
              roleLabel
            )} (${escapeHtml(createdBy)})</small>
          </article>
        `;
      })
      .join("");
  }

  const tasks = (Array.isArray(call.tasks) ? call.tasks : []).slice().sort((left, right) => {
    const leftDone = sanitizeSalesPhoneTaskStatus(left?.status) === "erledigt";
    const rightDone = sanitizeSalesPhoneTaskStatus(right?.status) === "erledigt";
    if (leftDone !== rightDone) {
      return leftDone ? 1 : -1;
    }
    const leftDue = sanitizeEmployeeAdminDate(left?.dueDate);
    const rightDue = sanitizeEmployeeAdminDate(right?.dueDate);
    if (leftDue !== rightDue) {
      return leftDue.localeCompare(rightDue);
    }
    return String(right?.updatedAt || "").localeCompare(String(left?.updatedAt || ""));
  });
  if (!tasks.length) {
    els.salesPhoneTaskList.innerHTML = '<p class="empty">Noch keine Aufgaben.</p>';
  } else {
    els.salesPhoneTaskList.innerHTML = tasks
      .map((task) => {
        const done = sanitizeSalesPhoneTaskStatus(task.status) === "erledigt";
        const assigneeName = String(task.assigneeName || getUserDisplayNameByUserId(task.assigneeUserId) || "Unbekannt").trim();
        const dueLabel = task.dueDate ? formatEmployeeAdminDate(task.dueDate) : "ohne Fälligkeit";
        return `
          <article class="sales-phone-task-item ${done ? "is-done" : ""}">
            <label class="sales-phone-task-actions">
              <input type="checkbox" data-sales-phone-task-toggle="${escapeHtml(task.id)}" ${done ? "checked" : ""} />
            </label>
            <div>
              <p class="sales-phone-task-title">${escapeHtml(task.title)}</p>
              <small class="sales-phone-task-meta">${escapeHtml(assigneeName)} · ${escapeHtml(dueLabel)}</small>
            </div>
            <button type="button" class="mini-btn danger" data-sales-phone-task-delete="${escapeHtml(task.id)}">✕</button>
          </article>
        `;
      })
      .join("");
  }
}

function renderSalesPhonePlanningList(rows) {
  if (!els.salesPhonePlanningList || !els.salesPhonePlanningMeta) {
    return;
  }
  const planningRows = (Array.isArray(rows) ? rows : [])
    .slice()
    .sort((left, right) => {
      const leftDate = sanitizeEmployeeAdminDate(left?.plannedDate || "");
      const rightDate = sanitizeEmployeeAdminDate(right?.plannedDate || "");
      if (leftDate !== rightDate) {
        if (!leftDate) {
          return 1;
        }
        if (!rightDate) {
          return -1;
        }
        return leftDate.localeCompare(rightDate);
      }
      return String(right?.updatedAt || "").localeCompare(String(left?.updatedAt || ""));
    });
  if (!planningRows.length) {
    els.salesPhonePlanningList.innerHTML = '<p class="empty">Noch keine Anbieter für Anrufplanung angelegt.</p>';
    els.salesPhonePlanningMeta.textContent = "0 Einträge";
    return;
  }
  els.salesPhonePlanningList.innerHTML = planningRows
    .map((entry) => {
      const provider = getSalesPhoneProviderById(entry.providerId);
      const providerName = String(provider?.name || entry.providerName || "Anbieter").trim();
      const assigneeUserId = normalizeUserId(entry.assigneeUserId || "");
      const assigneeName = String(entry.assigneeName || getUserDisplayNameByUserId(entry.assigneeUserId) || "Unbekannt").trim();
      const plannedDateLabel = entry.plannedDate ? formatTourDateLabel(entry.plannedDate) : "ohne Datum";
      return `
        <article class="sales-phone-planning-item">
          <div>
            <strong>${escapeHtml(providerName)}</strong>
            <small>${escapeHtml(plannedDateLabel)} · ${escapeHtml(getSalesPhonePlanSlotLabel(entry.planSlot))}</small>
            <small>${renderEmployeeColorTag(assigneeUserId, assigneeName)} · ${escapeHtml(
              getSalesPhoneStatusLabel(entry.status)
            )}</small>
          </div>
          <div class="sales-phone-planning-actions">
            <button
              type="button"
              class="mini-btn"
              title="Bearbeiten"
              aria-label="Bearbeiten"
              data-sales-phone-edit="${escapeHtml(entry.id)}"
            >✎</button>
            <button
              type="button"
              class="mini-btn danger"
              title="Löschen"
              aria-label="Löschen"
              data-sales-phone-delete="${escapeHtml(entry.id)}"
            >✕</button>
          </div>
        </article>
      `;
    })
    .join("");
  els.salesPhonePlanningMeta.textContent = `${planningRows.length} geplante Anbieter`;
}

function renderSalesPhoneSection() {
  if (
    !els.salesPhoneTableBody ||
    !els.salesPhoneTableMeta ||
    !els.salesPhoneProviderSelect ||
    !els.salesPhoneAssigneeSelect ||
    !els.salesPhoneTaskAssignee
  ) {
    return;
  }
  const allCalls = getSalesPhoneCalls();
  setSalesPhoneSubpage(salesPhoneSubpage, { render: false });

  if (els.salesPhonePlannedDate && !els.salesPhonePlannedDate.value) {
    els.salesPhonePlannedDate.value = getTodayDateInputValue();
  }
  renderSalesPhonePlanningList(allCalls);
  upsertSalesPhoneProviderOptions(els.salesPhoneProviderSelect.value || "");
  upsertSalesPhoneAssigneeOptions(els.salesPhoneAssigneeSelect.value || "");

  if (els.salesPhoneSearchInput && els.salesPhoneSearchInput.value !== salesPhoneSearchTerm) {
    els.salesPhoneSearchInput.value = salesPhoneSearchTerm;
  }
  if (els.salesPhoneDateFrom && els.salesPhoneDateFrom.value !== salesPhoneDateFrom) {
    els.salesPhoneDateFrom.value = salesPhoneDateFrom;
  }
  if (els.salesPhoneDateTo && els.salesPhoneDateTo.value !== salesPhoneDateTo) {
    els.salesPhoneDateTo.value = salesPhoneDateTo;
  }
  salesPhoneAssigneeFilter = normalizeSalesPhoneAssigneeFilterValue(salesPhoneAssigneeFilter);
  salesPhoneStatusFilter = normalizeSalesPhoneStatusFilterValue(salesPhoneStatusFilter);
  if (els.salesPhoneFilterStatus && els.salesPhoneFilterStatus.value !== salesPhoneStatusFilter) {
    els.salesPhoneFilterStatus.value = salesPhoneStatusFilter;
  }

  const searchNeedle = normalizeText(salesPhoneSearchTerm);
  const fromDate = parseDateInputStart(salesPhoneDateFrom);
  const toDate = parseDateInputStart(salesPhoneDateTo);
  const filteredCalls = allCalls.filter((entry) => {
    if (salesPhoneAssigneeFilter !== "all" && normalizeUserId(entry.assigneeUserId) !== salesPhoneAssigneeFilter) {
      return false;
    }
    const entryStatus = sanitizeSalesPhoneStatus(entry.status);
    if (salesPhoneStatusFilter !== "all" && entryStatus !== salesPhoneStatusFilter) {
      return false;
    }
    if (!matchesSalesPhoneDateRange(entry, fromDate, toDate)) {
      return false;
    }
    const searchHaystack = normalizeText(
      [
        entry.providerName,
        getSalesPhoneStatusLabel(entry.status),
        entry.assigneeName,
        entry.plannedDate,
        entry.reminderAt,
        (Array.isArray(entry.notes) ? entry.notes : []).map((note) => note.text).join(" "),
      ]
        .filter(Boolean)
        .join(" ")
    );
    if (searchNeedle && !searchHaystack.includes(searchNeedle)) {
      return false;
    }
    return true;
  });

  renderSalesPhoneKpis(filteredCalls);

  if (!filteredCalls.length) {
    els.salesPhoneTableBody.innerHTML = '<tr><td colspan="7" class="empty">Keine Anrufpläne im gewählten Filter.</td></tr>';
  } else {
    els.salesPhoneTableBody.innerHTML = filteredCalls
      .map((entry) => {
        const provider = getSalesPhoneProviderById(entry.providerId);
        const providerName = String(provider?.name || entry.providerName || "Anbieter").trim();
        const providerPhone = String(provider?.phone || entry.providerPhone || "").trim();
        const telHref = buildTelHref(providerPhone);
        const reminderState = getSalesPhoneReminderState(entry.reminderAt);
        const reminderClass = reminderState ? `sales-phone-reminder ${reminderState}` : "sales-phone-reminder";
        const openTasks = (Array.isArray(entry.tasks) ? entry.tasks : []).filter(
          (task) => sanitizeSalesPhoneTaskStatus(task.status) !== "erledigt"
        ).length;
        return `
          <tr>
            <td>
              <div class="sales-phone-provider-cell">
                <strong>${escapeHtml(providerName)}</strong>
                <small>${telHref ? `<a href="${escapeHtml(telHref)}">${escapeHtml(providerPhone)}</a>` : "Kein Telefon"}</small>
              </div>
            </td>
            <td>
              <span class="sales-phone-status ${getSalesPhoneStatusCssClass(entry.status)}">${escapeHtml(
                getSalesPhoneStatusLabel(entry.status)
              )}</span>
            </td>
            <td>
              <div class="sales-phone-plan-cell">
                <strong>${escapeHtml(entry.plannedDate ? formatTourDateLabel(entry.plannedDate) : "ohne Datum")}</strong>
                <small>${escapeHtml(getSalesPhonePlanSlotLabel(entry.planSlot))}</small>
              </div>
            </td>
            <td>${renderEmployeeColorTag(
              normalizeUserId(entry.assigneeUserId || ""),
              entry.assigneeName || getUserDisplayNameByUserId(entry.assigneeUserId) || "Unbekannt"
            )}</td>
            <td><span class="${escapeHtml(reminderClass)}">${escapeHtml(entry.reminderAt ? formatDateTime(entry.reminderAt) : "–")}</span></td>
            <td>${escapeHtml(String(openTasks))}</td>
            <td><button type="button" class="mini-btn sales-phone-open-btn" data-sales-phone-select="${escapeHtml(entry.id)}">Öffnen</button></td>
          </tr>
        `;
      })
      .join("");
  }
  const filterStatusPart =
    salesPhoneStatusFilter === "all" ? "alle Status" : `Status: ${getSalesPhoneStatusLabel(salesPhoneStatusFilter)}`;
  els.salesPhoneTableMeta.textContent = `${filteredCalls.length} Einträge · ${filterStatusPart}`;

  const hasSelectedInFiltered = filteredCalls.some((entry) => entry.id === salesPhoneSelectedCallId);
  if (!hasSelectedInFiltered) {
    salesPhoneSelectedCallId = String(filteredCalls[0]?.id || "");
  }
  const selectedCall = getSalesPhoneCallById(salesPhoneSelectedCallId);
  renderSalesPhoneDetail(selectedCall || null);
}

async function handleSalesPhoneCreateCall() {
  const providerId = String(els.salesPhoneProviderSelect?.value || "").trim();
  if (!providerId) {
    showWarningFeedback("Bitte Anbieter auswählen.");
    return;
  }
  const provider = getSalesPhoneProviderById(providerId);
  if (!provider) {
    showWarningFeedback("Anbieter nicht gefunden oder nicht sichtbar.");
    return;
  }
  const calls = getSalesPhoneCalls();
  const existingActivePlan = (buildSalesPhoneOpenPlanMap(calls).get(providerId) || [])[0] || null;
  if (existingActivePlan) {
    salesPhoneSelectedCallId = String(existingActivePlan.id || "").trim();
    renderSalesPhoneSection();
    const plannedByLabel = String(
      existingActivePlan.assigneeName || getUserDisplayNameByUserId(existingActivePlan.assigneeUserId) || "Mitarbeiter"
    ).trim();
    const plannedDateLabel = existingActivePlan.plannedDate ? formatTourDateLabel(existingActivePlan.plannedDate) : "ohne Datum";
    showInfoFeedback(`Dieser Anbieter ist bereits geplant (${plannedByLabel} · ${plannedDateLabel}).`);
    return;
  }
  const assigneeUserId = normalizeUserId(els.salesPhoneAssigneeSelect?.value || getCurrentActorInfo().userId || "");
  const assigneeName = getUserDisplayNameByUserId(assigneeUserId) || String(els.salesPhoneAssigneeSelect?.selectedOptions?.[0]?.textContent || "").trim();
  const plannedDate = sanitizeEmployeeAdminDate(els.salesPhonePlannedDate?.value || getTodayDateInputValue()) || getTodayDateInputValue();
  const planSlot = sanitizeSalesPhonePlanSlot(els.salesPhonePlanSlot?.value || "vormittag");
  const reminderAt = normalizeSalesPhoneReminderAt(els.salesPhoneReminderInput?.value || "");
  const actor = getCurrentActorInfo();
  const nowIso = new Date().toISOString();
  const duplicate = calls.find(
    (entry) =>
      String(entry.providerId || "").trim() === providerId &&
      sanitizeEmployeeAdminDate(entry.plannedDate) === plannedDate &&
      normalizeUserId(entry.assigneeUserId) === assigneeUserId &&
      !isSalesPhoneStatusFinal(entry.status)
  );
  if (duplicate) {
    salesPhoneSelectedCallId = duplicate.id;
    renderSalesPhoneSection();
    showInfoFeedback("Offener Anrufplan bereits vorhanden und wurde geöffnet.");
    return;
  }
  const nextCall = {
    id: createId("scall"),
    providerId,
    providerName: String(provider.name || "Anbieter").trim(),
    providerPhone: String(provider.phone || "").trim(),
    assigneeUserId,
    assigneeName: assigneeName || "Unbekannt",
    plannedDate,
    planSlot,
    status: "neu",
    reminderAt,
    lastContactAt: "",
    createdAt: nowIso,
    createdByUserId: actor.userId,
    createdByName: actor.name,
    createdByRole: actor.role,
    updatedAt: nowIso,
    updatedByUserId: actor.userId,
    updatedByName: actor.name,
    updatedByRole: actor.role,
    notes: [],
    tasks: [],
  };
  setSalesPhoneCalls(calls.concat(nextCall));
  salesPhoneSelectedCallId = nextCall.id;
  saveState({ showFeedback: false });
  renderSalesPhoneSection();
  showSuccessFeedback("Anrufplan angelegt.");
}

async function handleSalesPhoneDeleteCall() {
  const selectedCall = getSalesPhoneCallById(salesPhoneSelectedCallId);
  if (!selectedCall) {
    return;
  }
  const providerName = String(selectedCall.providerName || "Eintrag").trim();
  const confirmed = await confirmDeleteAction(`Anrufplan "${providerName}" wirklich löschen?`);
  if (!confirmed) {
    return;
  }
  const nextCalls = getSalesPhoneCalls().filter((entry) => entry.id !== selectedCall.id);
  setSalesPhoneCalls(nextCalls);
  salesPhoneSelectedCallId = String(nextCalls[0]?.id || "");
  saveState({ showFeedback: false });
  renderSalesPhoneSection();
  showSuccessFeedback("Anrufplan gelöscht.");
}

async function handleSalesPhoneDetailSave() {
  const selectedCall = getSalesPhoneCallById(salesPhoneSelectedCallId);
  if (!selectedCall) {
    return;
  }
  const nextStatus = sanitizeSalesPhoneStatus(els.salesPhoneDetailStatus?.value || selectedCall.status);
  const nextReminderAt = normalizeSalesPhoneReminderAt(els.salesPhoneDetailReminder?.value || "");
  const actor = getCurrentActorInfo();
  const nowIso = new Date().toISOString();
  const calls = getSalesPhoneCalls();
  const nextCalls = calls.map((entry) => {
    if (entry.id !== selectedCall.id) {
      return entry;
    }
    const shouldStampContact =
      nextStatus !== sanitizeSalesPhoneStatus(entry.status) &&
      ["erreicht", "kein_interesse", "interessiert", "angebot_gesendet", "termin_vereinbart", "abschluss"].includes(nextStatus);
    return normalizeSalesPhoneCallRecord({
      ...entry,
      status: nextStatus,
      reminderAt: nextReminderAt,
      lastContactAt: shouldStampContact ? nowIso : entry.lastContactAt,
      updatedAt: nowIso,
      updatedByUserId: actor.userId,
      updatedByName: actor.name,
      updatedByRole: actor.role,
    });
  }).filter(Boolean);
  setSalesPhoneCalls(nextCalls);
  saveState({ showFeedback: false });
  closeSalesPhoneModal("status");
  renderSalesPhoneSection();
  showSuccessFeedback("Status aktualisiert.");
}

async function handleSalesPhoneAddNote() {
  const selectedCall = getSalesPhoneCallById(salesPhoneSelectedCallId);
  if (!selectedCall) {
    return;
  }
  const noteText = String(els.salesPhoneNoteInput?.value || "").trim();
  if (!noteText) {
    showWarningFeedback("Bitte eine Notiz eingeben.");
    return;
  }
  const actor = getCurrentActorInfo();
  const nowIso = new Date().toISOString();
  const nextNote = {
    id: createId("snote"),
    text: noteText,
    createdAt: nowIso,
    createdByUserId: actor.userId,
    createdByName: actor.name,
    createdByRole: actor.role,
  };
  const calls = getSalesPhoneCalls();
  const nextCalls = calls.map((entry) => {
    if (entry.id !== selectedCall.id) {
      return entry;
    }
    return normalizeSalesPhoneCallRecord({
      ...entry,
      notes: (Array.isArray(entry.notes) ? entry.notes : []).concat(nextNote),
      lastContactAt: nowIso,
      updatedAt: nowIso,
      updatedByUserId: actor.userId,
      updatedByName: actor.name,
      updatedByRole: actor.role,
    });
  }).filter(Boolean);
  setSalesPhoneCalls(nextCalls);
  if (els.salesPhoneNoteInput) {
    els.salesPhoneNoteInput.value = "";
  }
  saveState({ showFeedback: false });
  closeSalesPhoneModal("note");
  renderSalesPhoneSection();
  showSuccessFeedback("Notiz gespeichert.");
}

async function handleSalesPhoneAddTask() {
  const selectedCall = getSalesPhoneCallById(salesPhoneSelectedCallId);
  if (!selectedCall) {
    return;
  }
  const title = String(els.salesPhoneTaskTitle?.value || "").trim();
  if (!title) {
    showWarningFeedback("Aufgabentitel fehlt.");
    return;
  }
  const assigneeUserId = normalizeUserId(els.salesPhoneTaskAssignee?.value || getCurrentActorInfo().userId || "");
  const assigneeName = getUserDisplayNameByUserId(assigneeUserId) || String(els.salesPhoneTaskAssignee?.selectedOptions?.[0]?.textContent || "").trim() || "Unbekannt";
  const dueDate = sanitizeEmployeeAdminDate(els.salesPhoneTaskDue?.value || "");
  const actor = getCurrentActorInfo();
  const nowIso = new Date().toISOString();
  const task = {
    id: createId("stask"),
    title,
    assigneeUserId,
    assigneeName,
    dueDate,
    status: "offen",
    createdAt: nowIso,
    createdByUserId: actor.userId,
    createdByName: actor.name,
    createdByRole: actor.role,
    updatedAt: nowIso,
    updatedByUserId: actor.userId,
    updatedByName: actor.name,
    updatedByRole: actor.role,
  };
  const calls = getSalesPhoneCalls();
  const nextCalls = calls.map((entry) => {
    if (entry.id !== selectedCall.id) {
      return entry;
    }
    return normalizeSalesPhoneCallRecord({
      ...entry,
      tasks: (Array.isArray(entry.tasks) ? entry.tasks : []).concat(task),
      updatedAt: nowIso,
      updatedByUserId: actor.userId,
      updatedByName: actor.name,
      updatedByRole: actor.role,
    });
  }).filter(Boolean);
  setSalesPhoneCalls(nextCalls);
  if (els.salesPhoneTaskTitle) {
    els.salesPhoneTaskTitle.value = "";
  }
  if (els.salesPhoneTaskDue) {
    els.salesPhoneTaskDue.value = "";
  }
  saveState({ showFeedback: false });
  closeSalesPhoneModal("task");
  renderSalesPhoneSection();
  showSuccessFeedback("Aufgabe angelegt.");
}

async function handleSalesPhoneTaskToggle(taskId, done) {
  const normalizedTaskId = String(taskId || "").trim();
  if (!normalizedTaskId) {
    return;
  }
  const selectedCall = getSalesPhoneCallById(salesPhoneSelectedCallId);
  if (!selectedCall) {
    return;
  }
  const actor = getCurrentActorInfo();
  const nowIso = new Date().toISOString();
  const calls = getSalesPhoneCalls();
  const nextCalls = calls.map((entry) => {
    if (entry.id !== selectedCall.id) {
      return entry;
    }
    const nextTasks = (Array.isArray(entry.tasks) ? entry.tasks : []).map((task) => {
      if (String(task.id || "").trim() !== normalizedTaskId) {
        return task;
      }
      return normalizeSalesPhoneTaskRecord({
        ...task,
        status: done ? "erledigt" : "offen",
        updatedAt: nowIso,
        updatedByUserId: actor.userId,
        updatedByName: actor.name,
        updatedByRole: actor.role,
      });
    }).filter(Boolean);
    return normalizeSalesPhoneCallRecord({
      ...entry,
      tasks: nextTasks,
      updatedAt: nowIso,
      updatedByUserId: actor.userId,
      updatedByName: actor.name,
      updatedByRole: actor.role,
    });
  }).filter(Boolean);
  setSalesPhoneCalls(nextCalls);
  saveState({ showFeedback: false });
  renderSalesPhoneSection();
  showSuccessFeedback(done ? "Aufgabe erledigt." : "Aufgabe geöffnet.");
}

async function handleSalesPhoneTaskDelete(taskId) {
  const normalizedTaskId = String(taskId || "").trim();
  if (!normalizedTaskId) {
    return;
  }
  const selectedCall = getSalesPhoneCallById(salesPhoneSelectedCallId);
  if (!selectedCall) {
    return;
  }
  const actor = getCurrentActorInfo();
  const nowIso = new Date().toISOString();
  const calls = getSalesPhoneCalls();
  const nextCalls = calls.map((entry) => {
    if (entry.id !== selectedCall.id) {
      return entry;
    }
    const nextTasks = (Array.isArray(entry.tasks) ? entry.tasks : []).filter(
      (task) => String(task.id || "").trim() !== normalizedTaskId
    );
    return normalizeSalesPhoneCallRecord({
      ...entry,
      tasks: nextTasks,
      updatedAt: nowIso,
      updatedByUserId: actor.userId,
      updatedByName: actor.name,
      updatedByRole: actor.role,
    });
  }).filter(Boolean);
  setSalesPhoneCalls(nextCalls);
  saveState({ showFeedback: false });
  renderSalesPhoneSection();
  showSuccessFeedback("Aufgabe gelöscht.");
}

function normalizeIncomingInvoicesView(value) {
  const normalized = String(value || "").trim().toLowerCase();
  if (["pending", "paid", "all"].includes(normalized)) {
    return normalized;
  }
  return "pending";
}

function normalizeIncomingInvoicesWorkspaceTab(value) {
  const normalized = String(value || "").trim().toLowerCase();
  if (normalized === "entry" || normalized === "overview") {
    return normalized;
  }
  return "overview";
}

function normalizeIncomingInvoiceApprovalStatus(value) {
  const normalized = normalizeText(value || "");
  return INCOMING_INVOICE_APPROVAL_STATUSES.has(normalized) ? normalized : "freigabe_offen";
}

function normalizeIncomingInvoicePaymentStatus(value) {
  const normalized = normalizeText(value || "");
  return INCOMING_INVOICE_PAYMENT_STATUSES.has(normalized) ? normalized : "offen";
}

function normalizeIncomingInvoicePaymentMethod(value) {
  const normalized = normalizeText(value || "");
  return INCOMING_INVOICE_PAYMENT_METHODS.has(normalized) ? normalized : "";
}

function normalizeIncomingInvoiceSupplierCompanyId(value) {
  return String(value || "").trim();
}

function normalizeIncomingInvoiceDateInputValue(value) {
  return sanitizeEmployeeAdminDate(value);
}

function normalizeIncomingInvoiceAmount(value) {
  const numeric = parseOptionalNumber(value);
  if (typeof numeric !== "number" || !Number.isFinite(numeric) || numeric < 0) {
    return 0;
  }
  return Math.round(numeric * 100) / 100;
}

function normalizeIncomingInvoiceRecord(entry, index = 0) {
  if (!entry || typeof entry !== "object") {
    return null;
  }
  const id = String(entry.id || "").trim() || `inv_${index + 1}`;
  const invoiceDate = normalizeIncomingInvoiceDateInputValue(entry.invoiceDate || entry.invoice_date || "");
  if (!id || !invoiceDate) {
    return null;
  }
  const dueDate = normalizeIncomingInvoiceDateInputValue(entry.dueDate || entry.due_date || "");
  const paidAtRaw = String(entry.paidAt || entry.paid_at || "").trim();
  const paidAtParsed = paidAtRaw ? new Date(`${paidAtRaw}`) : null;
  const paidAt = paidAtParsed && !Number.isNaN(paidAtParsed.getTime()) ? paidAtParsed.toISOString() : "";
  const createdAtRaw = String(entry.createdAt || entry.created_at || "").trim();
  const createdAt = Number.isNaN(new Date(createdAtRaw).getTime()) ? new Date().toISOString() : createdAtRaw;
  const updatedAtRaw = String(entry.updatedAt || entry.updated_at || createdAt).trim();
  const updatedAt = Number.isNaN(new Date(updatedAtRaw).getTime()) ? createdAt : updatedAtRaw;
  const approvalStatus = normalizeIncomingInvoiceApprovalStatus(entry.approvalStatus || entry.approval_status || "");
  const paymentStatus = normalizeIncomingInvoicePaymentStatus(entry.paymentStatus || entry.payment_status || "");
  return {
    id,
    invoiceNumber: String(entry.invoiceNumber || entry.invoice_number || "").trim(),
    supplierCompanyId: normalizeIncomingInvoiceSupplierCompanyId(entry.supplierCompanyId || entry.supplier_company_id || ""),
    supplierName: String(entry.supplierName || entry.supplier_name || "").trim(),
    supplierVatId: String(entry.supplierVatId || entry.supplier_vat_id || "").trim(),
    invoiceDate,
    dueDate,
    currency: String(entry.currency || "EUR").trim().toUpperCase() || "EUR",
    totalNet: normalizeIncomingInvoiceAmount(entry.totalNet || entry.total_net),
    totalTax: normalizeIncomingInvoiceAmount(entry.totalTax || entry.total_tax),
    totalGross: normalizeIncomingInvoiceAmount(entry.totalGross || entry.total_gross),
    category: String(entry.category || "").trim(),
    costCenter: String(entry.costCenter || entry.cost_center || "").trim(),
    notes: String(entry.notes || "").trim(),
    approvalStatus,
    paymentStatus,
    paidAt,
    paymentMethod: normalizeIncomingInvoicePaymentMethod(entry.paymentMethod || entry.payment_method || ""),
    externalBookingRef: String(entry.externalBookingRef || entry.external_booking_ref || "").trim(),
    createdAt,
    updatedAt,
    createdByUserId: normalizeUserId(entry.createdByUserId || entry.created_by_user_id || ""),
    updatedByUserId: normalizeUserId(entry.updatedByUserId || entry.updated_by_user_id || ""),
  };
}

function normalizeIncomingInvoices(rawList) {
  if (!Array.isArray(rawList)) {
    return [];
  }
  const seen = new Set();
  const rows = [];
  rawList.forEach((entry, index) => {
    const normalized = normalizeIncomingInvoiceRecord(entry, index);
    if (!normalized || seen.has(normalized.id)) {
      return;
    }
    seen.add(normalized.id);
    rows.push(normalized);
  });
  return rows.sort((left, right) => {
    const leftKey = `${left.invoiceDate}|${left.updatedAt}`;
    const rightKey = `${right.invoiceDate}|${right.updatedAt}`;
    return rightKey.localeCompare(leftKey);
  });
}

function normalizeIncomingInvoiceFileRecord(entry, index = 0) {
  if (!entry || typeof entry !== "object") {
    return null;
  }
  const id = String(entry.id || "").trim() || `ifile_${index + 1}`;
  const invoiceId = String(entry.invoiceId || entry.invoice_id || "").trim();
  if (!id || !invoiceId) {
    return null;
  }
  const uploadedAtRaw = String(entry.uploadedAt || entry.uploaded_at || "").trim();
  const uploadedAt = Number.isNaN(new Date(uploadedAtRaw).getTime()) ? new Date().toISOString() : uploadedAtRaw;
  return {
    id,
    invoiceId,
    storageMode: String(entry.storageMode || entry.storage_mode || "nas").trim().toLowerCase(),
    nasPath: String(entry.nasPath || entry.nas_path || "").trim(),
    originalName: String(entry.originalName || entry.original_name || "").trim(),
    mimeType: String(entry.mimeType || entry.mime_type || "application/pdf").trim(),
    sizeBytes: Math.max(0, Number(entry.sizeBytes || entry.size_bytes || 0) || 0),
    uploadedAt,
    uploadedByUserId: normalizeUserId(entry.uploadedByUserId || entry.uploaded_by_user_id || ""),
  };
}

function normalizeIncomingInvoiceFiles(rawList) {
  if (!Array.isArray(rawList)) {
    return [];
  }
  const seen = new Set();
  const rows = [];
  rawList.forEach((entry, index) => {
    const normalized = normalizeIncomingInvoiceFileRecord(entry, index);
    if (!normalized || seen.has(normalized.id)) {
      return;
    }
    seen.add(normalized.id);
    rows.push(normalized);
  });
  return rows.sort((left, right) => String(right.uploadedAt || "").localeCompare(String(left.uploadedAt || "")));
}

function normalizeIncomingInvoiceEventRecord(entry, index = 0) {
  if (!entry || typeof entry !== "object") {
    return null;
  }
  const id = String(entry.id || "").trim() || `ievt_${index + 1}`;
  const invoiceId = String(entry.invoiceId || entry.invoice_id || "").trim();
  if (!id || !invoiceId) {
    return null;
  }
  const createdAtRaw = String(entry.createdAt || entry.created_at || "").trim();
  const createdAt = Number.isNaN(new Date(createdAtRaw).getTime()) ? new Date().toISOString() : createdAtRaw;
  return {
    id,
    invoiceId,
    eventType: String(entry.eventType || entry.event_type || "updated").trim(),
    payload: entry.payload && typeof entry.payload === "object" ? entry.payload : {},
    createdAt,
    createdByUserId: normalizeUserId(entry.createdByUserId || entry.created_by_user_id || ""),
  };
}

function normalizeIncomingInvoiceEvents(rawList) {
  if (!Array.isArray(rawList)) {
    return [];
  }
  const seen = new Set();
  const rows = [];
  rawList.forEach((entry, index) => {
    const normalized = normalizeIncomingInvoiceEventRecord(entry, index);
    if (!normalized || seen.has(normalized.id)) {
      return;
    }
    seen.add(normalized.id);
    rows.push(normalized);
  });
  return rows.sort((left, right) => String(right.createdAt || "").localeCompare(String(left.createdAt || "")));
}

function applyIncomingInvoicesCache(nextInvoices, nextFiles, nextEvents, options = {}) {
  incomingInvoices = normalizeIncomingInvoices(nextInvoices || []);
  incomingInvoiceFiles = normalizeIncomingInvoiceFiles(nextFiles || []);
  incomingInvoiceEvents = normalizeIncomingInvoiceEvents(nextEvents || []);
  state.settings = normalizeSettings({
    ...state.settings,
    incomingInvoices,
    incomingInvoiceFiles,
    incomingInvoiceEvents,
  });
  if (options?.persistBackup !== false) {
    persistLocalBackup();
  }
}

function getIncomingInvoicesLocalFallback() {
  return {
    invoices: normalizeIncomingInvoices(state.settings?.incomingInvoices || []),
    files: normalizeIncomingInvoiceFiles(state.settings?.incomingInvoiceFiles || []),
    events: normalizeIncomingInvoiceEvents(state.settings?.incomingInvoiceEvents || []),
  };
}

function getIncomingInvoices() {
  return normalizeIncomingInvoices(incomingInvoices || []);
}

function getIncomingInvoiceById(invoiceId) {
  const normalizedId = String(invoiceId || "").trim();
  if (!normalizedId) {
    return null;
  }
  return getIncomingInvoices().find((entry) => entry.id === normalizedId) || null;
}

function getIncomingInvoiceSupplierCompanies() {
  return getConversationOrganizations()
    .slice()
    .sort((left, right) => String(left?.name || "").localeCompare(String(right?.name || ""), "de", { sensitivity: "base" }));
}

function renderIncomingInvoiceSupplierOptions(selectedCompanyId = "", fallbackSupplierName = "") {
  if (!els.incomingInvoiceSupplier) {
    return "";
  }
  const companies = getIncomingInvoiceSupplierCompanies();
  const selectedId = normalizeIncomingInvoiceSupplierCompanyId(selectedCompanyId);
  const fallbackName = String(fallbackSupplierName || "").trim();
  const optionRows = [];
  optionRows.push(`<option value="">${companies.length ? "Firma wählen..." : "Keine Firmen vorhanden"}</option>`);
  companies.forEach((company) => {
    const companyId = String(company?.id || "").trim();
    const name = String(company?.name || "").trim();
    if (!companyId || !name) {
      return;
    }
    const locationLabel = [String(company?.postalCode || "").trim(), String(company?.city || "").trim(), String(company?.country || "").trim()]
      .filter(Boolean)
      .join(" ");
    const label = locationLabel ? `${name} · ${locationLabel}` : name;
    optionRows.push(`<option value="${escapeHtml(companyId)}">${escapeHtml(label)}</option>`);
  });
  if (fallbackName && !companies.some((entry) => normalizeText(entry?.name || "") === normalizeText(fallbackName))) {
    optionRows.push(`<option value="__legacy_supplier__">${escapeHtml(`${fallbackName} (Altbestand)`)}</option>`);
  }
  els.incomingInvoiceSupplier.innerHTML = optionRows.join("");
  els.incomingInvoiceSupplier.disabled = companies.length === 0;
  if (els.incomingInvoiceSaveBtn) {
    els.incomingInvoiceSaveBtn.disabled = companies.length === 0;
  }
  if (selectedId && companies.some((entry) => String(entry?.id || "").trim() === selectedId)) {
    els.incomingInvoiceSupplier.value = selectedId;
    return selectedId;
  }
  if (fallbackName && els.incomingInvoiceSupplier.querySelector('option[value="__legacy_supplier__"]')) {
    els.incomingInvoiceSupplier.value = "__legacy_supplier__";
    return "__legacy_supplier__";
  }
  els.incomingInvoiceSupplier.value = "";
  return "";
}

function getIncomingInvoiceFileForInvoice(invoiceId) {
  const normalizedId = String(invoiceId || "").trim();
  if (!normalizedId) {
    return null;
  }
  return (
    normalizeIncomingInvoiceFiles(incomingInvoiceFiles || []).find((entry) => String(entry.invoiceId || "").trim() === normalizedId) ||
    null
  );
}

function getIncomingInvoiceApprovalLabel(status) {
  const normalized = normalizeIncomingInvoiceApprovalStatus(status);
  if (normalized === "freigegeben") {
    return "Freigegeben";
  }
  if (normalized === "abgelehnt") {
    return "Abgelehnt";
  }
  if (normalized === "nicht_noetig") {
    return "Nicht nötig";
  }
  return "Freigabe offen";
}

function getIncomingInvoicePaymentLabel(status) {
  const normalized = normalizeIncomingInvoicePaymentStatus(status);
  if (normalized === "bezahlt") {
    return "Bezahlt";
  }
  if (normalized === "teilbezahlt") {
    return "Teilbezahlt";
  }
  return "Offen";
}

function formatIncomingInvoiceMoney(amount, currency = "EUR") {
  const numeric = Number(amount || 0);
  const safe = Number.isFinite(numeric) ? numeric : 0;
  return new Intl.NumberFormat("de-AT", {
    style: "currency",
    currency: String(currency || "EUR").trim().toUpperCase() || "EUR",
  }).format(safe);
}

function isIncomingInvoiceOverdue(invoice) {
  const dueDate = normalizeIncomingInvoiceDateInputValue(invoice?.dueDate || "");
  if (!dueDate) {
    return false;
  }
  if (normalizeIncomingInvoicePaymentStatus(invoice?.paymentStatus) === "bezahlt") {
    return false;
  }
  return dueDate < getTodayDateInputValue();
}

function normalizeIncomingInvoiceApprovalFilter(value) {
  const normalized = String(value || "").trim();
  if (!normalized || normalizeText(normalized) === "all") {
    return "all";
  }
  return normalizeIncomingInvoiceApprovalStatus(normalized);
}

function normalizeIncomingInvoicePaymentFilter(value) {
  const normalized = String(value || "").trim();
  if (!normalized || normalizeText(normalized) === "all") {
    return "all";
  }
  return normalizeIncomingInvoicePaymentStatus(normalized);
}

function setIncomingInvoicesView(nextView, options = {}) {
  incomingInvoicesView = normalizeIncomingInvoicesView(nextView);
  const activeView = incomingInvoicesView;
  els.incomingInvoicesViewButtons?.forEach((button) => {
    const target = normalizeIncomingInvoicesView(button.dataset.incomingInvoicesViewTarget || "");
    const isActive = target === activeView;
    button.classList.toggle("is-active", isActive);
    setTabButtonA11yState(button, isActive);
  });
  if (options?.render !== false) {
    renderIncomingInvoicesSection();
  }
}

function setIncomingInvoicesWorkspaceTab(nextTab, options = {}) {
  incomingInvoicesWorkspaceTab = normalizeIncomingInvoicesWorkspaceTab(nextTab);
  const activeTab = incomingInvoicesWorkspaceTab;
  els.incomingInvoicesWorkspaceTabButtons?.forEach((button) => {
    const target = normalizeIncomingInvoicesWorkspaceTab(button.dataset.incomingInvoicesWorkspaceTab || "");
    const isActive = target === activeTab;
    button.classList.toggle("is-active", isActive);
    setTabButtonA11yState(button, isActive);
  });
  els.incomingInvoicesWorkspacePanels?.forEach((panel) => {
    const target = normalizeIncomingInvoicesWorkspaceTab(panel.dataset.incomingInvoicesWorkspacePanel || "");
    const isActive = target === activeTab;
    panel.classList.toggle("hidden", !isActive);
    setTabPanelA11yState(panel, isActive);
  });
  if (options?.render !== false) {
    renderIncomingInvoicesSection();
  }
}

function renderIncomingInvoicesKpis(rows) {
  if (!els.incomingInvoicesKpis) {
    return;
  }
  const stats = {
    openApprovalAmount: 0,
    paidAmount: 0,
    overdueCount: 0,
    totalCount: 0,
  };
  (Array.isArray(rows) ? rows : []).forEach((entry) => {
    stats.totalCount += 1;
    const approvalStatus = normalizeIncomingInvoiceApprovalStatus(entry?.approvalStatus);
    const paymentStatus = normalizeIncomingInvoicePaymentStatus(entry?.paymentStatus);
    const gross = normalizeIncomingInvoiceAmount(entry?.totalGross);
    if (approvalStatus === "freigabe_offen" && paymentStatus !== "bezahlt") {
      stats.openApprovalAmount += gross;
    }
    if (paymentStatus === "bezahlt") {
      stats.paidAmount += gross;
    }
    if (isIncomingInvoiceOverdue(entry)) {
      stats.overdueCount += 1;
    }
  });
  els.incomingInvoicesKpis.innerHTML = `
    <article class="incoming-invoices-kpi">
      <span>Freigabe offen</span>
      <strong>${escapeHtml(formatIncomingInvoiceMoney(stats.openApprovalAmount))}</strong>
    </article>
    <article class="incoming-invoices-kpi">
      <span>Bereits bezahlt</span>
      <strong>${escapeHtml(formatIncomingInvoiceMoney(stats.paidAmount))}</strong>
    </article>
    <article class="incoming-invoices-kpi">
      <span>Überfällig</span>
      <strong>${escapeHtml(String(stats.overdueCount))}</strong>
    </article>
    <article class="incoming-invoices-kpi">
      <span>Rechnungen</span>
      <strong>${escapeHtml(String(stats.totalCount))}</strong>
    </article>
  `;
}

function matchesIncomingInvoiceDateRange(invoice, fromDate, toDate) {
  if (!fromDate && !toDate) {
    return true;
  }
  const invoiceDate = parseDateInputStart(normalizeIncomingInvoiceDateInputValue(invoice?.invoiceDate || ""));
  if (!invoiceDate) {
    return false;
  }
  if (fromDate && invoiceDate < fromDate) {
    return false;
  }
  if (toDate) {
    const toEnd = new Date(toDate.getTime());
    toEnd.setDate(toEnd.getDate() + 1);
    if (invoiceDate >= toEnd) {
      return false;
    }
  }
  return true;
}

function getFilteredIncomingInvoices() {
  const searchNeedle = normalizeText(incomingInvoicesSearchTerm || "");
  const fromDate = parseDateInputStart(incomingInvoicesDateFrom);
  const toDate = parseDateInputStart(incomingInvoicesDateTo);
  return getIncomingInvoices().filter((entry) => {
    const approvalStatus = normalizeIncomingInvoiceApprovalStatus(entry?.approvalStatus);
    const paymentStatus = normalizeIncomingInvoicePaymentStatus(entry?.paymentStatus);

    if (incomingInvoicesView === "pending") {
      if (!(approvalStatus === "freigabe_offen" && paymentStatus !== "bezahlt")) {
        return false;
      }
    } else if (incomingInvoicesView === "paid" && paymentStatus !== "bezahlt") {
      return false;
    }

    if (incomingInvoicesApprovalFilter !== "all" && approvalStatus !== incomingInvoicesApprovalFilter) {
      return false;
    }
    if (incomingInvoicesPaymentFilter !== "all" && paymentStatus !== incomingInvoicesPaymentFilter) {
      return false;
    }
    if (!matchesIncomingInvoiceDateRange(entry, fromDate, toDate)) {
      return false;
    }
    if (searchNeedle) {
      const haystack = normalizeText(
        [
          entry.invoiceNumber,
          entry.supplierName,
          entry.category,
          entry.costCenter,
          entry.notes,
          entry.externalBookingRef,
          getIncomingInvoiceApprovalLabel(approvalStatus),
          getIncomingInvoicePaymentLabel(paymentStatus),
        ]
          .filter(Boolean)
          .join(" ")
      );
      if (!haystack.includes(searchNeedle)) {
        return false;
      }
    }
    return true;
  });
}

function syncIncomingInvoiceFilterControls() {
  if (els.incomingInvoicesSearchInput && els.incomingInvoicesSearchInput.value !== incomingInvoicesSearchTerm) {
    els.incomingInvoicesSearchInput.value = incomingInvoicesSearchTerm;
  }
  if (els.incomingInvoicesFilterApproval) {
    incomingInvoicesApprovalFilter = normalizeIncomingInvoiceApprovalFilter(incomingInvoicesApprovalFilter);
    if (els.incomingInvoicesFilterApproval.value !== incomingInvoicesApprovalFilter) {
      els.incomingInvoicesFilterApproval.value = incomingInvoicesApprovalFilter;
    }
  }
  if (els.incomingInvoicesFilterPayment) {
    incomingInvoicesPaymentFilter = normalizeIncomingInvoicePaymentFilter(incomingInvoicesPaymentFilter);
    if (els.incomingInvoicesFilterPayment.value !== incomingInvoicesPaymentFilter) {
      els.incomingInvoicesFilterPayment.value = incomingInvoicesPaymentFilter;
    }
  }
  if (els.incomingInvoicesDateFrom && els.incomingInvoicesDateFrom.value !== incomingInvoicesDateFrom) {
    els.incomingInvoicesDateFrom.value = incomingInvoicesDateFrom;
  }
  if (els.incomingInvoicesDateTo && els.incomingInvoicesDateTo.value !== incomingInvoicesDateTo) {
    els.incomingInvoicesDateTo.value = incomingInvoicesDateTo;
  }
}

function getIncomingInvoiceApprovalCssClass(status) {
  const normalized = normalizeIncomingInvoiceApprovalStatus(status);
  if (normalized === "freigegeben") {
    return "is-approved";
  }
  if (normalized === "freigabe_offen") {
    return "is-approval-open";
  }
  if (normalized === "abgelehnt") {
    return "is-approval-open";
  }
  return "";
}

function getIncomingInvoicePaymentCssClass(status) {
  const normalized = normalizeIncomingInvoicePaymentStatus(status);
  if (normalized === "bezahlt") {
    return "is-paid";
  }
  if (normalized === "teilbezahlt") {
    return "is-partial";
  }
  return "";
}

function renderIncomingInvoicesSection() {
  if (!els.incomingInvoicesTableBody) {
    return;
  }
  renderIncomingInvoiceSupplierOptions(els.incomingInvoiceSupplier?.value || "");
  setIncomingInvoicesWorkspaceTab(incomingInvoicesWorkspaceTab, { render: false });
  setIncomingInvoicesView(incomingInvoicesView, { render: false });
  syncIncomingInvoiceFilterControls();
  const rows = getFilteredIncomingInvoices();
  renderIncomingInvoicesKpis(rows);

  if (!rows.length) {
    els.incomingInvoicesTableBody.innerHTML = '<tr><td colspan="8" class="empty">Keine Rechnungen im gewählten Filter.</td></tr>';
  } else {
    els.incomingInvoicesTableBody.innerHTML = rows
      .map((entry) => {
        const approvalLabel = getIncomingInvoiceApprovalLabel(entry.approvalStatus);
        const paymentLabel = getIncomingInvoicePaymentLabel(entry.paymentStatus);
        const approvalClass = getIncomingInvoiceApprovalCssClass(entry.approvalStatus);
        const paymentClass = getIncomingInvoicePaymentCssClass(entry.paymentStatus);
        const file = getIncomingInvoiceFileForInvoice(entry.id);
        const hasDocument = Boolean(String(file?.nasPath || "").trim() || String(file?.originalName || "").trim());
        const overdueBadge = isIncomingInvoiceOverdue(entry) ? " · überfällig" : "";
        const canMarkPaid =
          normalizeIncomingInvoicePaymentStatus(entry.paymentStatus) !== "bezahlt" &&
          normalizeIncomingInvoiceApprovalStatus(entry.approvalStatus) !== "freigabe_offen";
        return `
          <tr>
            <td>${escapeHtml(entry.invoiceNumber || "–")}</td>
            <td>
              ${
                entry.supplierName
                  ? `<button
                      type="button"
                      class="entity-link-btn"
                      data-incoming-invoice-open-company="${escapeHtml(String(entry.supplierCompanyId || "").trim())}"
                      data-incoming-invoice-open-company-name="${escapeHtml(String(entry.supplierName || "").trim())}"
                    >${escapeHtml(entry.supplierName)}</button>`
                  : "–"
              }
            </td>
            <td>${escapeHtml(entry.invoiceDate ? formatTourDateLabel(entry.invoiceDate) : "–")}</td>
            <td>${escapeHtml(entry.dueDate ? `${formatTourDateLabel(entry.dueDate)}${overdueBadge}` : "–")}</td>
            <td>${escapeHtml(formatIncomingInvoiceMoney(entry.totalGross, entry.currency || "EUR"))}</td>
            <td><span class="incoming-invoices-pill ${escapeHtml(approvalClass)}">${escapeHtml(approvalLabel)}</span></td>
            <td><span class="incoming-invoices-pill ${escapeHtml(paymentClass)}">${escapeHtml(paymentLabel)}</span></td>
            <td>
              <div class="incoming-invoices-actions-inline">
                <button type="button" class="mini-btn" data-incoming-invoice-edit="${escapeHtml(entry.id)}">Bearbeiten</button>
                <button type="button" class="mini-btn" data-incoming-invoice-approve="${escapeHtml(entry.id)}">Freigeben</button>
                <button type="button" class="mini-btn danger" data-incoming-invoice-reject="${escapeHtml(entry.id)}">Ablehnen</button>
                ${
                  hasDocument
                    ? `<button type="button" class="mini-btn" data-incoming-invoice-open-document="${escapeHtml(entry.id)}">Beleg öffnen</button>`
                    : ""
                }
                ${
                  canMarkPaid
                    ? `<button type="button" class="mini-btn" data-incoming-invoice-paid="${escapeHtml(entry.id)}">Bezahlt</button>`
                    : ""
                }
              </div>
            </td>
          </tr>
        `;
      })
      .join("");
  }
  if (els.incomingInvoicesTableMeta) {
    const modeText =
      incomingInvoicesView === "paid"
        ? "Bereits bezahlt"
        : incomingInvoicesView === "pending"
          ? "Freigabe offen"
          : "Alle";
    const remoteNote = incomingInvoicesRemoteUnavailable ? " · Lokaler Fallback aktiv" : "";
    els.incomingInvoicesTableMeta.textContent = `${rows.length} Einträge · Ansicht: ${modeText}${remoteNote}`;
  }
}

function resetIncomingInvoiceForm() {
  if (els.incomingInvoiceForm) {
    els.incomingInvoiceForm.reset();
  }
  if (els.incomingInvoiceId) {
    els.incomingInvoiceId.value = "";
  }
  if (els.incomingInvoiceApprovalStatus) {
    els.incomingInvoiceApprovalStatus.value = "freigabe_offen";
  }
  if (els.incomingInvoicePaymentStatus) {
    els.incomingInvoicePaymentStatus.value = "offen";
  }
  if (els.incomingInvoiceDate && !els.incomingInvoiceDate.value) {
    els.incomingInvoiceDate.value = getTodayDateInputValue();
  }
  if (els.incomingInvoiceFileUpload) {
    els.incomingInvoiceFileUpload.value = "";
  }
  incomingInvoicesPendingFile = null;
  renderIncomingInvoiceSupplierOptions();
  incomingInvoicesSelectedId = "";
  if (els.incomingInvoiceSaveBtn) {
    els.incomingInvoiceSaveBtn.textContent = "Rechnung speichern";
  }
}

function fillIncomingInvoiceForm(invoice) {
  if (!invoice) {
    return;
  }
  const file = getIncomingInvoiceFileForInvoice(invoice.id);
  incomingInvoicesSelectedId = String(invoice.id || "").trim();
  if (els.incomingInvoiceId) {
    els.incomingInvoiceId.value = incomingInvoicesSelectedId;
  }
  if (els.incomingInvoiceNumber) {
    els.incomingInvoiceNumber.value = invoice.invoiceNumber || "";
  }
  if (els.incomingInvoiceSupplier) {
    renderIncomingInvoiceSupplierOptions(invoice.supplierCompanyId || "", invoice.supplierName || "");
  }
  if (els.incomingInvoiceDate) {
    els.incomingInvoiceDate.value = normalizeIncomingInvoiceDateInputValue(invoice.invoiceDate);
  }
  if (els.incomingInvoiceDueDate) {
    els.incomingInvoiceDueDate.value = normalizeIncomingInvoiceDateInputValue(invoice.dueDate);
  }
  if (els.incomingInvoiceTotalGross) {
    els.incomingInvoiceTotalGross.value = String(normalizeIncomingInvoiceAmount(invoice.totalGross));
  }
  if (els.incomingInvoiceTotalNet) {
    els.incomingInvoiceTotalNet.value = String(normalizeIncomingInvoiceAmount(invoice.totalNet));
  }
  if (els.incomingInvoiceTotalTax) {
    els.incomingInvoiceTotalTax.value = String(normalizeIncomingInvoiceAmount(invoice.totalTax));
  }
  if (els.incomingInvoiceCategory) {
    els.incomingInvoiceCategory.value = invoice.category || "";
  }
  if (els.incomingInvoiceCostCenter) {
    els.incomingInvoiceCostCenter.value = invoice.costCenter || "";
  }
  if (els.incomingInvoiceApprovalStatus) {
    els.incomingInvoiceApprovalStatus.value = normalizeIncomingInvoiceApprovalStatus(invoice.approvalStatus);
  }
  if (els.incomingInvoicePaymentStatus) {
    els.incomingInvoicePaymentStatus.value = normalizeIncomingInvoicePaymentStatus(invoice.paymentStatus);
  }
  if (els.incomingInvoicePaidAt) {
    const paidAtDate = String(invoice.paidAt || "").trim();
    els.incomingInvoicePaidAt.value = paidAtDate ? paidAtDate.slice(0, 10) : "";
  }
  if (els.incomingInvoicePaymentMethod) {
    els.incomingInvoicePaymentMethod.value = normalizeIncomingInvoicePaymentMethod(invoice.paymentMethod);
  }
  if (els.incomingInvoiceFileName) {
    els.incomingInvoiceFileName.value = file?.originalName || "";
  }
  if (els.incomingInvoiceFileUpload) {
    els.incomingInvoiceFileUpload.value = "";
  }
  incomingInvoicesPendingFile = null;
  if (els.incomingInvoiceNasPath) {
    els.incomingInvoiceNasPath.value = file?.nasPath || "";
  }
  if (els.incomingInvoiceNotes) {
    els.incomingInvoiceNotes.value = invoice.notes || "";
  }
  if (els.incomingInvoiceSaveBtn) {
    els.incomingInvoiceSaveBtn.textContent = "Rechnung aktualisieren";
  }
}

function buildIncomingInvoicePayloadFromForm() {
  const invoiceDate = normalizeIncomingInvoiceDateInputValue(els.incomingInvoiceDate?.value || "");
  const invoiceNumber = String(els.incomingInvoiceNumber?.value || "").trim();
  const selectedSupplierValue = String(els.incomingInvoiceSupplier?.value || "").trim();
  const selectedSupplierOption = els.incomingInvoiceSupplier?.selectedOptions?.[0] || null;
  const supplierCompanyId = selectedSupplierValue === "__legacy_supplier__" ? "" : normalizeIncomingInvoiceSupplierCompanyId(selectedSupplierValue);
  const supplierNameRaw = selectedSupplierOption ? String(selectedSupplierOption.textContent || "").trim() : "";
  const supplierName = supplierNameRaw
    .replace(/\s·\s[^·]*$/, "")
    .replace(/\s\(Altbestand\)\s*$/i, "")
    .trim();
  const totalGross = normalizeIncomingInvoiceAmount(els.incomingInvoiceTotalGross?.value || 0);
  const approvalStatus = normalizeIncomingInvoiceApprovalStatus(els.incomingInvoiceApprovalStatus?.value || "freigabe_offen");
  const paymentStatus = normalizeIncomingInvoicePaymentStatus(els.incomingInvoicePaymentStatus?.value || "offen");
  if (!invoiceDate) {
    showWarningFeedback("Rechnungsdatum fehlt.");
    return null;
  }
  if (!invoiceNumber) {
    showWarningFeedback("Rechnungsnummer fehlt.");
    return null;
  }
  if (!supplierCompanyId || !supplierName) {
    showWarningFeedback("Bitte Lieferant aus Firmen auswählen.");
    return null;
  }
  if (totalGross <= 0) {
    showWarningFeedback("Bruttobetrag muss größer als 0 sein.");
    return null;
  }
  if (paymentStatus === "bezahlt" && approvalStatus === "freigabe_offen") {
    showWarningFeedback("Bezahlt ist erst nach Freigabe möglich.");
    return null;
  }
  const paidAtDate = normalizeIncomingInvoiceDateInputValue(els.incomingInvoicePaidAt?.value || "");
  return {
    invoiceNumber,
    supplierCompanyId,
    supplierName,
    invoiceDate,
    dueDate: normalizeIncomingInvoiceDateInputValue(els.incomingInvoiceDueDate?.value || ""),
    totalGross,
    totalNet: normalizeIncomingInvoiceAmount(els.incomingInvoiceTotalNet?.value || 0),
    totalTax: normalizeIncomingInvoiceAmount(els.incomingInvoiceTotalTax?.value || 0),
    category: String(els.incomingInvoiceCategory?.value || "").trim(),
    costCenter: String(els.incomingInvoiceCostCenter?.value || "").trim(),
    approvalStatus,
    paymentStatus,
    paidAt: paidAtDate ? `${paidAtDate}T00:00:00.000Z` : "",
    paymentMethod: normalizeIncomingInvoicePaymentMethod(els.incomingInvoicePaymentMethod?.value || ""),
    notes: String(els.incomingInvoiceNotes?.value || "").trim(),
    fileName: String(els.incomingInvoiceFileName?.value || "").trim(),
    nasPath: String(els.incomingInvoiceNasPath?.value || "").trim(),
  };
}

async function hydrateIncomingInvoicesFromSupabase(options = {}) {
  if (incomingInvoicesLoadingRemote) {
    return;
  }
  const force = options?.force === true;
  if (!force && (incomingInvoicesLoadedRemote || incomingInvoicesRemoteUnavailable)) {
    return;
  }
  const client = getSupabaseClient();
  if (!client) {
    const fallback = getIncomingInvoicesLocalFallback();
    applyIncomingInvoicesCache(fallback.invoices, fallback.files, fallback.events, { persistBackup: false });
    incomingInvoicesLoadedRemote = true;
    return;
  }

  incomingInvoicesLoadingRemote = true;
  try {
    const invoicesTable = getIncomingInvoicesTable();
    const filesTable = getIncomingInvoiceFilesTable();
    const eventsTable = getIncomingInvoiceEventsTable();
    const [invoicesResult, filesResult, eventsResult] = await Promise.all([
      client.from(invoicesTable).select("*").order("invoice_date", { ascending: false }),
      client.from(filesTable).select("*").order("uploaded_at", { ascending: false }),
      client.from(eventsTable).select("*").order("created_at", { ascending: false }),
    ]);
    const failures = [invoicesResult, filesResult, eventsResult].filter((result) => result.error);
    if (failures.length) {
      const remoteUnavailable = failures.some(
        (result) =>
          isSupabaseMissingRelationError(result.error) ||
          isSupabaseWritePermissionError(result.error) ||
          String(result.error?.code || "").trim() === "42501"
      );
      if (remoteUnavailable) {
        incomingInvoicesRemoteUnavailable = true;
        if (!incomingInvoicesRemoteWarningShown) {
          showWarningFeedback(
            `Rechnungsmodul läuft im lokalen Fallback. Bitte SQL-Patch "${getIncomingInvoicesTable()}" / "${getIncomingInvoiceFilesTable()}" ausführen.`
          );
          incomingInvoicesRemoteWarningShown = true;
        }
        const fallback = getIncomingInvoicesLocalFallback();
        applyIncomingInvoicesCache(fallback.invoices, fallback.files, fallback.events, { persistBackup: false });
        incomingInvoicesLoadedRemote = true;
        return;
      }
      throw failures[0].error;
    }
    applyIncomingInvoicesCache(invoicesResult.data || [], filesResult.data || [], eventsResult.data || [], {
      persistBackup: true,
    });
    incomingInvoicesLoadedRemote = true;
    incomingInvoicesRemoteUnavailable = false;
  } catch (error) {
    console.warn("Eingangsrechnungen konnten nicht aus Supabase geladen werden.", error);
    incomingInvoicesRemoteUnavailable = true;
    const fallback = getIncomingInvoicesLocalFallback();
    applyIncomingInvoicesCache(fallback.invoices, fallback.files, fallback.events, { persistBackup: false });
    incomingInvoicesLoadedRemote = true;
  } finally {
    incomingInvoicesLoadingRemote = false;
  }
}

async function readIncomingInvoiceBridgePayload(response) {
  try {
    return await response.json();
  } catch (_error) {
    return null;
  }
}

function getIncomingInvoiceBridgeErrorMessage(response, payload) {
  const code = Number(response?.status || 0);
  const errorText =
    String(payload?.error || payload?.message || payload?.detail || "").trim() || `HTTP ${code || "Fehler"}`;
  return errorText;
}

async function uploadIncomingInvoiceDocument(invoiceId, fileBlob) {
  const normalizedInvoiceId = String(invoiceId || "").trim();
  const file = fileBlob instanceof File ? fileBlob : null;
  if (!normalizedInvoiceId || !file) {
    return null;
  }
  if (file.size > INCOMING_INVOICE_UPLOAD_MAX_BYTES) {
    throw new Error(`Datei ist zu gross. Maximal ${Math.round(INCOMING_INVOICE_UPLOAD_MAX_BYTES / 1024 / 1024)} MB.`);
  }
  const accessToken = await getAuthAccessToken();
  const formData = new FormData();
  formData.set("file", file, String(file.name || "beleg"));
  formData.set("invoiceId", normalizedInvoiceId);
  const response = await fetch(INCOMING_INVOICE_FILE_UPLOAD_ENDPOINT, {
    method: "POST",
    headers: accessToken ? { Authorization: `Bearer ${accessToken}` } : {},
    body: formData,
  });
  const payload = await readIncomingInvoiceBridgePayload(response);
  if (!response.ok) {
    throw new Error(getIncomingInvoiceBridgeErrorMessage(response, payload));
  }
  const storedPath = String(
    payload?.document_path || payload?.documentPath || payload?.nas_path || payload?.path || payload?.ref || ""
  ).trim();
  const storedName = String(payload?.original_name || payload?.originalName || payload?.file_name || payload?.fileName || file.name).trim();
  return {
    originalName: storedName || String(file.name || "beleg"),
    documentPath: storedPath,
    mimeType: String(payload?.mime_type || payload?.mimeType || file.type || "application/octet-stream").trim(),
    sizeBytes: Math.max(0, Number(payload?.size_bytes ?? payload?.sizeBytes ?? file.size) || 0),
  };
}

async function upsertIncomingInvoiceFileRemote(invoiceId, fileName, nasPath, mimeType = "application/pdf", sizeBytes = 0) {
  const normalizedInvoiceId = String(invoiceId || "").trim();
  if (!normalizedInvoiceId) {
    return;
  }
  const normalizedFileName = String(fileName || "").trim();
  const normalizedNasPath = String(nasPath || "").trim();
  if (!normalizedFileName && !normalizedNasPath) {
    return;
  }
  const client = getSupabaseClient();
  if (!client || incomingInvoicesRemoteUnavailable) {
    return;
  }
  const payload = {
    invoice_id: normalizedInvoiceId,
    storage_mode: "supabase",
    nas_path:
      normalizedNasPath || `/invoices/${getTodayDateInputValue().slice(0, 7).replace("-", "/")}/${normalizedFileName || "rechnung.pdf"}`,
    original_name: normalizedFileName || "rechnung.pdf",
    mime_type: String(mimeType || "application/pdf").trim() || "application/pdf",
    size_bytes: Math.max(0, Number(sizeBytes) || 0),
    uploaded_by_user_id: getAuthUid() || null,
  };
  await client.from(getIncomingInvoiceFilesTable()).delete().eq("invoice_id", normalizedInvoiceId);
  const { error } = await client.from(getIncomingInvoiceFilesTable()).insert(payload);
  if (error && !isSupabaseMissingRelationError(error, getIncomingInvoiceFilesTable())) {
    console.warn("Rechnungsdatei-Metadaten konnten nicht gespeichert werden.", error);
  }
}

async function handleIncomingInvoiceOpenDocument(invoiceId) {
  const normalizedInvoiceId = String(invoiceId || "").trim();
  if (!normalizedInvoiceId) {
    return;
  }
  const file = getIncomingInvoiceFileForInvoice(normalizedInvoiceId);
  const documentRef = String(file?.nasPath || "").trim();
  if (!documentRef) {
    showInfoFeedback("Kein Beleg für diese Rechnung gespeichert.");
    return;
  }
  try {
    const accessToken = await getAuthAccessToken();
    const query = new URLSearchParams({
      ref: documentRef,
      invoiceId: normalizedInvoiceId,
    });
    if (file?.originalName) {
      query.set("name", String(file.originalName || "").trim());
    }
    const response = await fetch(`${INCOMING_INVOICE_FILE_DOWNLOAD_ENDPOINT}?${query.toString()}`, {
      method: "GET",
      headers: accessToken ? { Authorization: `Bearer ${accessToken}` } : {},
    });
    if (!response.ok) {
      const payload = await readIncomingInvoiceBridgePayload(response);
      throw new Error(getIncomingInvoiceBridgeErrorMessage(response, payload));
    }
    const blob = await response.blob();
    const downloadUrl = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = downloadUrl;
    link.download = String(file?.originalName || `beleg_${normalizedInvoiceId}.pdf`).trim() || `beleg_${normalizedInvoiceId}.pdf`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(downloadUrl);
  } catch (error) {
    const message = String(error?.message || "").trim();
    showWarningFeedback(message ? `Beleg konnte nicht geladen werden (${message}).` : "Beleg konnte nicht geladen werden.");
  }
}

function writeIncomingInvoiceLocalFallback(invoicePayload, invoiceId = "") {
  const actor = getCurrentActorInfo();
  const nowIso = new Date().toISOString();
  const normalizedId = String(invoiceId || "").trim() || createId("inv");
  const currentRows = getIncomingInvoices();
  const existing = currentRows.find((entry) => entry.id === normalizedId) || null;
  const nextRow = normalizeIncomingInvoiceRecord({
    id: normalizedId,
    invoice_number: invoicePayload.invoiceNumber,
    supplier_company_id: invoicePayload.supplierCompanyId,
    supplier_name: invoicePayload.supplierName,
    invoice_date: invoicePayload.invoiceDate,
    due_date: invoicePayload.dueDate,
    total_gross: invoicePayload.totalGross,
    total_net: invoicePayload.totalNet,
    total_tax: invoicePayload.totalTax,
    category: invoicePayload.category,
    cost_center: invoicePayload.costCenter,
    approval_status: invoicePayload.approvalStatus,
    payment_status: invoicePayload.paymentStatus,
    paid_at: invoicePayload.paidAt || null,
    payment_method: invoicePayload.paymentMethod,
    notes: invoicePayload.notes,
    updated_at: nowIso,
    updated_by_user_id: actor.userId || null,
    created_at: existing?.createdAt || nowIso,
    created_by_user_id: existing?.createdByUserId || actor.userId || null,
  });
  if (!nextRow) {
    return "";
  }
  const nextRows = existing
    ? currentRows.map((entry) => (entry.id === normalizedId ? nextRow : entry))
    : currentRows.concat(nextRow);
  let nextFiles = normalizeIncomingInvoiceFiles(incomingInvoiceFiles || []).filter((entry) => entry.invoiceId !== normalizedId);
  if (invoicePayload.fileName || invoicePayload.nasPath) {
    const fallbackPath =
      String(invoicePayload.nasPath || "").trim() ||
      `/invoices/${getTodayDateInputValue().slice(0, 7).replace("-", "/")}/${String(invoicePayload.fileName || "rechnung.pdf").trim() || "rechnung.pdf"}`;
    nextFiles = nextFiles.concat(
      normalizeIncomingInvoiceFileRecord({
        id: createId("ifile"),
        invoice_id: normalizedId,
        storage_mode: "supabase",
        nas_path: fallbackPath,
        original_name: invoicePayload.fileName || "",
        mime_type: invoicePayload.fileMimeType || "application/octet-stream",
        size_bytes: Math.max(0, Number(invoicePayload.fileSizeBytes) || 0),
        uploaded_at: nowIso,
        uploaded_by_user_id: actor.userId || null,
      }) || []
    );
  }
  applyIncomingInvoicesCache(nextRows, nextFiles, incomingInvoiceEvents || [], { persistBackup: true });
  saveState({ showFeedback: false });
  return normalizedId;
}

async function handleIncomingInvoiceSave() {
  const payload = buildIncomingInvoicePayloadFromForm();
  if (!payload) {
    return;
  }
  const selectedUploadFile = incomingInvoicesPendingFile || els.incomingInvoiceFileUpload?.files?.[0] || null;
  if (selectedUploadFile && !payload.fileName) {
    payload.fileName = String(selectedUploadFile.name || "").trim();
  }
  const editingId = String(els.incomingInvoiceId?.value || incomingInvoicesSelectedId || "").trim();
  const client = getSupabaseClient();
  const useRemote = Boolean(client) && !incomingInvoicesRemoteUnavailable;

  if (!useRemote) {
    const savedId = writeIncomingInvoiceLocalFallback(payload, editingId);
    if (!savedId) {
      showWarningFeedback("Rechnung konnte nicht lokal gespeichert werden.");
      return;
    }
    if (selectedUploadFile) {
      try {
        const uploaded = await uploadIncomingInvoiceDocument(savedId, selectedUploadFile);
        if (uploaded) {
          writeIncomingInvoiceLocalFallback(
            {
              ...payload,
              fileName: uploaded.originalName,
              nasPath: uploaded.documentPath,
              fileMimeType: uploaded.mimeType,
              fileSizeBytes: uploaded.sizeBytes,
            },
            savedId
          );
        }
      } catch (error) {
        console.warn("Lokaler Upload in Dokumentablage fehlgeschlagen.", error);
        const message = String(error?.message || "").trim();
        showWarningFeedback(
          message
            ? `Rechnung lokal gespeichert, Beleg konnte nicht hochgeladen werden (${message}).`
            : "Rechnung lokal gespeichert, Beleg konnte nicht hochgeladen werden."
        );
      }
    }
    incomingInvoicesSelectedId = savedId;
    resetIncomingInvoiceForm();
    setIncomingInvoicesWorkspaceTab("overview", { render: false });
    renderIncomingInvoicesSection();
    showSuccessFeedback("Rechnung gespeichert (lokal).");
    return;
  }

  const actorUserId = getAuthUid() || null;
  const dbPayload = {
    invoice_number: payload.invoiceNumber,
    supplier_company_id: payload.supplierCompanyId,
    supplier_name: payload.supplierName,
    invoice_date: payload.invoiceDate,
    due_date: payload.dueDate || null,
    total_gross: payload.totalGross,
    total_net: payload.totalNet,
    total_tax: payload.totalTax,
    category: payload.category || "Sonstiges",
    cost_center: payload.costCenter || "",
    approval_status: payload.approvalStatus,
    payment_status: payload.paymentStatus,
    paid_at: payload.paidAt || null,
    payment_method: payload.paymentMethod || "",
    notes: payload.notes || "",
    updated_by_user_id: actorUserId,
  };
  const table = getIncomingInvoicesTable();
  let savedInvoiceId = editingId;
  let uploadWarning = "";
  try {
    if (editingId) {
      const { error } = await client.from(table).update(dbPayload).eq("id", editingId);
      if (error) {
        throw error;
      }
    } else {
      const { data, error } = await client
        .from(table)
        .insert({
          ...dbPayload,
          created_by_user_id: actorUserId,
        })
        .select("id")
        .single();
      if (error) {
        throw error;
      }
      savedInvoiceId = String(data?.id || "").trim();
    }
    if (savedInvoiceId) {
      let effectiveFileName = String(payload.fileName || "").trim();
      let effectiveDocumentPath = String(payload.nasPath || "").trim();
      let effectiveMimeType = "application/octet-stream";
      let effectiveSizeBytes = 0;
      if (selectedUploadFile) {
        try {
          const uploaded = await uploadIncomingInvoiceDocument(savedInvoiceId, selectedUploadFile);
          if (uploaded) {
            effectiveFileName = String(uploaded.originalName || effectiveFileName || selectedUploadFile.name).trim();
            effectiveDocumentPath = String(uploaded.documentPath || effectiveDocumentPath).trim();
            effectiveMimeType = String(uploaded.mimeType || effectiveMimeType).trim() || effectiveMimeType;
            effectiveSizeBytes = Math.max(0, Number(uploaded.sizeBytes) || selectedUploadFile.size || 0);
          }
        } catch (error) {
          uploadWarning = String(error?.message || "").trim();
        }
      }
      if (!selectedUploadFile || effectiveDocumentPath) {
        await upsertIncomingInvoiceFileRemote(
          savedInvoiceId,
          effectiveFileName,
          effectiveDocumentPath,
          effectiveMimeType,
          effectiveSizeBytes
        );
      }
    }
    await hydrateIncomingInvoicesFromSupabase({ force: true });
    resetIncomingInvoiceForm();
    setIncomingInvoicesWorkspaceTab("overview", { render: false });
    renderIncomingInvoicesSection();
    if (uploadWarning) {
      showWarningFeedback(
        `Rechnung gespeichert, Beleg konnte nicht hochgeladen werden (${uploadWarning}).`
      );
    } else {
      showSuccessFeedback(editingId ? "Rechnung aktualisiert." : "Rechnung angelegt.");
    }
  } catch (error) {
    const summary = getSupabaseErrorSummary(error);
    showWarningFeedback(summary ? `Rechnung konnte nicht gespeichert werden (${summary}).` : "Rechnung konnte nicht gespeichert werden.");
  }
}

async function patchIncomingInvoiceStatus(invoiceId, patch, successMessage) {
  const normalizedInvoiceId = String(invoiceId || "").trim();
  if (!normalizedInvoiceId) {
    return;
  }
  const invoice = getIncomingInvoiceById(normalizedInvoiceId);
  if (!invoice) {
    return;
  }
  const client = getSupabaseClient();
  const useRemote = Boolean(client) && !incomingInvoicesRemoteUnavailable;
  const actorUserId = getAuthUid() || null;
  const nowIso = new Date().toISOString();
  if (!useRemote) {
    const nextRows = getIncomingInvoices().map((entry) => {
      if (entry.id !== normalizedInvoiceId) {
        return entry;
      }
      return normalizeIncomingInvoiceRecord({
        ...entry,
        approval_status: Object.prototype.hasOwnProperty.call(patch, "approval_status") ? patch.approval_status : entry.approvalStatus,
        payment_status: Object.prototype.hasOwnProperty.call(patch, "payment_status") ? patch.payment_status : entry.paymentStatus,
        paid_at: Object.prototype.hasOwnProperty.call(patch, "paid_at") ? patch.paid_at : entry.paidAt,
        payment_method: Object.prototype.hasOwnProperty.call(patch, "payment_method")
          ? patch.payment_method
          : entry.paymentMethod,
        notes: Object.prototype.hasOwnProperty.call(patch, "notes") ? patch.notes : entry.notes,
        updated_at: nowIso,
      });
    });
    applyIncomingInvoicesCache(nextRows, incomingInvoiceFiles || [], incomingInvoiceEvents || [], { persistBackup: true });
    saveState({ showFeedback: false });
    renderIncomingInvoicesSection();
    showSuccessFeedback(successMessage);
    return;
  }
  try {
    const { error } = await client
      .from(getIncomingInvoicesTable())
      .update({
        ...patch,
        updated_by_user_id: actorUserId,
      })
      .eq("id", normalizedInvoiceId);
    if (error) {
      throw error;
    }
    await hydrateIncomingInvoicesFromSupabase({ force: true });
    renderIncomingInvoicesSection();
    showSuccessFeedback(successMessage);
  } catch (error) {
    const summary = getSupabaseErrorSummary(error);
    showWarningFeedback(summary ? `Status konnte nicht geändert werden (${summary}).` : "Status konnte nicht geändert werden.");
  }
}

async function handleIncomingInvoiceApprove(invoiceId) {
  await patchIncomingInvoiceStatus(
    invoiceId,
    {
      approval_status: "freigegeben",
    },
    "Rechnung freigegeben."
  );
}

async function handleIncomingInvoiceReject(invoiceId) {
  const reason = String(window.prompt("Ablehnungsgrund (optional):", "") || "").trim();
  await patchIncomingInvoiceStatus(
    invoiceId,
    {
      approval_status: "abgelehnt",
      notes: reason ? `${reason}` : getIncomingInvoiceById(invoiceId)?.notes || "",
    },
    "Rechnung abgelehnt."
  );
}

async function handleIncomingInvoiceMarkPaid(invoiceId) {
  const invoice = getIncomingInvoiceById(invoiceId);
  if (!invoice) {
    return;
  }
  if (normalizeIncomingInvoiceApprovalStatus(invoice.approvalStatus) === "freigabe_offen") {
    showWarningFeedback("Bitte zuerst freigeben, danach als bezahlt markieren.");
    return;
  }
  await patchIncomingInvoiceStatus(
    invoiceId,
    {
      payment_status: "bezahlt",
      paid_at: new Date().toISOString(),
      payment_method: normalizeIncomingInvoicePaymentMethod(invoice.paymentMethod || "ueberweisung"),
    },
    "Rechnung als bezahlt markiert."
  );
}

function buildIncomingInvoicesCsvRows(rows) {
  const header = [
    "invoice_number",
    "supplier_name",
    "invoice_date",
    "due_date",
    "total_net",
    "total_tax",
    "total_gross",
    "currency",
    "approval_status",
    "payment_status",
    "paid_at",
    "payment_method",
    "category",
    "cost_center",
    "notes",
    "document_reference",
    "file_name",
  ];
  const lines = [header];
  (Array.isArray(rows) ? rows : []).forEach((entry) => {
    const file = getIncomingInvoiceFileForInvoice(entry.id);
    lines.push([
      entry.invoiceNumber || "",
      entry.supplierName || "",
      entry.invoiceDate || "",
      entry.dueDate || "",
      String(normalizeIncomingInvoiceAmount(entry.totalNet)),
      String(normalizeIncomingInvoiceAmount(entry.totalTax)),
      String(normalizeIncomingInvoiceAmount(entry.totalGross)),
      entry.currency || "EUR",
      normalizeIncomingInvoiceApprovalStatus(entry.approvalStatus),
      normalizeIncomingInvoicePaymentStatus(entry.paymentStatus),
      entry.paidAt || "",
      normalizeIncomingInvoicePaymentMethod(entry.paymentMethod),
      entry.category || "",
      entry.costCenter || "",
      entry.notes || "",
      file?.nasPath || "",
      file?.originalName || "",
    ]);
  });
  return lines;
}

function csvEscapeCell(value) {
  const text = String(value ?? "");
  return `"${text.replaceAll('"', '""')}"`;
}

function exportIncomingInvoicesCsv() {
  const rows = getFilteredIncomingInvoices();
  if (!rows.length) {
    showInfoFeedback("Keine Rechnungen zum Export im aktuellen Filter.");
    return;
  }
  const csvRows = buildIncomingInvoicesCsvRows(rows);
  const csvContent = csvRows.map((row) => row.map((cell) => csvEscapeCell(cell)).join(";")).join("\n");
  const blob = new Blob([`\uFEFF${csvContent}`], { type: "text/csv;charset=utf-8;" });
  const url = URL.createObjectURL(blob);
  const link = document.createElement("a");
  link.href = url;
  link.download = `eingangsrechnungen_${getTodayDateInputValue()}.csv`;
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
  URL.revokeObjectURL(url);
  showSuccessFeedback("CSV Export erstellt.");
}

function normalizeIncomingOffersView(value) {
  const normalized = String(value || "").trim().toLowerCase();
  if (["open", "decided", "all"].includes(normalized)) {
    return normalized;
  }
  return "open";
}

function normalizeIncomingOffersWorkspaceTab(value) {
  const normalized = String(value || "").trim().toLowerCase();
  if (normalized === "entry" || normalized === "overview") {
    return normalized;
  }
  return "overview";
}

function normalizeIncomingOfferStatus(value) {
  const normalized = normalizeText(value || "");
  return INCOMING_OFFER_STATUSES.has(normalized) ? normalized : "offen";
}

function normalizeIncomingOfferPriority(value) {
  const normalized = normalizeText(value || "");
  return INCOMING_OFFER_PRIORITIES.has(normalized) ? normalized : "normal";
}

function normalizeIncomingOfferStatusFilter(value) {
  const normalized = String(value || "").trim();
  if (!normalized || normalizeText(normalized) === "all") {
    return "all";
  }
  return normalizeIncomingOfferStatus(normalized);
}

function normalizeIncomingOfferPriorityFilter(value) {
  const normalized = String(value || "").trim();
  if (!normalized || normalizeText(normalized) === "all") {
    return "all";
  }
  return normalizeIncomingOfferPriority(normalized);
}

function normalizeIncomingOfferRecord(entry, index = 0) {
  if (!entry || typeof entry !== "object") {
    return null;
  }
  const id = String(entry.id || "").trim() || `off_${index + 1}`;
  const receivedDate = normalizeIncomingInvoiceDateInputValue(entry.receivedDate || entry.received_date || "");
  if (!id || !receivedDate) {
    return null;
  }
  const validUntilDate = normalizeIncomingInvoiceDateInputValue(entry.validUntilDate || entry.valid_until_date || "");
  const decidedAtRaw = String(entry.decidedAt || entry.decided_at || "").trim();
  const decidedAtParsed = decidedAtRaw ? new Date(`${decidedAtRaw}`) : null;
  const decidedAt = decidedAtParsed && !Number.isNaN(decidedAtParsed.getTime()) ? decidedAtParsed.toISOString() : "";
  const createdAtRaw = String(entry.createdAt || entry.created_at || "").trim();
  const createdAt = Number.isNaN(new Date(createdAtRaw).getTime()) ? new Date().toISOString() : createdAtRaw;
  const updatedAtRaw = String(entry.updatedAt || entry.updated_at || createdAt).trim();
  const updatedAt = Number.isNaN(new Date(updatedAtRaw).getTime()) ? createdAt : updatedAtRaw;
  return {
    id,
    offerNumber: String(entry.offerNumber || entry.offer_number || "").trim(),
    supplierCompanyId: normalizeIncomingInvoiceSupplierCompanyId(entry.supplierCompanyId || entry.supplier_company_id || ""),
    supplierName: String(entry.supplierName || entry.supplier_name || "").trim(),
    receivedDate,
    validUntilDate,
    currency: String(entry.currency || "EUR").trim().toUpperCase() || "EUR",
    totalNet: normalizeIncomingInvoiceAmount(entry.totalNet || entry.total_net),
    totalTax: normalizeIncomingInvoiceAmount(entry.totalTax || entry.total_tax),
    totalGross: normalizeIncomingInvoiceAmount(entry.totalGross || entry.total_gross),
    category: String(entry.category || "").trim(),
    costCenter: String(entry.costCenter || entry.cost_center || "").trim(),
    notes: String(entry.notes || "").trim(),
    status: normalizeIncomingOfferStatus(entry.status),
    priority: normalizeIncomingOfferPriority(entry.priority),
    decidedAt,
    createdAt,
    updatedAt,
    createdByUserId: normalizeUserId(entry.createdByUserId || entry.created_by_user_id || ""),
    updatedByUserId: normalizeUserId(entry.updatedByUserId || entry.updated_by_user_id || ""),
  };
}

function normalizeIncomingOffers(rawList) {
  if (!Array.isArray(rawList)) {
    return [];
  }
  const seen = new Set();
  const rows = [];
  rawList.forEach((entry, index) => {
    const normalized = normalizeIncomingOfferRecord(entry, index);
    if (!normalized || seen.has(normalized.id)) {
      return;
    }
    seen.add(normalized.id);
    rows.push(normalized);
  });
  return rows.sort((left, right) => {
    const leftKey = `${left.receivedDate}|${left.updatedAt}`;
    const rightKey = `${right.receivedDate}|${right.updatedAt}`;
    return rightKey.localeCompare(leftKey);
  });
}

function normalizeIncomingOfferFileRecord(entry, index = 0) {
  if (!entry || typeof entry !== "object") {
    return null;
  }
  const id = String(entry.id || "").trim() || `ofile_${index + 1}`;
  const offerId = String(entry.offerId || entry.offer_id || "").trim();
  if (!id || !offerId) {
    return null;
  }
  const uploadedAtRaw = String(entry.uploadedAt || entry.uploaded_at || "").trim();
  const uploadedAt = Number.isNaN(new Date(uploadedAtRaw).getTime()) ? new Date().toISOString() : uploadedAtRaw;
  return {
    id,
    offerId,
    documentPath: String(entry.documentPath || entry.document_path || entry.nasPath || entry.nas_path || "").trim(),
    originalName: String(entry.originalName || entry.original_name || "").trim(),
    mimeType: String(entry.mimeType || entry.mime_type || "application/pdf").trim(),
    sizeBytes: Math.max(0, Number(entry.sizeBytes || entry.size_bytes || 0) || 0),
    uploadedAt,
    uploadedByUserId: normalizeUserId(entry.uploadedByUserId || entry.uploaded_by_user_id || ""),
  };
}

function normalizeIncomingOfferFiles(rawList) {
  if (!Array.isArray(rawList)) {
    return [];
  }
  const seen = new Set();
  const rows = [];
  rawList.forEach((entry, index) => {
    const normalized = normalizeIncomingOfferFileRecord(entry, index);
    if (!normalized || seen.has(normalized.id)) {
      return;
    }
    seen.add(normalized.id);
    rows.push(normalized);
  });
  return rows.sort((left, right) => String(right.uploadedAt || "").localeCompare(String(left.uploadedAt || "")));
}

function applyIncomingOffersCache(nextOffers, nextFiles, options = {}) {
  incomingOffers = normalizeIncomingOffers(nextOffers || []);
  incomingOfferFiles = normalizeIncomingOfferFiles(nextFiles || []);
  state.settings = normalizeSettings({
    ...state.settings,
    incomingOffers,
    incomingOfferFiles,
  });
  if (options?.persistBackup !== false) {
    persistLocalBackup();
  }
}

function getIncomingOffersLocalFallback() {
  return {
    offers: normalizeIncomingOffers(state.settings?.incomingOffers || []),
    files: normalizeIncomingOfferFiles(state.settings?.incomingOfferFiles || []),
  };
}

function getIncomingOffers() {
  return normalizeIncomingOffers(incomingOffers || []);
}

function getIncomingOfferById(offerId) {
  const normalizedId = String(offerId || "").trim();
  if (!normalizedId) {
    return null;
  }
  return getIncomingOffers().find((entry) => entry.id === normalizedId) || null;
}

function getIncomingOfferFileForOffer(offerId) {
  const normalizedId = String(offerId || "").trim();
  if (!normalizedId) {
    return null;
  }
  return (
    normalizeIncomingOfferFiles(incomingOfferFiles || []).find((entry) => String(entry.offerId || "").trim() === normalizedId) ||
    null
  );
}

function renderIncomingOfferSupplierOptions(selectedCompanyId = "", fallbackSupplierName = "") {
  if (!els.incomingOfferSupplier) {
    return "";
  }
  const companies = getIncomingInvoiceSupplierCompanies();
  const selectedId = normalizeIncomingInvoiceSupplierCompanyId(selectedCompanyId);
  const fallbackName = String(fallbackSupplierName || "").trim();
  const optionRows = [];
  optionRows.push(`<option value="">${companies.length ? "Firma wählen..." : "Keine Firmen vorhanden"}</option>`);
  companies.forEach((company) => {
    const companyId = String(company?.id || "").trim();
    const name = String(company?.name || "").trim();
    if (!companyId || !name) {
      return;
    }
    const locationLabel = [String(company?.postalCode || "").trim(), String(company?.city || "").trim(), String(company?.country || "").trim()]
      .filter(Boolean)
      .join(" ");
    const label = locationLabel ? `${name} · ${locationLabel}` : name;
    optionRows.push(`<option value="${escapeHtml(companyId)}">${escapeHtml(label)}</option>`);
  });
  if (fallbackName && !companies.some((entry) => normalizeText(entry?.name || "") === normalizeText(fallbackName))) {
    optionRows.push(`<option value="__legacy_supplier__">${escapeHtml(`${fallbackName} (Altbestand)`)}</option>`);
  }
  els.incomingOfferSupplier.innerHTML = optionRows.join("");
  els.incomingOfferSupplier.disabled = companies.length === 0;
  if (els.incomingOfferSaveBtn) {
    els.incomingOfferSaveBtn.disabled = companies.length === 0;
  }
  if (selectedId && companies.some((entry) => String(entry?.id || "").trim() === selectedId)) {
    els.incomingOfferSupplier.value = selectedId;
    return selectedId;
  }
  if (fallbackName && els.incomingOfferSupplier.querySelector('option[value="__legacy_supplier__"]')) {
    els.incomingOfferSupplier.value = "__legacy_supplier__";
    return "__legacy_supplier__";
  }
  els.incomingOfferSupplier.value = "";
  return "";
}

function getIncomingOfferStatusLabel(status) {
  const normalized = normalizeIncomingOfferStatus(status);
  if (normalized === "in_pruefung") {
    return "In Prüfung";
  }
  if (normalized === "angenommen") {
    return "Angenommen";
  }
  if (normalized === "abgelehnt") {
    return "Abgelehnt";
  }
  if (normalized === "abgelaufen") {
    return "Abgelaufen";
  }
  return "Offen";
}

function getIncomingOfferPriorityLabel(priority) {
  return normalizeIncomingOfferPriority(priority) === "hoch" ? "Hoch" : "Normal";
}

function getIncomingOfferStatusCssClass(status) {
  const normalized = normalizeIncomingOfferStatus(status);
  if (normalized === "angenommen") {
    return "is-approved";
  }
  if (normalized === "abgelehnt") {
    return "is-approval-open";
  }
  if (normalized === "abgelaufen") {
    return "is-partial";
  }
  if (normalized === "in_pruefung") {
    return "is-paid";
  }
  return "";
}

function getIncomingOfferPriorityCssClass(priority) {
  return normalizeIncomingOfferPriority(priority) === "hoch" ? "is-approval-open" : "";
}

function setIncomingOffersView(nextView, options = {}) {
  incomingOffersView = normalizeIncomingOffersView(nextView);
  const activeView = incomingOffersView;
  els.incomingOffersViewButtons?.forEach((button) => {
    const target = normalizeIncomingOffersView(button.dataset.incomingOffersViewTarget || "");
    const isActive = target === activeView;
    button.classList.toggle("is-active", isActive);
    setTabButtonA11yState(button, isActive);
  });
  if (options?.render !== false) {
    renderIncomingOffersSection();
  }
}

function setIncomingOffersWorkspaceTab(nextTab, options = {}) {
  incomingOffersWorkspaceTab = normalizeIncomingOffersWorkspaceTab(nextTab);
  const activeTab = incomingOffersWorkspaceTab;
  els.incomingOffersWorkspaceTabButtons?.forEach((button) => {
    const target = normalizeIncomingOffersWorkspaceTab(button.dataset.incomingOffersWorkspaceTab || "");
    const isActive = target === activeTab;
    button.classList.toggle("is-active", isActive);
    setTabButtonA11yState(button, isActive);
  });
  els.incomingOffersWorkspacePanels?.forEach((panel) => {
    const target = normalizeIncomingOffersWorkspaceTab(panel.dataset.incomingOffersWorkspacePanel || "");
    const isActive = target === activeTab;
    panel.classList.toggle("hidden", !isActive);
    setTabPanelA11yState(panel, isActive);
  });
  if (options?.render !== false) {
    renderIncomingOffersSection();
  }
}

function isIncomingOfferExpired(offer) {
  if (!offer) {
    return false;
  }
  if (["angenommen", "abgelehnt", "abgelaufen"].includes(normalizeIncomingOfferStatus(offer.status))) {
    return false;
  }
  const validUntil = parseDateInputStart(normalizeIncomingInvoiceDateInputValue(offer.validUntilDate || ""));
  if (!validUntil) {
    return false;
  }
  const now = new Date();
  const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());
  return validUntil < today;
}

function renderIncomingOffersKpis(rows) {
  if (!els.incomingOffersKpis) {
    return;
  }
  const stats = {
    openAmount: 0,
    acceptedAmount: 0,
    expiredCount: 0,
    totalCount: 0,
  };
  (Array.isArray(rows) ? rows : []).forEach((entry) => {
    stats.totalCount += 1;
    const status = normalizeIncomingOfferStatus(entry?.status);
    const gross = normalizeIncomingInvoiceAmount(entry?.totalGross);
    if (status === "offen" || status === "in_pruefung") {
      stats.openAmount += gross;
    }
    if (status === "angenommen") {
      stats.acceptedAmount += gross;
    }
    if (isIncomingOfferExpired(entry) || status === "abgelaufen") {
      stats.expiredCount += 1;
    }
  });
  els.incomingOffersKpis.innerHTML = `
    <article class="incoming-invoices-kpi">
      <span>Offen & In Prüfung</span>
      <strong>${escapeHtml(formatIncomingInvoiceMoney(stats.openAmount))}</strong>
    </article>
    <article class="incoming-invoices-kpi">
      <span>Angenommen</span>
      <strong>${escapeHtml(formatIncomingInvoiceMoney(stats.acceptedAmount))}</strong>
    </article>
    <article class="incoming-invoices-kpi">
      <span>Ablauf / Abgelaufen</span>
      <strong>${escapeHtml(String(stats.expiredCount))}</strong>
    </article>
    <article class="incoming-invoices-kpi">
      <span>Angebote</span>
      <strong>${escapeHtml(String(stats.totalCount))}</strong>
    </article>
  `;
}

function matchesIncomingOfferDateRange(offer, fromDate, toDate) {
  if (!fromDate && !toDate) {
    return true;
  }
  const receivedDate = parseDateInputStart(normalizeIncomingInvoiceDateInputValue(offer?.receivedDate || ""));
  if (!receivedDate) {
    return false;
  }
  if (fromDate && receivedDate < fromDate) {
    return false;
  }
  if (toDate) {
    const toEnd = new Date(toDate.getTime());
    toEnd.setDate(toEnd.getDate() + 1);
    if (receivedDate >= toEnd) {
      return false;
    }
  }
  return true;
}

function getFilteredIncomingOffers() {
  const searchNeedle = normalizeText(incomingOffersSearchTerm || "");
  const fromDate = parseDateInputStart(incomingOffersDateFrom);
  const toDate = parseDateInputStart(incomingOffersDateTo);
  return getIncomingOffers().filter((entry) => {
    const status = normalizeIncomingOfferStatus(entry?.status);
    const priority = normalizeIncomingOfferPriority(entry?.priority);
    const isDecided = ["angenommen", "abgelehnt", "abgelaufen"].includes(status);
    if (incomingOffersView === "open" && isDecided) {
      return false;
    }
    if (incomingOffersView === "decided" && !isDecided) {
      return false;
    }
    if (incomingOffersStatusFilter !== "all" && status !== incomingOffersStatusFilter) {
      return false;
    }
    if (incomingOffersPriorityFilter !== "all" && priority !== incomingOffersPriorityFilter) {
      return false;
    }
    if (!matchesIncomingOfferDateRange(entry, fromDate, toDate)) {
      return false;
    }
    if (searchNeedle) {
      const haystack = normalizeText(
        [
          entry.offerNumber,
          entry.supplierName,
          entry.category,
          entry.costCenter,
          entry.notes,
          getIncomingOfferStatusLabel(status),
          getIncomingOfferPriorityLabel(priority),
        ]
          .filter(Boolean)
          .join(" ")
      );
      if (!haystack.includes(searchNeedle)) {
        return false;
      }
    }
    return true;
  });
}

function syncIncomingOfferFilterControls() {
  if (els.incomingOffersSearchInput && els.incomingOffersSearchInput.value !== incomingOffersSearchTerm) {
    els.incomingOffersSearchInput.value = incomingOffersSearchTerm;
  }
  if (els.incomingOffersFilterStatus) {
    incomingOffersStatusFilter = normalizeIncomingOfferStatusFilter(incomingOffersStatusFilter);
    if (els.incomingOffersFilterStatus.value !== incomingOffersStatusFilter) {
      els.incomingOffersFilterStatus.value = incomingOffersStatusFilter;
    }
  }
  if (els.incomingOffersFilterPriority) {
    incomingOffersPriorityFilter = normalizeIncomingOfferPriorityFilter(incomingOffersPriorityFilter);
    if (els.incomingOffersFilterPriority.value !== incomingOffersPriorityFilter) {
      els.incomingOffersFilterPriority.value = incomingOffersPriorityFilter;
    }
  }
  if (els.incomingOffersDateFrom && els.incomingOffersDateFrom.value !== incomingOffersDateFrom) {
    els.incomingOffersDateFrom.value = incomingOffersDateFrom;
  }
  if (els.incomingOffersDateTo && els.incomingOffersDateTo.value !== incomingOffersDateTo) {
    els.incomingOffersDateTo.value = incomingOffersDateTo;
  }
}

function renderIncomingOffersSection() {
  if (!els.incomingOffersTableBody) {
    return;
  }
  renderIncomingOfferSupplierOptions(els.incomingOfferSupplier?.value || "");
  setIncomingOffersWorkspaceTab(incomingOffersWorkspaceTab, { render: false });
  setIncomingOffersView(incomingOffersView, { render: false });
  syncIncomingOfferFilterControls();
  const rows = getFilteredIncomingOffers();
  renderIncomingOffersKpis(rows);

  if (!rows.length) {
    els.incomingOffersTableBody.innerHTML = '<tr><td colspan="8" class="empty">Keine Angebote im gewählten Filter.</td></tr>';
  } else {
    els.incomingOffersTableBody.innerHTML = rows
      .map((entry) => {
        const statusLabel = getIncomingOfferStatusLabel(entry.status);
        const statusClass = getIncomingOfferStatusCssClass(entry.status);
        const priorityLabel = getIncomingOfferPriorityLabel(entry.priority);
        const priorityClass = getIncomingOfferPriorityCssClass(entry.priority);
        const file = getIncomingOfferFileForOffer(entry.id);
        const hasDocument = Boolean(String(file?.documentPath || "").trim() || String(file?.originalName || "").trim());
        const expiredLabel = isIncomingOfferExpired(entry) ? " · abgelaufen" : "";
        const canDecide = ["offen", "in_pruefung"].includes(normalizeIncomingOfferStatus(entry.status));
        return `
          <tr>
            <td>${escapeHtml(entry.offerNumber || "–")}</td>
            <td>
              ${
                entry.supplierName
                  ? `<button
                      type="button"
                      class="entity-link-btn"
                      data-incoming-offer-open-company="${escapeHtml(String(entry.supplierCompanyId || "").trim())}"
                      data-incoming-offer-open-company-name="${escapeHtml(String(entry.supplierName || "").trim())}"
                    >${escapeHtml(entry.supplierName)}</button>`
                  : "–"
              }
            </td>
            <td>${escapeHtml(entry.receivedDate ? formatTourDateLabel(entry.receivedDate) : "–")}</td>
            <td>${escapeHtml(entry.validUntilDate ? `${formatTourDateLabel(entry.validUntilDate)}${expiredLabel}` : "–")}</td>
            <td>${escapeHtml(formatIncomingInvoiceMoney(entry.totalGross, entry.currency || "EUR"))}</td>
            <td><span class="incoming-invoices-pill ${escapeHtml(statusClass)}">${escapeHtml(statusLabel)}</span></td>
            <td><span class="incoming-invoices-pill ${escapeHtml(priorityClass)}">${escapeHtml(priorityLabel)}</span></td>
            <td>
              <div class="incoming-invoices-actions-inline">
                <button type="button" class="mini-btn" data-incoming-offer-edit="${escapeHtml(entry.id)}">Bearbeiten</button>
                ${canDecide ? `<button type="button" class="mini-btn" data-incoming-offer-review="${escapeHtml(entry.id)}">In Prüfung</button>` : ""}
                ${canDecide ? `<button type="button" class="mini-btn" data-incoming-offer-accept="${escapeHtml(entry.id)}">Annehmen</button>` : ""}
                ${canDecide ? `<button type="button" class="mini-btn danger" data-incoming-offer-reject="${escapeHtml(entry.id)}">Ablehnen</button>` : ""}
                ${
                  normalizeIncomingOfferStatus(entry.status) === "angenommen"
                    ? `<button type="button" class="mini-btn" data-incoming-offer-to-invoice="${escapeHtml(entry.id)}">Als Rechnung</button>`
                    : ""
                }
                ${
                  normalizeIncomingOfferStatus(entry.status) !== "abgelaufen"
                    ? `<button type="button" class="mini-btn" data-incoming-offer-expired="${escapeHtml(entry.id)}">Abgelaufen</button>`
                    : ""
                }
                ${
                  hasDocument
                    ? `<button type="button" class="mini-btn" data-incoming-offer-open-document="${escapeHtml(entry.id)}">Angebot öffnen</button>`
                    : ""
                }
              </div>
            </td>
          </tr>
        `;
      })
      .join("");
  }
  if (els.incomingOffersTableMeta) {
    const modeText =
      incomingOffersView === "decided"
        ? "Entschieden"
        : incomingOffersView === "open"
          ? "Offen & in Prüfung"
          : "Alle";
    els.incomingOffersTableMeta.textContent = `${rows.length} Einträge · Ansicht: ${modeText}`;
  }
}

function resetIncomingOfferForm() {
  if (els.incomingOfferForm) {
    els.incomingOfferForm.reset();
  }
  if (els.incomingOfferId) {
    els.incomingOfferId.value = "";
  }
  if (els.incomingOfferStatus) {
    els.incomingOfferStatus.value = "offen";
  }
  if (els.incomingOfferPriority) {
    els.incomingOfferPriority.value = "normal";
  }
  if (els.incomingOfferReceivedDate && !els.incomingOfferReceivedDate.value) {
    els.incomingOfferReceivedDate.value = getTodayDateInputValue();
  }
  if (els.incomingOfferFileUpload) {
    els.incomingOfferFileUpload.value = "";
  }
  incomingOffersPendingFile = null;
  incomingOffersSelectedId = "";
  renderIncomingOfferSupplierOptions();
  if (els.incomingOfferSaveBtn) {
    els.incomingOfferSaveBtn.textContent = "Angebot speichern";
  }
}

function fillIncomingOfferForm(offer) {
  if (!offer) {
    return;
  }
  const file = getIncomingOfferFileForOffer(offer.id);
  incomingOffersSelectedId = String(offer.id || "").trim();
  if (els.incomingOfferId) {
    els.incomingOfferId.value = incomingOffersSelectedId;
  }
  if (els.incomingOfferNumber) {
    els.incomingOfferNumber.value = offer.offerNumber || "";
  }
  if (els.incomingOfferSupplier) {
    renderIncomingOfferSupplierOptions(offer.supplierCompanyId || "", offer.supplierName || "");
  }
  if (els.incomingOfferReceivedDate) {
    els.incomingOfferReceivedDate.value = normalizeIncomingInvoiceDateInputValue(offer.receivedDate);
  }
  if (els.incomingOfferValidUntilDate) {
    els.incomingOfferValidUntilDate.value = normalizeIncomingInvoiceDateInputValue(offer.validUntilDate);
  }
  if (els.incomingOfferTotalGross) {
    els.incomingOfferTotalGross.value = String(normalizeIncomingInvoiceAmount(offer.totalGross));
  }
  if (els.incomingOfferTotalNet) {
    els.incomingOfferTotalNet.value = String(normalizeIncomingInvoiceAmount(offer.totalNet));
  }
  if (els.incomingOfferTotalTax) {
    els.incomingOfferTotalTax.value = String(normalizeIncomingInvoiceAmount(offer.totalTax));
  }
  if (els.incomingOfferCategory) {
    els.incomingOfferCategory.value = offer.category || "";
  }
  if (els.incomingOfferCostCenter) {
    els.incomingOfferCostCenter.value = offer.costCenter || "";
  }
  if (els.incomingOfferStatus) {
    els.incomingOfferStatus.value = normalizeIncomingOfferStatus(offer.status);
  }
  if (els.incomingOfferPriority) {
    els.incomingOfferPriority.value = normalizeIncomingOfferPriority(offer.priority);
  }
  if (els.incomingOfferDecidedAt) {
    const decidedDate = String(offer.decidedAt || "").trim();
    els.incomingOfferDecidedAt.value = decidedDate ? decidedDate.slice(0, 10) : "";
  }
  if (els.incomingOfferFileName) {
    els.incomingOfferFileName.value = file?.originalName || "";
  }
  if (els.incomingOfferFileUpload) {
    els.incomingOfferFileUpload.value = "";
  }
  incomingOffersPendingFile = null;
  if (els.incomingOfferDocumentPath) {
    els.incomingOfferDocumentPath.value = file?.documentPath || "";
  }
  if (els.incomingOfferNotes) {
    els.incomingOfferNotes.value = offer.notes || "";
  }
  if (els.incomingOfferSaveBtn) {
    els.incomingOfferSaveBtn.textContent = "Angebot aktualisieren";
  }
}

function buildIncomingOfferPayloadFromForm() {
  const receivedDate = normalizeIncomingInvoiceDateInputValue(els.incomingOfferReceivedDate?.value || "");
  const offerNumber = String(els.incomingOfferNumber?.value || "").trim();
  const selectedSupplierValue = String(els.incomingOfferSupplier?.value || "").trim();
  const selectedSupplierOption = els.incomingOfferSupplier?.selectedOptions?.[0] || null;
  const supplierCompanyId = selectedSupplierValue === "__legacy_supplier__" ? "" : normalizeIncomingInvoiceSupplierCompanyId(selectedSupplierValue);
  const supplierNameRaw = selectedSupplierOption ? String(selectedSupplierOption.textContent || "").trim() : "";
  const supplierName = supplierNameRaw
    .replace(/\s·\s[^·]*$/, "")
    .replace(/\s\(Altbestand\)\s*$/i, "")
    .trim();
  const totalGross = normalizeIncomingInvoiceAmount(els.incomingOfferTotalGross?.value || 0);
  const status = normalizeIncomingOfferStatus(els.incomingOfferStatus?.value || "offen");
  if (!receivedDate) {
    showWarningFeedback("Eingangsdatum fehlt.");
    return null;
  }
  if (!offerNumber) {
    showWarningFeedback("Angebotsnummer fehlt.");
    return null;
  }
  if (!supplierCompanyId || !supplierName) {
    showWarningFeedback("Bitte Lieferant aus Firmen auswählen.");
    return null;
  }
  if (totalGross <= 0) {
    showWarningFeedback("Bruttobetrag muss größer als 0 sein.");
    return null;
  }
  const decidedAtDate = normalizeIncomingInvoiceDateInputValue(els.incomingOfferDecidedAt?.value || "");
  return {
    offerNumber,
    supplierCompanyId,
    supplierName,
    receivedDate,
    validUntilDate: normalizeIncomingInvoiceDateInputValue(els.incomingOfferValidUntilDate?.value || ""),
    totalGross,
    totalNet: normalizeIncomingInvoiceAmount(els.incomingOfferTotalNet?.value || 0),
    totalTax: normalizeIncomingInvoiceAmount(els.incomingOfferTotalTax?.value || 0),
    category: String(els.incomingOfferCategory?.value || "").trim(),
    costCenter: String(els.incomingOfferCostCenter?.value || "").trim(),
    status,
    priority: normalizeIncomingOfferPriority(els.incomingOfferPriority?.value || "normal"),
    decidedAt: decidedAtDate ? `${decidedAtDate}T00:00:00.000Z` : "",
    notes: String(els.incomingOfferNotes?.value || "").trim(),
    fileName: String(els.incomingOfferFileName?.value || "").trim(),
    documentPath: String(els.incomingOfferDocumentPath?.value || "").trim(),
  };
}

function writeIncomingOfferLocalFallback(offerPayload, offerId = "") {
  const actor = getCurrentActorInfo();
  const nowIso = new Date().toISOString();
  const normalizedId = String(offerId || "").trim() || createId("offer");
  const currentRows = getIncomingOffers();
  const existing = currentRows.find((entry) => entry.id === normalizedId) || null;
  const nextRow = normalizeIncomingOfferRecord({
    id: normalizedId,
    offer_number: offerPayload.offerNumber,
    supplier_company_id: offerPayload.supplierCompanyId,
    supplier_name: offerPayload.supplierName,
    received_date: offerPayload.receivedDate,
    valid_until_date: offerPayload.validUntilDate,
    total_gross: offerPayload.totalGross,
    total_net: offerPayload.totalNet,
    total_tax: offerPayload.totalTax,
    category: offerPayload.category,
    cost_center: offerPayload.costCenter,
    status: offerPayload.status,
    priority: offerPayload.priority,
    decided_at: offerPayload.decidedAt || null,
    notes: offerPayload.notes,
    updated_at: nowIso,
    updated_by_user_id: actor.userId || null,
    created_at: existing?.createdAt || nowIso,
    created_by_user_id: existing?.createdByUserId || actor.userId || null,
  });
  if (!nextRow) {
    return "";
  }
  const nextRows = existing
    ? currentRows.map((entry) => (entry.id === normalizedId ? nextRow : entry))
    : currentRows.concat(nextRow);
  const currentFiles = normalizeIncomingOfferFiles(incomingOfferFiles || []);
  const existingFile = currentFiles.find((entry) => entry.offerId === normalizedId) || null;
  let nextFiles = currentFiles.filter((entry) => entry.offerId !== normalizedId);
  if (offerPayload.fileName || offerPayload.documentPath) {
    const fallbackPath =
      String(offerPayload.documentPath || "").trim() ||
      `/offers/${getTodayDateInputValue().slice(0, 7).replace("-", "/")}/${String(offerPayload.fileName || "angebot.pdf").trim() || "angebot.pdf"}`;
    nextFiles = nextFiles.concat(
      normalizeIncomingOfferFileRecord({
        id: createId("ofile"),
        offer_id: normalizedId,
        document_path: fallbackPath,
        original_name: offerPayload.fileName || "",
        mime_type: offerPayload.fileMimeType || "application/octet-stream",
        size_bytes: Math.max(0, Number(offerPayload.fileSizeBytes) || 0),
        uploaded_at: nowIso,
        uploaded_by_user_id: actor.userId || null,
      }) || []
    );
  } else if (existingFile) {
    nextFiles = nextFiles.concat(existingFile);
  }
  applyIncomingOffersCache(nextRows, nextFiles, { persistBackup: true });
  saveState({ showFeedback: false });
  return normalizedId;
}

async function handleIncomingOfferSave() {
  const payload = buildIncomingOfferPayloadFromForm();
  if (!payload) {
    return;
  }
  const selectedUploadFile = incomingOffersPendingFile || els.incomingOfferFileUpload?.files?.[0] || null;
  if (selectedUploadFile && !payload.fileName) {
    payload.fileName = String(selectedUploadFile.name || "").trim();
  }
  const editingId = String(els.incomingOfferId?.value || incomingOffersSelectedId || "").trim();
  const draftPayload = selectedUploadFile
    ? {
        ...payload,
        fileName: "",
        documentPath: "",
      }
    : payload;
  let savedId = writeIncomingOfferLocalFallback(draftPayload, editingId);
  if (!savedId) {
    showWarningFeedback("Angebot konnte nicht gespeichert werden.");
    return;
  }
  if (selectedUploadFile) {
    try {
      const uploaded = await uploadIncomingInvoiceDocument(savedId, selectedUploadFile);
      if (uploaded) {
        savedId = writeIncomingOfferLocalFallback(
          {
            ...payload,
            fileName: uploaded.originalName,
            documentPath: uploaded.documentPath,
            fileMimeType: uploaded.mimeType,
            fileSizeBytes: uploaded.sizeBytes,
          },
          savedId
        );
      }
    } catch (error) {
      console.warn("Upload für Eingangsangebot fehlgeschlagen.", error);
      const message = String(error?.message || "").trim();
      showWarningFeedback(
        message
          ? `Angebot gespeichert, Datei konnte nicht hochgeladen werden (${message}).`
          : "Angebot gespeichert, Datei konnte nicht hochgeladen werden."
      );
    }
  }
  incomingOffersSelectedId = savedId;
  resetIncomingOfferForm();
  setIncomingOffersWorkspaceTab("overview", { render: false });
  renderIncomingOffersSection();
  showSuccessFeedback(editingId ? "Angebot aktualisiert." : "Angebot angelegt.");
}

function handleIncomingOfferSetStatus(offerId, status, successMessage) {
  const normalizedOfferId = String(offerId || "").trim();
  if (!normalizedOfferId) {
    return;
  }
  const offer = getIncomingOfferById(normalizedOfferId);
  if (!offer) {
    return;
  }
  const nowIso = new Date().toISOString();
  const nextRows = getIncomingOffers().map((entry) => {
    if (entry.id !== normalizedOfferId) {
      return entry;
    }
    const nextStatus = normalizeIncomingOfferStatus(status);
    return normalizeIncomingOfferRecord({
      ...entry,
      status: nextStatus,
      decided_at: ["angenommen", "abgelehnt", "abgelaufen"].includes(nextStatus) ? nowIso : entry.decidedAt,
      updated_at: nowIso,
      updated_by_user_id: getAuthUid() || "",
    });
  });
  applyIncomingOffersCache(nextRows, incomingOfferFiles || [], { persistBackup: true });
  saveState({ showFeedback: false });
  renderIncomingOffersSection();
  showSuccessFeedback(successMessage);
  if (normalizeIncomingOfferStatus(status) === "angenommen") {
    showInfoFeedback("Über „Als Rechnung“ kannst du das Angebot direkt in eine Rechnung übernehmen.");
  }
}

async function handleIncomingOfferOpenDocument(offerId) {
  const normalizedOfferId = String(offerId || "").trim();
  if (!normalizedOfferId) {
    return;
  }
  const file = getIncomingOfferFileForOffer(normalizedOfferId);
  const documentRef = String(file?.documentPath || "").trim();
  if (!documentRef) {
    showInfoFeedback("Keine Datei für dieses Angebot gespeichert.");
    return;
  }
  try {
    const accessToken = await getAuthAccessToken();
    const query = new URLSearchParams({
      ref: documentRef,
      offerId: normalizedOfferId,
    });
    if (file?.originalName) {
      query.set("name", String(file.originalName || "").trim());
    }
    const response = await fetch(`${INCOMING_INVOICE_FILE_DOWNLOAD_ENDPOINT}?${query.toString()}`, {
      method: "GET",
      headers: accessToken ? { Authorization: `Bearer ${accessToken}` } : {},
    });
    if (!response.ok) {
      const payload = await readIncomingInvoiceBridgePayload(response);
      throw new Error(getIncomingInvoiceBridgeErrorMessage(response, payload));
    }
    const blob = await response.blob();
    const downloadUrl = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = downloadUrl;
    link.download = String(file?.originalName || `angebot_${normalizedOfferId}.pdf`).trim() || `angebot_${normalizedOfferId}.pdf`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(downloadUrl);
  } catch (error) {
    const message = String(error?.message || "").trim();
    showWarningFeedback(message ? `Datei konnte nicht geladen werden (${message}).` : "Datei konnte nicht geladen werden.");
  }
}

function handleIncomingOfferConvertToInvoice(offerId) {
  const normalizedOfferId = String(offerId || "").trim();
  if (!normalizedOfferId) {
    return;
  }
  const offer = getIncomingOfferById(normalizedOfferId);
  if (!offer) {
    showWarningFeedback("Angebot wurde nicht gefunden.");
    return;
  }
  const file = getIncomingOfferFileForOffer(normalizedOfferId);
  const derivedInvoiceNumber = String(offer.offerNumber || "").trim()
    ? `RE-${String(offer.offerNumber || "").trim()}`
    : "";

  setActiveSection("incoming-invoices-section");
  resetIncomingInvoiceForm();
  setIncomingInvoicesWorkspaceTab("entry", { render: false });
  incomingInvoicesSelectedId = "";
  if (els.incomingInvoiceId) {
    els.incomingInvoiceId.value = "";
  }
  if (els.incomingInvoiceNumber) {
    els.incomingInvoiceNumber.value = derivedInvoiceNumber;
  }
  if (els.incomingInvoiceSupplier) {
    renderIncomingInvoiceSupplierOptions(offer.supplierCompanyId || "", offer.supplierName || "");
  }
  if (els.incomingInvoiceDate) {
    els.incomingInvoiceDate.value = normalizeIncomingInvoiceDateInputValue(offer.receivedDate || "") || getTodayDateInputValue();
  }
  if (els.incomingInvoiceDueDate) {
    els.incomingInvoiceDueDate.value = normalizeIncomingInvoiceDateInputValue(offer.validUntilDate || "");
  }
  if (els.incomingInvoiceTotalGross) {
    els.incomingInvoiceTotalGross.value = String(normalizeIncomingInvoiceAmount(offer.totalGross));
  }
  if (els.incomingInvoiceTotalNet) {
    els.incomingInvoiceTotalNet.value = String(normalizeIncomingInvoiceAmount(offer.totalNet));
  }
  if (els.incomingInvoiceTotalTax) {
    els.incomingInvoiceTotalTax.value = String(normalizeIncomingInvoiceAmount(offer.totalTax));
  }
  if (els.incomingInvoiceCategory) {
    els.incomingInvoiceCategory.value = offer.category || "Übernahme Angebot";
  }
  if (els.incomingInvoiceCostCenter) {
    els.incomingInvoiceCostCenter.value = offer.costCenter || "";
  }
  if (els.incomingInvoiceApprovalStatus) {
    els.incomingInvoiceApprovalStatus.value = "freigabe_offen";
  }
  if (els.incomingInvoicePaymentStatus) {
    els.incomingInvoicePaymentStatus.value = "offen";
  }
  if (els.incomingInvoicePaidAt) {
    els.incomingInvoicePaidAt.value = "";
  }
  if (els.incomingInvoicePaymentMethod) {
    els.incomingInvoicePaymentMethod.value = "";
  }
  if (els.incomingInvoiceFileName) {
    els.incomingInvoiceFileName.value = file?.originalName || "";
  }
  if (els.incomingInvoiceNasPath) {
    els.incomingInvoiceNasPath.value = file?.documentPath || "";
  }
  if (els.incomingInvoiceNotes) {
    const baseNotes = String(offer.notes || "").trim();
    const hint = `Übernommen aus Angebot ${offer.offerNumber || normalizedOfferId}`;
    els.incomingInvoiceNotes.value = baseNotes ? `${hint}\n${baseNotes}` : hint;
  }
  if (els.incomingInvoiceSaveBtn) {
    els.incomingInvoiceSaveBtn.textContent = "Rechnung speichern";
  }
  renderIncomingInvoicesSection();
  showSuccessFeedback("Angebot wurde als Rechnung vorbereitet.");
}

function buildIncomingOffersCsvRows(rows) {
  const header = [
    "offer_number",
    "supplier_name",
    "received_date",
    "valid_until_date",
    "total_net",
    "total_tax",
    "total_gross",
    "currency",
    "status",
    "priority",
    "decided_at",
    "category",
    "cost_center",
    "notes",
    "document_reference",
    "file_name",
  ];
  const lines = [header];
  (Array.isArray(rows) ? rows : []).forEach((entry) => {
    const file = getIncomingOfferFileForOffer(entry.id);
    lines.push([
      entry.offerNumber || "",
      entry.supplierName || "",
      entry.receivedDate || "",
      entry.validUntilDate || "",
      String(normalizeIncomingInvoiceAmount(entry.totalNet)),
      String(normalizeIncomingInvoiceAmount(entry.totalTax)),
      String(normalizeIncomingInvoiceAmount(entry.totalGross)),
      entry.currency || "EUR",
      normalizeIncomingOfferStatus(entry.status),
      normalizeIncomingOfferPriority(entry.priority),
      entry.decidedAt || "",
      entry.category || "",
      entry.costCenter || "",
      entry.notes || "",
      file?.documentPath || "",
      file?.originalName || "",
    ]);
  });
  return lines;
}

function exportIncomingOffersCsv() {
  const rows = getFilteredIncomingOffers();
  if (!rows.length) {
    showInfoFeedback("Keine Angebote zum Export im aktuellen Filter.");
    return;
  }
  const csvRows = buildIncomingOffersCsvRows(rows);
  const csvContent = csvRows.map((row) => row.map((cell) => csvEscapeCell(cell)).join(";")).join("\n");
  const blob = new Blob([`\uFEFF${csvContent}`], { type: "text/csv;charset=utf-8;" });
  const url = URL.createObjectURL(blob);
  const link = document.createElement("a");
  link.href = url;
  link.download = `eingangsangebote_${getTodayDateInputValue()}.csv`;
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
  URL.revokeObjectURL(url);
  showSuccessFeedback("CSV Export erstellt.");
}

function normalizeContractManagerView(value) {
  const normalized = String(value || "").trim().toLowerCase();
  if (["due", "active", "all"].includes(normalized)) {
    return normalized;
  }
  return "due";
}

function normalizeContractManagerWorkspaceTab(value) {
  const normalized = String(value || "").trim().toLowerCase();
  if (normalized === "entry" || normalized === "overview") {
    return normalized;
  }
  return "overview";
}

function normalizeContractManagerStatus(value) {
  const normalized = normalizeText(value || "");
  return CONTRACT_MANAGER_STATUSES.has(normalized) ? normalized : "aktiv";
}

function normalizeContractManagerType(value) {
  const normalized = normalizeText(value || "");
  return CONTRACT_MANAGER_TYPES.has(normalized) ? normalized : "dienstleistung";
}

function normalizeContractManagerBillingCycle(value) {
  const normalized = normalizeText(value || "");
  return CONTRACT_MANAGER_BILLING_CYCLES.has(normalized) ? normalized : "monatlich";
}

function normalizeContractManagerStatusFilter(value) {
  const normalized = String(value || "").trim();
  if (!normalized || normalizeText(normalized) === "all") {
    return "all";
  }
  return normalizeContractManagerStatus(normalized);
}

function normalizeContractManagerTypeFilter(value) {
  const normalized = String(value || "").trim();
  if (!normalized || normalizeText(normalized) === "all") {
    return "all";
  }
  return normalizeContractManagerType(normalized);
}

function normalizeContractManagerDays(value, fallback = 0) {
  const numeric = parseOptionalNumber(value);
  if (typeof numeric !== "number" || !Number.isFinite(numeric)) {
    return fallback;
  }
  return Math.max(0, Math.min(3650, Math.round(numeric)));
}

function normalizeContractManagerAmount(value) {
  return normalizeIncomingInvoiceAmount(value);
}

function normalizeContractManagerRecord(entry, index = 0) {
  if (!entry || typeof entry !== "object") {
    return null;
  }
  const id = String(entry.id || "").trim() || `contract_${index + 1}`;
  const title = String(entry.title || entry.contractTitle || "").trim();
  const startDate = normalizeIncomingInvoiceDateInputValue(entry.startDate || entry.start_date || "");
  if (!id || !title || !startDate) {
    return null;
  }
  const createdAtRaw = String(entry.createdAt || entry.created_at || "").trim();
  const createdAt = Number.isNaN(new Date(createdAtRaw).getTime()) ? new Date().toISOString() : createdAtRaw;
  const updatedAtRaw = String(entry.updatedAt || entry.updated_at || createdAt).trim();
  const updatedAt = Number.isNaN(new Date(updatedAtRaw).getTime()) ? createdAt : updatedAtRaw;
  return {
    id,
    title,
    companyId: normalizeIncomingInvoiceSupplierCompanyId(entry.companyId || entry.company_id || ""),
    companyName: String(entry.companyName || entry.company_name || "").trim(),
    type: normalizeContractManagerType(entry.type),
    status: normalizeContractManagerStatus(entry.status),
    startDate,
    endDate: normalizeIncomingInvoiceDateInputValue(entry.endDate || entry.end_date || ""),
    noticeDays: normalizeContractManagerDays(entry.noticeDays || entry.notice_days, 30),
    reminderDays: normalizeContractManagerDays(entry.reminderDays || entry.reminder_days, 45),
    amountEur: normalizeContractManagerAmount(entry.amountEur || entry.amount_eur || 0),
    billingCycle: normalizeContractManagerBillingCycle(entry.billingCycle || entry.billing_cycle || ""),
    ownerUserId: normalizeUserId(entry.ownerUserId || entry.owner_user_id || ""),
    documentRef: String(entry.documentRef || entry.document_ref || "").trim(),
    notes: String(entry.notes || "").trim(),
    createdAt,
    updatedAt,
    createdByUserId: normalizeUserId(entry.createdByUserId || entry.created_by_user_id || ""),
    updatedByUserId: normalizeUserId(entry.updatedByUserId || entry.updated_by_user_id || ""),
  };
}

function normalizeContractManagerEntries(rawList) {
  if (!Array.isArray(rawList)) {
    return [];
  }
  const seen = new Set();
  const rows = [];
  rawList.forEach((entry, index) => {
    const normalized = normalizeContractManagerRecord(entry, index);
    if (!normalized || seen.has(normalized.id)) {
      return;
    }
    seen.add(normalized.id);
    rows.push(normalized);
  });
  return rows.sort((left, right) => {
    const leftEnd = String(left.endDate || "9999-12-31");
    const rightEnd = String(right.endDate || "9999-12-31");
    if (leftEnd !== rightEnd) {
      return leftEnd.localeCompare(rightEnd);
    }
    return String(right.updatedAt || "").localeCompare(String(left.updatedAt || ""));
  });
}

function applyContractManagerCache(nextEntries, options = {}) {
  contractManagerEntries = normalizeContractManagerEntries(nextEntries || []);
  state.settings = normalizeSettings({
    ...state.settings,
    contractManagerEntries,
  });
  if (options?.persistBackup !== false) {
    persistLocalBackup();
  }
}

function getContractManagerLocalFallback() {
  return normalizeContractManagerEntries(state.settings?.contractManagerEntries || []);
}

function getContractManagerEntries() {
  return normalizeContractManagerEntries(contractManagerEntries || []);
}

function getContractManagerEntryById(entryId) {
  const normalizedId = String(entryId || "").trim();
  if (!normalizedId) {
    return null;
  }
  return getContractManagerEntries().find((entry) => entry.id === normalizedId) || null;
}

function getContractManagerStatusLabel(status) {
  const normalized = normalizeContractManagerStatus(status);
  if (normalized === "entwurf") {
    return "Entwurf";
  }
  if (normalized === "gekundigt") {
    return "Gekuendigt";
  }
  if (normalized === "beendet") {
    return "Beendet";
  }
  return "Aktiv";
}

function getContractManagerTypeLabel(type) {
  const normalized = normalizeContractManagerType(type);
  if (normalized === "software") {
    return "Software";
  }
  if (normalized === "leasing") {
    return "Leasing";
  }
  if (normalized === "miete") {
    return "Miete";
  }
  if (normalized === "telekom") {
    return "Telekom";
  }
  if (normalized === "sonstiges") {
    return "Sonstiges";
  }
  return "Dienstleistung";
}

function getContractManagerBillingCycleLabel(cycle) {
  const normalized = normalizeContractManagerBillingCycle(cycle);
  if (normalized === "quartal") {
    return "Quartal";
  }
  if (normalized === "jahrlich") {
    return "Jaehrlich";
  }
  if (normalized === "einmalig") {
    return "Einmalig";
  }
  return "Monatlich";
}

function getContractManagerStatusCssClass(status) {
  const normalized = normalizeContractManagerStatus(status);
  if (normalized === "beendet") {
    return "is-partial";
  }
  if (normalized === "gekundigt") {
    return "is-approval-open";
  }
  if (normalized === "aktiv") {
    return "is-approved";
  }
  return "";
}

function renderContractManagerCompanyOptions(selectedCompanyId = "", fallbackName = "") {
  if (!els.contractManagerCompany) {
    return "";
  }
  const companies = getIncomingInvoiceSupplierCompanies();
  const selectedId = normalizeIncomingInvoiceSupplierCompanyId(selectedCompanyId);
  const fallbackCompany = String(fallbackName || "").trim();
  const optionRows = [];
  optionRows.push(`<option value="">${companies.length ? "Firma waehlen..." : "Keine Firmen vorhanden"}</option>`);
  companies.forEach((company) => {
    const companyId = String(company?.id || "").trim();
    const name = String(company?.name || "").trim();
    if (!companyId || !name) {
      return;
    }
    const locationLabel = [String(company?.postalCode || "").trim(), String(company?.city || "").trim(), String(company?.country || "").trim()]
      .filter(Boolean)
      .join(" ");
    const label = locationLabel ? `${name} · ${locationLabel}` : name;
    optionRows.push(`<option value="${escapeHtml(companyId)}">${escapeHtml(label)}</option>`);
  });
  if (fallbackCompany && !companies.some((entry) => normalizeText(entry?.name || "") === normalizeText(fallbackCompany))) {
    optionRows.push(`<option value="__legacy_company__">${escapeHtml(`${fallbackCompany} (Altbestand)`)}</option>`);
  }
  els.contractManagerCompany.innerHTML = optionRows.join("");
  if (selectedId && companies.some((entry) => String(entry?.id || "").trim() === selectedId)) {
    els.contractManagerCompany.value = selectedId;
    return selectedId;
  }
  if (fallbackCompany && els.contractManagerCompany.querySelector('option[value="__legacy_company__"]')) {
    els.contractManagerCompany.value = "__legacy_company__";
    return "__legacy_company__";
  }
  els.contractManagerCompany.value = "";
  return "";
}

function renderContractManagerOwnerOptions(selectedOwnerId = "") {
  if (!els.contractManagerOwner) {
    return "";
  }
  const normalizedSelected = normalizeUserId(selectedOwnerId);
  const users = state.users
    .filter((entry) => entry.source === "profile" && isUserStatusActive(entry.status))
    .map((entry) => ({
      userId: normalizeUserId(entry.sourceId || entry.id || ""),
      name: String(entry.name || entry.email || "").trim(),
      role: normalizeUserRole(entry.role),
    }))
    .filter((entry) => entry.userId && entry.name)
    .sort((left, right) => left.name.localeCompare(right.name, "de", { sensitivity: "base" }));
  const options = ['<option value="">Nicht gesetzt</option>'];
  users.forEach((entry) => {
    options.push(
      `<option value="${escapeHtml(entry.userId)}">${escapeHtml(entry.name)} · ${escapeHtml(getRoleLabel(entry.role))}</option>`
    );
  });
  els.contractManagerOwner.innerHTML = options.join("");
  if (normalizedSelected && users.some((entry) => entry.userId === normalizedSelected)) {
    els.contractManagerOwner.value = normalizedSelected;
    return normalizedSelected;
  }
  els.contractManagerOwner.value = "";
  return "";
}

function getContractManagerNoticeDate(entry) {
  const endDate = normalizeIncomingInvoiceDateInputValue(entry?.endDate || "");
  if (!endDate) {
    return "";
  }
  const parsed = parseDateInputStart(endDate);
  if (!parsed) {
    return "";
  }
  const noticeDays = normalizeContractManagerDays(entry?.noticeDays, 0);
  if (noticeDays <= 0) {
    return endDate;
  }
  parsed.setDate(parsed.getDate() - noticeDays);
  return toDateInputValue(parsed);
}

function getDayDiffFromToday(dateInputValue) {
  const parsed = parseDateInputStart(normalizeIncomingInvoiceDateInputValue(dateInputValue || ""));
  if (!parsed) {
    return null;
  }
  const today = parseDateInputStart(getTodayDateInputValue());
  if (!today) {
    return null;
  }
  return Math.round((parsed.getTime() - today.getTime()) / 86400000);
}

function getContractManagerReminderState(entry) {
  const normalizedStatus = normalizeContractManagerStatus(entry?.status);
  if (normalizedStatus === "beendet") {
    return { key: "done", label: "Beendet", cssClass: "is-partial" };
  }
  const noticeDate = getContractManagerNoticeDate(entry);
  if (!noticeDate) {
    return { key: "open", label: "Kein Fristdatum", cssClass: "" };
  }
  const dayDiff = getDayDiffFromToday(noticeDate);
  if (typeof dayDiff !== "number") {
    return { key: "open", label: "Kein Fristdatum", cssClass: "" };
  }
  if (dayDiff < 0) {
    return { key: "overdue", label: `Frist vorbei (${Math.abs(dayDiff)} T)`, cssClass: "is-approval-open" };
  }
  const reminderDays = normalizeContractManagerDays(entry?.reminderDays, 45);
  if (dayDiff <= reminderDays) {
    return { key: "due", label: dayDiff === 0 ? "Heute kuendigen" : `In ${dayDiff} T`, cssClass: "is-partial" };
  }
  return { key: "ok", label: `${dayDiff} T Rest`, cssClass: "is-approved" };
}

function getContractManagerAnnualAmount(entry) {
  const amount = normalizeContractManagerAmount(entry?.amountEur || 0);
  const cycle = normalizeContractManagerBillingCycle(entry?.billingCycle || "");
  if (cycle === "quartal") {
    return amount * 4;
  }
  if (cycle === "jahrlich") {
    return amount;
  }
  if (cycle === "einmalig") {
    return amount;
  }
  return amount * 12;
}

function matchesContractManagerDateRange(entry, fromDate, toDate) {
  if (!fromDate && !toDate) {
    return true;
  }
  const endDate = parseDateInputStart(normalizeIncomingInvoiceDateInputValue(entry?.endDate || ""));
  if (!endDate) {
    return false;
  }
  if (fromDate && endDate < fromDate) {
    return false;
  }
  if (toDate) {
    const toEnd = new Date(toDate.getTime());
    toEnd.setDate(toEnd.getDate() + 1);
    if (endDate >= toEnd) {
      return false;
    }
  }
  return true;
}

function getFilteredContractManagerEntries() {
  const searchNeedle = normalizeText(contractManagerSearchTerm || "");
  const fromDate = parseDateInputStart(contractManagerDateFrom);
  const toDate = parseDateInputStart(contractManagerDateTo);
  return getContractManagerEntries().filter((entry) => {
    const normalizedStatus = normalizeContractManagerStatus(entry?.status);
    const reminderState = getContractManagerReminderState(entry);
    if (contractManagerView === "due" && !["due", "overdue"].includes(reminderState.key)) {
      return false;
    }
    if (contractManagerView === "active" && !["aktiv", "entwurf", "gekundigt"].includes(normalizedStatus)) {
      return false;
    }
    if (contractManagerStatusFilter !== "all" && normalizedStatus !== contractManagerStatusFilter) {
      return false;
    }
    if (contractManagerTypeFilter !== "all" && normalizeContractManagerType(entry?.type) !== contractManagerTypeFilter) {
      return false;
    }
    if (!matchesContractManagerDateRange(entry, fromDate, toDate)) {
      return false;
    }
    if (searchNeedle) {
      const haystack = normalizeText(
        [
          entry.title,
          entry.companyName,
          getContractManagerTypeLabel(entry.type),
          getContractManagerStatusLabel(normalizedStatus),
          getUserDisplayNameByUserId(entry.ownerUserId),
          entry.notes,
        ]
          .filter(Boolean)
          .join(" ")
      );
      if (!haystack.includes(searchNeedle)) {
        return false;
      }
    }
    return true;
  });
}

function syncContractManagerFilterControls() {
  if (els.contractManagerSearchInput && els.contractManagerSearchInput.value !== contractManagerSearchTerm) {
    els.contractManagerSearchInput.value = contractManagerSearchTerm;
  }
  if (els.contractManagerFilterStatus) {
    contractManagerStatusFilter = normalizeContractManagerStatusFilter(contractManagerStatusFilter);
    if (els.contractManagerFilterStatus.value !== contractManagerStatusFilter) {
      els.contractManagerFilterStatus.value = contractManagerStatusFilter;
    }
  }
  if (els.contractManagerFilterType) {
    contractManagerTypeFilter = normalizeContractManagerTypeFilter(contractManagerTypeFilter);
    if (els.contractManagerFilterType.value !== contractManagerTypeFilter) {
      els.contractManagerFilterType.value = contractManagerTypeFilter;
    }
  }
  if (els.contractManagerDateFrom && els.contractManagerDateFrom.value !== contractManagerDateFrom) {
    els.contractManagerDateFrom.value = contractManagerDateFrom;
  }
  if (els.contractManagerDateTo && els.contractManagerDateTo.value !== contractManagerDateTo) {
    els.contractManagerDateTo.value = contractManagerDateTo;
  }
}

function setContractManagerView(nextView, options = {}) {
  contractManagerView = normalizeContractManagerView(nextView);
  const activeView = contractManagerView;
  els.contractManagerViewButtons?.forEach((button) => {
    const target = normalizeContractManagerView(button.dataset.contractManagerViewTarget || "");
    const isActive = target === activeView;
    button.classList.toggle("is-active", isActive);
    setTabButtonA11yState(button, isActive);
  });
  if (options?.render !== false) {
    renderContractManagerSection();
  }
}

function setContractManagerWorkspaceTab(nextTab, options = {}) {
  contractManagerWorkspaceTab = normalizeContractManagerWorkspaceTab(nextTab);
  const activeTab = contractManagerWorkspaceTab;
  els.contractManagerWorkspaceTabButtons?.forEach((button) => {
    const target = normalizeContractManagerWorkspaceTab(button.dataset.contractManagerWorkspaceTab || "");
    const isActive = target === activeTab;
    button.classList.toggle("is-active", isActive);
    setTabButtonA11yState(button, isActive);
  });
  els.contractManagerWorkspacePanels?.forEach((panel) => {
    const target = normalizeContractManagerWorkspaceTab(panel.dataset.contractManagerWorkspacePanel || "");
    const isActive = target === activeTab;
    panel.classList.toggle("hidden", !isActive);
    setTabPanelA11yState(panel, isActive);
  });
  if (options?.render !== false) {
    renderContractManagerSection();
  }
}

function renderContractManagerKpis(rows) {
  if (!els.contractManagerKpis) {
    return;
  }
  const stats = {
    dueCount: 0,
    overdueCount: 0,
    activeCount: 0,
    annualAmount: 0,
  };
  (Array.isArray(rows) ? rows : []).forEach((entry) => {
    const status = normalizeContractManagerStatus(entry?.status);
    const reminder = getContractManagerReminderState(entry);
    if (["aktiv", "entwurf", "gekundigt"].includes(status)) {
      stats.activeCount += 1;
      stats.annualAmount += getContractManagerAnnualAmount(entry);
    }
    if (reminder.key === "due") {
      stats.dueCount += 1;
    }
    if (reminder.key === "overdue") {
      stats.overdueCount += 1;
    }
  });
  els.contractManagerKpis.innerHTML = `
    <article class="incoming-invoices-kpi">
      <span>Frist bald faellig</span>
      <strong>${escapeHtml(String(stats.dueCount))}</strong>
    </article>
    <article class="incoming-invoices-kpi">
      <span>Frist verpasst</span>
      <strong>${escapeHtml(String(stats.overdueCount))}</strong>
    </article>
    <article class="incoming-invoices-kpi">
      <span>Aktive Vertraege</span>
      <strong>${escapeHtml(String(stats.activeCount))}</strong>
    </article>
    <article class="incoming-invoices-kpi">
      <span>Kosten pro Jahr</span>
      <strong>${escapeHtml(formatIncomingInvoiceMoney(stats.annualAmount))}</strong>
    </article>
  `;
}

function renderContractManagerSection() {
  if (!els.contractManagerTableBody) {
    return;
  }
  renderContractManagerCompanyOptions(els.contractManagerCompany?.value || "");
  renderContractManagerOwnerOptions(els.contractManagerOwner?.value || "");
  setContractManagerWorkspaceTab(contractManagerWorkspaceTab, { render: false });
  setContractManagerView(contractManagerView, { render: false });
  syncContractManagerFilterControls();
  const rows = getFilteredContractManagerEntries();
  renderContractManagerKpis(rows);
  if (!rows.length) {
    els.contractManagerTableBody.innerHTML = '<tr><td colspan="8" class="empty">Keine Vertraege im gewaehlten Filter.</td></tr>';
  } else {
    els.contractManagerTableBody.innerHTML = rows
      .map((entry) => {
        const statusClass = getContractManagerStatusCssClass(entry.status);
        const reminderState = getContractManagerReminderState(entry);
        const noticeDate = getContractManagerNoticeDate(entry);
        const canSetCancelled = !["gekundigt", "beendet"].includes(normalizeContractManagerStatus(entry.status));
        const canSetEnded = normalizeContractManagerStatus(entry.status) !== "beendet";
        return `
          <tr>
            <td>
              <strong>${escapeHtml(entry.title || "–")}</strong><br />
              <span class="incoming-invoices-table-meta">${escapeHtml(getContractManagerTypeLabel(entry.type))}</span>
            </td>
            <td>
              ${
                entry.companyName
                  ? `<button
                      type="button"
                      class="entity-link-btn"
                      data-contract-manager-open-company="${escapeHtml(String(entry.companyId || "").trim())}"
                      data-contract-manager-open-company-name="${escapeHtml(String(entry.companyName || "").trim())}"
                    >${escapeHtml(entry.companyName)}</button>`
                  : "–"
              }
            </td>
            <td>${escapeHtml(entry.endDate ? formatTourDateLabel(entry.endDate) : "Ohne Ende")}</td>
            <td>${escapeHtml(noticeDate ? formatTourDateLabel(noticeDate) : "–")}</td>
            <td>${escapeHtml(formatIncomingInvoiceMoney(getContractManagerAnnualAmount(entry)))}</td>
            <td><span class="incoming-invoices-pill ${escapeHtml(statusClass)}">${escapeHtml(getContractManagerStatusLabel(entry.status))}</span></td>
            <td><span class="incoming-invoices-pill ${escapeHtml(reminderState.cssClass)}">${escapeHtml(reminderState.label)}</span></td>
            <td>
              <div class="incoming-invoices-actions-inline">
                <button type="button" class="mini-btn" data-contract-manager-edit="${escapeHtml(entry.id)}">Bearbeiten</button>
                <button type="button" class="mini-btn" data-contract-manager-open-invoices="${escapeHtml(entry.id)}">Rechnungen</button>
                <button type="button" class="mini-btn" data-contract-manager-open-offers="${escapeHtml(entry.id)}">Angebote</button>
                ${canSetCancelled ? `<button type="button" class="mini-btn danger" data-contract-manager-cancel="${escapeHtml(entry.id)}">Kuendigen</button>` : ""}
                ${canSetEnded ? `<button type="button" class="mini-btn" data-contract-manager-terminate="${escapeHtml(entry.id)}">Beenden</button>` : ""}
              </div>
            </td>
          </tr>
        `;
      })
      .join("");
  }
  if (els.contractManagerTableMeta) {
    const modeText =
      contractManagerView === "active"
        ? "Aktiv"
        : contractManagerView === "due"
          ? "Bald faellig"
          : "Alle";
    els.contractManagerTableMeta.textContent = `${rows.length} Eintraege · Ansicht: ${modeText}`;
  }
}

function resetContractManagerForm() {
  if (els.contractManagerForm) {
    els.contractManagerForm.reset();
  }
  if (els.contractManagerId) {
    els.contractManagerId.value = "";
  }
  if (els.contractManagerStatus) {
    els.contractManagerStatus.value = "aktiv";
  }
  if (els.contractManagerType) {
    els.contractManagerType.value = "dienstleistung";
  }
  if (els.contractManagerBillingCycle) {
    els.contractManagerBillingCycle.value = "monatlich";
  }
  if (els.contractManagerNoticeDays) {
    els.contractManagerNoticeDays.value = "30";
  }
  if (els.contractManagerReminderDays) {
    els.contractManagerReminderDays.value = "45";
  }
  if (els.contractManagerStartDate && !els.contractManagerStartDate.value) {
    els.contractManagerStartDate.value = getTodayDateInputValue();
  }
  renderContractManagerCompanyOptions();
  renderContractManagerOwnerOptions();
  contractManagerSelectedId = "";
  if (els.contractManagerSaveBtn) {
    els.contractManagerSaveBtn.textContent = "Vertrag speichern";
  }
}

function fillContractManagerForm(entry) {
  if (!entry) {
    return;
  }
  contractManagerSelectedId = String(entry.id || "").trim();
  if (els.contractManagerId) {
    els.contractManagerId.value = contractManagerSelectedId;
  }
  if (els.contractManagerTitle) {
    els.contractManagerTitle.value = entry.title || "";
  }
  if (els.contractManagerCompany) {
    renderContractManagerCompanyOptions(entry.companyId || "", entry.companyName || "");
  }
  if (els.contractManagerType) {
    els.contractManagerType.value = normalizeContractManagerType(entry.type);
  }
  if (els.contractManagerStatus) {
    els.contractManagerStatus.value = normalizeContractManagerStatus(entry.status);
  }
  if (els.contractManagerStartDate) {
    els.contractManagerStartDate.value = normalizeIncomingInvoiceDateInputValue(entry.startDate);
  }
  if (els.contractManagerEndDate) {
    els.contractManagerEndDate.value = normalizeIncomingInvoiceDateInputValue(entry.endDate);
  }
  if (els.contractManagerNoticeDays) {
    els.contractManagerNoticeDays.value = String(normalizeContractManagerDays(entry.noticeDays, 30));
  }
  if (els.contractManagerReminderDays) {
    els.contractManagerReminderDays.value = String(normalizeContractManagerDays(entry.reminderDays, 45));
  }
  if (els.contractManagerAmount) {
    els.contractManagerAmount.value = String(normalizeContractManagerAmount(entry.amountEur));
  }
  if (els.contractManagerBillingCycle) {
    els.contractManagerBillingCycle.value = normalizeContractManagerBillingCycle(entry.billingCycle);
  }
  if (els.contractManagerOwner) {
    renderContractManagerOwnerOptions(entry.ownerUserId || "");
  }
  if (els.contractManagerDocumentRef) {
    els.contractManagerDocumentRef.value = entry.documentRef || "";
  }
  if (els.contractManagerNotes) {
    els.contractManagerNotes.value = entry.notes || "";
  }
  if (els.contractManagerSaveBtn) {
    els.contractManagerSaveBtn.textContent = "Vertrag aktualisieren";
  }
}

function buildContractManagerPayloadFromForm() {
  const title = String(els.contractManagerTitle?.value || "").trim();
  const startDate = normalizeIncomingInvoiceDateInputValue(els.contractManagerStartDate?.value || "");
  const selectedCompanyValue = String(els.contractManagerCompany?.value || "").trim();
  const selectedCompanyOption = els.contractManagerCompany?.selectedOptions?.[0] || null;
  const companyId = selectedCompanyValue === "__legacy_company__" ? "" : normalizeIncomingInvoiceSupplierCompanyId(selectedCompanyValue);
  const companyNameRaw = selectedCompanyOption ? String(selectedCompanyOption.textContent || "").trim() : "";
  const companyName = companyNameRaw
    .replace(/\s·\s[^·]*$/, "")
    .replace(/\s\(Altbestand\)\s*$/i, "")
    .trim();
  if (!title) {
    showWarningFeedback("Vertragsname fehlt.");
    return null;
  }
  if (!companyId || !companyName) {
    showWarningFeedback("Bitte Firma aus Firmen auswaehlen.");
    return null;
  }
  if (!startDate) {
    showWarningFeedback("Startdatum fehlt.");
    return null;
  }
  return {
    title,
    companyId,
    companyName,
    type: normalizeContractManagerType(els.contractManagerType?.value || "dienstleistung"),
    status: normalizeContractManagerStatus(els.contractManagerStatus?.value || "aktiv"),
    startDate,
    endDate: normalizeIncomingInvoiceDateInputValue(els.contractManagerEndDate?.value || ""),
    noticeDays: normalizeContractManagerDays(els.contractManagerNoticeDays?.value, 30),
    reminderDays: normalizeContractManagerDays(els.contractManagerReminderDays?.value, 45),
    amountEur: normalizeContractManagerAmount(els.contractManagerAmount?.value || 0),
    billingCycle: normalizeContractManagerBillingCycle(els.contractManagerBillingCycle?.value || "monatlich"),
    ownerUserId: normalizeUserId(els.contractManagerOwner?.value || ""),
    documentRef: String(els.contractManagerDocumentRef?.value || "").trim(),
    notes: String(els.contractManagerNotes?.value || "").trim(),
  };
}

function writeContractManagerLocalFallback(payload, entryId = "") {
  const actor = getCurrentActorInfo();
  const nowIso = new Date().toISOString();
  const normalizedId = String(entryId || "").trim() || createId("contract");
  const existing = getContractManagerEntryById(normalizedId);
  const nextRow = normalizeContractManagerRecord({
    id: normalizedId,
    title: payload.title,
    company_id: payload.companyId,
    company_name: payload.companyName,
    type: payload.type,
    status: payload.status,
    start_date: payload.startDate,
    end_date: payload.endDate,
    notice_days: payload.noticeDays,
    reminder_days: payload.reminderDays,
    amount_eur: payload.amountEur,
    billing_cycle: payload.billingCycle,
    owner_user_id: payload.ownerUserId,
    document_ref: payload.documentRef,
    notes: payload.notes,
    updated_at: nowIso,
    updated_by_user_id: actor.userId || null,
    created_at: existing?.createdAt || nowIso,
    created_by_user_id: existing?.createdByUserId || actor.userId || null,
  });
  if (!nextRow) {
    return "";
  }
  const nextRows = existing
    ? getContractManagerEntries().map((entry) => (entry.id === normalizedId ? nextRow : entry))
    : getContractManagerEntries().concat(nextRow);
  applyContractManagerCache(nextRows, { persistBackup: true });
  saveState({ showFeedback: false });
  return normalizedId;
}

function handleContractManagerSave() {
  const payload = buildContractManagerPayloadFromForm();
  if (!payload) {
    return;
  }
  const editingId = String(els.contractManagerId?.value || contractManagerSelectedId || "").trim();
  const savedId = writeContractManagerLocalFallback(payload, editingId);
  if (!savedId) {
    showWarningFeedback("Vertrag konnte nicht gespeichert werden.");
    return;
  }
  contractManagerSelectedId = savedId;
  resetContractManagerForm();
  setContractManagerWorkspaceTab("overview", { render: false });
  renderContractManagerSection();
  showSuccessFeedback(editingId ? "Vertrag aktualisiert." : "Vertrag angelegt.");
}

function handleContractManagerSetStatus(contractId, status, successMessage) {
  const normalizedId = String(contractId || "").trim();
  if (!normalizedId) {
    return;
  }
  const row = getContractManagerEntryById(normalizedId);
  if (!row) {
    return;
  }
  const nowIso = new Date().toISOString();
  const nextStatus = normalizeContractManagerStatus(status);
  const nextRows = getContractManagerEntries().map((entry) => {
    if (entry.id !== normalizedId) {
      return entry;
    }
    const nextEndDate =
      nextStatus === "beendet" && !normalizeIncomingInvoiceDateInputValue(entry.endDate || "")
        ? getTodayDateInputValue()
        : entry.endDate;
    return normalizeContractManagerRecord({
      ...entry,
      status: nextStatus,
      end_date: nextEndDate,
      updated_at: nowIso,
      updated_by_user_id: getAuthUid() || "",
    });
  });
  applyContractManagerCache(nextRows, { persistBackup: true });
  saveState({ showFeedback: false });
  renderContractManagerSection();
  showSuccessFeedback(successMessage);
}

function buildContractManagerCsvRows(rows) {
  const header = [
    "title",
    "company_name",
    "type",
    "status",
    "start_date",
    "end_date",
    "notice_date",
    "notice_days",
    "reminder_days",
    "amount_eur",
    "billing_cycle",
    "annualized_cost_eur",
    "owner",
    "document_ref",
    "notes",
  ];
  const lines = [header];
  (Array.isArray(rows) ? rows : []).forEach((entry) => {
    lines.push([
      entry.title || "",
      entry.companyName || "",
      getContractManagerTypeLabel(entry.type),
      getContractManagerStatusLabel(entry.status),
      entry.startDate || "",
      entry.endDate || "",
      getContractManagerNoticeDate(entry) || "",
      String(normalizeContractManagerDays(entry.noticeDays, 0)),
      String(normalizeContractManagerDays(entry.reminderDays, 0)),
      String(normalizeContractManagerAmount(entry.amountEur)),
      getContractManagerBillingCycleLabel(entry.billingCycle),
      String(Math.round(getContractManagerAnnualAmount(entry) * 100) / 100),
      getUserDisplayNameByUserId(entry.ownerUserId) || "",
      entry.documentRef || "",
      entry.notes || "",
    ]);
  });
  return lines;
}

function exportContractManagerCsv() {
  const rows = getFilteredContractManagerEntries();
  if (!rows.length) {
    showInfoFeedback("Keine Vertraege zum Export im aktuellen Filter.");
    return;
  }
  const csvRows = buildContractManagerCsvRows(rows);
  const csvContent = csvRows.map((row) => row.map((cell) => csvEscapeCell(cell)).join(";")).join("\n");
  const blob = new Blob([`\uFEFF${csvContent}`], { type: "text/csv;charset=utf-8;" });
  const url = URL.createObjectURL(blob);
  const link = document.createElement("a");
  link.href = url;
  link.download = `vertraege_fristen_${getTodayDateInputValue()}.csv`;
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
  URL.revokeObjectURL(url);
  showSuccessFeedback("CSV Export erstellt.");
}

function renderTourSelect(tours, selectedTour) {
  if (!els.tourSelectInput) {
    return;
  }
  const rows = Array.isArray(tours) ? tours : [];
  if (els.tourListMeta) {
    els.tourListMeta.textContent = `${rows.length} ${rows.length === 1 ? "Tour" : "Touren"}`;
  }
  if (!rows.length) {
    els.tourSelectInput.innerHTML = '<option value="">Keine Tour</option>';
    els.tourSelectInput.value = "";
    els.tourSelectInput.disabled = true;
    return;
  }

  els.tourSelectInput.innerHTML = rows
    .map((tour) => {
      const stopCount = Array.isArray(tour.stops) ? tour.stops.length : 0;
      const optionLabel = `${tour.name} · ${formatTourDateLabel(tour.plannedDate)} · ${stopCount} ${
        stopCount === 1 ? "Stop" : "Stops"
      }`;
      return `<option value="${escapeHtml(tour.id)}">${escapeHtml(optionLabel)}</option>`;
    })
    .join("");
  els.tourSelectInput.disabled = false;
  els.tourSelectInput.value = selectedTour?.id || rows[0]?.id || "";
}

function renderTourMobileTourList(tours, selectedTour) {
  if (!els.tourMobileTourList) {
    return;
  }
  const rows = Array.isArray(tours) ? tours : [];
  const showList = isTourMobileViewport() && rows.length > 1;
  if (!showList) {
    els.tourMobileTourList.classList.add("hidden");
    els.tourMobileTourList.innerHTML = "";
    return;
  }

  const activeTourId = String(selectedTour?.id || "").trim();
  els.tourMobileTourList.innerHTML = rows
    .map((tour) => {
      const stopCount = Array.isArray(tour?.stops) ? tour.stops.length : 0;
      const isActive = String(tour?.id || "").trim() === activeTourId;
      return `
        <button
          type="button"
          class="tour-mobile-tour-btn ${isActive ? "is-active" : ""}"
          data-tour-mobile-select="${escapeHtml(tour.id)}"
          aria-pressed="${isActive ? "true" : "false"}"
        >
          <strong>${escapeHtml(String(tour.name || "Tour").trim())}</strong>
          <span>${escapeHtml(formatTourDateLabel(tour.plannedDate))}</span>
          <small>${escapeHtml(String(stopCount))} ${stopCount === 1 ? "Stop" : "Stops"}</small>
        </button>
      `;
    })
    .join("");
  els.tourMobileTourList.classList.remove("hidden");
}

