function fillProviderForm(provider) {
  const locations = getProviderLocations(provider);
  const primaryLocation = locations[0] || createEmptyProviderLocation();
  const coverageMode = getProviderCoverageMode(provider);
  const coverageCountry = getProviderCoverageCountry(provider);
  const coverageStates = getProviderCoverageStates(provider);
  const formElements = els.providerForm.elements;
  formElements.name.value = provider.name;
  formElements.address.value = primaryLocation.address;
  formElements.postalCode.value = primaryLocation.postalCode;
  formElements.city.value = primaryLocation.city;
  formElements.country.value = primaryLocation.country;
  formElements.state.value = primaryLocation.state;
  formElements.website.value = provider.website;
  syncProviderWebsitePreviewLink();
  formElements.email.value = provider.email;
  formElements.phone.value = provider.phone;
  setProviderStatusInForm(provider.status);
  if (formElements.adminOnly) {
    formElements.adminOnly.checked = isProviderAdminOnly(provider);
  }
  if (formElements.onlineOnly) {
    formElements.onlineOnly.checked = isProviderOnlineOnly(provider);
  }
  formElements.latitude.value =
    typeof primaryLocation.latitude === "number" && Number.isFinite(primaryLocation.latitude)
      ? String(primaryLocation.latitude)
      : "";
  formElements.longitude.value =
    typeof primaryLocation.longitude === "number" && Number.isFinite(primaryLocation.longitude)
      ? String(primaryLocation.longitude)
      : "";
  setCoverageModeInForm(coverageMode);
  if (els.providerCoverageCountryInput) {
    els.providerCoverageCountryInput.value = coverageCountry;
  }
  providerCoverageStatesDraft = normalizeProviderCoverageStatesForCountry(
    coverageStates,
    coverageCountry
  );
  syncProviderCoverageFormState();
  if (els.providerCreatedMeta) {
    els.providerCreatedMeta.textContent = formatAuditStamp(
      provider.createdAt,
      provider.createdByRole,
      provider.createdByName
    );
  }
  if (els.providerUpdatedMeta) {
    els.providerUpdatedMeta.textContent = formatAuditStamp(
      provider.updatedAt,
      provider.updatedByRole,
      provider.updatedByName
    );
  }
  if (els.providerLiveMeta) {
    els.providerLiveMeta.textContent = getProviderLiveAuditStamp(provider);
  }

  clearProviderNameSuggestions();
  clearAddressSuggestions();
  resetProviderNoteEditorState();
  providerAdditionalLocationsDraft = locations.slice(1).map((location) => ({ ...location }));
  renderProviderAdditionalLocations();
  providerTopicSelection = new Set(provider.topicIds || []);
  if (els.providerTopicSearch) {
    els.providerTopicSearch.value = "";
  }
  providerLiveStatusConfirmedInForm = isLiveStatus(provider.status);
  providerLiveProvisionAssigneeInForm = isLiveStatus(provider.status)
    ? resolveProviderProvisionUserId(provider)
    : "";
  renderProviderTopicPicker();
  renderProviderNotes();
  syncProviderStatusSliderUi();
  setProviderDetailTab("master");
  void fetchProviderNotesForProvider(provider.id, { force: true });
  providerFormDirty = false;
  providerDraftPendingResume = false;
}

function normalizeUserFormTab(value) {
  const normalizedValue = String(value || "").trim().toLowerCase();
  if (["profil", "kontakt", "anstellung", "notizen", "role", "visibility"].includes(normalizedValue)) {
    return normalizedValue;
  }
  return "profil";
}

const USER_FORM_STEP_ORDER = ["profil", "kontakt", "anstellung", "role", "visibility", "notizen"];
const USER_FORM_STEP_LABELS = {
  profil: "Profil",
  kontakt: "Kontakt",
  anstellung: "Anstellung",
  notizen: "Notizen",
  role: "Rolle",
  visibility: "Sichtbarkeit",
};

function getUserFormStepIndex(tab = userFormTab) {
  const normalizedTab = normalizeUserFormTab(tab);
  const index = USER_FORM_STEP_ORDER.indexOf(normalizedTab);
  return index >= 0 ? index : 0;
}

function getUserFormStepLabel(tab = userFormTab) {
  const normalizedTab = normalizeUserFormTab(tab);
  return USER_FORM_STEP_LABELS[normalizedTab] || "Profil";
}

function setUserFormGuidedMode(guided) {
  userFormGuidedMode = Boolean(guided);
  if (els.userFormWizardBar) {
    els.userFormWizardBar.classList.toggle("hidden", !userFormGuidedMode);
  }
  setUserFormTab(userFormTab);
}

function validateUserFormIdentityFields() {
  const identityFields = ["name", "address", "email", "phone"];
  for (const fieldName of identityFields) {
    const field = els.userForm?.elements?.[fieldName];
    if (!field || typeof field.reportValidity !== "function") {
      continue;
    }
    if (!field.reportValidity()) {
      return false;
    }
  }
  return true;
}

function validateCurrentUserFormStep() {
  if (!validateUserFormIdentityFields()) {
    return false;
  }
  const activePanel = Array.from(els.userFormTabPanels || []).find((panel) => !panel.classList.contains("hidden"));
  if (!activePanel) {
    return true;
  }
  const controls = activePanel.querySelectorAll("input, select, textarea");
  for (const control of controls) {
    if (control.disabled || typeof control.reportValidity !== "function") {
      continue;
    }
    if (!control.reportValidity()) {
      return false;
    }
  }
  return true;
}

function navigateUserFormToTab(targetTab) {
  if (!userFormGuidedMode) {
    setUserFormTab(targetTab);
    return;
  }
  const nextIndex = getUserFormStepIndex(targetTab);
  const currentIndex = getUserFormStepIndex(userFormTab);
  if (nextIndex === currentIndex) {
    return;
  }
  if (nextIndex > currentIndex) {
    if (nextIndex > currentIndex + 1) {
      return;
    }
    if (!validateCurrentUserFormStep()) {
      return;
    }
  }
  setUserFormTab(USER_FORM_STEP_ORDER[nextIndex]);
}

function navigateUserFormStep(direction) {
  if (!userFormGuidedMode) {
    return;
  }
  const currentIndex = getUserFormStepIndex(userFormTab);
  if (direction < 0) {
    const previousIndex = Math.max(0, currentIndex - 1);
    setUserFormTab(USER_FORM_STEP_ORDER[previousIndex]);
    return;
  }
  if (!validateCurrentUserFormStep()) {
    return;
  }
  const nextIndex = Math.min(USER_FORM_STEP_ORDER.length - 1, currentIndex + 1);
  setUserFormTab(USER_FORM_STEP_ORDER[nextIndex]);
}

function setUserFormTab(nextTab) {
  userFormTab = normalizeUserFormTab(nextTab);
  const currentIndex = getUserFormStepIndex(userFormTab);
  const lastIndex = USER_FORM_STEP_ORDER.length - 1;
  const stepLabel = getUserFormStepLabel(userFormTab);
  els.userFormTabButtons?.forEach((button) => {
    const target = normalizeUserFormTab(button.dataset.userFormTab || "");
    const targetIndex = getUserFormStepIndex(target);
    const isActive = target === userFormTab;
    button.classList.toggle("is-active", isActive);
    setTabButtonA11yState(button, isActive);
    button.disabled = userFormGuidedMode && targetIndex > currentIndex;
  });
  els.userFormTabPanels?.forEach((panel) => {
    const target = normalizeUserFormTab(panel.dataset.userFormTabPanel || "");
    const isActive = target === userFormTab;
    panel.classList.toggle("hidden", !isActive);
    setTabPanelA11yState(panel, isActive);
  });
  if (els.userFormStepMeta) {
    els.userFormStepMeta.textContent = userFormGuidedMode
      ? `Schritt ${currentIndex + 1} von ${USER_FORM_STEP_ORDER.length} · ${stepLabel}`
      : `Bearbeitung · ${stepLabel}`;
  }
  if (els.userFormStepProgressFill) {
    const progressValue = ((currentIndex + 1) / USER_FORM_STEP_ORDER.length) * 100;
    els.userFormStepProgressFill.style.width = `${progressValue.toFixed(2)}%`;
  }
  if (els.userFormPrevBtn) {
    els.userFormPrevBtn.disabled = currentIndex === 0;
    els.userFormPrevBtn.classList.toggle("hidden", !userFormGuidedMode);
  }
  if (els.userFormNextBtn) {
    const isLastStep = currentIndex >= lastIndex;
    els.userFormNextBtn.classList.toggle("hidden", !userFormGuidedMode || isLastStep);
  }
  if (els.userSaveBtn) {
    const showSave = !userFormGuidedMode || currentIndex >= lastIndex;
    els.userSaveBtn.classList.toggle("hidden", !showSave);
  }
}

function resolveUserProfileUserId(user = null, emailFallback = "") {
  if (user?.source === "profile" || user?.source === "invite") {
    return normalizeUserId(user.sourceId || "");
  }
  const fallbackUserId = normalizeUserId(user?.id || "");
  if (fallbackUserId) {
    return fallbackUserId;
  }
  const normalizedEmail = normalizeUserEmail(emailFallback || user?.email || "");
  if (!normalizedEmail) {
    return "";
  }
  const matchedUser = state.users.find(
    (entry) =>
      (entry.source === "profile" || entry.source === "invite") && normalizeUserEmail(entry.email) === normalizedEmail
  );
  return normalizeUserId(matchedUser?.sourceId || matchedUser?.id || "");
}

function normalizeResponsibilityItems(value) {
  const rawItems = Array.isArray(value)
    ? value
    : String(value || "")
        .split(/\r?\n|;/g)
        .flatMap((entry) => String(entry || "").split("•"));
  const seen = new Set();
  return rawItems
    .map((entry) =>
      String(entry || "")
        .replace(/^[\s\-*•]+/, "")
        .trim()
    )
    .filter(Boolean)
    .filter((entry) => {
      const key = normalizeText(entry);
      if (!key || seen.has(key)) {
        return false;
      }
      seen.add(key);
      return true;
    });
}

function serializeResponsibilityItems(items) {
  return normalizeResponsibilityItems(items).join("\n");
}

function getResponsibilityTagSuggestions() {
  const departments = getDepartments();
  const profilesMap = normalizeEmployeeProfilesByUserId(state.settings?.employeeProfilesByUserId || {}, departments);
  const existingTags = Object.values(profilesMap).flatMap((profile) =>
    normalizeResponsibilityItems(profile?.responsibility || "")
  );
  const draftTags = normalizeResponsibilityItems([...userResponsibilityDraft, ...employeeAdminResponsibilityDraft]);
  return normalizeResponsibilityItems([...existingTags, ...draftTags]).sort((left, right) =>
    left.localeCompare(right, "de")
  );
}

function renderResponsibilityTagSuggestions() {
  if (!els.responsibilityTagSuggestionsDatalist) {
    return;
  }
  const suggestions = getResponsibilityTagSuggestions();
  els.responsibilityTagSuggestionsDatalist.innerHTML = suggestions
    .map((tag) => `<option value="${escapeHtml(tag)}"></option>`)
    .join("");
}

function getResponsibilityListMarkup(value, emptyLabel = "Keine Aufgabenbeschreibung hinterlegt.") {
  const items = normalizeResponsibilityItems(value);
  if (!items.length) {
    return `<p class="orgchart-info-responsibility-empty">${escapeHtml(emptyLabel)}</p>`;
  }
  return `<ul class="orgchart-info-responsibility-list">${items
    .map((item) => `<li>${escapeHtml(item)}</li>`)
    .join("")}</ul>`;
}

function getSharedResponsibilityGroups(selectedUserId, selectedResponsibilityItems) {
  const normalizedSelectedUserId = normalizeUserId(selectedUserId);
  const selectedTags = normalizeResponsibilityItems(selectedResponsibilityItems);
  if (!normalizedSelectedUserId || !selectedTags.length) {
    return [];
  }
  const selectedTagByKey = new Map();
  selectedTags.forEach((tag) => {
    selectedTagByKey.set(normalizeText(tag), tag);
  });
  const groupsByTagKey = new Map();
  const users = getOrgChartManagedUsers();
  users.forEach((user) => {
    const userId = normalizeUserId(user.userId || "");
    if (!userId || userId === normalizedSelectedUserId) {
      return;
    }
    const profile = getEmployeeProfileByUserId(userId);
    const userTags = normalizeResponsibilityItems(profile.responsibility || "");
    if (!userTags.length) {
      return;
    }
    const departmentLabel = getDepartmentLabelByValue(profile.department) || "Ohne Abteilung";
    userTags.forEach((tag) => {
      const tagKey = normalizeText(tag);
      if (!tagKey || !selectedTagByKey.has(tagKey)) {
        return;
      }
      if (!groupsByTagKey.has(tagKey)) {
        groupsByTagKey.set(tagKey, {
          tag: selectedTagByKey.get(tagKey) || tag,
          members: [],
        });
      }
      const group = groupsByTagKey.get(tagKey);
      const memberExists = group.members.some((entry) => entry.userId === userId);
      if (memberExists) {
        return;
      }
      group.members.push({
        userId,
        name: String(user.name || "").trim() || "Unbekannt",
        departmentLabel,
      });
    });
  });
  const groups = Array.from(groupsByTagKey.values())
    .map((group) => ({
      tag: group.tag,
      members: group.members.sort((left, right) => left.name.localeCompare(right.name, "de")),
    }))
    .sort((left, right) => {
      if (right.members.length !== left.members.length) {
        return right.members.length - left.members.length;
      }
      return left.tag.localeCompare(right.tag, "de");
    });
  return groups;
}

function getSharedResponsibilityMarkup(selectedUserId, selectedResponsibilityItems) {
  const selectedTags = normalizeResponsibilityItems(selectedResponsibilityItems);
  if (!selectedTags.length) {
    return '<p class="orgchart-info-responsibility-empty">Keine Aufgabenbeschreibung hinterlegt.</p>';
  }
  const groups = getSharedResponsibilityGroups(selectedUserId, selectedTags);
  if (!groups.length) {
    return '<p class="orgchart-info-responsibility-empty">Noch keine gemeinsamen Zuständigkeiten mit anderen Mitarbeitern gefunden.</p>';
  }
  return `<ul class="orgchart-info-shared-list">${groups
    .map(
      (group) => `
        <li class="orgchart-info-shared-item">
          <div class="orgchart-info-shared-tag">
            <strong>${escapeHtml(group.tag)}</strong>
            <span>${group.members.length}</span>
          </div>
          <div class="orgchart-info-shared-members">${group.members
            .map((member) => `<span>${escapeHtml(member.name)} · ${escapeHtml(member.departmentLabel)}</span>`)
            .join("")}</div>
        </li>
      `
    )
    .join("")}</ul>`;
}

