function renderUserProfileDepartmentOptions(selectedValue = "") {
  if (!els.userProfileDepartmentSelect) {
    return;
  }
  const departments = getDepartments();
  const options = ['<option value="">Keine Zuordnung</option>'].concat(
    departments.map((entry) => `<option value="${escapeHtml(entry.id)}">${escapeHtml(entry.name)}</option>`)
  );
  const normalizedSelectedValue = String(selectedValue || "").trim();
  const knownValue = normalizedSelectedValue && departments.some((entry) => entry.id === normalizedSelectedValue);
  if (normalizedSelectedValue && !knownValue) {
    options.push(
      `<option value="${escapeHtml(normalizedSelectedValue)}">${escapeHtml(
        getDepartmentLabelByValue(normalizedSelectedValue, departments)
      )}</option>`
    );
  }
  els.userProfileDepartmentSelect.innerHTML = options.join("");
  els.userProfileDepartmentSelect.value = normalizedSelectedValue || "";
}

function renderUserProfileManagerOptions(selectedUserId = "", managerUserId = "") {
  if (!els.userProfileManagerSelect) {
    return;
  }
  const options = getEmployeeAdminManagedUsers()
    .filter((entry) => entry.userId !== selectedUserId)
    .map((entry) => `<option value="${escapeHtml(entry.userId)}">${escapeHtml(entry.name)}</option>`);
  els.userProfileManagerSelect.innerHTML = ['<option value="">Keine Zuordnung</option>', ...options].join("");
  const normalizedManagerId = normalizeUserId(managerUserId);
  const managerExists = normalizedManagerId
    ? Array.from(els.userProfileManagerSelect.options).some((option) => option.value === normalizedManagerId)
    : false;
  els.userProfileManagerSelect.value = managerExists ? normalizedManagerId : "";
}

function renderUserProfileTaskList(userId = userProfileTasksUserId) {
  if (!els.userProfileTaskList) {
    return;
  }
  const normalizedUserId = normalizeUserId(userId);
  if (!normalizedUserId) {
    els.userProfileTaskList.innerHTML =
      '<li class="empty">Aufgaben sind verfügbar, sobald der Mitarbeiter ein aktives Profil hat.</li>';
    return;
  }
  const tasks = getEmployeeTasksByUserId(normalizedUserId).sort((left, right) => {
    if (!!left.done !== !!right.done) {
      return left.done ? 1 : -1;
    }
    const leftDue = left.dueDate || "9999-12-31";
    const rightDue = right.dueDate || "9999-12-31";
    if (leftDue !== rightDue) {
      return leftDue.localeCompare(rightDue);
    }
    return String(right.createdAt || "").localeCompare(String(left.createdAt || ""));
  });
  if (!tasks.length) {
    els.userProfileTaskList.innerHTML = '<li class="empty">Noch keine Aufgaben für diesen Mitarbeiter.</li>';
    return;
  }
  els.userProfileTaskList.innerHTML = tasks
    .map((task) => {
      const taskId = String(task.id || "").trim();
      const dueLabel = task.dueDate ? `Fällig: ${formatEmployeeAdminDate(task.dueDate)}` : "Ohne Fälligkeit";
      return `
        <li class="employee-admin-task-item ${task.done ? "done" : ""}">
          <label class="employee-admin-task-check">
            <input type="checkbox" data-user-profile-task-toggle="${escapeHtml(taskId)}" ${task.done ? "checked" : ""} />
            <span>${escapeHtml(task.title)}</span>
          </label>
          <div class="employee-admin-task-meta">
            <small>${escapeHtml(dueLabel)}</small>
            <button type="button" class="mini-btn danger" title="Aufgabe löschen" aria-label="Aufgabe löschen" data-user-profile-task-delete="${escapeHtml(
              taskId
            )}">✕</button>
          </div>
        </li>
      `;
    })
    .join("");
}

function syncUserProfileTaskControls(userId = userProfileTasksUserId) {
  const normalizedUserId = normalizeUserId(userId);
  const enabled = !!normalizedUserId;
  if (els.userProfileTaskInput) {
    els.userProfileTaskInput.disabled = !enabled;
    if (!enabled) {
      els.userProfileTaskInput.value = "";
    }
  }
  if (els.userProfileTaskDue) {
    els.userProfileTaskDue.disabled = !enabled;
    if (!enabled) {
      els.userProfileTaskDue.value = "";
    }
  }
  if (els.userProfileTaskAddBtn) {
    els.userProfileTaskAddBtn.disabled = !enabled;
  }
}

function syncUserProfileFieldControls(userId = userProfileTasksUserId) {
  const normalizedUserId = normalizeUserId(userId);
  const enabled = userFormGuidedMode || !!normalizedUserId;
  const fieldNames = [
    "profileDepartment",
    "profileMarkerColor",
    "profilePosition",
    "profileLocation",
    "profileBirthDate",
    "profileManagerUserId",
    "profileHrStatus",
    "profileStreet",
    "profilePostalCode",
    "profileCity",
    "profileCountry",
    "profileEmail",
    "profilePhone",
    "profileEmploymentType",
    "profileWorkModel",
    "profileStartDate",
    "profileNextReviewDate",
    "profileResponsibility",
    "profileNotes",
  ];
  fieldNames.forEach((fieldName) => {
    const field = els.userForm?.elements?.[fieldName];
    if (!field || typeof field.disabled !== "boolean") {
      return;
    }
    field.disabled = !enabled;
  });
  if (els.userResponsibilityInput) {
    els.userResponsibilityInput.disabled = !enabled;
  }
  const selectedEmploymentType = String(els.userForm?.elements?.profileEmploymentType?.value || "").trim();
  syncUserEmploymentDetailsVisibility(selectedEmploymentType, enabled);
}

function fillUserForm(user) {
  setUserFormGuidedMode(false);
  setUserFormTab("profil");
  const formElements = els.userForm.elements;
  formElements.name.value = user.name;
  formElements.address.value = user.address;
  formElements.email.value = user.email;
  formElements.phone.value = user.phone;
  formElements.role.value = normalizeUserRole(user.role);
  renderUserTerritoryOptions(user.territories);
  formElements.email.disabled = user.source === "profile";
  userProfileTasksUserId = resolveUserProfileUserId(user);
  const profile = getEmployeeProfileByUserId(userProfileTasksUserId);
  const normalizedDepartmentValue = sanitizeEmployeeDepartmentValue(profile.department, getDepartments());
  renderUserProfileDepartmentOptions(normalizedDepartmentValue);
  renderUserProfileManagerOptions(userProfileTasksUserId, profile.managerUserId || "");
  formElements.profileDepartment.value = normalizedDepartmentValue;
  formElements.profileMarkerColor.value =
    sanitizeEmployeeMarkerColorValue(profile.markerColor) || getEmployeeMarkerColorByUserId(userProfileTasksUserId, user.name);
  formElements.profilePosition.value = profile.position || "";
  formElements.profileLocation.value = profile.location || "";
  formElements.profileBirthDate.value = profile.birthDate || "";
  formElements.profileHrStatus.value = profile.hrStatus || "aktiv";
  formElements.profileStreet.value = profile.street || "";
  formElements.profilePostalCode.value = profile.postalCode || "";
  formElements.profileCity.value = profile.city || "";
  formElements.profileCountry.value = profile.country || "";
  formElements.profileEmail.value = profile.email || user.email || "";
  formElements.profilePhone.value = profile.phone || user.phone || "";
  formElements.profileEmploymentType.value = profile.employmentType || "";
  applyEmployeeEmploymentDetailsToForm(profile, els.userForm);
  formElements.profileWorkModel.value = profile.workModel || "";
  formElements.profileStartDate.value = profile.startDate || "";
  formElements.profileNextReviewDate.value = profile.nextReviewDate || "";
  userResponsibilityDraft = normalizeResponsibilityItems(profile.responsibility || "");
  if (els.userResponsibilityInput) {
    els.userResponsibilityInput.value = "";
  }
  renderUserResponsibilityTags();
  formElements.profileNotes.value = profile.notes || "";
  formElements.profileManagerUserId.value = normalizeUserId(profile.managerUserId || "");
  syncUserProfileFieldControls(userProfileTasksUserId);
  syncUserProfileTaskControls(userProfileTasksUserId);
  renderUserProfileTaskList(userProfileTasksUserId);
  const isProfileUser = user.source === "profile";
  if (els.userHonorariumEnabled) {
    els.userHonorariumEnabled.checked = isProfileUser ? isEmployeeHonorariumEnabled(user.sourceId) : false;
    els.userHonorariumEnabled.disabled = !isProfileUser;
  }
  if (els.userHonorariumRate) {
    els.userHonorariumRate.value = isProfileUser ? formatRateInputValue(getEmployeeRateByUserId(user.sourceId)) : "0.00";
  }
  if (els.userHonorariumHint) {
    els.userHonorariumHint.textContent = isProfileUser
      ? "Honorar und Freischaltung werden nur hier in der Detailansicht gepflegt."
      : "Honorar kann erst nach der ersten Anmeldung (aktives Profil) freigeschaltet werden.";
  }
  if (els.userHonorariumField) {
    els.userHonorariumField.classList.remove("hidden");
  }
  syncUserHonorariumFieldState();
  els.userSaveBtn.textContent = "Aktualisieren";
}

function clearUserForm() {
  editingUserId = null;
  setUserFormGuidedMode(true);
  setUserFormTab("profil");
  userProfileTasksUserId = "";
  els.userForm.reset();
  renderUserTerritoryOptions([]);
  renderUserProfileDepartmentOptions("");
  renderUserProfileManagerOptions("", "");
  syncUserProfileFieldControls("");
  userResponsibilityDraft = [];
  if (els.userResponsibilityInput) {
    els.userResponsibilityInput.value = "";
  }
  renderUserResponsibilityTags();
  syncUserProfileTaskControls("");
  renderUserProfileTaskList("");
  els.userForm.elements.email.disabled = false;
  if (els.userHonorariumEnabled) {
    els.userHonorariumEnabled.checked = false;
    els.userHonorariumEnabled.disabled = true;
  }
  if (els.userHonorariumRate) {
    els.userHonorariumRate.value = "0.00";
  }
  if (els.userHonorariumHint) {
    els.userHonorariumHint.textContent =
      "Honorar kann erst nach der ersten Anmeldung (aktives Profil) freigeschaltet werden.";
  }
  if (els.userHonorariumField) {
    els.userHonorariumField.classList.remove("hidden");
  }
  syncUserHonorariumFieldState();
  els.userSaveBtn.textContent = "Speichern";
}

function syncUserHonorariumFieldState() {
  if (!els.userHonorariumRate) {
    return;
  }
  const canUseHonorarium = !!els.userHonorariumEnabled && !els.userHonorariumEnabled.disabled;
  const enabled = canUseHonorarium && els.userHonorariumEnabled.checked;
  els.userHonorariumRate.disabled = !enabled;
}

function handleUserProfileTaskAdd() {
  const normalizedUserId = normalizeUserId(userProfileTasksUserId);
  if (!normalizedUserId) {
    return;
  }
  const title = String(els.userProfileTaskInput?.value || "").trim();
  if (!title) {
    return;
  }
  const dueDate = sanitizeEmployeeAdminDate(els.userProfileTaskDue?.value || "");
  const currentTasks = getEmployeeTasksByUserId(normalizedUserId);
  currentTasks.push({
    id: createId("etask"),
    title,
    dueDate,
    done: false,
    createdAt: new Date().toISOString(),
  });
  setEmployeeTasksByUserId(normalizedUserId, currentTasks);
  saveState({ showFeedback: false });
  if (els.userProfileTaskInput) {
    els.userProfileTaskInput.value = "";
  }
  if (els.userProfileTaskDue) {
    els.userProfileTaskDue.value = "";
  }
  renderUserProfileTaskList(normalizedUserId);
}

function handleUserProfileTaskToggle(taskId, done) {
  const normalizedUserId = normalizeUserId(userProfileTasksUserId);
  if (!normalizedUserId) {
    return;
  }
  const normalizedTaskId = String(taskId || "").trim();
  if (!normalizedTaskId) {
    return;
  }
  const currentTasks = getEmployeeTasksByUserId(normalizedUserId);
  const nextTasks = currentTasks.map((entry) =>
    String(entry.id || "").trim() === normalizedTaskId ? { ...entry, done: !!done } : entry
  );
  setEmployeeTasksByUserId(normalizedUserId, nextTasks);
  saveState({ showFeedback: false });
  renderUserProfileTaskList(normalizedUserId);
}

function handleUserProfileTaskDelete(taskId) {
  const normalizedUserId = normalizeUserId(userProfileTasksUserId);
  if (!normalizedUserId) {
    return;
  }
  const normalizedTaskId = String(taskId || "").trim();
  if (!normalizedTaskId) {
    return;
  }
  const currentTasks = getEmployeeTasksByUserId(normalizedUserId);
  const nextTasks = currentTasks.filter((entry) => String(entry.id || "").trim() !== normalizedTaskId);
  setEmployeeTasksByUserId(normalizedUserId, nextTasks);
  saveState({ showFeedback: false });
  renderUserProfileTaskList(normalizedUserId);
}

function normalizeProviderDetailTab(tab) {
  return tab === "notes" ? "notes" : "master";
}

function setProviderDetailTab(tab) {
  providerDetailTab = normalizeProviderDetailTab(tab);
  els.providerDetailTabButtons.forEach((button) => {
    const tabId = normalizeProviderDetailTab(button.dataset.providerDetailTabBtn || "master");
    const isActive = tabId === providerDetailTab;
    button.classList.toggle("active", isActive);
    setTabButtonA11yState(button, isActive);
  });
  if (els.providerMasterTabPanel) {
    const isActive = providerDetailTab === "master";
    els.providerMasterTabPanel.classList.toggle("hidden", !isActive);
    setTabPanelA11yState(els.providerMasterTabPanel, isActive);
  }
  if (els.providerNotesTabPanel) {
    const isActive = providerDetailTab === "notes";
    els.providerNotesTabPanel.classList.toggle("hidden", !isActive);
    setTabPanelA11yState(els.providerNotesTabPanel, isActive);
  }
  if (els.providerSaveBtn) {
    els.providerSaveBtn.classList.toggle("hidden", providerDetailTab !== "master");
  }
  if (providerDetailTab === "notes") {
    renderProviderNotes();
    if (editingProviderId) {
      void fetchProviderNotesForProvider(editingProviderId);
    }
  }
}

function getCurrentUserId() {
  const currentUser = getCurrentUser();
  return String(authProfile?.user_id || currentUser?.sourceId || "").trim();
}

function getProviderNotesSource(provider) {
  const providerId = String(provider?.id || "").trim();
  if (!providerId) {
    return [];
  }
  if (providerNotesLocalOnlyProviderIds.has(providerId)) {
    return normalizeProviderNotes(provider?.notes || []);
  }
  const hasLoadedRemoteNotes = providerNotesLoadedProviderIds.has(providerId);
  if (hasLoadedRemoteNotes) {
    return normalizeProviderNotes(providerNotesCacheByProviderId[providerId] || []);
  }

  // Solange Supabase-Notizen normal lesbar sind, keinen lokalen Fallback nutzen,
  // um veraltete Anzeigen zu vermeiden. Bei aktivem Fallback-Modus (SQL/RLS Problem)
  // greifen wir dagegen bewusst auf local/app_state Notizen zurueck.
  if (getSupabaseClient() && !providerNotesRemoteFallbackMode) {
    return [];
  }

  return normalizeProviderNotes(provider?.notes || []);
}

function setProviderNotesSource(providerId, notes) {
  const normalizedProviderId = String(providerId || "").trim();
  if (!normalizedProviderId) {
    return;
  }
  const normalizedNotes = normalizeProviderNotes(notes || []);
  providerNotesCacheByProviderId[normalizedProviderId] = normalizedNotes;
  providerNotesLoadedProviderIds.add(normalizedProviderId);
  const provider = state.providers.find((entry) => entry.id === normalizedProviderId);
  if (provider) {
    provider.notes = normalizedNotes;
  }
}

function resetProviderNoteEditorState() {
  editingProviderNoteId = "";
  if (els.providerNoteInput) {
    els.providerNoteInput.value = "";
  }
  if (els.providerNoteAddBtn) {
    els.providerNoteAddBtn.textContent = "Notiz speichern";
  }
}

function syncProviderNoteEditorForEdit(note) {
  if (!note || !els.providerNoteInput) {
    resetProviderNoteEditorState();
    return;
  }
  editingProviderNoteId = String(note.id || "").trim();
  els.providerNoteInput.value = note.text || "";
  if (els.providerNoteAddBtn) {
    els.providerNoteAddBtn.textContent = "Notiz aktualisieren";
  }
}

function getProviderNotesVisibleForCurrentUser(provider) {
  const currentUserId = normalizeUserId(getCurrentUserId());
  if (!currentUserId) {
    return [];
  }
  const sourceNotes = getProviderNotesSource(provider);
  return sourceNotes
    .filter((note) => note.createdByUserId === currentUserId)
    .sort((a, b) => String(b.createdAt || "").localeCompare(String(a.createdAt || "")));
}

function getProviderOpenNotesVisibleForCurrentUser(provider) {
  return getProviderNotesVisibleForCurrentUser(provider).filter((note) => !note.done);
}

function getProviderOpenNotesCountForCurrentUser(provider) {
  return getProviderOpenNotesVisibleForCurrentUser(provider).length;
}

function setProviderNotesLocalOnlyMode(providerId, enabled) {
  const normalizedProviderId = String(providerId || "").trim();
  if (!normalizedProviderId) {
    return;
  }
  if (enabled) {
    providerNotesLocalOnlyProviderIds.add(normalizedProviderId);
    providerNotesRemoteFallbackMode = true;
    return;
  }
  providerNotesLocalOnlyProviderIds.delete(normalizedProviderId);
}

function queueProviderNotesPrefetchForList(providers) {
  if (!Array.isArray(providers) || !providers.length) {
    return;
  }
  providers.forEach((provider) => {
    const providerId = String(provider?.id || "").trim();
    if (!providerId || providerNotesLoadedProviderIds.has(providerId) || providerNotesLoadingProviderIds.has(providerId)) {
      return;
    }
    void fetchProviderNotesForProvider(providerId, { force: false });
  });
}

function renderProviderNotes() {
  if (!els.providerNotesList) {
    return;
  }
  if (!editingProviderId) {
    els.providerNotesList.innerHTML =
      '<p class="empty">Notizen können nach dem ersten Speichern des Anbieters erstellt werden.</p>';
    return;
  }
  const provider = state.providers.find((entry) => entry.id === editingProviderId);
  if (!provider) {
    els.providerNotesList.innerHTML = '<p class="empty">Anbieter nicht gefunden.</p>';
    return;
  }
  const providerId = String(provider.id || "").trim();
  const loading = providerNotesLoadingProviderIds.has(providerId);
  const errorMessage = String(providerNotesErrorByProviderId[providerId] || "").trim();
  const visibleNotes = getProviderNotesVisibleForCurrentUser(provider);
  const infoPrefix = errorMessage ? `<p class="empty">${escapeHtml(errorMessage)}</p>` : "";
  if (loading && !visibleNotes.length) {
    els.providerNotesList.innerHTML = `${infoPrefix}<p class="empty">Notizen werden geladen...</p>`;
    return;
  }
  if (!visibleNotes.length) {
    els.providerNotesList.innerHTML = `${infoPrefix}<p class="empty">Noch keine eigenen Notizen vorhanden.</p>`;
    return;
  }

  if (editingProviderNoteId) {
    const editingVisible = visibleNotes.some((note) => String(note.id || "").trim() === editingProviderNoteId);
    if (!editingVisible) {
      resetProviderNoteEditorState();
    }
  }

  els.providerNotesList.innerHTML =
    infoPrefix +
    visibleNotes
      .map(
        (note) => `
          <article class="provider-note-item ${editingProviderNoteId === String(note.id || "").trim() ? "editing" : ""} ${note.done ? "done" : ""}">
            <div class="provider-note-head">
              <p class="provider-note-meta">
                ${escapeHtml(formatDateTime(note.createdAt))} · ${escapeHtml(getRoleLabel(note.createdByRole))} (${escapeHtml(
            note.createdByName || "Unbekannt"
          )})
                ${
                  note.done
                    ? ` · <span class="provider-note-done-badge">Erledigt${
                        note.doneAt ? ` am ${escapeHtml(formatDateTime(note.doneAt))}` : ""
                      }${
                        note.doneByName ? ` von ${escapeHtml(note.doneByName)}` : ""
                      }</span>`
                    : ""
                }
              </p>
              <div class="provider-note-actions">
                <button
                  type="button"
                  class="mini-btn"
                  title="Notiz bearbeiten"
                  aria-label="Notiz bearbeiten"
                  data-edit-provider-note="${escapeHtml(note.id)}"
                  data-admin-lock-exempt="true"
                >✎</button>
                <button
                  type="button"
                  class="mini-btn danger"
                  title="Notiz löschen"
                  aria-label="Notiz löschen"
                  data-delete-provider-note="${escapeHtml(note.id)}"
                  data-admin-lock-exempt="true"
                >✕</button>
              </div>
            </div>
            <p class="provider-note-text">${escapeHtml(note.text).replace(/\n/g, "<br/>")}</p>
          </article>
        `
      )
      .join("");
}

function isProviderOpenNotesModalOpen() {
  return !!els.providerOpenNotesPanel && !els.providerOpenNotesPanel.classList.contains("hidden");
}

function closeProviderOpenNotesModal() {
  if (!els.providerOpenNotesPanel) {
    return;
  }
  providerOpenNotesProviderId = "";
  els.providerOpenNotesPanel.classList.add("hidden");
  if (els.providerOpenNotesList) {
    els.providerOpenNotesList.innerHTML = "";
  }
  if (els.providerOpenNotesSubtitle) {
    els.providerOpenNotesSubtitle.textContent = "";
  }
  syncBodyModalOpenState();
}

function renderProviderOpenNotesModalContent(providerId = providerOpenNotesProviderId) {
  if (!els.providerOpenNotesSubtitle || !els.providerOpenNotesList) {
    return;
  }

  const normalizedProviderId = String(providerId || "").trim();
  if (!normalizedProviderId) {
    els.providerOpenNotesSubtitle.textContent = "";
    els.providerOpenNotesList.innerHTML = '<p class="empty">Kein Anbieter ausgewählt.</p>';
    return;
  }
  const provider = state.providers.find((entry) => entry.id === normalizedProviderId) || null;
  if (!provider) {
    els.providerOpenNotesSubtitle.textContent = "";
    els.providerOpenNotesList.innerHTML = '<p class="empty">Anbieter nicht gefunden.</p>';
    return;
  }

  const openNotes = getProviderOpenNotesVisibleForCurrentUser(provider);
  const loading = providerNotesLoadingProviderIds.has(normalizedProviderId);
  const errorMessage = String(providerNotesErrorByProviderId[normalizedProviderId] || "").trim();
  els.providerOpenNotesSubtitle.textContent =
    `${provider.name} · Offene Aufgaben: ${openNotes.length}`;
  const infoPrefix = errorMessage ? `<p class="empty">${escapeHtml(errorMessage)}</p>` : "";
  if (loading && !openNotes.length) {
    els.providerOpenNotesList.innerHTML = `${infoPrefix}<p class="empty">Notizen werden geladen...</p>`;
    return;
  }
  if (!openNotes.length) {
    els.providerOpenNotesList.innerHTML = `${infoPrefix}<p class="empty">Keine offenen Aufgaben.</p>`;
    return;
  }

  els.providerOpenNotesList.innerHTML =
    infoPrefix +
    openNotes
      .map((note) => {
        const noteId = String(note.id || "").trim();
        return `
          <article class="provider-open-note-item">
            <div class="provider-open-note-head">
              <p class="provider-note-meta">
                ${escapeHtml(formatDateTime(note.createdAt))} · ${escapeHtml(getRoleLabel(note.createdByRole))} (${escapeHtml(
            note.createdByName || "Unbekannt"
          )})
              </p>
              <label class="provider-open-note-check">
                <input type="checkbox" data-provider-note-done="${escapeHtml(noteId)}" />
                <span>Erledigt</span>
              </label>
            </div>
            <p class="provider-note-text">${escapeHtml(note.text).replace(/\n/g, "<br/>")}</p>
          </article>
        `;
      })
      .join("");
}

async function openProviderOpenNotesModal(providerId) {
  const normalizedProviderId = String(providerId || "").trim();
  if (!normalizedProviderId || !els.providerOpenNotesPanel) {
    return;
  }
  const provider = state.providers.find((entry) => entry.id === normalizedProviderId) || null;
  const currentUser = getCurrentUser();
  if (!provider || !currentUser || !providerVisibleForCurrentUser(provider, currentUser)) {
    return;
  }

  providerOpenNotesProviderId = normalizedProviderId;
  els.providerOpenNotesPanel.classList.remove("hidden");
  renderProviderOpenNotesModalContent(normalizedProviderId);
  syncBodyModalOpenState();
  await fetchProviderNotesForProvider(normalizedProviderId, { force: true });
  if (providerOpenNotesProviderId !== normalizedProviderId) {
    return;
  }
  renderProviderOpenNotesModalContent(normalizedProviderId);
  renderProvidersTable();
}

async function setProviderNoteDoneStatus(providerId, noteId, done) {
  const normalizedProviderId = String(providerId || "").trim();
  const normalizedNoteId = String(noteId || "").trim();
  if (!normalizedProviderId || !normalizedNoteId) {
    return;
  }
  const provider = state.providers.find((entry) => entry.id === normalizedProviderId) || null;
  if (!provider) {
    return;
  }
  const currentUserId = normalizeUserId(getCurrentUserId());
  if (!currentUserId) {
    return;
  }

  const sourceNotes = getProviderNotesSource(provider);
  const noteToUpdate = sourceNotes.find(
    (entry) =>
      String(entry.id || "").trim() === normalizedNoteId &&
      String(entry.createdByUserId || "").trim() === currentUserId
  );
  if (!noteToUpdate) {
    return;
  }
  if (!!noteToUpdate.done === !!done) {
    return;
  }
  const doneAt = done ? new Date().toISOString() : "";
  const doneActor = done ? getCurrentActorInfo() : null;
  const doneByUserId = done ? normalizeUserId(doneActor?.userId || currentUserId) : "";
  const doneByName = done ? String(doneActor?.name || "").trim() : "";
  const doneByRole = done ? normalizeUserRole(doneActor?.role || "") : "";

  const nextNotes = sourceNotes.map((entry) =>
    String(entry.id || "").trim() === normalizedNoteId &&
    String(entry.createdByUserId || "").trim() === currentUserId
      ? { ...entry, done: !!done, doneAt, doneByUserId, doneByName, doneByRole }
      : entry
  );
  setProviderNotesSource(normalizedProviderId, nextNotes);
  saveState({ showFeedback: false });

  if (editingProviderId === normalizedProviderId && providerDetailTab === "notes") {
    renderProviderNotes();
  }
  renderProviderOpenNotesModalContent(normalizedProviderId);
  renderProvidersTable();

  const client = getSupabaseClient();
  if (!client) {
    setProviderNotesLocalOnlyMode(normalizedProviderId, true);
    return;
  }
  const noteTextForStorage = toProviderNoteStorageText({
    text: noteToUpdate.text,
    done,
    doneAt,
    doneByUserId,
    doneByName,
    doneByRole,
  });
  const { error } = await client
    .from("provider_notes")
    .update({ note_text: noteTextForStorage })
    .eq("id", normalizedNoteId)
    .eq("provider_id", normalizedProviderId);

  if (error) {
    setProviderNotesLocalOnlyMode(normalizedProviderId, true);
    const technicalDetail = getSupabaseErrorSummary(error);
    showActionFeedback(
      isSupabaseWritePermissionError(error)
        ? `Notiz lokal aktualisiert. Supabase UPDATE-RLS für "provider_notes" fehlt noch.${technicalDetail ? ` (${technicalDetail})` : ""}`
        : `Notiz lokal aktualisiert. Supabase-Update aktuell nicht verfügbar.${technicalDetail ? ` (${technicalDetail})` : ""}`,
      { tone: "warning", toast: false, statusPersistMs: 5600 }
    );
    return;
  }

  await fetchProviderNotesForProvider(normalizedProviderId, { force: true });
  if (editingProviderId === normalizedProviderId && providerDetailTab === "notes") {
    renderProviderNotes();
  }
  renderProviderOpenNotesModalContent(normalizedProviderId);
  renderProvidersTable();
  showSuccessFeedback(done ? "Notiz als erledigt markiert." : "Notiz wieder geöffnet.");
}

async function fetchProviderNotesForProvider(providerId, options = {}) {
  const normalizedProviderId = String(providerId || "").trim();
  if (!normalizedProviderId) {
    return [];
  }
  const forceReload = options?.force === true;
  const provider = state.providers.find((entry) => entry.id === normalizedProviderId) || null;
  const fallbackNotes = normalizeProviderNotes(provider?.notes || []);
  if (providerNotesLocalOnlyProviderIds.has(normalizedProviderId) && !forceReload) {
    providerNotesCacheByProviderId[normalizedProviderId] = fallbackNotes;
    providerNotesLoadedProviderIds.add(normalizedProviderId);
    providerNotesErrorByProviderId[normalizedProviderId] = "";
    return fallbackNotes;
  }
  if (!forceReload && providerNotesLoadedProviderIds.has(normalizedProviderId)) {
    return normalizeProviderNotes(providerNotesCacheByProviderId[normalizedProviderId] || []);
  }
  if (providerNotesLoadingProviderIds.has(normalizedProviderId)) {
    return normalizeProviderNotes(providerNotesCacheByProviderId[normalizedProviderId] || []);
  }

  const hadCachedNotes = providerNotesLoadedProviderIds.has(normalizedProviderId);
  const cachedNotes = normalizeProviderNotes(providerNotesCacheByProviderId[normalizedProviderId] || []);
  providerNotesLoadingProviderIds.add(normalizedProviderId);
  providerNotesErrorByProviderId[normalizedProviderId] = "";
  if (editingProviderId === normalizedProviderId && providerDetailTab === "notes") {
    renderProviderNotes();
  }

  const client = getSupabaseClient();
  if (!client) {
    providerNotesCacheByProviderId[normalizedProviderId] = fallbackNotes;
    providerNotesLoadedProviderIds.add(normalizedProviderId);
    providerNotesLoadingProviderIds.delete(normalizedProviderId);
    if (editingProviderId === normalizedProviderId && providerDetailTab === "notes") {
      renderProviderNotes();
    }
    return fallbackNotes;
  }

  try {
    const { data, error } = await client
      .from("provider_notes")
      .select("id, provider_id, note_text, created_by_user_id, created_by_name, created_by_role, created_at")
      .eq("provider_id", normalizedProviderId)
      .order("created_at", { ascending: false });

    if (error) {
      throw error;
    }

    const remoteNotes = normalizeProviderNotes(Array.isArray(data) ? data : []);
    const mergedNotes = mergeProviderNoteCollections(remoteNotes, fallbackNotes);
    providerNotesRemoteFallbackMode = false;
    setProviderNotesLocalOnlyMode(normalizedProviderId, false);
    setProviderNotesSource(normalizedProviderId, mergedNotes);
    providerNotesErrorByProviderId[normalizedProviderId] = "";
    return mergedNotes;
  } catch (error) {
    const message = String(error?.message || "").trim();
    const tableMissing =
      message.includes("relation") && message.includes("provider_notes") && message.includes("does not exist");
    const permissionBlocked =
      isSupabaseWritePermissionError(error) ||
      /permission denied|not authorized|violates row-level security/i.test(message);
    const remoteUnavailable = tableMissing || permissionBlocked;
    if (remoteUnavailable) {
      setProviderNotesLocalOnlyMode(normalizedProviderId, true);
    }
    const notesOnError = remoteUnavailable
      ? fallbackNotes
      : hadCachedNotes
        ? cachedNotes
        : fallbackNotes;
    providerNotesRemoteFallbackMode = providerNotesRemoteFallbackMode || remoteUnavailable;
    providerNotesCacheByProviderId[normalizedProviderId] = notesOnError;
    providerNotesLoadedProviderIds.add(normalizedProviderId);
    providerNotesErrorByProviderId[normalizedProviderId] = tableMissing
      ? 'SQL fehlt: Tabelle "provider_notes" bitte in Supabase anlegen.'
      : permissionBlocked
        ? 'Supabase-RLS für "provider_notes" blockiert aktuell. Lokale Notizen werden verwendet.'
        : "Notizen konnten nicht geladen werden.";
    return notesOnError;
  } finally {
    providerNotesLoadingProviderIds.delete(normalizedProviderId);
    if (isSectionActive("providers-section") && providersViewMode === "list") {
      renderProvidersTable();
    }
    if (editingProviderId === normalizedProviderId && providerDetailTab === "notes") {
      renderProviderNotes();
    }
    if (providerOpenNotesProviderId === normalizedProviderId) {
      renderProviderOpenNotesModalContent(normalizedProviderId);
      renderProvidersTable();
    }
  }
}

async function handleStartProviderNoteEdit(noteId) {
  const normalizedNoteId = String(noteId || "").trim();
  if (!normalizedNoteId || !editingProviderId) {
    return;
  }
  const provider = state.providers.find((entry) => entry.id === editingProviderId);
  if (!provider) {
    return;
  }
  const currentUserId = getCurrentUserId();
  if (!currentUserId) {
    return;
  }
  const sourceNotes = getProviderNotesSource(provider);
  const note = sourceNotes.find(
    (entry) =>
      String(entry.id || "").trim() === normalizedNoteId &&
      String(entry.createdByUserId || "").trim() === currentUserId
  );
  if (!note) {
    return;
  }
  syncProviderNoteEditorForEdit(note);
  renderProviderNotes();
  els.providerNoteInput?.focus();
}

function applyLocalProviderNoteUpsert(providerId, noteDraft, editNoteId, currentUserId) {
  const normalizedProviderId = String(providerId || "").trim();
  const normalizedEditNoteId = String(editNoteId || "").trim();
  const normalizedCurrentUserId = normalizeUserId(currentUserId);
  if (!normalizedProviderId || !normalizedCurrentUserId) {
    return false;
  }
  const provider = state.providers.find((entry) => entry.id === normalizedProviderId) || null;
  if (!provider) {
    return false;
  }
  const sourceNotes = getProviderNotesSource(provider);
  const currentNotes = normalizeProviderNotes(sourceNotes);
  const nextNotes = normalizedEditNoteId
    ? currentNotes.map((entry) =>
        String(entry.id || "").trim() === normalizedEditNoteId &&
        String(entry.createdByUserId || "").trim() === normalizedCurrentUserId
          ? { ...entry, text: String(noteDraft?.text || "").trim() }
          : entry
      )
    : currentNotes.concat(noteDraft);

  provider.notes = normalizeProviderNotes(nextNotes);
  setProviderNotesSource(normalizedProviderId, provider.notes || []);
  providerNotesErrorByProviderId[normalizedProviderId] = "";
  saveState({ showFeedback: false });
  resetProviderNoteEditorState();
  renderProviderNotes();
  renderProviderOpenNotesModalContent(normalizedProviderId);
  renderProvidersTable();
  return true;
}

function applyLocalProviderNoteDelete(providerId, noteId, currentUserId) {
  const normalizedProviderId = String(providerId || "").trim();
  const normalizedNoteId = String(noteId || "").trim();
  const normalizedCurrentUserId = normalizeUserId(currentUserId);
  if (!normalizedProviderId || !normalizedNoteId || !normalizedCurrentUserId) {
    return false;
  }
  const provider = state.providers.find((entry) => entry.id === normalizedProviderId) || null;
  if (!provider) {
    return false;
  }
  const sourceNotes = getProviderNotesSource(provider);
  const nextNotes = normalizeProviderNotes(sourceNotes).filter(
    (entry) =>
      !(
        String(entry.id || "").trim() === normalizedNoteId &&
        String(entry.createdByUserId || "").trim() === normalizedCurrentUserId
      )
  );
  provider.notes = nextNotes;
  setProviderNotesSource(normalizedProviderId, nextNotes);
  providerNotesErrorByProviderId[normalizedProviderId] = "";
  saveState({ showFeedback: false });
  if (editingProviderNoteId === normalizedNoteId) {
    resetProviderNoteEditorState();
  }
  renderProviderNotes();
  renderProviderOpenNotesModalContent(normalizedProviderId);
  renderProvidersTable();
  return true;
}

async function handleDeleteProviderNote(noteId) {
  const normalizedNoteId = String(noteId || "").trim();
  if (!normalizedNoteId || !editingProviderId) {
    return;
  }
  const normalizedProviderId = String(editingProviderId || "").trim();
  const currentUserId = normalizeUserId(getCurrentUserId());
  if (!currentUserId) {
    return;
  }

  const confirmed = window.confirm("Notiz wirklich löschen?");
  if (!confirmed) {
    return;
  }

  const client = getSupabaseClient();
  if (!client) {
    setProviderNotesLocalOnlyMode(normalizedProviderId, true);
    const localDeleted = applyLocalProviderNoteDelete(normalizedProviderId, normalizedNoteId, currentUserId);
    if (localDeleted) {
      showSuccessFeedback("Notiz gelöscht.");
    }
    return;
  }

  // Immer zuerst lokal entfernen, damit der nachfolgende Remote-Refresh
  // den geloeschten Eintrag nicht aus altem Fallback-Stand wieder einblendet.
  const localDeletedBeforeRemote = applyLocalProviderNoteDelete(
    normalizedProviderId,
    normalizedNoteId,
    currentUserId
  );

  const { error } = await client
    .from("provider_notes")
    .delete()
    .eq("id", normalizedNoteId)
    .eq("provider_id", normalizedProviderId);

  if (error) {
    setProviderNotesLocalOnlyMode(normalizedProviderId, true);
    const technicalDetail = getSupabaseErrorSummary(error);
    if (localDeletedBeforeRemote) {
      showActionFeedback(
        isSupabaseWritePermissionError(error)
          ? `Notiz lokal gelöscht. Supabase DELETE-RLS für "provider_notes" fehlt noch.${technicalDetail ? ` (${technicalDetail})` : ""}`
          : `Notiz lokal gelöscht. Supabase-Löschen aktuell nicht verfügbar.${technicalDetail ? ` (${technicalDetail})` : ""}`,
        { tone: "warning", toast: false, statusPersistMs: 5600 }
      );
    } else {
      window.alert(
        isSupabaseWritePermissionError(error)
          ? 'Notiz konnte nicht gelöscht werden. In Supabase fehlt vermutlich eine DELETE-RLS-Policy für "provider_notes".'
          : "Notiz konnte nicht gelöscht werden."
      );
    }
    return;
  }

  await fetchProviderNotesForProvider(normalizedProviderId, { force: true });
  renderProviderNotes();
  renderProviderOpenNotesModalContent(normalizedProviderId);
  renderProvidersTable();
  showSuccessFeedback("Notiz gelöscht.");
}

async function handleAddProviderNote() {
  if (!editingProviderId) {
    window.alert("Notizen können erst nach dem Speichern des Anbieters erstellt werden.");
    return;
  }
  const normalizedProviderId = String(editingProviderId || "").trim();
  const provider = state.providers.find((entry) => entry.id === normalizedProviderId) || null;
  const text = String(els.providerNoteInput?.value || "").trim();
  if (!text) {
    return;
  }
  const normalizedEditNoteId = String(editingProviderNoteId || "").trim();
  const actor = getCurrentActorInfo();
  const currentUserId = normalizeUserId(actor.userId || "");
  if (!currentUserId) {
    window.alert("Benutzer konnte nicht ermittelt werden.");
    return;
  }
  const nowIso = new Date().toISOString();
  const note = {
    id: createId("note"),
    text,
    createdAt: nowIso,
    createdByUserId: currentUserId,
    createdByName: actor.name,
    createdByRole: actor.role,
    done: false,
  };
  const client = getSupabaseClient();
  const sourceNotes = provider ? getProviderNotesSource(provider) : [];
  const editSourceNote = normalizedEditNoteId
    ? sourceNotes.find(
        (entry) =>
          String(entry.id || "").trim() === normalizedEditNoteId &&
          String(entry.createdByUserId || "").trim() === currentUserId
      ) || null
    : null;

  if (!client) {
    setProviderNotesLocalOnlyMode(normalizedProviderId, true);
    const localSaved = applyLocalProviderNoteUpsert(normalizedProviderId, note, normalizedEditNoteId, currentUserId);
    if (localSaved) {
      showSuccessFeedback(normalizedEditNoteId ? "Notiz aktualisiert." : "Notiz gespeichert.");
    }
    return;
  }

  let error = null;
  if (normalizedEditNoteId) {
    const noteTextForStorage = toProviderNoteStorageText({
      text,
      done: !!editSourceNote?.done,
      doneAt: editSourceNote?.doneAt || "",
      doneByUserId: editSourceNote?.doneByUserId || "",
      doneByName: editSourceNote?.doneByName || "",
      doneByRole: editSourceNote?.doneByRole || "",
    });
    const updateResult = await client
      .from("provider_notes")
      .update({ note_text: noteTextForStorage })
      .eq("id", normalizedEditNoteId)
      .eq("provider_id", normalizedProviderId);
    error = updateResult.error;
  } else {
    const insertResult = await client.from("provider_notes").insert({
      provider_id: normalizedProviderId,
      note_text: toProviderNoteStorageText(note),
      created_by_user_id: note.createdByUserId,
      created_by_name: note.createdByName,
      created_by_role: note.createdByRole,
    });
    error = insertResult.error;
  }

  if (error) {
    setProviderNotesLocalOnlyMode(normalizedProviderId, true);
    const message = String(error.message || "").trim();
    const technicalDetail = getSupabaseErrorSummary(error);
    const tableMissing =
      message.includes("relation") && message.includes("provider_notes") && message.includes("does not exist");
    const localSaved = applyLocalProviderNoteUpsert(normalizedProviderId, note, normalizedEditNoteId, currentUserId);
    if (localSaved) {
      showActionFeedback(
        tableMissing
          ? `Notiz lokal gespeichert. SQL fehlt: Tabelle "provider_notes" in Supabase anlegen.${technicalDetail ? ` (${technicalDetail})` : ""}`
          : isSupabaseWritePermissionError(error)
            ? `Notiz lokal gespeichert. Supabase-RLS für "provider_notes" fehlt noch.${technicalDetail ? ` (${technicalDetail})` : ""}`
            : `Notiz lokal gespeichert. Supabase aktuell nicht verfügbar.${technicalDetail ? ` (${technicalDetail})` : ""}`,
        { tone: "warning", toast: false, statusPersistMs: 5600 }
      );
    } else {
      window.alert(
        tableMissing
          ? 'SQL fehlt: Tabelle "provider_notes" bitte in Supabase anlegen.'
          : normalizedEditNoteId
            ? "Notiz konnte nicht aktualisiert werden."
            : "Notiz konnte nicht gespeichert werden."
      );
    }
    return;
  }

  resetProviderNoteEditorState();
  await fetchProviderNotesForProvider(normalizedProviderId, { force: true });
  renderProviderNotes();
  renderProvidersTable();
  showSuccessFeedback(normalizedEditNoteId ? "Notiz aktualisiert." : "Notiz gespeichert.");
}

