async function handleActivateUser(userId) {
  const user = state.users.find((entry) => entry.id === userId);
  if (!user) {
    return;
  }
  if (user.source !== "profile") {
    window.alert("Freischaltung ist erst möglich, sobald der Mitarbeiter ein Konto erstellt hat.");
    return;
  }
  if (isUserStatusActive(user.status)) {
    return;
  }

  const client = getSupabaseClient();
  if (!client) {
    window.alert("Supabase Verbindung fehlt.");
    return;
  }

  const { error } = await client
    .from("profiles")
    .update({ status: "active" })
    .eq("user_id", user.sourceId);
  if (error) {
    window.alert("Mitarbeiter konnte nicht freigeschaltet werden.");
    return;
  }

  await syncUsersFromSupabase();
  renderAll();
  showSuccessFeedback("Mitarbeiter freigeschaltet.");
}

async function handleDeleteUser(userId) {
  const userIndex = state.users.findIndex((entry) => entry.id === userId);
  if (userIndex < 0) {
    return;
  }

  const user = state.users[userIndex];
  const activeProfiles = state.users.filter(
    (entry) => entry.source === "profile" && isUserStatusActive(entry.status)
  );
  if (user.source === "profile" && isUserStatusActive(user.status) && activeProfiles.length <= 1) {
    window.alert("Mindestens ein aktiver Mitarbeiter muss bestehen bleiben.");
    return;
  }

  const privilegedCount = state.users.filter(
    (entry) => entry.source === "profile" && isPrivilegedRole(entry.role) && isUserStatusActive(entry.status)
  ).length;
  if (isPrivilegedRole(user.role) && isUserStatusActive(user.status) && privilegedCount <= 1) {
    window.alert("Der letzte Admin/Superadmin kann nicht gelöscht werden.");
    return;
  }

  if (user.source === "profile" && user.sourceId === authProfile?.user_id) {
    window.alert("Du kannst deinen eigenen Zugang nicht löschen.");
    return;
  }

  const confirmed = await confirmDeleteAction(`Mitarbeiter "${user.name}" wirklich löschen?`);
  if (!confirmed) {
    return;
  }

  const client = getSupabaseClient();
  if (!client) {
    window.alert("Supabase Verbindung fehlt.");
    return;
  }

  if (user.source === "invite") {
    const { error } = await client.from("employee_invites").delete().eq("id", user.sourceId);
    if (error) {
      window.alert("Einladung konnte nicht gelöscht werden.");
      return;
    }
  } else if (user.source === "profile") {
    const { error } = await client.from("profiles").delete().eq("user_id", user.sourceId);
    if (error) {
      window.alert("Mitarbeiter konnte nicht gelöscht werden.");
      return;
    }
  }

  if (editingUserId === userId) {
    clearUserForm();
  }
  if (user.source === "profile") {
    clearUserTerritoriesForUserId(user.sourceId);
    clearEmployeeRateByUserId(user.sourceId);
    clearEmployeeHonorariumEnabledByUserId(user.sourceId);
    clearEmployeeProfileByUserId(user.sourceId);
    clearEmployeeTasksByUserId(user.sourceId);
  }
  clearUserTerritoriesForEmail(user.email);
  saveState({ showFeedback: false });
  await syncUsersFromSupabase();
  ensureSessionUser();
  renderAll();
  showSuccessFeedback(user.source === "invite" ? "Einladung gelöscht." : "Mitarbeiter gelöscht.");
}

async function handleDeleteProvider(providerId) {
  const providerIndex = state.providers.findIndex((entry) => entry.id === providerId);
  if (providerIndex < 0) {
    return;
  }

  const provider = state.providers[providerIndex];
  if (!canCurrentUserDeleteProvider(provider)) {
    window.alert("Löschen nur als Superadmin oder als Ersteller des Anbieters.");
    return;
  }
  const confirmed = await confirmDeleteAction(`Anbieter "${provider.name}" wirklich löschen?`);
  if (!confirmed) {
    return;
  }

  state.providers.splice(providerIndex, 1);
  const criticalPersistResult = await persistCriticalStateSnapshot({ retries: 3 });
  if (!criticalPersistResult.ok) {
    const rollbackIndex = Math.max(0, Math.min(providerIndex, state.providers.length));
    state.providers.splice(rollbackIndex, 0, provider);
    renderAll();
    showActionFeedback(
      "Anbieter konnte nicht gelöscht werden (Server-Sync fehlgeschlagen). Bitte erneut versuchen.",
      { tone: "error", toast: true, statusPersistMs: 6200, toastDurationMs: 6200 }
    );
    return;
  }

  await releaseProviderRegistryKey(provider.id);
  if (providerOpenNotesProviderId === providerId) {
    closeProviderOpenNotesModal();
  }
  if (editingProviderId === providerId) {
    clearProviderForm();
    setProvidersView("list");
  }

  saveState({ showFeedback: false });
  renderAll();
  showSuccessFeedback("Anbieter gelöscht.");
}

function renderManagementSummary() {
  const categoryCount = state.categories.length;
  const subcategoryCount = getTotalSubcategoryCount();
  const topicCount = getAllTopics().length;

  els.managementCatCount.textContent = String(categoryCount);
  els.managementSubcatCount.textContent = String(subcategoryCount);
  els.managementTopicCount.textContent = String(topicCount);
}

function renderCategoryList() {
  const admin = isAdmin();
  if (!state.categories.length) {
    els.categoriesList.innerHTML =
      '<li class="lane-empty">Noch keine Kategorien vorhanden.</li>';
    return;
  }

  els.categoriesList.innerHTML = state.categories
    .map((category) => {
      const topicCount = category.subcategories.reduce((count, sub) => count + sub.topics.length, 0);
      const activeClass = category.id === selectedCategoryId ? "active" : "";

      return `
        <li>
          <div class="lane-row">
            <button type="button" class="lane-item ${activeClass}" data-select-category="${escapeHtml(
              category.id
            )}">
              <span class="row-handle">≡</span>
              <span class="lane-item-text">
                <span class="lane-item-title">${escapeHtml(category.name)}</span>
                <span class="lane-item-meta">${escapeHtml(
                  String(category.subcategories.length)
                )} Bereiche · ${escapeHtml(String(topicCount))} Themen</span>
              </span>
            </button>
            ${
              admin
                ? `<div class="lane-actions">
                    <button type="button" class="mini-btn" title="Kategorie bearbeiten" aria-label="Kategorie bearbeiten" data-edit-category="${escapeHtml(
                      category.id
                    )}">✎</button>
                    <button type="button" class="mini-btn danger" title="Kategorie löschen" aria-label="Kategorie löschen" data-delete-category="${escapeHtml(
                      category.id
                    )}">✕</button>
                  </div>`
                : ""
            }
          </div>
        </li>
      `;
    })
    .join("");
}

function renderSubcategoriesList() {
  const admin = isAdmin();
  const category = getSelectedCategory();
  const subcategoryInput = els.subcategoryForm.querySelector("input[name='name']");

  setFormControlsDisabled(els.subcategoryForm, !isAdmin() || !category);

  if (!category) {
    subcategoryInput.placeholder = "Zuerst links eine Kategorie auswählen";
    els.subcategoryContext.textContent = "Bitte links eine Kategorie auswählen.";
    els.subcategoriesList.innerHTML =
      '<li class="lane-empty">Bitte zuerst eine Kategorie anlegen.</li>';
    return;
  }

  subcategoryInput.placeholder = `Neue Unterkategorie in "${category.name}"`;
  els.subcategoryContext.textContent = `Kategorie: ${category.name}`;

  if (!category.subcategories.length) {
    els.subcategoriesList.innerHTML =
      '<li class="lane-empty">Noch keine Unterkategorien in dieser Kategorie.</li>';
    return;
  }

  els.subcategoriesList.innerHTML = category.subcategories
    .map((subcategory) => {
      const activeClass = subcategory.id === selectedSubcategoryId ? "active" : "";
      return `
        <li>
          <div class="lane-row">
            <button type="button" class="lane-item ${activeClass}" data-select-subcategory="${escapeHtml(
              subcategory.id
            )}">
              <span class="row-handle">≡</span>
              <span class="lane-item-text">
                <span class="lane-item-title">${escapeHtml(subcategory.name)}</span>
                <span class="lane-item-meta">${escapeHtml(
                  String(subcategory.topics.length)
                )} Themen · ${escapeHtml(category.name)}</span>
              </span>
            </button>
            ${
              admin
                ? `<div class="lane-actions">
                    <button type="button" class="mini-btn" title="Unterkategorie bearbeiten" aria-label="Unterkategorie bearbeiten" data-edit-subcategory="${escapeHtml(
                      subcategory.id
                    )}">✎</button>
                    <button type="button" class="mini-btn" title="In andere Kategorie verschieben" aria-label="In andere Kategorie verschieben" data-move-subcategory="${escapeHtml(
                      subcategory.id
                    )}">↔</button>
                    <button type="button" class="mini-btn danger" title="Unterkategorie löschen" aria-label="Unterkategorie löschen" data-delete-subcategory="${escapeHtml(
                      subcategory.id
                    )}">✕</button>
                  </div>`
                : ""
            }
          </div>
        </li>
      `;
    })
    .join("");
}

function renderTopicsList() {
  const admin = isAdmin();
  const category = getSelectedCategory();
  const subcategory = getSelectedSubcategory();
  const topicInput = els.topicForm.querySelector("input[name='name']");

  setFormControlsDisabled(els.topicForm, !isAdmin() || !category || !subcategory);

  if (!category || !subcategory) {
    topicInput.placeholder = "Zuerst Kategorie und Unterkategorie auswählen";
    els.topicContext.textContent = "Bitte Kategorie und Unterkategorie auswählen.";
    els.topicsList.innerHTML =
      '<li class="lane-empty">Bitte zuerst Kategorie und Unterkategorie anlegen.</li>';
    return;
  }

  topicInput.placeholder = `Neues Thema in "${subcategory.name}"`;
  els.topicContext.textContent = `${category.name} > ${subcategory.name}`;

  if (!subcategory.topics.length) {
    els.topicsList.innerHTML = '<li class="lane-empty">Noch keine Themen vorhanden.</li>';
    return;
  }

  els.topicsList.innerHTML = subcategory.topics
    .map(
      (topic) => `
        <li>
          <div class="lane-row">
            <div class="lane-item topic-item">
              <span class="row-handle">≡</span>
              <span class="lane-item-text">
                <span class="lane-item-title">${escapeHtml(topic.name)}</span>
                <span class="lane-item-meta">${escapeHtml(category.name)} · ${escapeHtml(
                  subcategory.name
                )}</span>
              </span>
            </div>
            ${
              admin
                ? `<div class="lane-actions">
                    <button type="button" class="mini-btn" title="Thema bearbeiten" aria-label="Thema bearbeiten" data-edit-topic="${escapeHtml(
                      topic.id
                    )}">✎</button>
                    <button type="button" class="mini-btn" title="In anderen Themenbereich verschieben" aria-label="In anderen Themenbereich verschieben" data-move-topic="${escapeHtml(
                      topic.id
                    )}">↔</button>
                    <button type="button" class="mini-btn danger" title="Thema löschen" aria-label="Thema löschen" data-delete-topic="${escapeHtml(
                      topic.id
                    )}">✕</button>
                  </div>`
                : ""
            }
          </div>
        </li>
      `
    )
    .join("");
}

function applyProviderTopicTemplate(templateId) {
  if (!templateId) {
    return;
  }
  const topics = getAllTopics();
  if (!topics.length) {
    return;
  }

  const template = PROVIDER_TOPIC_TEMPLATES.find((entry) => entry.id === templateId);
  if (!template) {
    return;
  }

  if (template.id === "all") {
    topics.forEach((topic) => providerTopicSelection.add(topic.id));
    return;
  }

  const keywords = template.keywords.map((entry) => normalizeText(entry));
  topics.forEach((topic) => {
    const haystack = normalizeText(`${topic.name} ${topic.subcategoryName} ${topic.categoryName}`);
    if (keywords.some((keyword) => haystack.includes(keyword))) {
      providerTopicSelection.add(topic.id);
    }
  });
}

function handleEditCategory(categoryId) {
  const category = state.categories.find((entry) => entry.id === categoryId);
  if (!category) {
    return;
  }

  const nextName = window.prompt("Kategorie bearbeiten", category.name);
  if (nextName === null) {
    return;
  }

  const name = nextName.trim();
  if (!name) {
    return;
  }

  category.name = name;
  saveState({ showFeedback: false });
  renderAll();
}

async function handleDeleteCategory(categoryId) {
  const categoryIndex = state.categories.findIndex((entry) => entry.id === categoryId);
  if (categoryIndex < 0) {
    return;
  }

  const category = state.categories[categoryIndex];
  const topicIds = collectTopicIdsFromCategory(category);
  const confirmed = await confirmDeleteAction(
    `Kategorie "${category.name}" wirklich löschen? Unterkategorien und Themen werden mitgelöscht.`
  );
  if (!confirmed) {
    return;
  }

  state.categories.splice(categoryIndex, 1);
  removeTopicIdsFromProviders(topicIds);

  if (selectedCategoryId === categoryId) {
    selectedCategoryId = null;
    selectedSubcategoryId = null;
  }

  saveState({ showFeedback: false });
  renderAll();
}

function handleEditSubcategory(subcategoryId) {
  const subcategory = getSelectedCategory()?.subcategories.find((entry) => entry.id === subcategoryId);
  if (!subcategory) {
    return;
  }

  const nextName = window.prompt("Unterkategorie bearbeiten", subcategory.name);
  if (nextName === null) {
    return;
  }

  const name = nextName.trim();
  if (!name) {
    return;
  }

  subcategory.name = name;
  saveState({ showFeedback: false });
  renderAll();
}

function promptForManagementMoveTarget(promptTitle, options) {
  if (!Array.isArray(options) || !options.length) {
    return null;
  }
  const optionLines = options.map((entry, index) => `${index + 1}. ${entry}`).join("\n");
  const answer = window.prompt(`${promptTitle}\n\n${optionLines}\n\nBitte Nummer eingeben:`, "1");
  if (answer === null) {
    return null;
  }
  const selectedIndex = Number(String(answer || "").trim()) - 1;
  if (!Number.isInteger(selectedIndex) || selectedIndex < 0 || selectedIndex >= options.length) {
    window.alert("Ungültige Auswahl. Bitte eine gültige Nummer eingeben.");
    return null;
  }
  return selectedIndex;
}

async function promptTopicMoveTarget(topicName, sourceLabel, targetSubcategories) {
  if (!Array.isArray(targetSubcategories) || !targetSubcategories.length) {
    return "";
  }
  if (
    !els.topicMovePanel ||
    !els.topicMoveText ||
    !els.topicMoveTargetSelect ||
    !els.topicMoveYes ||
    !els.topicMoveNo ||
    !els.topicMoveClose
  ) {
    const fallbackIndex = promptForManagementMoveTarget(
      `Thema "${topicName}" verschieben nach:`,
      targetSubcategories.map((entry) => entry.label)
    );
    if (fallbackIndex === null) {
      return "";
    }
    return String(targetSubcategories[fallbackIndex]?.subcategory?.id || "").trim();
  }

  els.topicMoveText.textContent = `Thema "${topicName}" aktuell in ${sourceLabel}. Bitte neuen Themenbereich auswählen.`;
  els.topicMoveTargetSelect.innerHTML = targetSubcategories
    .map(
      (entry) =>
        `<option value="${escapeHtml(entry.subcategory.id)}">${escapeHtml(entry.label)} (${escapeHtml(
          String(entry.topicCount)
        )} Themen)</option>`
    )
    .join("");

  const initialTargetId = String(targetSubcategories[0]?.subcategory?.id || "").trim();
  if (initialTargetId) {
    els.topicMoveTargetSelect.value = initialTargetId;
  }

  els.topicMovePanel.classList.remove("hidden");
  syncBodyModalOpenState();
  window.setTimeout(() => {
    try {
      els.topicMoveTargetSelect.focus({ preventScroll: true });
    } catch (_error) {
      els.topicMoveTargetSelect.focus();
    }
  }, 0);

  return new Promise((resolve) => {
    let settled = false;

    const closePanel = (selectedTargetId = "") => {
      if (settled) {
        return;
      }
      settled = true;
      els.topicMovePanel.classList.add("hidden");
      syncBodyModalOpenState();
      els.topicMoveYes.removeEventListener("click", onYes);
      els.topicMoveNo.removeEventListener("click", onNo);
      els.topicMoveClose.removeEventListener("click", onNo);
      resolve(String(selectedTargetId || "").trim());
    };

    const onYes = () => {
      closePanel(els.topicMoveTargetSelect.value);
    };
    const onNo = () => {
      closePanel("");
    };
    els.topicMoveYes.addEventListener("click", onYes);
    els.topicMoveNo.addEventListener("click", onNo);
    els.topicMoveClose.addEventListener("click", onNo);
  });
}

function findSubcategoryLocation(subcategoryId) {
  const normalizedId = String(subcategoryId || "").trim();
  if (!normalizedId) {
    return null;
  }
  for (let categoryIndex = 0; categoryIndex < state.categories.length; categoryIndex += 1) {
    const category = state.categories[categoryIndex];
    const subcategoryIndex = category.subcategories.findIndex((entry) => entry.id === normalizedId);
    if (subcategoryIndex >= 0) {
      return {
        category,
        categoryIndex,
        subcategory: category.subcategories[subcategoryIndex],
        subcategoryIndex,
      };
    }
  }
  return null;
}

function findTopicLocation(topicId) {
  const normalizedId = String(topicId || "").trim();
  if (!normalizedId) {
    return null;
  }
  for (let categoryIndex = 0; categoryIndex < state.categories.length; categoryIndex += 1) {
    const category = state.categories[categoryIndex];
    for (let subcategoryIndex = 0; subcategoryIndex < category.subcategories.length; subcategoryIndex += 1) {
      const subcategory = category.subcategories[subcategoryIndex];
      const topicIndex = subcategory.topics.findIndex((entry) => entry.id === normalizedId);
      if (topicIndex >= 0) {
        return {
          category,
          categoryIndex,
          subcategory,
          subcategoryIndex,
          topic: subcategory.topics[topicIndex],
          topicIndex,
        };
      }
    }
  }
  return null;
}

function handleMoveSubcategory(subcategoryId) {
  const source = findSubcategoryLocation(subcategoryId);
  if (!source) {
    return;
  }
  const targetCategories = state.categories.filter((entry) => entry.id !== source.category.id);
  if (!targetCategories.length) {
    window.alert("Es gibt aktuell keine andere Kategorie, in die verschoben werden kann.");
    return;
  }

  const selectedTargetIndex = promptForManagementMoveTarget(
    `Themenbereich "${source.subcategory.name}" verschieben nach:`,
    targetCategories.map((entry) => entry.name || "Kategorie")
  );
  if (selectedTargetIndex === null) {
    return;
  }

  const targetCategory = targetCategories[selectedTargetIndex];
  source.category.subcategories.splice(source.subcategoryIndex, 1);
  targetCategory.subcategories.push(source.subcategory);

  selectedCategoryId = targetCategory.id;
  selectedSubcategoryId = source.subcategory.id;
  saveState();
  renderAll();
}

async function handleDeleteSubcategory(subcategoryId) {
  const category = getSelectedCategory();
  if (!category) {
    return;
  }

  const subcategoryIndex = category.subcategories.findIndex((entry) => entry.id === subcategoryId);
  if (subcategoryIndex < 0) {
    return;
  }

  const subcategory = category.subcategories[subcategoryIndex];
  const confirmed = await confirmDeleteAction(
    `Unterkategorie "${subcategory.name}" wirklich löschen? Alle Themen darin werden mitgelöscht.`
  );
  if (!confirmed) {
    return;
  }

  const topicIds = subcategory.topics.map((topic) => topic.id);
  category.subcategories.splice(subcategoryIndex, 1);
  removeTopicIdsFromProviders(topicIds);

  if (selectedSubcategoryId === subcategoryId) {
    selectedSubcategoryId = null;
  }

  saveState();
  renderAll();
}

function handleEditTopic(topicId) {
  const subcategory = getSelectedSubcategory();
  if (!subcategory) {
    return;
  }

  const topic = subcategory.topics.find((entry) => entry.id === topicId);
  if (!topic) {
    return;
  }

  const nextName = window.prompt("Thema bearbeiten", topic.name);
  if (nextName === null) {
    return;
  }

  const name = nextName.trim();
  if (!name) {
    return;
  }

  topic.name = name;
  saveState();
  renderAll();
}

async function handleMoveTopic(topicId) {
  const source = findTopicLocation(topicId);
  if (!source) {
    return;
  }

  const targetSubcategories = [];
  state.categories.forEach((category) => {
    category.subcategories.forEach((subcategory) => {
      if (subcategory.id === source.subcategory.id) {
        return;
      }
      targetSubcategories.push({
        category,
        subcategory,
        label: `${category.name} > ${subcategory.name}`,
        topicCount: Array.isArray(subcategory.topics) ? subcategory.topics.length : 0,
      });
    });
  });

  if (!targetSubcategories.length) {
    window.alert("Es gibt aktuell keinen anderen Themenbereich zum Verschieben.");
    return;
  }

  targetSubcategories.sort((left, right) => left.label.localeCompare(right.label, "de"));

  const selectedTargetSubcategoryId = await promptTopicMoveTarget(
    source.topic.name,
    `${source.category.name} > ${source.subcategory.name}`,
    targetSubcategories
  );
  if (!selectedTargetSubcategoryId) {
    return;
  }

  const target = targetSubcategories.find(
    (entry) => String(entry.subcategory.id || "").trim() === selectedTargetSubcategoryId
  );
  if (!target) {
    return;
  }
  source.subcategory.topics.splice(source.topicIndex, 1);
  target.subcategory.topics.push(source.topic);

  selectedCategoryId = target.category.id;
  selectedSubcategoryId = target.subcategory.id;
  saveState();
  renderAll();
}

async function handleDeleteTopic(topicId) {
  const subcategory = getSelectedSubcategory();
  if (!subcategory) {
    return;
  }

  const topicIndex = subcategory.topics.findIndex((entry) => entry.id === topicId);
  if (topicIndex < 0) {
    return;
  }

  const topic = subcategory.topics[topicIndex];
  const confirmed = await confirmDeleteAction(`Thema "${topic.name}" wirklich löschen?`);
  if (!confirmed) {
    return;
  }

  subcategory.topics.splice(topicIndex, 1);
  removeTopicIdsFromProviders([topicId]);
  saveState();
  renderAll();
}

function setActiveSection(targetId) {
  const currentSectionId = String(document.querySelector(".panel.active")?.id || "").trim();
  const requestedSectionId = String(targetId || "").trim();
  if (requestedSectionId === "org-chart-section") {
    departmentsPageTab = "orgchart";
  } else if (requestedSectionId === "departments-section") {
    departmentsPageTab = "departments";
  }
  let sectionId = String(targetId || "").trim();
  const activeRole = normalizeUserRole(getCurrentUser()?.role || authProfile?.role || "");
  sectionId = resolveAccessibleSectionForRole(sectionId, activeRole);
  targetId = sectionId;

  const leavingDirtyProviderForm =
    currentSectionId === "providers-section" &&
    providersViewMode === "form" &&
    providerFormDirty &&
    targetId !== "providers-section";
  if (leavingDirtyProviderForm) {
    const confirmed = window.confirm(
      "Ungespeicherte Anbieter-Eingaben sind vorhanden. Entwurf bleibt erhalten. Trotzdem zur anderen Seite wechseln?"
    );
    if (!confirmed) {
      return;
    }
    providerDraftPendingResume = true;
  }

  if (targetId === "users-section") {
    clearUserForm();
    setUsersView("list");
  } else {
    setUsersView("list");
  }
  if (targetId === "employee-admin-section") {
    ensureEmployeeAdminSelection();
    renderEmployeeAdminSection();
  }
  if (targetId === "conversation-notes-section") {
    ensureConversationSelection();
    renderConversationNotesSection();
    void hydrateConversationThreadsFromSupabase({ force: true });
  }
  if (targetId === "companies-section") {
    setCompaniesTab("overview", { render: false });
    ensureCompaniesSelection();
    renderCompaniesSection();
    void hydrateConversationThreadsFromSupabase({ force: true });
  }
  if (targetId === "providers-section") {
    if (providerDraftPendingResume && providerFormDirty) {
      setProvidersView("form");
      providerDraftPendingResume = false;
      showInfoFeedback("Ungespeicherter Anbieter-Entwurf wurde wieder geöffnet.", {
        toast: false,
        statusPersistMs: 1800,
      });
    } else {
      clearProviderForm();
      setProvidersView("list");
    }
  } else {
    setProvidersView("list");
  }
  if (targetId !== "dashboard-section") {
    selectedEmployeeActivityUserId = "";
    closeEmployeeDetailsModal();
  }
  if (targetId !== "providers-section") {
    closeProviderOpenNotesModal();
  }
  if (targetId !== "tour-planner-section") {
    closeTourModals();
  }
  if (targetId !== "sales-phone-section") {
    closeSalesPhoneModal();
  }
  if (targetId !== "employee-admin-section") {
    closeEmployeeAdminDetailModal();
  }
  if (targetId !== "conversation-notes-section") {
    closeConversationEditModal();
    conversationOrganizationCreateOpen = false;
    syncConversationOrganizationCreateFormVisibility();
  }
  if (targetId !== "companies-section") {
    closeCompanyModal();
    closeCompanyNoteReadModal();
  }
  if (targetId !== "departments-section") {
    closeDepartmentModal();
    closeDepartmentMembersModal();
  }
  if (targetId !== "departments-section") {
    closeOrgChartEditModal();
  }
  setOverviewNavSubmenuOpen(targetId === "dashboard-section");
  setOrganizationNavSubmenuOpen(
    targetId === "users-section" ||
      targetId === "employee-admin-section" ||
      targetId === "departments-section"
  );
  setMasterdataNavSubmenuOpen(
    targetId === "companies-section" ||
      targetId === "providers-section" ||
      targetId === "management-section" ||
      targetId === "parameters-section"
  );
  setSalesNavSubmenuOpen(
    targetId === "sales-dashboard-section" ||
      targetId === "tour-planner-section" ||
      targetId === "sales-leads-section" ||
      targetId === "sales-phone-section"
  );
  setFinanceNavSubmenuOpen(
    targetId === "incoming-invoices-section" ||
      targetId === "incoming-offers-section" ||
      targetId === "contract-manager-section"
  );
  setActivitiesNavSubmenuOpen(targetId === "conversation-notes-section");

  els.navButtons.forEach((button) => {
    const buttonTarget = String(button.dataset.target || "").trim();
    const childTargets = String(button.dataset.childTargets || "")
      .split(",")
      .map((entry) => entry.trim())
      .filter(Boolean);
    const isDirectTarget = buttonTarget === targetId;
    const isParentTarget = childTargets.includes(targetId);
    button.classList.toggle("active", isDirectTarget || isParentTarget);
  });

  els.panels.forEach((panel) => {
    panel.classList.toggle("active", panel.id === targetId);
  });

  if (targetId === "dashboard-section") {
    window.setTimeout(() => {
      renderDashboardAdminTabs();
      renderActiveDashboardAdminPanel();
    }, 0);
  }
  if (targetId === "parameters-section") {
    renderMapParameterForm();
  }
  if (targetId === "tour-planner-section") {
    renderToursSection({ forceRecenter: true });
  }
  if (targetId === "sales-dashboard-section") {
    renderSalesDashboardSection();
  }
  if (targetId === "sales-leads-section") {
    renderSalesLeadsSection();
  }
  if (targetId === "sales-phone-section") {
    renderSalesPhoneSection();
  }
  if (targetId === "incoming-invoices-section") {
    renderIncomingInvoicesSection();
  }
  if (targetId === "incoming-offers-section") {
    renderIncomingOffersSection();
  }
  if (targetId === "contract-manager-section") {
    renderContractManagerSection();
  }
  if (targetId === "departments-section") {
    renderDepartmentsSection();
  }
}

